(111, 1, NULL, 1, NULL, NULL, NULL, NULL, 'தமிழ்நாட்டில் கனமழை எச்சரிக்கை — 12 மாவட்டங்களுக்கு ஆரஞ்சு அலர்ட்', 'tamilnadu-heavy-rain-orange-alert-12-districts-june-2026', 'தென்மேற்கு பருவமழை வலுப்பெறுவதால் 12 மாவட்டங்களில் கனமழை பெய்யும் என சென்னை வானிலை ஆய்வு மையம் எச்சரிக்கை விடுத்துள்ளது.', '<p>தமிழ்நாட்டில் தென்மேற்கு பருவமழை வலுப்பெற்று வருவதால் நீலகிரி, கோயம்புத்தூர், திண்டுக்கல், தேனி, திருச்சிராப்பள்ளி உள்பட 12 மாவட்டங்களுக்கு ஆரஞ்சு அலர்ட் விடுக்கப்பட்டுள்ளது.</p><p>மாவட்ட ஆட்சியர்கள் பள்ளிகளுக்கு விடுமுறை அறிவித்துள்ளனர். மீனவர்களை கடலுக்கு செல்ல வேண்டாம் என கோரிக்கை விடுக்கப்பட்டுள்ளது. மழைநீர் வடிகால் சுத்தம் செய்யப்படுகிறது.</p><p>முதல்வர் அலுவலகம் அனைத்து மாவட்ட ஆட்சியர்களுக்கும் அவசர கட்டளை பிறப்பிக்கப்பட்டுள்ளது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1534274988757-a28bf1a57c17?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1534274988757-a28bf1a57c17?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-10 05:55:00', NULL, '2026-06-10 06:00:00', 1, 1, 0, 0, 0, NULL, NULL, 18528, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 10:02:11', NULL, 0),
(112, 1, NULL, 1, NULL, NULL, NULL, NULL, 'SSLC மதிப்பெண் மறுசரிபார்ப்பு — ஆன்லைனில் விண்ணப்பிக்கலாம்', 'sslc-revaluation-application-online-june-2026', '10ஆம் வகுப்பு பொதுத்தேர்வு முடிவுகளில் திருப்தியில்லாத மாணவர்கள் மறுசரிபார்ப்புக்கு ஆன்லைனில் விண்ணப்பிக்கலாம்.', '<p>தமிழ்நாடு பள்ளிக்கல்வித்துறை அறிவிப்பின்படி SSLC மதிப்பெண் மறுசரிபார்ப்புக்கு ஜூன் 20 வரை விண்ணப்பிக்கலாம்.</p><p>ஒரு பாடத்திற்கு ₹500 கட்டணம் நிர்ணயிக்கப்பட்டுள்ளது. dge.tn.gov.in இணையதளம் வழியாக விண்ணப்பிக்கலாம்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1588072432836-e10032774350?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1588072432836-e10032774350?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 08:55:00', NULL, '2026-06-09 09:00:00', 0, 0, 1, 0, 0, NULL, NULL, 12313, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-10 14:55:17', NULL, 0),
(113, 1, NULL, 1, NULL, NULL, NULL, NULL, 'சென்னை மெட்ரோ — ஷோலிங்கநல்லூர் வரை நீட்டிப்பு திட்டம் அறிவிப்பு', 'chennai-metro-sholinganallur-extension-announced', 'சென்னை மெட்ரோ ரயில் இரண்டாம் கட்ட திட்டத்தில் ஷோலிங்கநல்லூர் வரை நீட்டிக்கப்படும் என அரசு அறிவித்தது.', '<p>சென்னை மெட்ரோ ரயில் இரண்டாம் கட்ட திட்டத்தின் கீழ் நாப்பேர்தான் முதல் ஷோலிங்கநல்லூர் வரை 11.5 கிலோமீட்டர் தூரத்தில் 9 நிறுத்தங்கள் அமைக்கப்படும்.</p><p>₹3,200 கோடியில் நிறைவேற்றப்படும் இந்த திட்டம் 2027 ஆண்டுக்குள் முடிவடையும் என்று அரசு தெரிவித்தது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1581262208435-41726149a759?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1581262208435-41726149a759?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 09:55:00', NULL, '2026-06-08 10:00:00', 0, 1, 0, 0, 0, NULL, NULL, 9405, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-10 17:34:43', NULL, 0),
(114, 1, NULL, 1, NULL, NULL, NULL, NULL, 'தமிழகத்தில் 500 புதிய அரசு மருத்துவமனைகள் — முதல்வர் அறிவிப்பு', '500-new-government-hospitals-tamilnadu-cm-announcement', 'தமிழ்நாடு முழுவதும் 500 புதிய அரசு மருத்துவமனைகள் அமைக்கப்படும் என முதல்வர் அறிவித்தார்.', '<p>தமிழ்நாடு முதல்வர் 500 புதிய அரசு மருத்துவமனைகள் மூன்று ஆண்டுகளில் அமைக்கப்படும் என சட்டசபையில் அறிவித்தார்.</p><p>₹8,500 கோடி நிதி ஒதுக்கீடு அறிவிக்கப்பட்டுள்ளது. ஒவ்வொரு தாலுகாவிலும் குறைந்தது ஒரு மருத்துவமனை அமைக்கப்படும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1519494026892-80bbd2d6fd0d?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 10:55:00', NULL, '2026-06-07 11:00:00', 1, 0, 1, 0, 0, NULL, NULL, 15617, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 01:15:53', NULL, 0),
(115, 1, NULL, 1, NULL, NULL, NULL, NULL, 'மதுரை மீனாட்சி கோவில் — ஆடி உத்சவம் ஜூலை 20 தொடக்கம்', 'madurai-meenakshi-temple-aadi-festival-july-20', 'மதுரை மீனாட்சியம்மன் கோவிலில் ஆடி மாத சிறப்பு உத்சவம் ஜூலை 20 முதல் தொடங்குகிறது.', '<p>மதுரை மீனாட்சியம்மன் கோவிலில் ஆடி மாதம் சிறப்பு உத்சவங்கள் நடைபெறும். ஆடி பூரம் விழா 50 ஆண்டுகளில் இல்லாத அளவில் பிரமாண்டமாக கொண்டாடப்படும் என்று கோவில் நிர்வாகம் அறிவித்தது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1605649487212-47bdab064df7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1605649487212-47bdab064df7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 08:55:00', NULL, '2026-06-06 09:00:00', 0, 0, 0, 0, 0, NULL, NULL, 7810, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-10 17:20:58', NULL, 0),
(116, 1, NULL, 2, NULL, NULL, NULL, NULL, 'பிரதமர் மோடி — G7 உச்சி மாநாட்டில் இந்தியாவின் வலிமையான நிலைப்பாடு', 'pm-modi-g7-summit-india-strong-position-june-2026', 'இத்தாலியில் நடைபெறும் G7 உச்சி மாநாட்டில் பிரதமர் நரேந்திர மோடி இந்தியாவின் கொள்கைகளை வலியுறுத்தினார்.', '<p>G7 உச்சி மாநாட்டில் பிரதமர் நரேந்திர மோடி காலநிலை மாற்றம், டிஜிட்டல் உள்கட்டமைப்பு, தொழில்நுட்ப பரிமாற்றம் குறித்து உரையாற்றினார்.</p><p>இந்தியா-அமெரிக்கா இடையே ₹2.5 லட்சம் கோடி மதிப்பிலான வர்த்தக ஒப்பந்தம் கையெழுத்தானது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1555848962-6e79363ec58f?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1555848962-6e79363ec58f?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-10 06:55:00', NULL, '2026-06-10 07:00:00', 1, 1, 0, 0, 0, NULL, NULL, 22447, 0, 0, 4, '2026-06-10 13:42:26', '2026-07-13 05:26:50', NULL, 0),
(117, 1, NULL, 2, NULL, NULL, NULL, NULL, 'RBI வட்டி விகிதம் — 25 பேஸிஸ் பாயிண்ட் குறைப்பு அறிவிப்பு', 'rbi-repo-rate-cut-25-basis-points-june-2026', 'ரிசர்வ் வங்கி ரெப்போ வட்டி விகிதத்தை 25 பேஸிஸ் பாயிண்ட் குறைத்து 5.75% ஆக நிர்ணயித்துள்ளது.', '<p>ரிசர்வ் வங்கி நாணயக் கொள்கை குழு கூட்டத்தில் ரெப்போ விகிதம் 6% இலிருந்து 5.75% ஆக குறைக்கப்பட்டது.</p><p>இதனால் வீட்டு கடன், கார் கடன் வட்டி விகிதங்கள் குறையும். EMI சுமை குறையும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 13:55:00', NULL, '2026-06-09 14:00:00', 0, 1, 1, 0, 0, NULL, NULL, 19825, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 10:56:45', NULL, 0),
(118, 1, NULL, 2, NULL, NULL, NULL, NULL, 'NEET 2026 — AIIMSல் 100% மதிப்பெண் பெற்ற சிவகாசி மாணவர்', 'neet-2026-sivakasi-student-perfect-score-aiims', 'NEET 2026 தேர்வில் 720/720 மதிப்பெண் பெற்று AIIMSல் சேர்ந்த சிவகாசி மாணவர் கதை.', '<p>சிவகாசியை சேர்ந்த அர்ஜுன் பாலகிருஷ்ணன் NEET 2026 தேர்வில் 720/720 என முழு மதிப்பெண் பெற்று All India Rank 1 பெற்றார்.</p><p>அரசு பள்ளியில் படித்த இவருக்கு முதல்வர் வாழ்த்து தெரிவித்தார்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1523050854058-8df90110c9f1?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 07:55:00', NULL, '2026-06-08 08:00:00', 0, 0, 1, 0, 0, NULL, NULL, 28913, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-10 16:15:22', NULL, 0),
(119, 1, NULL, 2, NULL, NULL, NULL, NULL, 'UPI பரிவர்த்தனை — மே மாதம் 20 பில்லியன் சாதனை', 'upi-transactions-20-billion-may-2026-record', 'UPI டிஜிட்டல் கட்டண முறை மே மாதம் 20 பில்லியன் பரிவர்த்தனைகளை கடந்து சாதனை படைத்தது.', '<p>NPCI தரவின்படி மே 2026ல் UPI மூலம் 20.4 பில்லியன் பரிவர்த்தனைகள் நடைபெற்றன. மொத்த மதிப்பு ₹23 லட்சம் கோடி.</p><p>இது இந்திய டிஜிட்டல் பொருளாதார வரலாற்றில் மைல்கல்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1563013544-824ae1b704d3?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1563013544-824ae1b704d3?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 09:55:00', NULL, '2026-06-07 10:00:00', 0, 0, 0, 0, 0, NULL, NULL, 16707, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-08 04:27:32', NULL, 0),
(120, 1, NULL, 2, NULL, NULL, NULL, NULL, 'விண்வெளி வீரர்கள் — ககன்யான் டிசம்பர் 2026 புறப்பாடு உறுதி', 'gaganyaan-december-2026-launch-confirmed-isro', 'ISRO ககன்யான் திட்டத்தின் முதல் மனித விண்வெளி பயணம் டிசம்பர் 14 அன்று நடைபெறும் என உறுதிப்படுத்தப்பட்டது.', '<p>ISRO தலைவர் டாக்டர் வி.நாரயணன் ககன்யான் திட்டம் அட்டவணைப்படி முன்னேறுவதாக தெரிவித்தார். 4 விண்வெளி வீரர்கள் தயார் நிலையில் உள்ளனர்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1614728894747-a83421e2b9c9?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1614728894747-a83421e2b9c9?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 10:55:00', NULL, '2026-06-06 11:00:00', 0, 1, 0, 0, 0, NULL, NULL, 13409, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-10 19:10:21', NULL, 0),
(121, 1, NULL, 3, NULL, NULL, NULL, NULL, 'மத்திய கிழக்கு — இஸ்ரேல்-ஹமாஸ் போர்நிறுத்த பேச்சுவார்த்தை முடிவில்லாமல் முடிந்தது', 'israel-hamas-ceasefire-talks-inconclusive-june-2026', 'கத்தார் மத்தியஸ்தத்தில் நடைபெற்ற இஸ்ரேல்-ஹமாஸ் போர்நிறுத்த பேச்சுவார்த்தை முடிவில்லாமல் முடிந்தது.', '<p>டோஹாவில் நடைபெற்ற இஸ்ரேல்-ஹமாஸ் போர்நிறுத்த பேச்சுவார்த்தை 3 நாட்கள் நடந்தும் முடிவு எட்டப்படவில்லை. பந்தியாயினர் விடுவிப்பு முக்கிய தடையாக உள்ளது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1578496479914-7ef3b0193be3?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1578496479914-7ef3b0193be3?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-10 07:55:00', NULL, '2026-06-10 08:00:00', 1, 0, 0, 0, 0, NULL, NULL, 24524, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 02:05:39', NULL, 0),
(122, 1, NULL, 3, NULL, NULL, NULL, NULL, 'அமெரிக்கா — AI சட்டம் கான்கிரஸில் நிறைவேற்றம்', 'usa-ai-regulation-law-congress-passed-2026', 'செயற்கை நுண்ணறிவை கட்டுப்படுத்தும் வரலாற்று சிறப்பு AI சட்டம் அமெரிக்க கான்கிரஸில் நிறைவேற்றப்பட்டது.', '<p>அமெரிக்க கான்கிரஸ் AI Accountability and Safety Act 2026ஐ நிறைவேற்றியது. Tech நிறுவனங்கள் AI வெளிப்படைத்தன்மை அளிக்க வேண்டும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 09:55:00', NULL, '2026-06-09 10:00:00', 0, 1, 0, 0, 0, NULL, NULL, 18211, 0, 0, 4, '2026-06-10 13:42:26', '2026-07-12 10:04:21', NULL, 0),
(123, 1, NULL, 3, NULL, NULL, NULL, NULL, 'சீனா — மூன்றாம் நிலா இறங்கு திட்டம் வெற்றி', 'china-chang-e-7-moon-landing-success-2026', 'சீனாவின் Chang-e 7 விண்கலம் சந்திரனின் தென் துருவத்தில் வெற்றிகரமாக இறங்கியது.', '<p>சீனா விண்வெளி ஆராய்ச்சி நிலையம் Chang-e 7 விண்கலம் சந்திரனின் தென் துருவத்தில் நீர் ஐஸ் தேடும் பணியை தொடங்கியது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1446776811953-b23d57bd21aa?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 08:55:00', NULL, '2026-06-08 09:00:00', 0, 0, 1, 0, 0, NULL, NULL, 14611, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-09 23:47:52', NULL, 0),
(124, 1, NULL, 3, NULL, NULL, NULL, NULL, 'உக்ரைன் — ரஷ்யா ஆயுத பரிமாற்றம் தொடர்பு விசாரணை', 'ukraine-russia-arms-deal-investigation-2026', 'ரஷ்யா-உக்ரைன் போரில் ஆயுத கடத்தல் குறித்த சர்வதேச விசாரணை தொடங்கியது.', '<p>ஐ.நா. விசாரணை குழு ரஷ்யாவிற்கு ஆயுதம் வழங்கும் நாடுகள் குறித்து விசாரிக்கின்றது. 12 நாடுகள் கேள்விக்குட்படுகின்றன.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1580674285054-bed31e145f59?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1580674285054-bed31e145f59?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 07:55:00', NULL, '2026-06-07 08:00:00', 0, 0, 0, 0, 0, NULL, NULL, 11214, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-10 15:00:23', NULL, 0),
(125, 1, NULL, 3, NULL, NULL, NULL, NULL, 'பாகிஸ்தான் — பொருளாதார நெருக்கடி தீவிரம்; IMF நிபந்தனை', 'pakistan-economic-crisis-imf-conditions-june-2026', 'பாகிஸ்தான் பொருளாதார நெருக்கடி மோசமடைவதால் IMF புதிய நிபந்தனைகளை விதித்தது.', '<p>பாகிஸ்தான் அரசு IMF நிபந்தனைகளை ஏற்று மின்சாரம், பெட்ரோல் மானியங்களை நீக்கியது. இதனால் விலைவாசி கடுமையாக உயர்ந்தது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1526304640581-d334cdbbf45e?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1526304640581-d334cdbbf45e?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 09:55:00', NULL, '2026-06-06 10:00:00', 0, 0, 0, 0, 0, NULL, NULL, 9816, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-10 22:05:29', NULL, 0),
(127, 1, NULL, 4, NULL, NULL, NULL, NULL, 'ரஜினிகாந்த் புதிய படம் — ஜப்பானில் படப்பிடிப்பு தொடக்கம்', 'rajinikanth-new-film-japan-shoot-begins-2026', 'சூப்பர் ஸ்டார் ரஜினிகாந்தின் 171வது படம் ஜப்பான் டோக்கியோவில் படப்பிடிப்பு தொடங்கியது.', '<p>வெ.பிரபுதேவா இயக்கும் ரஜினிகாந்தின் 171வது படத்தின் முக்கிய காட்சிகள் டோக்கியோவில் படப்பிடிப்பு நடைபெற்றது. 2027 தொடக்கத்தில் வெளியாகும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1489599849927-2ee91cede3ba?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 10:55:00', NULL, '2026-06-09 11:00:00', 0, 1, 0, 0, 0, NULL, NULL, 41250, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 05:39:28', NULL, 0),
(128, 1, NULL, 4, NULL, NULL, NULL, NULL, 'ஆஸ்கர் 2027 — இந்தியாவின் அதிகாரப்பூர்வ நுழைவு \"மைக்கேல்\"', 'oscar-2027-india-official-entry-michael-tamil-film', 'Tamil திரைப்படம் \"மைக்கேல்\" ஆஸ்கர் 2027க்கான இந்தியாவின் அதிகாரப்பூர்வ நுழைவாக தேர்வு செய்யப்பட்டது.', '<p>Film Federation of India \"மைக்கேல்\" படத்தை Best International Feature Film பிரிவில் இந்தியாவின் அதிகாரப்பூர்வ நுழைவாக அறிவித்தது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1440404653325-ab127d49abc1?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1440404653325-ab127d49abc1?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 09:55:00', NULL, '2026-06-08 10:00:00', 0, 0, 1, 0, 0, NULL, NULL, 34826, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 22:34:55', NULL, 0),
(129, 1, NULL, 4, NULL, NULL, NULL, NULL, 'நயன்தாரா Netflix சீரிஸ் — வர்ல்ட்வைட் ஸ்ட்ரீமிங் தொடக்கம்', 'nayanthara-netflix-series-worldwide-streaming-begins', 'நயன்தாரா நடித்த Netflix Original Tamil சீரிஸ் உலகளவில் ஸ்ட்ரீம் ஆகத் தொடங்கியது.', '<p>நயன்தாரா நடித்த Action-Thriller Netflix Tamil சீரிஸ் 180 நாடுகளில் ஒரே நேரத்தில் வெளியானது. முதல் 24 மணி நேரத்தில் 5 மில்லியன் views.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 11:55:00', NULL, '2026-06-07 12:00:00', 0, 0, 0, 0, 0, NULL, NULL, 27614, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-14 04:17:03', NULL, 0),
(130, 1, NULL, 4, NULL, NULL, NULL, NULL, 'கமல்ஹாசன் 60 ஆண்டு திரைவாழ்க்கை — சிறப்பு விருது விழா', 'kamalhaasan-60-years-cinema-special-award-ceremony', 'கமல்ஹாசன் 60 ஆண்டு திரை வாழ்க்கையை கொண்டாட சிறப்பு விருது விழா சென்னையில் நடைபெற்றது.', '<p>கமல்ஹாசனின் 60 ஆண்டு திரைவாழ்க்கையை கொண்டாட தமிழக அரசு சிறப்பு விருது விழா ஏற்பாடு செய்தது. 500க்கும் மேற்பட்ட சினிமா பிரமுகர்கள் கலந்துகொண்டனர்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1516450360452-9312f5e86fc7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1516450360452-9312f5e86fc7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 13:55:00', NULL, '2026-06-06 14:00:00', 0, 1, 0, 0, 0, NULL, NULL, 19411, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 17:12:07', NULL, 0),
(132, 1, NULL, 5, NULL, NULL, NULL, NULL, 'நீரஜ் சோப்ரா — 92.08m ஈட்டி எறிந்து உலக சாதனை', 'neeraj-chopra-world-record-92-08m-javelin-2026', 'ஒலிம்பிக் சாம்பியன் நீரஜ் சோப்ரா ஜூரிச் Diamond League-ல் 92.08 மீட்டர் ஈட்டி எறிந்து உலக சாதனை படைத்தார்.', '<p>ஜூரிச் Diamond League-ல் நீரஜ் சோப்ரா 92.08 மீட்டர் ஈட்டி எறிந்து Jan Železný-யின் 98.48 மீட்டர் உலக சாதனைக்கு நெருங்கினார். இது இந்திய புதிய சாதனை.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1461896836934-ffe607ba8211?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1461896836934-ffe607ba8211?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 19:55:00', NULL, '2026-06-08 20:00:00', 0, 1, 0, 0, 0, NULL, NULL, 32117, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 18:30:24', NULL, 0),
(133, 1, NULL, 5, NULL, NULL, NULL, NULL, 'French Open 2026 — Carlos Alcaraz இரண்டாவது பட்டம்', 'french-open-2026-alcaraz-second-title-roland-garros', 'Carlos Alcaraz French Open 2026 Final-ல் Jannik Sinner ஐ 3-1 செட்டில் தோற்கடித்து இரண்டாவது Roland Garros பட்டம் வென்றார்.', '<p>Roland Garros Final-ல் Carlos Alcaraz Jannik Sinner ஐ 6-4, 3-6, 6-3, 6-2 என்ற கணக்கில் தோற்கடித்தார்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1622279457486-62dcc4a431d6?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1622279457486-62dcc4a431d6?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 20:55:00', NULL, '2026-06-08 21:00:00', 0, 0, 1, 0, 0, NULL, NULL, 21811, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 03:06:13', NULL, 0),
(134, 1, NULL, 5, NULL, NULL, NULL, NULL, 'Chess World Championship — அர்ஜுன் எரிகைசி உலக சாம்பியன்', 'arjun-erigaisi-chess-world-champion-2026', 'இந்தியாவின் அர்ஜுன் எரிகைசி Chess World Championship 2026-ல் Magnus Carlsen ஐ தோற்கடித்து உலக சாம்பியன் பட்டம் வென்றார்.', '<p>Chess World Championship 2026 Final-ல் அர்ஜுன் எரிகைசி Magnus Carlsen ஐ 7.5-6.5 என்ற கணக்கில் தோற்கடித்தார். இந்தியாவின் இரண்டாவது World Chess Champion.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1529699211952-734e80c4d42b?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1529699211952-734e80c4d42b?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-05 17:55:00', NULL, '2026-06-05 18:00:00', 0, 1, 0, 0, 0, NULL, NULL, 29416, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 20:45:46', NULL, 0),
(135, 1, NULL, 5, NULL, NULL, NULL, NULL, 'TNPL Season 6 — CSG vs Ruby Trichy Warriors Final', 'tnpl-season-6-final-csg-vs-ruby-trichy-warriors', 'TNPL Season 6 இறுதிப் போட்டி Chepauk Super Gillies vs Ruby Trichy Warriors இடையே நடைபெறும்.', '<p>TNPL Season 6 இறுதிப் போட்டி ஜூலை 28 அன்று சென்னை M.A.Chidambaram Stadium-ல் நடைபெறும். இரு அணிகளும் அதிரடி கிரிக்கட் ஆடி Final எட்டின.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1540747913346-19212a4b32a6?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1540747913346-19212a4b32a6?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-04 09:55:00', NULL, '2026-06-04 10:00:00', 0, 0, 0, 0, 0, NULL, NULL, 16813, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-13 21:33:48', NULL, 0),
(136, 1, NULL, 6, NULL, NULL, NULL, NULL, 'ChatGPT-5 — தமிழ் மொழி Native Support அறிவிப்பு', 'chatgpt-5-tamil-native-support-announcement', 'OpenAI ChatGPT-5 தமிழ் உட்பட 50 மொழிகளில் Native Language Support வழங்குவதாக அறிவித்தது.', '<p>OpenAI ChatGPT-5 தமிழ், தெலுங்கு, மலையாளம், கன்னடம் உட்பட 50 இந்திய மொழிகளில் Native support வழங்கும். கணிதம், அறிவியல் சூத்திரங்கள் Tamil-ல் விளக்கும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1677442135703-1787eea5ce01?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-10 09:55:00', NULL, '2026-06-10 10:00:00', 1, 1, 0, 0, 0, NULL, NULL, 48264, 0, 0, 4, '2026-06-10 13:42:26', '2026-07-13 05:02:51', NULL, 0),
(137, 1, NULL, 6, NULL, NULL, NULL, NULL, 'Apple iPhone 17 — Folding iPhone விலை விவரம் வெளியீடு', 'apple-iphone-17-fold-price-specs-leaked', 'Apple iPhone 17 Fold விலை $1,599 என்று வெளியானது. செப்டம்பர் 12 அன்று வெளியாகும்.', '<p>Apple iPhone 17 Fold $1,599 விலையில் கிடைக்கும். 7.8 இஞ்ச் foldable display, 48MP கேமரா, A19 Pro சிப் கொண்டது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1510557880182-3d4d3cba35a5?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1510557880182-3d4d3cba35a5?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 11:55:00', NULL, '2026-06-09 12:00:00', 0, 0, 1, 0, 0, NULL, NULL, 38622, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 02:49:24', NULL, 0),
(138, 1, NULL, 6, NULL, NULL, NULL, NULL, 'Jio 6G — இந்தியாவில் 2027 மார்ச் வணிக தொடக்கம் உறுதி', 'jio-6g-commercial-launch-india-march-2027', 'Reliance Jio 6G சேவை 2027 மார்ச்சில் இந்தியாவில் வணிக அளவில் தொடங்கும் என Mukesh Ambani உறுதிப்படுத்தினார்.', '<p>Reliance AGM-ல் Mukesh Ambani Jio 6G 10 Gbps வேகத்தில் 2027 மார்ச் தொடங்கும் என அறிவித்தார். ₹20,000 கோடி முதலீடு.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1516321497487-e288fb19713f?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1516321497487-e288fb19713f?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 10:55:00', NULL, '2026-06-08 11:00:00', 0, 1, 0, 0, 0, NULL, NULL, 26412, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 19:12:30', NULL, 0),
(139, 1, NULL, 6, NULL, NULL, NULL, NULL, 'Ola Electric — ₹5,000 கோடி Gigafactory விரிவாக்கம்', 'ola-electric-gigafactory-expansion-5000-crore', 'Ola Electric ₹5,000 கோடியில் Bangalore Gigafactory விரிவாக்கம் செய்து ஆண்டுக்கு 1 கோடி EV உற்பத்தி இலக்கு.', '<p>Ola Electric Gigafactory-ல் Phase 2 விரிவாக்கம் அறிவிக்கப்பட்டது. 2028ல் ஆண்டுக்கு 1 கோடி electric vehicle உற்பத்தி திறன் அடையும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 08:55:00', NULL, '2026-06-07 09:00:00', 0, 0, 0, 0, 0, NULL, NULL, 19815, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 16:28:33', NULL, 0),
(140, 1, NULL, 6, NULL, NULL, NULL, NULL, 'ISRO SpaDeX — 2 செயற்கைகோள்கள் சேர்த்து Docking வெற்றி', 'isro-spadex-satellite-docking-success', 'ISRO SpaDeX திட்டத்தில் இரண்டு செயற்கைக்கோள்கள் விண்வெளியில் வெற்றிகரமாக Docking செய்யப்பட்டன.', '<p>ISRO SpaDeX (Space Docking Experiment) திட்டத்தில் SDX01 மற்றும் SDX02 செயற்கைக்கோள்கள் 470km உயரத்தில் Docking வெற்றி பெற்றது. இது Gaganyaan-க்கான முக்கிய படி.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1517976487492-5750f3195933?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1517976487492-5750f3195933?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 07:55:00', NULL, '2026-06-06 08:00:00', 0, 1, 1, 0, 0, NULL, NULL, 31209, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-05 02:23:03', NULL, 0),
(141, 1, NULL, 7, NULL, NULL, NULL, NULL, 'திருப்பதி திருமலை — ரத சப்தமி விழா 5 லட்சம் பக்தர்கள்', 'tirupati-tirumala-ratha-saptami-festival-5-lakh', 'திருப்பதி திருமலை ஏழுமலையான் கோவிலில் ரத சப்தமி விழாவிற்கு 5 லட்சம் பக்தர்கள் வருகை.', '<p>திருமலை திருப்பதி தேவஸ்தானம் தெரிவிப்பதாவது, ரத சப்தமி மற்றும் ஐந்தாம் நாள் சிறப்பு அலங்காரத்திற்கு 5 லட்சம் பக்தர்கள் வருகை புரிந்தனர். Online booking முழுமையாக நிரம்பியது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1551009175-8a68da93d5f9?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1551009175-8a68da93d5f9?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 07:55:00', NULL, '2026-06-09 08:00:00', 0, 0, 1, 0, 0, NULL, NULL, 21417, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-11 14:20:40', NULL, 0),
(142, 1, NULL, 7, NULL, NULL, NULL, NULL, 'கைலாசம் மானசரோவர் யாத்திரை 2026 — தமிழக 48 பயணிகள்', 'kailash-mansarovar-yatra-2026-48-tamilnadu-pilgrims', 'கைலாசம் மானசரோவர் யாத்திரை 2026-ல் தமிழ்நாட்டிலிருந்து 48 பக்தர்கள் திருப்பயணம் தொடங்கினர்.', '<p>கைலாசம் மானசரோவர் யாத்திரை இரண்டாம் கட்டத்தில் தமிழ்நாட்டிலிருந்து 48 பக்தர்கள் தொடர்ந்தனர். ITBP வழிகாட்டலில் பயணம் தொடங்கியது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1605649487212-47bdab064df7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1605649487212-47bdab064df7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 06:55:00', NULL, '2026-06-08 07:00:00', 0, 0, 0, 0, 0, NULL, NULL, 12817, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-12 15:28:50', NULL, 0),
(143, 1, NULL, 7, NULL, NULL, NULL, NULL, 'ரிஷிகேஷ் — சர்வதேச யோகா தினம் 50,000 பங்கேற்பு', 'rishikesh-international-yoga-day-50000-participants', 'ஐ.நா. சர்வதேச யோகா தினம் ரிஷிகேஷ் கங்கை கரையில் 50,000 பேர் கலந்துகொண்டனர்.', '<p>ஜூன் 21 சர்வதேச யோகா தினத்தில் ரிஷிகேஷ் கங்கை கரையில் 95 நாடுகளிலிருந்து 50,000க்கும் மேற்பட்டோர் யோகா பயிற்சியில் கலந்துகொண்டனர்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 06:55:00', NULL, '2026-06-07 07:00:00', 0, 1, 0, 0, 0, NULL, NULL, 16613, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 04:28:11', NULL, 0),
(144, 1, NULL, 7, NULL, NULL, NULL, NULL, 'சிதம்பரம் நடராஜர் கோவில் — 1000 ஆண்டு மகோத்சவம் அறிவிப்பு', 'chidambaram-nataraja-temple-1000-year-festival', 'சிதம்பரம் நடராஜர் கோவில் 1000 ஆண்டு திருவிழா அடுத்த ஆண்டு நடைபெறும் என அறிவிக்கப்பட்டது.', '<p>சிதம்பரம் நடராஜர் கோவில் கும்பாபிஷேகம் 1000 ஆண்டு நிறைவை ஒட்டி 2027ல் மகோத்சவம் நடைபெறும். ₹100 கோடி நிதி ஒதுக்கீடு.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1548013146-72479768bada?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1548013146-72479768bada?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 07:55:00', NULL, '2026-06-06 08:00:00', 0, 0, 0, 0, 0, NULL, NULL, 9413, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-12 02:11:36', NULL, 0),
(145, 1, NULL, 7, NULL, NULL, NULL, NULL, 'வேதாரண்யம் — 5000 ஆண்டு பழைமை கடலடி கோவில் கண்டுபிடிப்பு', 'vedaranyam-5000-year-underwater-temple-discovery', 'வேதாரண்யம் கடற்கரையில் நடத்தப்பட்ட ஆராய்ச்சியில் 5000 ஆண்டு பழைமையான கடலடி சிவன் கோவில் கண்டுபிடிக்கப்பட்டது.', '<p>ASI ஆராய்ச்சியாளர்கள் வேதாரண்யம் கடலடியில் 5000 ஆண்டு பழைமையான சிவன் கோவில் இடிபாடுகளை கண்டுபிடித்தனர். சங்க கால தமிழர் கட்டிடக்கலை வெளிப்பட்டது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1544735716-392fe2489ffa?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-05 08:55:00', NULL, '2026-06-05 09:00:00', 1, 1, 1, 0, 0, NULL, NULL, 38720, 0, 0, 4, '2026-06-10 13:42:26', '2026-07-13 21:36:38', NULL, 0),
(146, 1, NULL, 8, NULL, NULL, NULL, NULL, 'TCS Infosys Wipro — 2026-27ல் 2 லட்சம் Freshers நியமனம்', 'tcs-infosys-wipro-2-lakh-freshers-hiring-2026-27', 'IT துறை மீட்சி — TCS, Infosys, Wipro சேர்ந்து 2026-27 நிதியாண்டில் 2 லட்சம் fresher பட்டதாரிகளை நியமிக்கும்.', '<p>IT துறை மந்தநிலையிலிருந்து மீண்டு வரும் நிலையில் TCS 80,000, Infosys 50,000, Wipro 40,000 என மொத்தம் 2 லட்சம் பட்டதாரிகளை நியமிக்க திட்டமிட்டுள்ளன.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1522202176988-66273c2fd55f?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-10 07:55:00', NULL, '2026-06-10 08:00:00', 1, 1, 0, 0, 0, NULL, NULL, 42814, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 19:07:43', NULL, 0),
(147, 1, NULL, 8, NULL, NULL, NULL, NULL, 'TNPSC Group 2 — 2500 காலியிடங்கள் விண்ணப்பம் ஜூலை 1', 'tnpsc-group-2-2500-vacancies-application-july-1', 'TNPSC Group 2 2026 அறிவிப்பு வெளியானது. 2500 காலியிடங்களுக்கு ஜூலை 1 முதல் விண்ணப்பிக்கலாம்.', '<p>தமிழ்நாடு அரசு பணிகள் தேர்வாணையம் Group 2 A & 2 தேர்வுக்கு 2500 காலியிடங்களை அறிவித்தது. தகுதி: எந்த பாடத்தில் பட்டதாரி பட்டம்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1434030216411-0b793f4b4173?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 09:55:00', NULL, '2026-06-09 10:00:00', 0, 1, 1, 0, 0, NULL, NULL, 56461, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-14 03:44:07', NULL, 0),
(148, 1, NULL, 8, NULL, NULL, NULL, NULL, 'IIT Madras — AI & Data Science புதிய பட்டப்படிப்பு தொடக்கம்', 'iit-madras-ai-data-science-new-degree-programme', 'IIT Madras 2026-27 கல்வியாண்டு முதல் AI & Data Science B.Tech படிப்பு தொடங்குகிறது.', '<p>IIT Madras AI & Data Science B.Tech திட்டம் 2026-27 முதல் 60 இடங்களில் தொடங்குகிறது. JEE Advanced மதிப்பெண் அடிப்படையில் சேர்க்கை.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1509062522246-3755977927d7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1509062522246-3755977927d7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 08:55:00', NULL, '2026-06-08 09:00:00', 0, 0, 1, 0, 0, NULL, NULL, 28920, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-14 00:23:22', NULL, 0),
(149, 1, NULL, 8, NULL, NULL, NULL, NULL, 'UPSC CSE 2025 — Final Result: 1016 பேர் தேர்வு, TN Top 5', 'upsc-cse-2025-final-result-1016-selected', 'UPSC Civil Services Exam 2025 இறுதி முடிவுகள் வெளியானது. 1016 பேர் தேர்வு, தமிழகத்திலிருந்து 5 பேர் Top 50.', '<p>UPSC CSE 2025 இறுதி முடிவுகளில் மொத்தம் 1016 பேர் தேர்வாகினர். சென்னையை சேர்ந்த Priya IAS Rank 8 பெற்றார்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 10:55:00', NULL, '2026-06-07 11:00:00', 0, 0, 0, 0, 0, NULL, NULL, 34708, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 06:49:53', NULL, 0),
(150, 1, NULL, 8, NULL, NULL, NULL, NULL, 'Central Govt — SSC MTS 2026 அறிவிப்பு: 15,547 காலியிடங்கள்', 'ssc-mts-2026-notification-15547-vacancies', 'மத்திய அரசு SSC Multi Tasking Staff 2026 தேர்வுக்கு 15,547 காலியிடங்கள் அறிவிக்கப்பட்டன.', '<p>Staff Selection Commission MTS 2026 அறிவிப்பு. தகுதி: 10ஆம் வகுப்பு தேர்ச்சி. ஜூலையில் தேர்வு. ஆன்லைனில் விண்ணப்பிக்கலாம்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1606761568499-6d2451b23c66?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1606761568499-6d2451b23c66?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 08:55:00', NULL, '2026-06-06 09:00:00', 0, 1, 0, 0, 0, NULL, NULL, 48228, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-13 17:55:23', NULL, 0),
(151, 1, NULL, 9, NULL, NULL, NULL, NULL, 'Sensex 90,000 கடந்தது — FII முதலீடு ₹50,000 கோடி', 'sensex-crosses-90000-fii-investment-50000-crore', 'BSE Sensex முதல்முறையாக 90,000 புள்ளிகளை கடந்தது. FII முதலீடு ₹50,000 கோடி.', '<p>BSE Sensex 90,000 புள்ளிகளை கடந்து வரலாற்று சாதனை படைத்தது. RBI வட்டி குறைப்பு மற்றும் வலுவான GDP வளர்ச்சி முதலீட்டாளர் நம்பிக்கையை ஏற்படுத்தியது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1611974789855-9c2a0a7236a3?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-10 08:55:00', NULL, '2026-06-10 09:00:00', 1, 1, 0, 0, 0, NULL, NULL, 38425, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 10:32:24', NULL, 0),
(152, 1, NULL, 9, NULL, NULL, NULL, NULL, 'Amazon India — ₹1 லட்சம் கோடி 5 ஆண்டு முதலீட்டு திட்டம்', 'amazon-india-1-lakh-crore-5-year-investment-plan', 'Amazon India 2030 வரை ₹1 லட்சம் கோடி முதலீடு செய்வதாக CEO Andy Jassy அறிவித்தார்.', '<p>Amazon India CEO Andy Jassy நரேந்திர மோடி சந்திப்பில் 5 ஆண்டுகளில் ₹1 லட்சம் கோடி முதலீட்டை உறுதிப்படுத்தினார். 2 லட்சம் வேலைவாய்ப்புகள் உருவாகும்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1523474253046-8cd2748b5fd2?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1523474253046-8cd2748b5fd2?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 10:55:00', NULL, '2026-06-09 11:00:00', 0, 0, 1, 0, 0, NULL, NULL, 24629, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 20:42:19', NULL, 0),
(153, 1, NULL, 9, NULL, NULL, NULL, NULL, 'Tata Motors EV — Nexon Electric 2.0 ₹12 லட்சத்தில் வெளியீடு', 'tata-motors-nexon-electric-2-launch-12-lakh', 'Tata Motors Nexon EV 2.0 ₹12 லட்சத்தில் வெளியிட்டது. 600km range, 30 நிமிடத்தில் 80% charging.', '<p>Tata Motors Nexon EV 2.0 ₹11.99 லட்சத்தில் (ex-showroom) வெளியிட்டது. 600km real-world range, 11.2kW fast charging, V2H technology.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1593941707882-a5bba14938c7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 11:55:00', NULL, '2026-06-08 12:00:00', 0, 1, 0, 0, 0, NULL, NULL, 19813, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-13 00:35:20', NULL, 0),
(154, 1, NULL, 9, NULL, NULL, NULL, NULL, 'Gold விலை — ₹80,000 கடந்தது; Akshaya Tritiya தேவை உயர்வு', 'gold-price-crosses-80000-per-10-gram-june-2026', 'தங்கம் விலை 10 கிராமுக்கு ₹80,000 கடந்தது. சர்வதேச அளவில் Dollar பலவீனமே காரணம்.', '<p>சென்னை சர்ரட்டா தங்கம் விலை 10 கிராமுக்கு ₹80,250 என்ற சாதனை விலையை தொட்டது. Silver ₹95,000/kg. Dollar index குறைவே காரணம்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1610375461246-83df859d849d?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1610375461246-83df859d849d?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 09:55:00', NULL, '2026-06-07 10:00:00', 1, 0, 1, 0, 0, NULL, NULL, 29414, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 19:45:13', NULL, 0),
(155, 1, NULL, 9, NULL, NULL, NULL, NULL, 'MSMEs — மத்திய அரசு ₹10,000 கோடி வட்டி இல்லா கடன் திட்டம்', 'msme-central-govt-10000-crore-interest-free-loan', 'மத்திய அரசு MSMEs-க்கு ₹10,000 கோடி வட்டி இல்லா கடன் திட்டம் அறிவித்தது.', '<p>மத்திய MSME அமைச்சகம் 50 லட்சம் சிறு, குறு நிறுவனங்களுக்கு ₹2 லட்சம் வரை வட்டி இல்லா கடன் வழங்கும் திட்டம் அறிவித்தது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1454165804606-c3d57bc86b40?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 09:55:00', NULL, '2026-06-06 10:00:00', 0, 0, 0, 0, 0, NULL, NULL, 14211, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-11 06:00:30', NULL, 0),
(156, 1, NULL, 10, NULL, NULL, NULL, NULL, 'ICMR — புதிய இந்திய உணவு வழிகாட்டுதல்கள் வெளியீடு', 'icmr-new-indian-dietary-guidelines-2026', 'ICMR இந்தியர்களுக்கான புதிய உணவு வழிகாட்டுதல்கள் வெளியிட்டது. Ultra-processed food எச்சரிக்கை.', '<p>ICMR புதிய Dietary Guidelines For Indians 2026 வெளியிட்டது. Ultra-processed food குறைக்க வலியுறுத்தல், பாரம்பரிய உணவுக்கு முன்னுரிமை.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-09 08:55:00', NULL, '2026-06-09 09:00:00', 0, 1, 0, 0, 0, NULL, NULL, 22815, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-11 12:05:35', NULL, 0),
(157, 1, NULL, 10, NULL, NULL, NULL, NULL, 'தமிழ்நாடு — Dengue எச்சரிக்கை; 500 பேருக்கு சிகிச்சை', 'tamilnadu-dengue-warning-500-cases-june-2026', 'தமிழ்நாட்டில் டெங்கு காய்ச்சல் பரவல் அதிகரிப்பால் சுகாதாரத்துறை எச்சரிக்கை விடுத்தது.', '<p>தமிழ்நாட்டில் ஜூன் மாதம் மட்டும் 500 டெங்கு காய்ச்சல் வழக்குகள் பதிவாகின. வீட்டில் தண்ணீர் தேக்கம் இல்லாமல் பார்த்துக்கொள்ள சுகாதாரத்துறை வேண்டுகோள்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1584515933487-779824d29309?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1584515933487-779824d29309?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 07:55:00', NULL, '2026-06-08 08:00:00', 1, 0, 0, 0, 0, NULL, NULL, 18618, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 11:15:57', NULL, 0),
(158, 1, NULL, 10, NULL, NULL, NULL, NULL, 'AI Doctor — இந்திய ஸ்டார்ட்அப் AI கண்டுபிடிப்பு சாதனை', 'indian-startup-ai-doctor-disease-detection-breakthrough', 'Chennai AI ஸ்டார்ட்அப் 98% துல்லியத்துடன் 20 நோய்களை கண்டுபிடிக்கும் AI கண்டுபிடித்தது.', '<p>சென்னை AI ஸ்டார்ட்அப் MedAI 98.7% துல்லியத்துடன் Cancer, Diabetes, Heart Disease உட்பட 20 நோய்களை கண்டுபிடிக்கும் AI Algorithm கண்டுபிடித்தது. WHO அங்கீகாரம் பெற்றது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1559757175-5700dde675bc?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 09:55:00', NULL, '2026-06-07 10:00:00', 0, 1, 1, 0, 0, NULL, NULL, 34215, 0, 0, 4, '2026-06-10 13:42:26', '2026-07-11 07:18:27', NULL, 0),
(159, 1, NULL, 10, NULL, NULL, NULL, NULL, 'யோகா — தினசரி 30 நிமிட பயிற்சி ரத்த அழுத்தம் குறைக்கும்: ஆய்வு', 'yoga-30-minutes-daily-reduces-blood-pressure-study', 'AIIMS புதிய ஆய்வு: தினசரி 30 நிமிட யோகா 12 வாரத்தில் ரத்த அழுத்தத்தை 15% குறைக்கும்.', '<p>AIIMS New Delhi நடத்திய ஆய்வில் 500 பேரிடம் 12 வாரம் யோகா பயிற்சி செய்தபோது systolic BP 15%, diastolic BP 10% குறைந்தது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1506126613408-eca07ce68773?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 06:55:00', NULL, '2026-06-06 07:00:00', 0, 0, 0, 0, 0, NULL, NULL, 16412, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-10 18:39:45', NULL, 0),
(160, 1, NULL, 10, NULL, NULL, NULL, NULL, 'AIIMS Chennai — Liver Transplant 1000வது வெற்றிகரமான அறுவை சிகிச்சை', 'aiims-chennai-1000th-successful-liver-transplant', 'AIIMS Chennai 1000வது Liver Transplant அறுவை சிகிச்சை வெற்றிகரமாக நடைபெற்றது.', '<p>AIIMS Chennai Liver Transplant Unit 1000வது சிகிச்சையை வெற்றிகரமாக நிறைவேற்றியது. 98.5% வெற்றி விகிதம் உலக தரத்தில் உள்ளது.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1551601651-2a8555f1a136?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1551601651-2a8555f1a136?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-05 10:55:00', NULL, '2026-06-05 11:00:00', 0, 1, 0, 0, 0, NULL, NULL, 12812, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-12 00:42:49', NULL, 0),
(161, 1, NULL, 11, NULL, NULL, NULL, NULL, 'Vikatan TV — தமிழ்நாடு பட்ஜெட் 2026 நேரடி ஒளிபரப்பு', 'vikatan-tv-tamilnadu-budget-2026-live-coverage', 'தமிழ்நாடு பட்ஜெட் 2026 நேரடி ஒளிபரப்பு Vikatan TV YouTube-ல் 2 மில்லியன் பார்வையாளர்கள்.', '<p>தமிழ்நாடு சட்டசபையில் நிதியமைச்சர் நிதிநிலை அறிக்கை வாசிக்கும்போது Vikatan TV YouTube நேரடி ஒளிபரப்பில் 2 மில்லியன் பேர் பார்த்தனர். Record.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1574375927938-d5a98e8ffe85?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-08 10:55:00', NULL, '2026-06-08 11:00:00', 0, 0, 0, 0, 0, NULL, NULL, 14808, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-12 08:38:03', NULL, 0),
(162, 1, NULL, 11, NULL, NULL, NULL, NULL, 'Rajinikanth Speech — Superstar பிறந்தநாள் FANS கொண்டாட்டம்', 'rajinikanth-birthday-fans-celebration-video', 'சூப்பர் ஸ்டார் ரஜினிகாந்த் 76வது பிறந்தநாளில் ரசிகர்கள் பிரமாண்ட கொண்டாட்டம் VIDEO.', '<p>ரஜினிகாந்தின் 76வது பிறந்தநாளில் உலகம் முழுவதும் ரசிகர்கள் கொண்டாட்டங்கள் நடத்தினர். Chennai Rajini Makkal Mandram கேக் வெட்டி கொண்டாட்டம்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1516450360452-9312f5e86fc7?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1516450360452-9312f5e86fc7?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-07 11:55:00', NULL, '2026-06-07 12:00:00', 0, 1, 0, 0, 0, NULL, NULL, 28610, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-08 14:45:28', NULL, 0),
(163, 1, NULL, 11, NULL, NULL, NULL, NULL, 'Chennai Floods — மழை நாசம் Aerial Video', 'chennai-floods-aerial-view-video-june-2026', 'சென்னையில் கனமழை ஏற்படுத்திய வெள்ளம் — Drone Aerial Video பரவி பரபரப்பு.', '<p>சென்னை வெள்ளத்தை Drone மூலம் எடுத்த Aerial Video Social Media-ல் வைரல். Velachery, Tambaram பகுதிகளில் மோசமான நிலை.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1504711434969-e33886168f5c?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-06 15:55:00', NULL, '2026-06-06 16:00:00', 1, 0, 1, 0, 0, NULL, NULL, 44211, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-12 04:50:34', NULL, 0),
(164, 1, NULL, 11, NULL, NULL, NULL, NULL, 'ISRO SpaDeX Docking — வரலாற்று தருணம் LIVE VIDEO', 'isro-spadex-docking-live-video-historic-moment', 'ISRO SpaDeX Docking வரலாற்று தருணம் — YouTube Live-ல் 5 மில்லியன் பேர் பார்த்தனர்.', '<p>ISRO SpaDeX Docking Live Stream-ல் 5.2 மில்லியன் பேர் ஒரே நேரத்தில் பார்த்து சாதனை. விண்வெளி வீரர்கள் கட்டுப்பாட்டு அறையில் கொண்டாட்டம்.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1517976487492-5750f3195933?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1517976487492-5750f3195933?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-05 08:55:00', NULL, '2026-06-05 09:00:00', 0, 1, 0, 0, 0, NULL, NULL, 32409, 0, 0, 3, '2026-06-10 13:42:26', '2026-07-08 07:09:04', NULL, 0),
(165, 1, NULL, 11, NULL, NULL, NULL, NULL, 'Viral Video — கோவை யானை குட்டி மீட்பு நெகிழ்ச்சி காட்சி', 'coimbatore-baby-elephant-rescue-viral-video', 'கோவை காட்டில் ஆற்றில் சிக்கிய யானை குட்டியை காட்டுயிர் அதிகாரிகள் மீட்ட நெகிழ்ச்சி VIDEO வைரல்.', '<p>கோவை டாப்ஸ்லிப் அருகே ஆற்றில் சிக்கிய யானை குட்டியை Forest Department அதிகாரிகள் 3 மணி நேர முயற்சிக்கு பிறகு மீட்டனர். Video 10 மில்லியன் views.</p>', 'news', NULL, 'ta', NULL, NULL, 'https://images.unsplash.com/photo-1551316679-9c6ae9dec224?w=800&q=80', NULL, 'https://images.unsplash.com/photo-1551316679-9c6ae9dec224?w=400&q=70', NULL, NULL, 'published', 'published', NULL, 1, '2026-06-04 13:55:00', NULL, '2026-06-04 14:00:00', 0, 0, 0, 0, 0, NULL, NULL, 18907, 0, 0, 2, '2026-06-10 13:42:26', '2026-07-08 06:26:41', NULL, 0),
(166, 4, NULL, 1, NULL, NULL, NULL, 6, 'அதிமுக விஜயபாஸ்கர் ராஜினாமா', '80d72058', 'அதிமுகவைச் சேர்ந்த முன்னாள் அமைச்சரும், விராலிமலை தொகுதி சட்டமன்ற உறுப்பினருமான டாக்டர் சி.விஜயபாஸ்கர் தனது எம்.எல்.ஏ பதவியை சமீபத்தில் ராஜினாமா செய்துள்ளார். இ…', 'அதிமுகவைச் சேர்ந்த முன்னாள் அமைச்சரும், விராலிமலை தொகுதி சட்டமன்ற உறுப்பினருமான டாக்டர் சி.விஜயபாஸ்கர் தனது எம்.எல்.ஏ பதவியை சமீபத்தில் ராஜினாமா செய்துள்ளார். இவரது ராஜினாமாவை சபாநாயகர் ஜே.சி.டி பிரபாகர் ஏற்றுக்கொண்டுள்ளார். 2026 ஆம் ஆண்டு நடைபெற்ற சட்டமன்றத் தேர்தலுக்குப் பிறகு, அதிமுகவில் இருந்து ராஜினாமா செய்த ஐந்தாவது சட்டமன்ற உறுப்பினர் இவர் என்பது குறிப்பிடத்தக்கது.தலைநகர் டெல்லியில் அரசு முறைப் பயணமாக சுற்றுப்பயணம் மேற்கொண்டுள்ள தமிழக முதலமைச்சர் மு.க.ஸ்டாலின் அவர்கள், குடியரசுத் தலைவர் மற்றும் துணைக் குடியரசுத் தலைவர் உள்ளிட்டோரைச் சந்தித்து முக்கியப் பேச்சுவார்த்தைகளை நடத்தி வருகிறார்.', 'news', NULL, 'ta', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-18 19:44:39', 0, 0, 0, 0, 0, NULL, NULL, 14, 0, 0, 1, '2026-06-16 13:56:28', '2026-07-10 17:06:08', NULL, 0),
(167, 4, NULL, 5, NULL, NULL, NULL, 5, 'ராயல் சேலஞ்சர்ஸ் பெங்களூரு (RCB) அணி சாம்பியன் பட்டத்தை வென்றுள்ளது', 'rcb', 'மே 31, 2026 அன்று நடைபெற்ற ஐபிஎல் (IPL 2026) இறுதிப் போட்டியில் குஜராத் டைட்டன்ஸ் (Gujarat Titans) அணியை 5 விக்கெட் வித்தியாசத்தில் வீழ்த்தி ராயல் சேலஞ்சர்ஸ் பெ…', 'மே 31, 2026 அன்று நடைபெற்ற ஐபிஎல் (IPL 2026) இறுதிப் போட்டியில் குஜராத் டைட்டன்ஸ் (Gujarat Titans) அணியை 5 விக்கெட் வித்தியாசத்தில் வீழ்த்தி ராயல் சேலஞ்சர்ஸ் <h2>பெங்களூரு (RCB) அணி சாம்பியன் </h2>பட்டத்தை வென்றுள்ளது.\r\n\r\nஐபிஎல் 2026 இறுதிப் போட்டி விவரங்கள்:இடம்: நரேந்திர மோடி ஸ்டேடியம், அகமதாபாத்.போட்டி முடிவு: ஆர்சிபி (RCB) 5 விக்கெட் வித்தியாசத்தில் அபார வெற்றி.சிறப்பு ஆட்டம்: <strong>விராட் கோலி 42 பந்துகளில் 75 ரன்கள்</strong> எடுத்து அணியின் வெற்றிக்கு முக்கியப் பங்காற்றினார்.குஜராத் டைட்டன்ஸ் நிர்ணயித்த 155 ரன்கள் என்ற வெற்றி இலக்கை நோக்கி களமிறங்கிய பெங்களூரு அணி, கடைசி ஓவர்களில் சிறப்பாக விளையாடி கோப்பையைத் தட்டிச் சென்றது. \r\n\r\nஇந்த வரலாற்று வெற்றியைத் தொடர்ந்து, கிரிக்கெட் ஜாம்பவான்களான சச்சின் டெண்டுல்கர், சுரேஷ் ரெய்னா போன்ற பிரபலங்களும், சென்னை சூப்பர் கிங்ஸ் (CSK) அணியும் ஆர்சிபிக்கு வாழ்த்துகளைத் தெரிவித்தனர்.', 'news', NULL, 'ta', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-16 19:39:52', 0, 1, 0, 0, 0, NULL, NULL, 191, 0, 0, 1, '2026-06-16 14:08:34', '2026-07-14 04:56:53', NULL, 0),
(169, 5, NULL, 1, NULL, NULL, NULL, 12, 'fasdfasdf', 'fasdfasdf', 'asfasdf aasdf df as fasdf asd', 'asfasdf aasdf df as fasdf asd', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/06/media_6a423a5dcc4435.89964829.png', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-19 19:11:10', 0, 0, 0, 0, 0, 'fasdfasdf', 'asfasdf aasdf df as fasdf asd', 11, 0, 0, 1, '2026-06-19 13:41:10', '2026-07-11 07:01:18', NULL, 0),
(170, 4, NULL, 1, NULL, NULL, NULL, 8, 'பூந்தமல்லி – வடபழனி மெட்ரோ சேவை தொடக்கம் எப்போது? பயணிகளின் எதிர்பார்ப்பு அதிகரிப்பு', 'பூந்தமல்லி-வடபழனி-மெட்ரோ-சேவை-தொடக்கம்-எப்போது-பயணிகளின்-எதிர்பார்ப்பு-அதிகரிப்பு', '# பூந்தமல்லி – வடபழனி மெட்ரோ சேவை தொடக்கம் எப்போது? பயணிகளின் எதிர்பார்ப்பு அதிகரிப்பு\r\n\r\nசென்னையின் இரண்டாம் கட்ட மெட்ரோ ரயில் திட்டத்தில் முக்கியமான பகுதியாகக…', '#<strong> பூந்தமல்லி – வடபழனி மெட்ரோ சேவை தொடக்கம் எப்போது? பயணிகளின் எதிர்பார்ப்பு அதிகரிப்பு</strong>\r\n\r\n<h2>சென்னையின் இரண்டாம் கட்ட மெட்ரோ ரயில் திட்டத்தில் முக்கியமான பகுதியாகக் கருதப்படும் பூந்தமல்லி – வடபழனி வழித்தடம் இயக்கத்திற்குத் தயாராக இருப்பதாக தகவல்கள் வெளியாகியுள்ளன. தேவையான பாதுகாப்பு ஆய்வுகள் மற்றும் தொழில்நுட்ப அனுமதிகள் பெரும்பாலும் நிறைவடைந்துள்ள நிலையில், இந்த சேவை எப்போது பொதுமக்கள் பயன்பாட்டுக்கு திறக்கப்படும் என்ற எதிர்பார்ப்பு அதிகரித்துள்ளது.</h2>\r\n\r\n<blockquote>14.6 கிலோமீட்டர் நீளமுள்ள இந்த வழித்தடத்தில் ரயில் இயக்கத்திற்கான இறுதி அனுமதி கிடைத்துள்ளதாக கூறப்படுகிறது. இதன் காரணமாக, தொடக்க விழா தொடர்பான முன்னேற்பாடுகளை சென்னை மெட்ரோ நிர்வாகம் மேற்கொண்டு வருகிறது.</blockquote>\r\n\r\nமுன்னதாக பாதுகாப்பு அதிகாரிகள் சில கட்டுப்பாடுகளுடன் மட்டுமே அனுமதி வழங்கியிருந்தனர். இதனால் குறைந்த எண்ணிக்கையிலான ரயில்களை மட்டுமே இயக்க முடிந்தது. தற்போது அந்த நிபந்தனைகள் தளர்த்தப்பட்டுள்ளதால், குறுகிய நேர இடைவெளியில் தொடர்ந்து சேவைகளை வழங்கும் வாய்ப்பு உருவாகியுள்ளது.\r\n\r\nஇந்த வழித்தடத்தில் பூந்தமல்லி பைபாஸ், பூந்தமல்லி, முல்லைத்தோட்டம், காரஞ்சாவடி, குமணன்சாவடி, காட்டுப்பாக்கம், ஐயப்பன்தாங்கல், தெள்ளியகரம், போரூர் பைபாஸ் மற்றும் போரூர் சந்திப்பு உள்ளிட்ட நிலையங்கள் பயன்பாட்டுக்கு தயாராக உள்ளன.\r\n\r\nஎனினும், ஆலப்பாக்கம், காரம்பாக்கம், வளசரவாக்கம், ஆழ்வார்திருநகர், சாலிகிராமம் கிடங்கு மற்றும் சாலிகிராமம் ஆகிய ஆறு இடைநிலை நிலையங்களில் கட்டுமானப் பணிகள் இன்னும் முழுமையடையவில்லை. இதனால் தொடக்ககட்டத்தில் போரூர் சந்திப்பிலிருந்து வடபழனி வரை இடைநிறுத்தமின்றி நேரடி சேவை இயக்கப்படும் என எதிர்பார்க்கப்படுகிறது.\r\n\r\nபாதுகாப்பு ஆய்வுக் குழுக்கள் பல கட்டங்களில் ஆய்வு மேற்கொண்டு தேவையான பரிந்துரைகளை வழங்கியுள்ளன. மீதமுள்ள நிலையங்களின் பணிகள் முடிவடைந்த பின்னரே முழுமையான நிரந்தர அங்கீகாரம் வழங்கப்படும் என அதிகாரப்பூர்வ வட்டாரங்கள் தெரிவித்துள்ளன.\r\n\r\nஇந்த மெட்ரோ பாதை செயல்பாட்டுக்கு வந்தால், மேற்குத் சென்னை பகுதிகளில் வசிக்கும் ஆயிரக்கணக்கான மாணவர்கள், அலுவலக ஊழியர்கள் மற்றும் மருத்துவமனைகளுக்குச் செல்லும் பொதுமக்கள் பெரிதும் பயன்பெறுவார்கள். பல கல்வி நிறுவனங்கள், வணிக வளாகங்கள் மற்றும் முக்கிய மருத்துவமனைகள் இந்த வழித்தடத்தை ஒட்டியுள்ளதால், பயண நேரம் கணிசமாகக் குறையும் என்று எதிர்பார்க்கப்படுகிறது.\r\n\r\nதற்போது முக்கிய நிலையங்கள் தயாராக இருந்தாலும், மீதமுள்ள கட்டுமானப் பணிகள் நிறைவடைந்த பிறகே சேவை தொடக்க தேதி அறிவிக்கப்படும் என மெட்ரோ நிர்வாகம் தெரிவித்துள்ளது. அனைத்து பாதுகாப்பு அனுமதிகளும் கிடைத்துள்ள நிலையில், பூந்தமல்லி – வடபழனி மெட்ரோ சேவை விரைவில் பொதுமக்கள் பயன்பாட்டிற்கு திறக்கப்படும் என்ற நம்பிக்கை நிலவுகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/06/media_6a363ca7f1b9e7.92068323.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-20 11:11:49', 0, 1, 0, 0, 0, 'பூந்தமல்லி – வடபழனி மெட்ரோ சேவை தொடக்கம் எப்போது? பயணிகளின் எதிர்பார்ப்பு அதிகரிப்பு', '# பூந்தமல்லி – வடபழனி மெட்ரோ சேவை தொடக்கம் எப்போது? பயணிகளின் எதிர்பார்ப்பு அதிகரிப்பு\r\n\r\nசென்னையின் இரண்டாம் கட்ட மெட்ரோ ரயில் திட்டத்தில் முக்கியமான பகுதியாகக', 95, 0, 0, 1, '2026-06-20 05:39:36', '2026-07-11 08:50:52', NULL, 0);
