(171, 5, NULL, 1, NULL, NULL, NULL, 10, 'எதிர்க்கட்சிகளின் குற்றச்சாட்டுகளுக்கு சட்டப்பேரவையில் பதிலளிக்கும் விஜய்', 'எதிர்க்கட்சிகளின்-குற்றச்சாட்டுகளுக்கு-சட்டப்பேரவையில்-பதிலளிக்கும்-விஜய்', 'முதலமைச்சர் விஜய் தலைமையிலான அரசின் முதல் சட்டப்பேரவை கூட்டத் தொடர் கடந்த 18ஆம் தேதி ஆளுநரின் உரையுடன் அதிகாரப்பூர்வமாக தொடங்கியது. அதனைத் தொடர்ந்து நடைபெற்ற அல…', 'முதலமைச்சர் விஜய் தலைமையிலான அரசின் முதல் சட்டப்பேரவை கூட்டத் தொடர் கடந்த 18ஆம் தேதி ஆளுநரின் உரையுடன் அதிகாரப்பூர்வமாக தொடங்கியது. அதனைத் தொடர்ந்து நடைபெற்ற அலுவல் ஆய்வுக் குழுக் கூட்டத்தில், சட்டப்பேரவை அமர்வை மூன்று நாட்கள் நடத்த தீர்மானிக்கப்பட்டது. அதன் அடிப்படையில் கூட்டத் தொடர் திட்டமிட்டபடி நடைபெற்று வருகிறது.\r\n\r\nகூட்டத் தொடரின் முதல் நாளில், காவிரி நதியின் குறுக்கே மேகதாது அணையை அமைக்க கர்நாடக அரசு மேற்கொண்டுள்ள முயற்சிக்கு எதிராக முதலமைச்சர் விஜய் தனித் தீர்மானத்தை சட்டப்பேரவையில் முன்வைத்தார். தமிழகத்தின் நீர்வள உரிமைகளை பாதுகாக்கும் நோக்கில் இந்த தீர்மானம் கொண்டு வரப்பட்டதாக தெரிவிக்கப்பட்டது.\r\n\r\nஇதற்கிடையில், சட்டப்பேரவையின் முதல் நாள் அமர்விலேயே தி.மு.க. மற்றும் த.வெ.க. உறுப்பினர்களுக்கிடையே கடுமையான கருத்து மோதல்கள் ஏற்பட்டன. பல்வேறு விவகாரங்கள் தொடர்பாக இரு தரப்பினரும் தங்களது நிலைப்பாடுகளை வலியுறுத்தியதால் அவையில் பரபரப்பான சூழல் நிலவியது. பின்னர் இரண்டு நாட்கள் விடுமுறைக்குப் பிறகு நேற்று மீண்டும் சட்டப்பேரவை அமர்வு தொடங்கியது.\r\n\r\nநேற்றைய அமர்வில் புதிய நடுவர் மன்றம் அமைப்பது தொடர்பான கோரிக்கை விவாதத்திற்கு வந்தது. இந்த விவகாரத்தில் அ.தி.மு.க. உள்ளிட்ட எதிர்க்கட்சிகள் கடுமையான எதிர்ப்பை பதிவு செய்தன. புதிய நடுவர் மன்றம் அமைக்கும் முடிவை அரசு மறுபரிசீலனை செய்து திரும்பப் பெற வேண்டும் என்றும் அவர்கள் வலியுறுத்தினர். இதனால் அவையில் மீண்டும் காரசாரமான விவாதங்கள் நடைபெற்றன.\r\n\r\nஇந்த நிலையில், ஆளுநர் உரைக்கு நன்றி தெரிவிக்கும் தீர்மானம் மீதான விவாதத்திற்கு இன்று முதலமைச்சர் விஜய் பதிலுரை வழங்க உள்ளார். கடந்த சில நாட்களாக உறுப்பினர்கள் முன்வைத்த கருத்துகள், விமர்சனங்கள் மற்றும் ஆலோசனைகளுக்கு அவர் விரிவாக விளக்கம் அளிப்பார் என எதிர்பார்க்கப்படுகிறது.\r\n\r\nமேலும், மாநிலத்தின் சட்டம் மற்றும் ஒழுங்கு நிலைமை தொடர்பாக எதிர்க்கட்சிகள் எழுப்பிய பல்வேறு கேள்விகளுக்கும் முதலமைச்சர் இன்று சட்டப்பேரவையில் பதிலளிக்க உள்ளார். மாநிலத்தில் நிலவும் பாதுகாப்பு சூழல், அரசின் நடவடிக்கைகள் மற்றும் பொதுமக்கள் நலன் சார்ந்த அம்சங்கள் குறித்து விரிவான விளக்கங்களை அவர் வழங்குவார் என அரசியல் வட்டாரங்கள் தெரிவித்துள்ளன.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/06/media_6a3a2958794838.85250353.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-23 12:12:31', 0, 0, 0, 0, 0, NULL, NULL, 21, 0, 0, 1, '2026-06-23 06:36:10', '2026-07-03 05:30:21', NULL, 0),
(172, 4, NULL, 1, NULL, NULL, NULL, 5, 'போதைப்பொருள் எதிர்ப்பு தினம்: சென்னையில் விழிப்புணர்வு மாரத்தானில் முதல்வர் விஜய் பங்கேற்பு', 'போதைப்பொருள்-எதிர்ப்பு-தினம்-சென்னையில்-விழிப்புணர்வு-மாரத்தானில்-முதல்வர்-விஜய்-பங்கேற்பு', 'சர்வதேச போதைப்பொருள் எதிர்ப்பு தினத்தை முன்னிட்டு, சென்னையில் போதைப்பொருள் ஒழிப்பு குறித்த விழிப்புணர்வை ஏற்படுத்தும் வகையில் மாரத்தான் ஓட்டம் நடைபெற்றது.\r\n\r\nஇந…', '<p>சர்வதேச போதைப்பொருள் எதிர்ப்பு தினத்தை முன்னிட்டு, சென்னையில் போதைப்பொருள் ஒழிப்பு குறித்த விழிப்புணர்வை ஏற்படுத்தும் வகையில் மாரத்தான் ஓட்டம் நடைபெற்றது.</p>\r\n\r\n<p>இந்த நிகழ்ச்சியை முதல்வர் விஜய் தொடங்கி வைத்து, பொதுமக்கள், மாணவர்கள் மற்றும் இளைஞர்களுடன் இணைந்து மாரத்தானில் பங்கேற்றார். மேலும், போதைப்பொருள் பழக்கத்துக்கு எதிராக உறுதிமொழி எடுக்கப்பட்டு, சமூகத்தில் விழிப்புணர்வை அதிகரிக்க வேண்டியதன் அவசியம் வலியுறுத்தப்பட்டது.</p>\r\n\r\n<blockquote>போதைப்பொருள் இல்லாத சமூகத்தை உருவாக்க அனைவரும் ஒன்றிணைந்து செயல்பட வேண்டும் என நிகழ்வில் வலியுறுத்தப்பட்டது. \"சென்னை மாரத்தானில் முதல்வர் விஜய் ஓட்டம்.. போதைப்பொருள் ஒழிப்பு விழிப்புணர்வில் பங்கேற்பு</blockquote>', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/06/media_6a315f2e8a0ae0.67488960.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-26 14:09:29', 0, 1, 0, 0, 0, 'போதைப்பொருள் எதிர்ப்பு தினம்: சென்னையில் விழிப்புணர்வு மாரத்தானில் முதல்வர் விஜய் பங்கேற்பு', 'சர்வதேச போதைப்பொருள் எதிர்ப்பு தினத்தை முன்னிட்டு, சென்னையில் போதைப்பொருள் ஒழிப்பு குறித்த விழிப்புணர்வை ஏற்படுத்தும் வகையில் மாரத்தான் ஓட்டம் நடைபெற்றது.\r\n\r\nஇந', 76, 0, 0, 1, '2026-06-26 08:39:08', '2026-07-13 23:50:00', NULL, 0),
(173, 4, NULL, 1, NULL, NULL, NULL, 14, 'அன்பில் மகேஷ் - APAAR', 'apaar', 'ஒளிந்திருந்த பூனை இவ்வளவு சீக்கிரம் வெளியே வரும் என எதிர்பார்க்கவில்லை! \r\n\r\nதேசியக் கல்விக் கொள்கை - 2020ன் ஒரு அங்கமாக APAAR(Automated Permanent Academic Accou…', 'ஒளிந்திருந்த பூனை இவ்வளவு சீக்கிரம் வெளியே வரும் என எதிர்பார்க்கவில்லை! \r\n\r\nதேசியக் கல்விக் கொள்கை - 2020ன் ஒரு அங்கமாக APAAR(Automated Permanent Academic Account Registry) Card வழங்கும் திட்டம் உள்ளது. அதாவது “ஒரே நாடு ஒரே அடையாள அட்டை” என்ற அடிப்படையில் நமது தமிழ்நாட்டு மாணவர்களின் சுயவிவரத்தை ஒன்றிய அரசிடம் (அதிகாரப்பூர்வமாக!) ஒப்படைக்கும் திட்டம். இதைத்தான் வேறு வடிவத்தில் அமல்படுத்த இருக்கிறார்கள் என்பது த.வெ.க. அரசின் அமைச்சர் பேசியிருப்பதில் இருந்து தெரியவருகிறது. அதுவும் மாண்புமிகு முதலமைச்சர் அவர்களின் ஆணைக்கிணங்க! \r\n\r\nதேசியக் கல்விக் கொள்கையை ஏற்கவே மாட்டோம் என்றவர்கள், இதுபோன்ற செயல்களில் இறங்கியுள்ளார்கள்.\r\n\r\n“இரண்டாயிரம் கோடி என்ன? 10000 கோடி கொடுத்தாலும் NEP-2020ஐ ஏற்க மாட்டோம்” எனச் சொன்ன எங்கள் கழகத்தலைவர் அவர்களின் நெஞ்சுரம் இந்த ஆட்சியாளர்களுக்கும் வேண்டும். அது இல்லாமல் தேவையின்றி நமது மாணவர்களின் அடிப்படைத் தகவல்களை ஒன்றிய அரசிடம் தட்டில் வைத்து மரியாதையோடு கொடுக்கும் வேலையை அறவே கைவிட வேண்டும்.\r\n-அன்பில் மகேஷ் பொய்யாமொழி\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/06/media_6a43743f1ec607.87950965.png', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-06-29 23:35:00', 0, 1, 0, 0, 0, 'அன்பில் மகேஷ் - APAAR', 'ஒளிந்திருந்த பூனை இவ்வளவு சீக்கிரம் வெளியே வரும் என எதிர்பார்க்கவில்லை! \r\n\r\nதேசியக் கல்விக் கொள்கை - 2020ன் ஒரு அங்கமாக APAAR(Automated Permanent Academic Accou', 51, 0, 0, 1, '2026-06-29 18:03:55', '2026-07-11 08:42:46', NULL, 0),
(175, 4, NULL, 1, NULL, NULL, NULL, 15, 'பொறியியல் மாணவர் சேர்க்கைக்கான தரவரிசை பட்டியல் வெளியீடு: தர்மபுரி மாணவி முதலிடம்...', 'பொறியியல்-மாணவர்-சேர்க்கைக்கான-தரவரிசை-பட்டியல்-வெளியீடு-தர்மபுரி-மாணவி-முதலிடம்', 'தமிழ்நாடு பொறியியல் மாணவர் சேர்க்கை (TNEA) 2026-க்கான தரவரிசை பட்டியல் இன்று வெளியிடப்பட்டது. இதன்மூலம் மாநிலம் முழுவதும் உள்ள லட்சக்கணக்கான மாணவர்கள் தங்களது த…', 'தமிழ்நாடு பொறியியல் மாணவர் சேர்க்கை (TNEA) 2026-க்கான தரவரிசை பட்டியல் இன்று வெளியிடப்பட்டது. இதன்மூலம் மாநிலம் முழுவதும் உள்ள லட்சக்கணக்கான மாணவர்கள் தங்களது தரவரிசையை அறிந்து, கலந்தாய்வுக்குத் தயாராகி வருகின்றனர்.\r\n\r\nஇந்த ஆண்டுக்கான பொது பிரிவு தரவரிசையில் தர்மபுரியைச் சேர்ந்த மாணவி **அக்ஷிதா** மாநில அளவில் முதல் இடத்தைப் பிடித்து சாதனை படைத்துள்ளார். மேலும், பல்வேறு பிரிவுகளிலும் சிறப்பான மதிப்பெண்கள் பெற்ற மாணவர்கள் முன்னணி இடங்களைப் பெற்றுள்ளனர்.\r\n\r\nஇந்த ஆண்டு பொறியியல் சேர்க்கைக்காக 2.36 லட்சத்திற்கும் அதிகமான மாணவர்கள் விண்ணப்பித்துள்ளனர். தரவரிசை பட்டியல் வெளியானதைத் தொடர்ந்து, அடுத்த கட்டமாக ஆன்லைன் கலந்தாய்வு (Counselling) ஜூலை மாதத்தில் தொடங்க உள்ளது.\r\n\r\nமாணவர்கள் தங்களது தரவரிசை மற்றும் சேர்க்கை தொடர்பான விவரங்களை அதிகாரப்பூர்வ இணையதளத்தில் சரிபார்த்து, அறிவிக்கப்பட்டுள்ள கால அட்டவணைப்படி அடுத்த கட்ட நடவடிக்கைகளை மேற்கொள்ளுமாறு அதிகாரிகள் அறிவுறுத்தியுள்ளனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a44d5050bb903.76726975.webp', NULL, NULL, NULL, NULL, 'published', 'chief_editor', NULL, NULL, NULL, NULL, '2026-07-01 17:27:47', 0, 1, 0, 0, 0, 'பொறியியல் மாணவர் சேர்க்கைக்கான தரவரிசை பட்டியல் வெளியீடு: தர்மபுரி மாணவி முதலிடம்...    ', 'தமிழ்நாடு பொறியியல் மாணவர் சேர்க்கை (TNEA) 2026-க்கான தரவரிசை பட்டியல் இன்று வெளியிடப்பட்டது. இதன்மூலம் மாநிலம் முழுவதும் உள்ள லட்சக்கணக்கான மாணவர்கள் தங்களது த', 19, 0, 0, 1, '2026-07-01 08:52:40', '2026-07-07 08:26:07', NULL, 0),
(176, 5, NULL, 1, NULL, NULL, NULL, 16, 'தமிழக அரசை கவிழ்க்க ₹35 கோடி பேரம்? எம்.எல்.ஏ. குற்றச்சாட்டால் அரசியல் களம் பரபரப்பு', 'தமிழக-அரசை-கவிழ்க்க-35-கோடி-பேரம்-எம்எல்ஏ-குற்றச்சாட்டால்-அரசியல்-களம்-பரபரப்பு', 'தமிழக அரசியலில் புதிய பரபரப்பை ஏற்படுத்தும் வகையில், தமிழக வெற்றிக் கழகத்தை (TVK) சேர்ந்த உத்தங்கரை தொகுதி சட்டமன்ற உறுப்பினர் என். இளையராஜா, தமக்கு ₹35 கோடி வழ…', 'தமிழக அரசியலில் புதிய பரபரப்பை ஏற்படுத்தும் வகையில், தமிழக வெற்றிக் கழகத்தை (TVK) சேர்ந்த உத்தங்கரை தொகுதி சட்டமன்ற உறுப்பினர் என். இளையராஜா, தமக்கு ₹35 கோடி வழங்க முன்வந்து அரசியல் நிலைப்பாட்டை மாற்ற முயற்சி செய்யப்பட்டதாக காவல்துறையில் புகார் அளித்துள்ளார். இந்த குற்றச்சாட்டைத் தொடர்ந்து மூன்று பேர் கைது செய்யப்பட்டுள்ளதாக காவல்துறை தெரிவித்துள்ளது.\r\n\r\nபுகாரின் படி, சட்டமன்றத்தில் வரவிருக்கும் முக்கிய வாக்கெடுப்பில் குறிப்பிட்ட வகையில் வாக்களிக்குமாறு தன்னை அணுகியதாகவும், அதற்காக பெரும் தொகை பணம் வழங்க முன்வந்ததாகவும் எம்.எல்.ஏ. தெரிவித்துள்ளார். மேலும், அந்த முயற்சியை ஏற்க மறுத்தபின் தமக்கும், குடும்பத்தினருக்கும் மிரட்டல் விடுக்கப்பட்டதாகவும் அவர் கூறியுள்ளார்.\r\n\r\nஇந்த புகாரின் அடிப்படையில் விசாரணை நடத்திய காவல்துறையினர், சம்பவத்துடன் தொடர்புடையதாக சந்தேகிக்கப்படும் மூவரை கைது செய்து விசாரணை மேற்கொண்டு வருகின்றனர். விசாரணையின் ஒரு பகுதியாக சில அரசியல் பிரமுகர்களின் பெயர்களும் இடம்பெற்றுள்ளதாக தகவல்கள் வெளியாகியுள்ளன. எனினும், அவர்கள் மீதான குற்றச்சாட்டுகள் நீதிமன்றத்தில் இன்னும் நிரூபிக்கப்படவில்லை.\r\n\r\nஇந்த விவகாரம் குறித்து தமிழக வெற்றிக் கழக நிர்வாகிகள், ஆட்சியை சீர்குலைக்கும் நோக்கில் சிலர் சட்டமன்ற உறுப்பினர்களை அணுகியதாக குற்றம்சாட்டியுள்ளனர். மறுபுறம், எதிர்க்கட்சியினர் இந்த குற்றச்சாட்டுகளை முழுமையாக மறுத்து, அரசியல் ஆதாயத்திற்காக பொய்யான குற்றச்சாட்டுகள் முன்வைக்கப்படுவதாக தெரிவித்துள்ளனர்.\r\n\r\nஇதன் காரணமாக மாநில அரசியலில் கடும் விவாதம் உருவாகியுள்ளது. சட்டமன்ற உறுப்பினர்களை பணம் கொடுத்து ஆதரவு மாற்ற முயற்சி செய்யப்பட்டதா, அல்லது இது அரசியல் குற்றச்சாட்டாக மட்டுமே உள்ளதா என்பது குறித்து காவல்துறையின் விசாரணை மற்றும் நீதிமன்ற நடவடிக்கைகளே இறுதி நிலையைத் தீர்மானிக்கும் என அரசியல் பார்வையாளர்கள் கருதுகின்றனர்.\r\n\r\nகுறிப்பு: இந்தச் செய்தியில் இடம்பெறும் ₹35 கோடி பேரம் உள்ளிட்ட தகவல்கள் புகார் மற்றும் காவல்துறை விசாரணையை அடிப்படையாகக் கொண்டவை. குற்றச்சாட்டுகள் தொடர்பாக இறுதி தீர்ப்பு நீதிமன்றத்தின் முடிவிற்கு உட்பட்டது.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45f4d0be2826.00508228.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 10:49:23', 0, 1, 0, 0, 0, 'தமிழக அரசை கவிழ்க்க ₹35 கோடி பேரம்? எம்.எல்.ஏ. குற்றச்சாட்டால் அரசியல் களம் பரபரப்பு', 'தமிழக அரசியலில் புதிய பரபரப்பை ஏற்படுத்தும் வகையில், தமிழக வெற்றிக் கழகத்தை (TVK) சேர்ந்த உத்தங்கரை தொகுதி சட்டமன்ற உறுப்பினர் என். இளையராஜா, தமக்கு ₹35 கோடி வழ', 10, 0, 0, 1, '2026-07-02 05:19:23', '2026-07-10 22:40:10', NULL, 0),
(177, 5, NULL, 1, NULL, NULL, NULL, 17, 'தமிழகம் முழுவதும் டாஸ்மாக் பார்கள் மூடல்: பொதுவிடங்களில் மது அருந்தினால் கடும் நடவடிக்கை – அரசு எச்சரிக்கை', 'தமிழகம்-முழுவதும்-டாஸ்மாக்-பார்கள்-மூடல்-பொதுவிடங்களில்-மது-அருந்தினால்-கடும்-நடவடிக்கை-அரசு-எச்சரிக்கை', 'தமிழகத்தில் டாஸ்மாக் மதுபானக் கடைகளுடன் இணைந்து செயல்பட்டு வந்த பார்கள் அனைத்தையும் மூடும் நடவடிக்கையை மாநில அரசு தீவிரப்படுத்தியுள்ளது. இந்த நடவடிக்கையின் மூலம…', 'தமிழகத்தில் டாஸ்மாக் மதுபானக் கடைகளுடன் இணைந்து செயல்பட்டு வந்த பார்கள் அனைத்தையும் மூடும் நடவடிக்கையை மாநில அரசு தீவிரப்படுத்தியுள்ளது. இந்த நடவடிக்கையின் மூலம் பொதுமக்களின் பாதுகாப்பை உறுதி செய்வதுடன், சட்டம்-ஒழுங்கை மேம்படுத்தவும் அரசு நோக்கமிட்டுள்ளது.\r\n\r\nஅரசின் உத்தரவின்படி, டாஸ்மாக் கடைகளுடன் இணைந்திருந்த பார்கள் இனி செயல்பட அனுமதிக்கப்படாது. இதனைத் தொடர்ந்து, மாநிலம் முழுவதும் பல இடங்களில் பார்கள் மூடப்பட்டு வருகின்றன. விதிமுறைகளை மீறி செயல்படும் பார்கள் மீது உரிய சட்ட நடவடிக்கை எடுக்கப்படும் என்றும் அதிகாரிகள் தெரிவித்துள்ளனர்.\r\n\r\nமேலும், மதுபானங்களை வாங்கியவர்கள் சாலையோரங்கள், பேருந்து நிலையங்கள், பூங்காக்கள், கடற்கரைகள் உள்ளிட்ட பொதுவிடங்களில் அமர்ந்து அல்லது நின்று மது அருந்துவது சட்டவிரோதமானது என அரசு மீண்டும் வலியுறுத்தியுள்ளது. இதுபோன்ற செயல்களில் ஈடுபடுபவர்களுக்கு அபராதம் விதிப்பதுடன், தேவையானால் காவல்துறையின் மூலம் வழக்குப்பதிவு செய்யப்படும் என்றும் எச்சரிக்கப்பட்டுள்ளது.\r\n\r\nஇந்த நடவடிக்கையை கண்காணிக்க காவல்துறை மற்றும் மதுவிலக்கு அமலாக்கப் பிரிவு அதிகாரிகளுக்கு சிறப்பு உத்தரவுகள் வழங்கப்பட்டுள்ளதாக கூறப்படுகிறது. பொதுமக்களிடமிருந்து புகார்கள் வந்தால் உடனடியாக ஆய்வு செய்து நடவடிக்கை எடுக்கவும் அறிவுறுத்தப்பட்டுள்ளது.\r\n\r\nஅரசின் இந்த முடிவுக்கு சமூக ஆர்வலர்கள் மற்றும் பொதுமக்களில் ஒரு பகுதியினர் வரவேற்பு தெரிவித்துள்ளனர். பொதுவிடங்களில் மது அருந்துவதால் ஏற்படும் சண்டை, போக்குவரத்து இடையூறு மற்றும் பெண்கள், குழந்தைகளுக்கு ஏற்படும் அசௌகரியங்கள் குறையும் என்ற நம்பிக்கையும் அவர்கள் தெரிவித்துள்ளனர்.\r\n\r\nஅதே நேரத்தில், சிலர் டாஸ்மாக் கடைகளில் மதுபானம் வாங்கிய பிறகு பயன்படுத்த மாற்று வசதிகள் இல்லாத நிலை உருவாகலாம் என்றும் கருத்து தெரிவித்து வருகின்றனர்.\r\n\r\nபொதுவிடங்களில் மது அருந்துதல் அல்லது சட்டவிரோதமாக பார்கள் செயல்படுவது குறித்து தகவல் கிடைத்தால் உடனடியாக காவல்துறைக்கு தெரிவிக்குமாறும் அதிகாரிகள் பொதுமக்களிடம் கேட்டுக்கொண்டுள்ளனர்.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45f62d3f1f07.60565611.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 10:55:06', 0, 1, 0, 0, 0, 'தமிழகம் முழுவதும் டாஸ்மாக் பார்கள் மூடல்: பொதுவிடங்களில் மது அருந்தினால் கடும் நடவடிக்கை – அரசு எச்சரிக்கை', 'தமிழகத்தில் டாஸ்மாக் கடைகளுடன் இணைந்திருந்த பார்கள் மூடப்பட்டுள்ளன. பொதுவிடங்களில் மது அருந்துவோர் மற்றும் விதிமுறைகளை மீறும் பார்கள் மீது கடுமையான சட்ட நடவடிக்கை எடுக்கப்படும் என அரசு எச்சரித்துள்ளது.', 10, 0, 0, 1, '2026-07-02 05:25:06', '2026-07-10 17:35:35', NULL, 0),
(178, 5, NULL, 1, NULL, NULL, NULL, 18, 'மாட்டிறைச்சி தடை வழக்கு உச்சநீதிமன்றம் சென்றது: தமிழக அரசின் மேல்முறையீடு – சட்ட ரீதியாக அடுத்து என்ன?', 'மாட்டிறைச்சி-தடை-வழக்கு-உச்சநீதிமன்றம்-சென்றது-தமிழக-அரசின்-மேல்முறையீடு-சட்ட-ரீதியாக-அடுத்து-என்ன', 'மாடுகளை அறுப்பதற்கான கட்டுப்பாடுகள் தொடர்பாக அண்மையில் வெளியான உயர்நீதிமன்ற உத்தரவை எதிர்த்து, தமிழக அரசு உச்சநீதிமன்றத்தில் மேல்முறையீடு செய்துள்ளது. இந்த நடவட…', 'மாடுகளை அறுப்பதற்கான கட்டுப்பாடுகள் தொடர்பாக அண்மையில் வெளியான உயர்நீதிமன்ற உத்தரவை எதிர்த்து, தமிழக அரசு உச்சநீதிமன்றத்தில் மேல்முறையீடு செய்துள்ளது. இந்த நடவடிக்கை மாநிலம் முழுவதும் அரசியல், சட்டம், கால்நடை வளர்ப்பு மற்றும் இறைச்சி வணிகம் தொடர்பான பல்வேறு தரப்பினரிடையே விவாதத்தை ஏற்படுத்தியுள்ளது.\r\n\r\nஉயர்நீதிமன்ற உத்தரவின் நடைமுறை விளைவுகள் பல்வேறு துறைகளில் தாக்கத்தை ஏற்படுத்தக்கூடும் என்ற காரணத்தினாலேயே மேல்முறையீடு செய்ய வேண்டிய நிலை ஏற்பட்டதாக அரசு தரப்பில் விளக்கப்பட்டுள்ளது. இந்த வழக்கின் இறுதி தீர்ப்பு வரும்வரை நிலைமையை தெளிவுபடுத்துவது அவசியம் என்றும் அதிகாரிகள் கருதுகின்றனர்.\r\n\r\nவழக்கின் பின்னணி\r\n\r\nமாடுகளை அறுப்பது தொடர்பாக நிலவும் விதிமுறைகள், கால்நடை பாதுகாப்பு, பொதுச் சுகாதாரம் மற்றும் விலங்கு நலன் உள்ளிட்ட அம்சங்கள் தொடர்பாக பல்வேறு வழக்குகள் நீதிமன்றங்களில் நிலுவையில் உள்ளன. அவற்றில் ஒன்றில் வழங்கப்பட்ட உத்தரவு மாநிலத்தின் நடைமுறை செயல்பாடுகளில் தாக்கத்தை ஏற்படுத்தும் வகையில் இருப்பதாக தமிழக அரசு கருதியுள்ளது.\r\n\r\nஇதனால், அந்த உத்தரவின் சட்டப்பூர்வ தன்மை மற்றும் அதன் அமலாக்கம் குறித்து இறுதி விளக்கம் பெறும் நோக்கில் உச்சநீதிமன்றத்தை அரசு அணுகியுள்ளது.\r\n\r\nஅரசின் நிலைப்பாடு\r\n\r\nமாநில அரசு தனது மேல்முறையீட்டில், நடைமுறையில் உள்ள சட்டங்கள், மாநில அரசின் நிர்வாக அதிகாரம் மற்றும் பொதுமக்களின் வாழ்வாதாரத்தை கருத்தில் கொண்டு இந்த விவகாரத்தை பரிசீலிக்க வேண்டும் என்று வலியுறுத்தியுள்ளதாக தகவல்கள் தெரிவிக்கின்றன.\r\n\r\nமேலும், கால்நடை வளர்ப்போர், இறைச்சி வணிகர்கள் மற்றும் அதனை சார்ந்த தொழில்களில் ஈடுபட்டிருப்போரின் வாழ்வாதாரத்தையும் கருத்தில் கொள்ள வேண்டும் என்பதும் அரசின் முக்கிய வாதங்களில் ஒன்றாக இருக்கலாம் என சட்ட வட்டாரங்கள் தெரிவிக்கின்றன.\r\n\r\nசட்ட நிபுணர்கள் கூறுவது\r\n\r\nசட்ட நிபுணர்களின் கருத்துப்படி, இந்த வழக்கில் உச்சநீதிமன்றம் வழங்கும் தீர்ப்பு தமிழகத்திற்கு மட்டுமல்லாமல், இதேபோன்ற சட்ட மற்றும் நிர்வாக விவகாரங்களை எதிர்கொள்ளும் பிற மாநிலங்களுக்கும் வழிகாட்டியாக அமைய வாய்ப்புள்ளது.\r\n\r\nவழக்கின் போது அரசியலமைப்புச் சட்டம், மாநில அதிகார வரம்புகள், கால்நடை பாதுகாப்பு சட்டங்கள் மற்றும் பொதுநலன் போன்ற பல்வேறு அம்சங்கள் விரிவாக விவாதிக்கப்படலாம் என எதிர்பார்க்கப்படுகிறது.\r\n\r\nஅரசியல் எதிர்வினைகள்\r\n\r\nஇந்த விவகாரம் அரசியல் கட்சிகளிடையேயும் கருத்து வேறுபாடுகளை உருவாக்கியுள்ளது. சிலர் மாநில அரசின் மேல்முறையீட்டை வரவேற்றுள்ள நிலையில், மற்றொரு தரப்பு நீதிமன்றத்தின் உத்தரவை மதிக்க வேண்டும் என்ற கருத்தையும் முன்வைத்துள்ளது.\r\n\r\nஅடுத்து என்ன?\r\n\r\nஉச்சநீதிமன்றம் மேல்முறையீட்டை விசாரணைக்கு ஏற்கிறதா, இடைக்கால உத்தரவு வழங்குகிறதா, அல்லது உயர்நீதிமன்ற உத்தரவை தொடரச் செய்கிறதா என்பது அடுத்தகட்ட சட்ட நடவடிக்கைகளில் தெளிவாகும்.\r\n\r\nஇவ்வழக்கின் தீர்ப்பு, மாநிலத்தின் நிர்வாக நடவடிக்கைகள் மட்டுமின்றி, கால்நடை வளர்ப்பு, இறைச்சி வணிகம் மற்றும் அதனை சார்ந்த பல துறைகளிலும் முக்கிய தாக்கத்தை ஏற்படுத்தக்கூடியதாக இருக்கும் என்று சட்ட வல்லுநர்கள் கருதுகின்றனர்.\r\n\r\n<p>குறிப்பு: இந்த செய்தி பொதுமக்களுக்கு சட்ட மற்றும் நிர்வாக முன்னேற்றத்தை விளக்கும் நோக்கில் தயாரிக்கப்பட்ட சுயாதீன செய்தி வடிவமாகும். வழக்கின் இறுதி தீர்ப்பு அல்லது நீதிமன்ற உத்தரவுகள் வெளியான பின்னர் சட்ட நிலைமையில் மாற்றங்கள் ஏற்படலாம்.</p>', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45f7267b2d41.29136957.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 11:00:23', 0, 0, 0, 0, 0, 'மாட்டிறைச்சி தடை வழக்கு உச்சநீதிமன்றம் சென்றது: தமிழக அரசின் மேல்முறையீடு – சட்ட ரீதியாக அடுத்து என்ன?', 'மாடுகளை அறுப்பதற்கான கட்டுப்பாடுகள் தொடர்பாக அண்மையில் வெளியான உயர்நீதிமன்ற உத்தரவை எதிர்த்து, தமிழக அரசு உச்சநீதிமன்றத்தில் மேல்முறையீடு செய்துள்ளது. இந்த நடவட', 10, 0, 0, 1, '2026-07-02 05:30:23', '2026-07-10 15:25:20', NULL, 0),
(179, 5, NULL, 1, NULL, NULL, NULL, 19, 'தமிழ்நாடு பொறியியல் சேர்க்கை (TNEA 2026) ரேங்க் பட்டியல்', 'தமிழ்நாடு-பொறியியல்-சேர்க்கை-tnea-2026-ரேங்க்-பட்டியல்', 'தமிழ்நாடு பொறியியல் சேர்க்கை (TNEA 2026) ரேங்க் பட்டியலை உயர்கல்வித்துறை அதிகாரப்பூர்வமாக வெளியிட்டுள்ளது. இதன் மூலம் மாநிலம் முழுவதும் பொறியியல் படிப்புகளுக்கா…', 'தமிழ்நாடு பொறியியல் சேர்க்கை (TNEA 2026) ரேங்க் பட்டியலை உயர்கல்வித்துறை அதிகாரப்பூர்வமாக வெளியிட்டுள்ளது. இதன் மூலம் மாநிலம் முழுவதும் பொறியியல் படிப்புகளுக்காக விண்ணப்பித்த 2.36 லட்சத்திற்கும் மேற்பட்ட மாணவர்கள் அடுத்த கட்டமான ஆன்லைன் கலந்தாய்வு (Counselling) செயல்முறைக்குத் தயாராகி வருகின்றனர்.\r\n\r\nஇந்த ரேங்க் பட்டியல், மாணவர்கள் பிளஸ்-2 தேர்வில் பெற்ற மதிப்பெண்கள் மற்றும் நடைமுறையில் உள்ள மதிப்பெண் சமநிலைப்படுத்தும் (Normalization) முறையின் அடிப்படையில் தயாரிக்கப்பட்டுள்ளது. ஒரே மதிப்பெண் பெற்ற மாணவர்களுக்கு கணிதம், இயற்பியல் மதிப்பெண்கள், பிற விதிமுறைகள் மற்றும் ரேண்டம் எண் (Random Number) உள்ளிட்ட அளவுகோல்கள் பயன்படுத்தப்பட்டு தரவரிசை நிர்ணயிக்கப்பட்டுள்ளது.\r\n\r\nஇந்த ஆண்டின் பொது பிரிவு தரவரிசையில் தர்மபுரியைச் சேர்ந்த மாணவி அக்ஷிதா (Akshitha) மாநில அளவில் முதலிடம் பெற்றுள்ளார். மேலும், 53 மாணவர்கள் 200-க்கு 200 கட்-ஆஃப் மதிப்பெண் பெற்று சாதனை படைத்துள்ளனர் என்பது குறிப்பிடத்தக்கது.\r\n\r\nரேங்க் பட்டியல் வெளியானதைத் தொடர்ந்து, மாணவர்கள் தங்களது தரவரிசையை அதிகாரப்பூர்வ இணையதளத்தில் உள்நுழைந்து சரிபார்க்கலாம். தரவரிசை தொடர்பாக ஏதேனும் சந்தேகம் அல்லது பிழை இருப்பின், குறிப்பிட்ட காலக்கெடுவுக்குள் முறையீடு செய்யும் வாய்ப்பும் வழங்கப்பட்டுள்ளது. அதன் பின்னர் இறுதி தரவரிசை உறுதி செய்யப்பட்டு கலந்தாய்வு செயல்முறை தொடங்கும்.\r\n\r\nஇந்த ஆண்டுக்கான ஆன்லைன் கலந்தாய்வு ஜூலை மாதத்தின் இரண்டாவது வாரத்தில் தொடங்கும் என அறிவிக்கப்பட்டுள்ளது. மாணவர்கள் தங்களது தரவரிசைக்கு ஏற்ப விருப்பமான கல்லூரிகள் மற்றும் படிப்புகளை முன்னுரிமை அடிப்படையில் தேர்வு செய்ய வேண்டும். அதன் பின்னர் இடஒதுக்கீடு (Seat Allotment) முடிவுகள் வெளியிடப்பட்டு, ஒதுக்கப்பட்ட கல்லூரிகளில் சேர்க்கை நடைமுறை மேற்கொள்ளப்படும்.\r\n\r\nகலந்தாய்வில் பங்கேற்கும் மாணவர்கள், தேவையான அனைத்து ஆவணங்களையும் முன்கூட்டியே தயார் நிலையில் வைத்திருப்பதுடன், அதிகாரப்பூர்வ அறிவிப்புகள் மற்றும் கால அட்டவணையை தொடர்ந்து கவனித்து வருவது அவசியம் என கல்வித்துறை அறிவுறுத்தியுள்ளது.\r\n\r\nதமிழகத்தில் அரசு, அரசு உதவி பெறும் மற்றும் சுயநிதி பொறியியல் கல்லூரிகளில் சேர விரும்பும் மாணவர்களுக்கு TNEA கலந்தாய்வே முக்கிய நுழைவாயிலாக இருப்பதால், ரேங்க் பட்டியல் வெளியீடு மாணவர்கள் மற்றும் பெற்றோர்களிடையே பெரும் எதிர்பார்ப்பை ஏற்படுத்தியுள்ளது. வரும் நாட்களில் நடைபெறவுள்ள கலந்தாய்வு மூலம் ஆயிரக்கணக்கான மாணவர்களின் உயர்கல்வி பயணம் புதிய கட்டத்தை எட்டவுள்ளது.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45f8ed528e87.06957917.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 11:07:14', 0, 0, 0, 0, 0, 'தமிழ்நாடு பொறியியல் சேர்க்கை (TNEA 2026) ரேங்க் பட்டியல்', 'தமிழ்நாடு பொறியியல் சேர்க்கை (TNEA 2026) ரேங்க் பட்டியலை உயர்கல்வித்துறை அதிகாரப்பூர்வமாக வெளியிட்டுள்ளது. இதன் மூலம் மாநிலம் முழுவதும் பொறியியல் படிப்புகளுக்கா', 8, 0, 0, 1, '2026-07-02 05:36:49', '2026-07-02 14:08:52', NULL, 0),
(180, 5, NULL, 1, NULL, NULL, NULL, 20, 'முந்தைய ஆட்சிக் கால பொதுப்பணித் துறை ஒப்பந்தங்களில் ஊழல்? – புகார் அளிக்குமாறு அமைச்சர் ஆதவ் அர்ஜுனா அழைப்பு', 'முந்தைய-ஆட்சிக்-கால-பொதுப்பணித்-துறை-ஒப்பந்தங்களில்-ஊழல்-புகார்-அளிக்குமாறு-அமைச்சர்-ஆதவ்-அர்ஜுனா-அழைப்பு', 'தமிழக பொதுப்பணித் துறை (PWD) மற்றும் நெடுஞ்சாலைத் துறை அமைச்சரான ஆதவ் அர்ஜுனா, முந்தைய ஆட்சிக் காலங்களில் பொதுப்பணித் துறை மற்றும் நெடுஞ்சாலைத் துறையில் மேற்கொள…', 'தமிழக பொதுப்பணித் துறை (PWD) மற்றும் நெடுஞ்சாலைத் துறை அமைச்சரான ஆதவ் அர்ஜுனா, முந்தைய ஆட்சிக் காலங்களில் பொதுப்பணித் துறை மற்றும் நெடுஞ்சாலைத் துறையில் மேற்கொள்ளப்பட்ட ஒப்பந்தங்கள் மற்றும் பணிகளில் முறைகேடுகள், ஊழல் உள்ளிட்ட பல்வேறு புகார்கள் இருப்பதாக தெரிவித்தார். இதனால் பாதிக்கப்பட்டவர்கள் மற்றும் ஆதாரங்களுடன் தகவல் வைத்திருப்பவர்கள் முன்வந்து புகார் அளிக்குமாறு அவர் அழைப்பு விடுத்துள்ளார்.\r\n\r\nஅரசு நிர்வாகத்தில் வெளிப்படைத்தன்மை மற்றும் பொறுப்புணர்வை உறுதி செய்வதே தற்போதைய அரசின் முக்கிய நோக்கமாக இருப்பதாக அமைச்சர் தெரிவித்தார். பொதுமக்களின் நலனுக்காக ஒதுக்கப்படும் அரசு நிதி முறையாக பயன்படுத்தப்பட வேண்டும் என்றும், எந்தவித முறைகேடும் அனுமதிக்கப்பட மாட்டாது என்றும் அவர் வலியுறுத்தினார்.\r\n\r\nபொதுப்பணித் துறை அல்லது நெடுஞ்சாலைத் துறையின் முந்தைய ஒப்பந்தங்கள், டெண்டர் நடைமுறைகள், பணிகள் ஒதுக்கீடு, கட்டுமான தரம் அல்லது நிதி முறைகேடுகள் தொடர்பாக பாதிக்கப்பட்ட ஒப்பந்ததாரர்கள், பொறியாளர்கள், பொதுமக்கள் அல்லது சம்பந்தப்பட்டவர்கள் தங்களிடம் உள்ள ஆவணங்கள் மற்றும் ஆதாரங்களுடன் புகார் அளிக்கலாம் என அமைச்சர் கூறியுள்ளார். புகார்கள் காவல்துறையிடமோ அல்லது துறைக்காக அறிவிக்கப்பட்ட மின்னஞ்சல் முகவரியிலோ சமர்ப்பிக்கலாம் என்றும் தெரிவிக்கப்பட்டுள்ளது.\r\n\r\n<strong>பெறப்படும் ஒவ்வொரு புகாரும் உரிய அதிகாரிகள் மூலம் ஆய்வு செய்யப்பட்டு, ஆதாரங்கள் உறுதி செய்யப்பட்டால் சட்டப்படி தேவையான நடவடிக்கைகள் எடுக்கப்படும் என்றும் அமைச்சர் ஆதவ் அர்ஜுனா தெரிவித்துள்ளார். அரசுத் திட்டங்களில் வெளிப்படைத்தன்மை, தரமான பணிகள் மற்றும் பொது நிதியின் பாதுகாப்பை உறுதி செய்வதில் அரசு உறுதியாக செயல்படும் என்றும் அவர் குறிப்பிட்டுள்ளார்.</strong>\r\n\r\nஇந்த அறிவிப்பைத் தொடர்ந்து, பொதுப்பணித் துறையில் கடந்த கால ஒப்பந்தங்கள் மற்றும் பணிகள் குறித்து புதிய விசாரணைகள் நடைபெறுமா என்ற எதிர்பார்ப்பு அரசியல் மற்றும் நிர்வாக வட்டாரங்களில் உருவாகியுள்ளது. <h3>சம்பந்தப்பட்ட புகார்களின் அடிப்படையில் அடுத்த கட்ட நடவடிக்கைகள் எடுக்கப்படுமா என்பது கவனிக்கத்தக்கதாக உள்ளது.</h3>', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45fb2d731ca0.50543853.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 11:16:25', 0, 1, 0, 0, 0, 'முந்தைய ஆட்சிக் கால பொதுப்பணித் துறை ஒப்பந்தங்களில் ஊழல்? – புகார் அளிக்குமாறு அமைச்சர் ஆதவ் அர்ஜுனா அழைப்பு', 'தமிழக பொதுப்பணித் துறை (PWD) மற்றும் நெடுஞ்சாலைத் துறை அமைச்சரான ஆதவ் அர்ஜுனா, முந்தைய ஆட்சிக் காலங்களில் பொதுப்பணித் துறை மற்றும் நெடுஞ்சாலைத் துறையில் மேற்கொள', 24, 0, 0, 1, '2026-07-02 05:46:25', '2026-07-10 17:26:05', NULL, 0),
(181, 5, NULL, 5, NULL, NULL, NULL, 21, 'மழையால் முடிவின்றி நிறைவடைந்த இந்தியா–இங்கிலாந்து முதல் டி20: ஸ்ரேயாஸ் ஐயர், அபிஷேக் சர்மா அதிரடி ஆட்டம்', 'மழையால்-முடிவின்றி-நிறைவடைந்த-இந்தியாஇங்கிலாந்து-முதல்-டி20-ஸ்ரேயாஸ்-ஐயர்-அபிஷேக்-சர்மா-அதிரடி-ஆட்டம்', 'இந்தியா மற்றும் இங்கிலாந்து அணிகளுக்கு இடையிலான முதல் டி20 போட்டி, ரசிகர்கள் பெரிதும் எதிர்பார்த்த நிலையில் நடைபெற்றது. ஆனால், மழை குறுக்கிட்டதால் போட்டிக்கு மு…', 'இந்தியா மற்றும் இங்கிலாந்து அணிகளுக்கு இடையிலான முதல் டி20 போட்டி, ரசிகர்கள் பெரிதும் எதிர்பார்த்த நிலையில் நடைபெற்றது. ஆனால், மழை குறுக்கிட்டதால் போட்டிக்கு முடிவு கிடைக்காமல் கைவிடப்பட்டது. இதனால் இரு அணிகளுக்கும் தலா ஒரு புள்ளி வழங்கப்பட்டது.\r\n\r\nமுதலில் பேட்டிங் செய்ய அழைக்கப்பட்ட இந்திய அணி தொடக்கத்திலிருந்தே அதிரடியான ஆட்டத்தை வெளிப்படுத்தியது. தொடக்க வீரர்கள் வேகமாக ரன்கள் சேர்த்து அணிக்கு வலுவான அடித்தளத்தை அமைத்தனர். குறிப்பாக <strong>அபிஷேக் சர்மா</strong> தனது இயல்பான தாக்குதல் பாணியில் விளையாடி, வெறும் 24 பந்துகளில் 59 ரன்கள் குவித்தார். அவரது இன்னிங்ஸில் பல பவுண்டரிகளும் சிக்ஸர்களும் இடம்பெற்றன. இந்த ஆட்டத்தின் மூலம் <strong>சர்வதேச டி20 கிரிக்கெட்டில் மிகக் குறைந்த இன்னிங்ஸ்களில் 100 சிக்ஸர்கள்</strong> அடைந்த இந்திய வீரர்களில் ஒருவராக அவர் புதிய சாதனையை பதிவு செய்தார்.\r\n\r\n<strong>அணியின் கேப்டனாக களமிறங்கிய ஸ்ரேயாஸ் ஐயரும் பொறுப்பான ஆட்டத்தை வெளிப்படுத்தினார். மிடில் ஆர்டரில் நிலைத்து நின்ற அவர் 68 ரன்கள் எடுத்ததன் மூலம் இந்திய அணியின் ஸ்கோரை உயர்த்த முக்கிய பங்காற்றினார். மேலும் இந்த இன்னிங்ஸ் மூலம் தனது சர்வதேச கிரிக்கெட் வாழ்க்கையில் 5,000 ரன்கள் என்ற முக்கிய மைல்கல்லையும் கடந்தார். இந்த சாதனை அவரது தொடர்ச்சியான சிறப்பான செயல்பாட்டிற்கு மேலும் ஒரு அங்கீகாரமாக பார்க்கப்படுகிறது.</strong>\r\n\r\nநிர்ணயிக்கப்பட்ட 20 ஓவர்களின் முடிவில் இந்திய அணி 7 விக்கெட்டுகளை இழந்து 189 ரன்கள் சேர்த்தது. போட்டித்தன்மை மிக்க இலக்குடன் இந்திய அணி பந்துவீச தயாரான நிலையில், மழை தீவிரமடைந்தது. மைதானத்தை விரைவாக தயார் செய்ய அதிகாரிகள் முயற்சி செய்தபோதிலும், மழை தொடர்ந்து பெய்ததால் இங்கிலாந்து அணியின் இன்னிங்ஸை தொடங்க முடியவில்லை.\r\n\r\nநீண்ட நேரம் காத்திருந்த நடுவர்கள் இறுதியில் போட்டியை கைவிடுவதாக அறிவித்தனர். இதனால் வெற்றி, தோல்வி எதுவும் தீர்மானிக்கப்படாமல் இரு அணிகளும் தலா ஒரு புள்ளியைப் பெற்றன.\r\n\r\nபோட்டி முடிவின்றி நிறைவடைந்தாலும், இந்திய அணியின் பேட்டிங் செயல்பாடு ரசிகர்களிடம் நல்ல வரவேற்பைப் பெற்றுள்ளது. குறிப்பாக அபிஷேக் சர்மாவின் அதிரடி அரைசதமும், ஸ்ரேயாஸ் ஐயரின் பொறுப்பான இன்னிங்ஸும் தொடரின் அடுத்த போட்டிகளுக்கான நம்பிக்கையை அதிகரித்துள்ளன. அடுத்த டி20 போட்டியில் இரு அணிகளும் முழு பலத்துடன் களமிறங்கி தொடரில் முன்னிலை பெற முயற்சிக்கும் என எதிர்பார்க்கப்படுகிறது', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45fd1562a173.06936338.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 11:24:32', 0, 1, 0, 0, 0, 'மழையால் முடிவின்றி நிறைவடைந்த இந்தியா–இங்கிலாந்து முதல் டி20: ஸ்ரேயாஸ் ஐயர், அபிஷேக் சர்மா அதிரடி ஆட்டம்', 'இந்தியா மற்றும் இங்கிலாந்து அணிகளுக்கு இடையிலான முதல் டி20 போட்டி, ரசிகர்கள் பெரிதும் எதிர்பார்த்த நிலையில் நடைபெற்றது. ஆனால், மழை குறுக்கிட்டதால் போட்டிக்கு மு', 34, 0, 0, 1, '2026-07-02 05:54:32', '2026-07-13 18:53:06', NULL, 0),
(183, 5, NULL, 5, NULL, NULL, NULL, 25, 'டாப் 10 விளையாட்டு செய்திகள் – 02 ஜூலை 2026', 'டாப்-10-விளையாட்டு-செய்திகள்-02-ஜூலை-2026', '## 1. மழையால் கைவிடப்பட்ட இந்தியா – இங்கிலாந்து முதல் டி20 போட்டி\r\n\r\n**லண்டன்:** இந்தியா மற்றும் இங்கிலாந்து அணிகள் மோதிய முதல் டி20 கிரிக்கெட் போட்டி மழை கார…', '## 1. மழையால் கைவிடப்பட்ட இந்தியா – இங்கிலாந்து முதல் டி20 போட்டி\r\n\r\n*லண்டன்:** இந்தியா மற்றும் இங்கிலாந்து அணிகள் மோதிய முதல் டி20 கிரிக்கெட் போட்டி மழை காரணமாக முடிவின்றி கைவிடப்பட்டது. முதலில் பேட்டிங் செய்த இந்திய அணி 20 ஓவர்களில் 7 விக்கெட் இழப்புக்கு 189 ரன்கள் குவித்தது. பின்னர் இங்கிலாந்து இன்னிங்ஸ் தொடங்குவதற்கு முன்பே கனமழை பெய்ததால் போட்டி ரத்து செய்யப்பட்டது. இதனால் இரு அணிகளுக்கும் தலா ஒரு புள்ளி வழங்கப்பட்டது. தொடரின் இரண்டாவது போட்டி ஜூலை 4 அன்று நடைபெற உள்ளது.\r\n\r\n## 2. சர்வதேச கிரிக்கெட்டில் 5,000 ரன்கள் கடந்த ஸ்ரேயாஸ் ஐயர்\r\n\r\nஇந்திய அணியின் நட்சத்திர பேட்ஸ்மேன் ஸ்ரேயாஸ் ஐயர், இங்கிலாந்துக்கு எதிரான போட்டியில் 68 ரன்கள் குவித்து தனது சர்வதேச கிரிக்கெட் வாழ்க்கையில் 5,000 ரன்கள் என்ற மைல்கல்லை எட்டினார். முக்கிய தருணத்தில் பொறுப்புடன் விளையாடிய அவரது இன்னிங்ஸ் ரசிகர்களிடையே பாராட்டைப் பெற்றுள்ளது.\r\n\r\n## 3. அபிஷேக் சர்மாவின் அதிரடி அரைசதம்\r\n\r\nஇந்திய தொடக்க வீரர் அபிஷேக் சர்மா வெறும் 24 பந்துகளில் 59 ரன்கள் விளாசி அசத்தினார். இந்த இன்னிங்ஸில் பல சிக்ஸர்களை பறக்கவிட்ட அவர், சர்வதேச டி20 கிரிக்கெட்டில் 100 சிக்ஸர்கள் அடைந்த வேகமான இந்திய வீரர் என்ற புதிய சாதனையை படைத்துள்ளார்.\r\n\r\n## 4. விம்பிள்டனில் ஜோகோவிச் அடுத்த சுற்றுக்கு முன்னேற்றம்\r\n\r\nவிம்பிள்டன் டென்னிஸ் தொடரில் முன்னாள் சாம்பியன் நோவாக் ஜோகோவிச் சிறப்பான ஆட்டத்தை வெளிப்படுத்தி மூன்றாவது சுற்றுக்கு முன்னேறினார். போட்டி முழுவதும் ஆதிக்கம் செலுத்திய அவர் தனது அனுபவத்தை மீண்டும் நிரூபித்தார்.\r\n\r\n## 5. FIFA உலகக்கோப்பை நாக்அவுட் சுற்று இன்று தொடக்கம்\r\n\r\nFIFA உலகக்கோப்பை கால்பந்து தொடரின் முக்கிய நாக்அவுட் போட்டிகள் இன்று நடைபெறுகின்றன. ஸ்பெயின், போர்ச்சுகல், பெல்ஜியம் மற்றும் அமெரிக்கா உள்ளிட்ட முன்னணி அணிகள் களமிறங்குவதால் ரசிகர்கள் பெரும் எதிர்பார்ப்புடன் காத்திருக்கின்றனர்.\r\n\r\n## 6. அமெரிக்கா கடைசி 16 சுற்றுக்கு தகுதி\r\n\r\nஉலகக்கோப்பை கால்பந்து தொடரில் அமெரிக்க அணி 2-0 என்ற கோல் கணக்கில் வெற்றி பெற்று கடைசி 16 சுற்றுக்கு முன்னேறியுள்ளது. ஒழுங்கான அணித்திறன் மற்றும் வலுவான பாதுகாப்பு ஆட்டம் வெற்றிக்கு காரணமாக அமைந்தது.\r\n\r\n## 7. இந்தியா – இங்கிலாந்து இரண்டாவது டி20 போட்டி மீது எதிர்பார்ப்பு\r\n\r\nமுதல் போட்டி மழையால் கைவிடப்பட்ட நிலையில், தொடரின் இரண்டாவது டி20 போட்டி ஜூலை 4 அன்று நடைபெறுகிறது. தொடரில் முன்னிலை பெற இரு அணிகளும் முழு பலத்துடன் களமிறங்க உள்ளன.\r\n\r\n## 8. இலங்கையை இன்னிங்ஸ் வித்தியாசத்தில் வீழ்த்திய வெஸ்ட் இண்டீஸ்\r\n\r\nடெஸ்ட் கிரிக்கெட் போட்டியில் வெஸ்ட் இண்டீஸ் அணி, இலங்கையை ஒரு இன்னிங்ஸ் மற்றும் 217 ரன்கள் வித்தியாசத்தில் வீழ்த்தி அபார வெற்றி பெற்றது. பேட்டிங் மற்றும் பந்துவீச்சு இரண்டிலும் ஆதிக்கம் செலுத்திய வெஸ்ட் இண்டீஸ் அணிக்கு பாராட்டுகள் குவிந்து வருகின்றன.\r\n\r\n## 9. வங்கதேசத்தை வீழ்த்தி தொடரை கைப்பற்றிய ஆஸ்திரேலியா\r\n\r\nஆஸ்திரேலியா மற்றும் வங்கதேசம் அணிகள் மோதிய மூன்றாவது டி20 போட்டியில் ஆஸ்திரேலியா 7 விக்கெட் வித்தியாசத்தில் வெற்றி பெற்று தொடரை வெற்றிகரமாக நிறைவு செய்தது.\r\n\r\n## 10. விம்பிள்டனில் முன்னணி வீரர்கள் தொடர்ந்த ஆதிக்கம்\r\n\r\nவிம்பிள்டன் டென்னிஸ் தொடரில் முன்னணி தரவரிசை வீரர்கள் தொடர்ந்து வெற்றி பெற்று அடுத்த சுற்றுகளுக்கு முன்னேறி வருகின்றனர். இந்த ஆண்டும் சாம்பியன் பட்டத்திற்கான போட்டி கடுமையாக இருக்கும் என விளையாட்டு நிபுணர்கள் கருத்து தெரிவிக்கின்றனர்.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a45ffead43623.80769728.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 11:37:11', 0, 1, 0, 0, 0, 'டாப் 10 விளையாட்டு செய்திகள் – 02 ஜூலை 2026', '## 1. மழையால் கைவிடப்பட்ட இந்தியா – இங்கிலாந்து முதல் டி20 போட்டி\r\n\r\n**லண்டன்:** இந்தியா மற்றும் இங்கிலாந்து அணிகள் மோதிய முதல் டி20 கிரிக்கெட் போட்டி மழை கார', 65, 0, 0, 1, '2026-07-02 06:07:11', '2026-07-13 07:16:29', NULL, 0),
(184, 4, NULL, 3, NULL, NULL, NULL, 31, 'உக்ரைன் தலைநகரில் டிரோன் தாக்குதல் நடத்திய ரஷியா - 8 பேர் உயிரிழப்பு...', 'உக்ரைன்-தலைநகரில்-டிரோன்-தாக்குதல்-நடத்திய-ரஷியா-8-பேர்-உயிரிழப்பு', 'உக்ரைன் தலைநகர் கீவ் மீது ரஷியா நடத்திய பெரிய அளவிலான ட்ரோன் மற்றும் ஏவுகணை தாக்குதலில் குறைந்தது 8 பேர் உயிரிழந்துள்ளனர்.\r\n\r\nஅதிகாரிகள் தகவலின்படி, இந்த தாக்கு…', 'உக்ரைன் தலைநகர் கீவ் மீது ரஷியா நடத்திய பெரிய அளவிலான ட்ரோன் மற்றும் ஏவுகணை தாக்குதலில் குறைந்தது 8 பேர் உயிரிழந்துள்ளனர்.\r\n\r\nஅதிகாரிகள் தகவலின்படி, இந்த தாக்குதல் இரவு நேரத்தில் நடத்தப்பட்டதாகும். பல ட்ரோன்கள் மற்றும் ஏவுகணைகள் நகரின் பல பகுதிகளை தாக்கியதால் குடியிருப்பு கட்டிடங்கள் கடுமையாக சேதமடைந்தன. தீ விபத்துகள் ஏற்பட்டதுடன், பலர் காயமடைந்துள்ளனர்.\r\n\r\nமீட்புப் படைகள் சம்பவ இடங்களில் தொடர்ந்து தேடுதல் மற்றும் மீட்பு பணிகளில் ஈடுபட்டுள்ளன. பொதுமக்கள் பாதுகாப்புக்காக அடைக்கலங்களில் இருக்குமாறு எச்சரிக்கப்பட்டுள்ளது.\r\n\r\nஇந்த தாக்குதல், ரஷியா–உக்ரைன் போரில் சமீப காலங்களில் ஏற்பட்ட மிக தீவிரமான தாக்குதல்களில் ஒன்றாகக் கருதப்படுகிறது. \r\n\r\nஇந்த தாக்குதலில்:\r\n\r\n* குடியிருப்பு கட்டிடங்கள் சேதமடைந்தன\r\n* தீ விபத்துகள் மற்றும் புகை மூட்டங்கள் ஏற்பட்டன\r\n* மீட்பு படையினர் இடிபாடுகளில் சிக்கியவர்களை தேடும் பணியில் ஈடுபட்டனர்\r\n* பொதுமக்கள் பலர் பாதிக்கப்பட்டனர்\r\n\r\nநகரின் பல பகுதிகள் இரவு நேர தாக்குதலால் அதிர்ச்சியடைந்த நிலையில், பாதுகாப்பு நடவடிக்கைகள் தீவிரப்படுத்தப்பட்டுள்ளன.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a462e705c28f6.74784420.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 14:55:22', 0, 1, 0, 0, 0, 'உக்ரைன் தலைநகரில் டிரோன் தாக்குதல் நடத்திய ரஷியா - 8 பேர் உயிரிழப்பு...    ', 'உக்ரைன் தலைநகர் கீவ் மீது ரஷியா நடத்திய பெரிய அளவிலான ட்ரோன் மற்றும் ஏவுகணை தாக்குதலில் குறைந்தது 8 பேர் உயிரிழந்துள்ளனர்.\r\n\r\nஅதிகாரிகள் தகவலின்படி, இந்த தாக்கு', 31, 0, 0, 1, '2026-07-02 09:25:22', '2026-07-12 16:28:56', NULL, 0),
(185, 4, NULL, 1, NULL, NULL, NULL, 32, 'அம்பேத்கர் சட்டப் பல்கலைக்கழகத்தில் புதிய மாணவர் விடுதி: அமைச்சர் நிர்மல்குமார் அடிக்கல் நாட்டினார்...', 'அம்பேத்கர்-சட்டப்-பல்கலைக்கழகத்தில்-புதிய-மாணவர்-விடுதி-அமைச்சர்-நிர்மல்குமார்-அடிக்கல்-நாட்டினார்', 'சென்னை தரமணியில் உள்ள தமிழ்நாடு டாக்டர் அம்பேத்கர் சட்டப் பல்கலைக்கழகத்தில், புதிய மாணவர் விடுதி கட்டுமான பணிக்கு அமைச்சர் நிர்மல்குமார் இன்று அடிக்கல் நாட்டி…', 'சென்னை தரமணியில் உள்ள தமிழ்நாடு டாக்டர் அம்பேத்கர் சட்டப் பல்கலைக்கழகத்தில், புதிய மாணவர் விடுதி கட்டுமான பணிக்கு அமைச்சர் நிர்மல்குமார் இன்று அடிக்கல் நாட்டினார்.\r\n\r\nஇந்த புதிய விடுதி சுமார் 240 மாணவர்கள் தங்கும் வசதியுடன உள்ளது. இதற்கான கட்டுமான செலவு ரூ.24.71 கோடி என மதிப்பிடப்பட்டுள்ளது. மாணவர்களின் தங்கும் வசதியை மேம்படுத்தும் நோக்கில் இந்த திட்டம் மேற்கொள்ளப்படுவதாக தெரிவிக்கப்பட்டுள்ளது.\r\n\r\nநிகழ்ச்சியில் பல்கலைக்கழக அதிகாரிகள், பேராசிரியர்கள் மற்றும் அரசு உயர் அதிகாரிகள் கலந்து கொண்டனர். புதிய விடுதி மூலம் மாணவர்களின் விடுதி வசதி குறைபாடுகள் தீர்க்கப்படும் என எதிர்பார்க்கப்படுகிறது.\r\n\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4634666fdce3.38004617.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-02 15:20:52', 0, 0, 0, 0, 0, ' அம்பேத்கர் சட்டப் பல்கலைக்கழகத்தில் புதிய மாணவர் விடுதி: அமைச்சர் நிர்மல்குமார் அடிக்கல் நாட்டினார்...    ', 'சென்னை தரமணியில் உள்ள தமிழ்நாடு டாக்டர் அம்பேத்கர் சட்டப் பல்கலைக்கழகத்தில், புதிய மாணவர் விடுதி கட்டுமான பணிக்கு அமைச்சர் நிர்மல்குமார் இன்று அடிக்கல் நாட்டி', 12, 0, 0, 1, '2026-07-02 09:50:52', '2026-07-03 15:36:53', NULL, 0),
(186, 4, NULL, 1, NULL, NULL, NULL, 33, 'வானிலை செய்திகள் தமிழகத்தில் 3 மாவட்டங்களில் நாளை கனமழைக்கு வாய்ப்பு...', 'வானிலை-செய்திகள்-தமிழகத்தில்-3-மாவட்டங்களில்-நாளை-கனமழைக்கு-வாய்ப்பு', 'தமிழகத்தில் தென்மேற்கு பருவமழை தீவிரமடைந்துள்ள நிலையில், மாநிலத்தின் சில பகுதிகளில் அடுத்த 24 மணி நேரத்திற்கு மழை தொடரும் என வானிலை ஆய்வு மையம் தெரிவித்துள்ளது.…', 'தமிழகத்தில் தென்மேற்கு பருவமழை தீவிரமடைந்துள்ள நிலையில், மாநிலத்தின் சில பகுதிகளில் அடுத்த 24 மணி நேரத்திற்கு மழை தொடரும் என வானிலை ஆய்வு மையம் தெரிவித்துள்ளது.\r\n\r\nஅதன்படி, **நீலகிரி, கோயம்புத்தூர் மற்றும் தேனி** ஆகிய 3 மாவட்டங்களில் நாளை (ஜூலை 3) ஓரிரு இடங்களில் கனமழை பெய்யக்கூடும் என்று கணிக்கப்பட்டுள்ளது.\r\n\r\nமேலும், மேற்கு தொடர்ச்சி மலையை ஒட்டிய பகுதிகள் மற்றும் சில உள் மாவட்டங்களில் லேசானது முதல் மிதமான மழை வரை பெய்ய வாய்ப்புள்ளதாகவும் தெரிவிக்கப்பட்டுள்ளது.\r\n\r\nகனமழை எச்சரிக்கை விடுக்கப்பட்டுள்ள மாவட்டங்களில் வசிக்கும் பொதுமக்கள் தேவையற்ற பயணங்களை தவிர்த்து, உள்ளூர் நிர்வாகம் மற்றும் வானிலை மையத்தின் அறிவுறுத்தல்களை பின்பற்றுமாறு அறிவுறுத்தப்பட்டுள்ளது.\r\n\r\nமீனவர்கள் கடலுக்கு செல்லும் முன் சமீபத்திய வானிலை அறிவிப்புகளை கவனமாக பின்பற்றவும் அறிவுறுத்தப்பட்டுள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4639d10f9ad7.52666187.webp', NULL, NULL, NULL, NULL, 'published', 'published', NULL, 4, '2026-07-03 07:07:00', NULL, '2026-07-02 15:43:55', 0, 0, 0, 0, 0, ' வானிலை செய்திகள் தமிழகத்தில் 3 மாவட்டங்களில் நாளை கனமழைக்கு வாய்ப்பு...   ', 'தமிழகத்தில் தென்மேற்கு பருவமழை தீவிரமடைந்துள்ள நிலையில், மாநிலத்தின் சில பகுதிகளில் அடுத்த 24 மணி நேரத்திற்கு மழை தொடரும் என வானிலை ஆய்வு மையம் தெரிவித்துள்ளது.', 15, 0, 0, 1, '2026-07-02 10:13:55', '2026-07-11 22:45:01', NULL, 0),
(187, 4, NULL, 3, NULL, NULL, NULL, 34, 'சொகுசு கப்பலில் பரவிய நோரோ வைரஸ் - 125 பேர் பாதிப்பு...', 'சொகுசு-கப்பலில்-பரவிய-நோரோ-வைரஸ்-125-பேர்-பாதிப்பு', 'அமெரிக்காவின் சான் பிரான்சிஸ்கோவில் இருந்து அலாஸ்கா மற்றும் கனடாவுக்கு சென்ற சொகுசு சுற்றுலா கப்பலில் நோரோ வைரஸ் பரவியதால் 125 பேர் உடல்நலக் குறைவால் பாதிக்கப்ப…', 'அமெரிக்காவின் சான் பிரான்சிஸ்கோவில் இருந்து அலாஸ்கா மற்றும் கனடாவுக்கு சென்ற சொகுசு சுற்றுலா கப்பலில் நோரோ வைரஸ் பரவியதால் 125 பேர் உடல்நலக் குறைவால் பாதிக்கப்பட்டுள்ளனர்.\r\n\r\nபாதிக்கப்பட்டவர்களில் 102 பயணிகளும், 23 பணியாளர்களும் அடங்குவதாக அதிகாரிகள் தெரிவித்துள்ளனர். வாந்தி, வயிற்றுப்போக்கு உள்ளிட்ட அறிகுறிகள் ஏற்பட்டதைத் தொடர்ந்து, பாதிக்கப்பட்டவர்கள் தனிமைப்படுத்தப்பட்டு சிகிச்சை அளிக்கப்பட்டது.\r\n\r\nவைரஸ் பரவலைக் கட்டுப்படுத்த கப்பல் முழுவதும் தீவிர கிருமிநாசினி தெளிப்பு மற்றும் சுகாதார நடவடிக்கைகள் மேற்கொள்ளப்பட்டுள்ளன. மேலும், அடுத்த பயணத்திற்கு முன்பு கப்பல் முழுமையாக சுத்தம் செய்யப்படும் என நிர்வாகம் தெரிவித்துள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a474a8deae723.05808269.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-03 11:07:35', 0, 1, 0, 0, 0, 'சொகுசு கப்பலில் பரவிய நோரோ வைரஸ் - 125 பேர் பாதிப்பு...    ', 'அமெரிக்காவின் சான் பிரான்சிஸ்கோவில் இருந்து அலாஸ்கா மற்றும் கனடாவுக்கு சென்ற சொகுசு சுற்றுலா கப்பலில் நோரோ வைரஸ் பரவியதால் 125 பேர் உடல்நலக் குறைவால் பாதிக்கப்ப', 16, 0, 0, 1, '2026-07-03 05:37:35', '2026-07-12 18:51:09', NULL, 0),
(189, 4, NULL, 1, NULL, NULL, NULL, 36, 'திருவள்ளூர் மாவட்டம் பெரியபாளையம் அமோனியா வாயு கசிவு: உயிரிழப்பு அதிகரிப்பு – விசாரணை தீவிரம்', 'திருவள்ளூர்-மாவட்டம்-பெரியபாளையம்-அமோனியா-வாயு-கசிவு-உயிரிழப்பு-அதிகரிப்பு-விசாரணை-தீவிரம்', 'திருவள்ளூர் மாவட்டம் பெரியபாளையம் அருகே உள்ள தனியார் கடலுணவு பதப்படுத்தும் தொழிற்சாலையில் ஏற்பட்ட அமோனியா வாயு கசிவு சம்பவத்தில் உயிரிழந்தோரின் எண்ணிக்கை தொடர்ந…', 'திருவள்ளூர் மாவட்டம் பெரியபாளையம் அருகே உள்ள தனியார் கடலுணவு பதப்படுத்தும் தொழிற்சாலையில் ஏற்பட்ட அமோனியா வாயு கசிவு சம்பவத்தில் உயிரிழந்தோரின் எண்ணிக்கை தொடர்ந்து அதிகரித்துள்ளது. சிகிச்சை பெற்று வந்த மேலும் சில தொழிலாளர்கள் உயிரிழந்ததைத் தொடர்ந்து பலி எண்ணிக்கை 18 ஆக உயர்ந்துள்ளது. \r\nஇந்த விபத்தில் பலர் கடுமையான மூச்சுத்திணறல் மற்றும் உடல்நலக் கோளாறுகளால் மருத்துவமனைகளில் அனுமதிக்கப்பட்டுள்ளனர். அவர்களில் சிலருக்கு தொடர்ந்து தீவிர சிகிச்சை அளிக்கப்பட்டு வருகிறது.\r\nசம்பவத்துக்கான காரணம் குறித்து அதிகாரிகள் தீவிர விசாரணை மேற்கொண்டு வருகின்றனர். தொழிற்சாலையில் பாதுகாப்பு நடைமுறைகள் முறையாக பின்பற்றப்பட்டனவா என்பது குறித்து ஆய்வு நடைபெறுகிறது. மேலும், எதிர்காலத்தில் இதுபோன்ற விபத்துகள் ஏற்படாமல் தடுக்க மாநிலம் முழுவதும் ஆபத்தான தொழிற்சாலைகளில் பாதுகாப்பு ஆய்வுகளை மேற்கொள்ள அரசு உத்தரவிட்டுள்ளது.\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4753111bc349.89692476.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-03 11:44:05', 0, 1, 0, 0, 0, 'திருவள்ளூர் மாவட்டம் பெரியபாளையம் அமோனியா வாயு கசிவு: உயிரிழப்பு அதிகரிப்பு – விசாரணை தீவிரம்', 'திருவள்ளூர் மாவட்டம் பெரியபாளையம் அருகே உள்ள தனியார் கடலுணவு பதப்படுத்தும் தொழிற்சாலையில் ஏற்பட்ட அமோனியா வாயு கசிவு சம்பவத்தில் உயிரிழந்தோரின் எண்ணிக்கை தொடர்ந', 12, 0, 0, 1, '2026-07-03 06:13:59', '2026-07-12 04:34:49', NULL, 0),
(190, 4, NULL, 1, NULL, NULL, NULL, 37, 'கோத்தகிரி அருகே குட்டிகளை முதுகில் சுமந்தவாறு கரடி உலா -', 'கோத்தகிரி-அருகே-குட்டிகளை-முதுகில்-சுமந்தவாறு-கரடி-உலா', 'நீலகிரி மாவட்டம் கோத்தகிரி அருகேயுள்ள கன்னிகா தேவி காலனி பகுதியில் தாய்க் கரடி ஒன்று தனது இரண்டு குட்டிகளை முதுகில் சுமந்தபடி குடியிருப்பு பகுதி மற்றும் தேயில…', 'நீலகிரி மாவட்டம் கோத்தகிரி அருகேயுள்ள கன்னிகா தேவி காலனி பகுதியில் தாய்க் கரடி ஒன்று தனது இரண்டு குட்டிகளை முதுகில் சுமந்தபடி குடியிருப்பு பகுதி மற்றும் தேயிலைத் தோட்டம் அருகே உலா வந்தது.\r\nஇந்தக் காட்சியைப் பார்த்த தேயிலைத் தொழிலாளர்கள் மற்றும் அப்பகுதி மக்கள் அச்சமடைந்தனர். பொதுமக்கள் சத்தம் எழுப்பியதைத் தொடர்ந்து, கரடி சிறிது நேரம் தனது குட்டிகளுடன் அங்கிருந்தபின் மீண்டும் தேயிலைத் தோட்டப் பகுதிக்குள் சென்று மறைந்ததாக தெரிவிக்கப்பட்டுள்ளது. \r\nகடந்த சில ஆண்டுகளாக இந்தப் பகுதியில் கரடிகள் அடிக்கடி நடமாடி வருவதால், மனிதர்–வனவிலங்கு மோதல் ஏற்படும் அபாயம் இருப்பதாக உள்ளூர் மக்கள் கவலை தெரிவித்து வருகின்றனர். எனவே, குடியிருப்பு பகுதிகளில் தொடர்ந்து உலா வரும் கரடிகளை பாதுகாப்பான முறையில் வனப்பகுதிக்குள் மாற்ற வனத்துறை உரிய நடவடிக்கை எடுக்க வேண்டும் என்று பொதுமக்கள் கோரிக்கை விடுத்துள்ளனர். ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a47570faecfb6.76436065.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-03 12:00:54', 0, 1, 0, 0, 0, 'கோத்தகிரி அருகே குட்டிகளை முதுகில் சுமந்தவாறு கரடி உலா - ', 'நீலகிரி மாவட்டம் கோத்தகிரி அருகேயுள்ள கன்னிகா தேவி காலனி பகுதியில் தாய்க் கரடி ஒன்று தனது இரண்டு குட்டிகளை முதுகில் சுமந்தபடி குடியிருப்பு பகுதி மற்றும் தேயில', 19, 0, 0, 1, '2026-07-03 06:30:54', '2026-07-11 02:04:21', NULL, 0),
(191, 4, NULL, 2, 3, NULL, 'Madurai', 38, 'பாதாள சாக்கடைக்குள் தவறி விழுந்த முதியவர் பலி...', 'பாதாள-சாக்கடைக்குள்-தவறி-விழுந்த-முதியவர்-பலி', 'மராட்டிய மாநிலம் மும்பையின் சாக்கிநாகா பகுதியில் திறந்த நிலையில் இருந்த பாதாள சாக்கடை குழிக்குள் தவறி விழுந்த முதியவர் உயிரிழந்தார்.\r\n\r\nமழை காரணமாக சாலையில் த…', 'மராட்டிய மாநிலம் மும்பையின் சாக்கிநாகா பகுதியில் திறந்த நிலையில் இருந்த பாதாள சாக்கடை குழிக்குள் தவறி விழுந்த முதியவர் உயிரிழந்தார்.\r\n\r\nமழை காரணமாக சாலையில் தேங்கியிருந்த நீரில் குழி தெரியாததால் இந்த விபத்து ஏற்பட்டதாக முதற்கட்ட தகவல்கள் தெரிவிக்கின்றன. தகவலறிந்த தீயணைப்பு மற்றும் மீட்புப் படையினர் பல மணி நேர தேடுதல் நடவடிக்கைக்குப் பிறகு முதியவரின் உடலை மீட்டனர்.\r\n\r\nஇந்த சம்பவம் தொடர்பாக அலட்சியம் ஏற்பட்டதா என்பது குறித்து மாநகராட்சி அதிகாரிகள் விசாரணை மேற்கொண்டுள்ளனர். பொதுமக்களின் பாதுகாப்பை உறுதி செய்யும் வகையில் திறந்த நிலையில் உள்ள பாதாள சாக்கடை குழிகளை உடனடியாக மூட வேண்டும் என்ற கோரிக்கையும் வலுத்துள்ளது. \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4759e428b591.85588159.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-03 12:13:14', 0, 1, 0, 0, 0, ' பாதாள சாக்கடைக்குள் தவறி விழுந்த முதியவர் பலி...   ', 'மராட்டிய மாநிலம் மும்பையின் சாக்கிநாகா பகுதியில் திறந்த நிலையில் இருந்த பாதாள சாக்கடை குழிக்குள் தவறி விழுந்த முதியவர் உயிரிழந்தார்.\r\n\r\nமழை காரணமாக சாலையில் த', 34, 0, 0, 1, '2026-07-03 06:43:14', '2026-07-12 07:35:48', NULL, 0),
(192, 4, NULL, 2, NULL, NULL, NULL, 40, 'அமர்நாத் யாத்திரை இன்று முதல் தொடக்கம்...', 'அமர்நாத்-யாத்திரை-இன்று-முதல்-தொடக்கம்', '**அமர்நாத் யாத்திரை இன்று முதல் தொடக்கம்; பலத்த பாதுகாப்புடன் பக்தர்கள் பயணம்**\r\n\r\nஜம்மு-காஷ்மீரில் ஆண்டுதோறும் நடைபெறும் புனித அமர்நாத் யாத்திரை இன்று முதல் அத…', '**அமர்நாத் யாத்திரை இன்று முதல் தொடக்கம்; பலத்த பாதுகாப்புடன் பக்தர்கள் பயணம்**\r\n\r\nஜம்மு-காஷ்மீரில் ஆண்டுதோறும் நடைபெறும் புனித அமர்நாத் யாத்திரை இன்று முதல் அதிகாரப்பூர்வமாக தொடங்கியது. முதல் கட்டமாக ஆயிரக்கணக்கான பக்தர்கள் ஜம்முவில் இருந்து அமர்நாத் குகைக் கோவிலை நோக்கி உற்சாகமாக புறப்பட்டனர்.\r\n\r\nயாத்திரை தொடக்கத்தை முன்னிட்டு நிர்வாகம் மற்றும் பாதுகாப்புப் படையினர் விரிவான ஏற்பாடுகளை செய்துள்ளனர். யாத்திரை பாதை முழுவதும் பலத்த பாதுகாப்பு ஏற்பாடுகள் செய்யப்பட்டுள்ளதுடன், மருத்துவ முகாம்கள், ஓய்வு மையங்கள் மற்றும் அவசரகால உதவி வசதிகளும் தயார் நிலையில் வைக்கப்பட்டுள்ளன.\r\n\r\nபக்தர்கள் வழக்கமான பால்டால் மற்றும் பகல்காம் ஆகிய இரண்டு முக்கிய வழித்தடங்கள் வழியாக புனித குகையை அடைந்து இயற்கையாக உருவாகும் பனிலிங்கத்தை தரிசிக்க உள்ளனர்.\r\nஇந்த ஆண்டுக்கான அமர்நாத் யாத்திரை பல நாட்கள் நடைபெறவுள்ள நிலையில், நாடுமுழுவதும் இருந்து ஏராளமான பக்தர்கள் பங்கேற்பார்கள் என எதிர்பார்க்கப்படுகிறது. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4775d75102f0.66158183.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-03 13:14:59', 0, 0, 0, 0, 0, ' அமர்நாத் யாத்திரை இன்று முதல் தொடக்கம்...  ', '**அமர்நாத் யாத்திரை இன்று முதல் தொடக்கம்; பலத்த பாதுகாப்புடன் பக்தர்கள் பயணம்**\r\n\r\nஜம்மு-காஷ்மீரில் ஆண்டுதோறும் நடைபெறும் புனித அமர்நாத் யாத்திரை இன்று முதல் அத', 46, 0, 0, 1, '2026-07-03 07:44:59', '2026-07-12 07:05:00', NULL, 0),
(193, 4, NULL, 1, NULL, NULL, NULL, 41, 'மின்சார ரெயில்கள் இன்று ரத்து:', 'மின்சார-ரெயில்கள்-இன்று-ரத்து', 'சென்னையில் கூடுதலாக 50 பஸ்கள் இயக்கம்\r\n\r\nசென்னையில் பராமரிப்பு பணிகள் காரணமாக இன்று பல புறநகர் மின்சார ரெயில் சேவைகள் தற்காலிகமாக ரத்து செய்யப்பட்டுள்ளன. இதனால்…', 'சென்னையில் கூடுதலாக 50 பஸ்கள் இயக்கம்\r\n\r\nசென்னையில் பராமரிப்பு பணிகள் காரணமாக இன்று பல புறநகர் மின்சார ரெயில் சேவைகள் தற்காலிகமாக ரத்து செய்யப்பட்டுள்ளன. இதனால் பயணிகளுக்கு ஏற்படும் சிரமத்தை குறைக்கும் வகையில் மாநகரப் போக்குவரத்து கழகம் (MTC) கூடுதலாக  50 சிறப்பு பேருந்துகளை இயக்கியுள்ளது. \r\nரத்து செய்யப்பட்ட ரெயில் சேவைகளுக்கு மாற்றாக, முக்கிய வழித்தடங்களில் கூடுதல் பேருந்துகள் இயக்கப்படுவதுடன், சில பகுதிகளில் சிறப்பு ரெயில் சேவைகளும் ஏற்பாடு செய்யப்பட்டுள்ளன. பயணிகள் தங்கள் பயணத்தை முன்கூட்டியே திட்டமிட்டு, மாற்று போக்குவரத்து வசதிகளை பயன்படுத்துமாறு அதிகாரிகள் அறிவுறுத்தியுள்ளனர். \r\n\r\nமின்சார ரெயில் சேவைகள் மீண்டும் வழக்கமான அட்டவணைப்படி இயக்கப்படும் நேரம் குறித்து தெற்கு ரெயில்வே தொடர்ந்து தகவல்களை வெளியிட்டு வருகிறது.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a49e9b7734e70.69060521.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-05 10:51:10', 0, 1, 0, 0, 0, 'மின்சார ரெயில்கள் இன்று ரத்து: ', 'சென்னையில் கூடுதலாக 50 பஸ்கள் இயக்கம்\r\n\r\nசென்னையில் பராமரிப்பு பணிகள் காரணமாக இன்று பல புறநகர் மின்சார ரெயில் சேவைகள் தற்காலிகமாக ரத்து செய்யப்பட்டுள்ளன. இதனால்', 4, 0, 0, 1, '2026-07-05 05:21:10', '2026-07-11 15:05:42', NULL, 0),
(194, 4, NULL, 1, NULL, NULL, NULL, 42, 'குற்றாலத்தில் அனைத்து அருவிகளிலும் சுற்றுலா பயணிகள் குளிக்க அனுமதி...', 'குற்றாலத்தில்-அனைத்து-அருவிகளிலும்-சுற்றுலா-பயணிகள்-குளிக்க-அனுமதி', 'தென்காசி மாவட்டம் குற்றாலத்தில் கடந்த சில நாட்களாக பெய்த மழையால் அருவிகளில் நீர்வரத்து அதிகரித்திருந்தது. பாதுகாப்பு நிலைமையை தொடர்ந்து கண்காணித்த அதிகாரிகள், த…', 'தென்காசி மாவட்டம் குற்றாலத்தில் கடந்த சில நாட்களாக பெய்த மழையால் அருவிகளில் நீர்வரத்து அதிகரித்திருந்தது. பாதுகாப்பு நிலைமையை தொடர்ந்து கண்காணித்த அதிகாரிகள், தற்போது நிலைமை சீராக இருப்பதாக தெரிவித்துள்ளனர்.\r\n\r\nஇதையடுத்து, குற்றாலத்தின் அனைத்து முக்கிய அருவிகளிலும் சுற்றுலா பயணிகள் குளிக்க மீண்டும் அனுமதி வழங்கப்பட்டுள்ளது. சுற்றுலாப் பயணிகள் உற்சாகத்துடன் அருவிகளில் குளித்து இயற்கை அழகை ரசித்து வருகின்றனர்.\r\n\r\nபொதுமக்கள் மற்றும் சுற்றுலாப் பயணிகள் பாதுகாப்பு விதிமுறைகளை கடைபிடிக்கவும், அதிகாரிகள் வழங்கும் அறிவுறுத்தல்களை பின்பற்றவும் மாவட்ட நிர்வாகம் அறிவுறுத்தியுள்ளது. நீர்வரத்து அதிகரிக்கும் சூழல் ஏற்பட்டால் பாதுகாப்பு கருதி மீண்டும் கட்டுப்பாடுகள் விதிக்கப்படலாம் என்றும் தெரிவிக்கப்பட்டுள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a49eb6708cf20.79220301.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-05 10:58:32', 0, 1, 0, 0, 0, 'குற்றாலத்தில் அனைத்து அருவிகளிலும் சுற்றுலா பயணிகள் குளிக்க அனுமதி...  ', 'தென்காசி மாவட்டம் குற்றாலத்தில் கடந்த சில நாட்களாக பெய்த மழையால் அருவிகளில் நீர்வரத்து அதிகரித்திருந்தது. பாதுகாப்பு நிலைமையை தொடர்ந்து கண்காணித்த அதிகாரிகள், த', 21, 0, 0, 1, '2026-07-05 05:28:32', '2026-07-12 13:51:38', NULL, 0),
(195, 4, NULL, 2, NULL, NULL, NULL, 44, 'திருப்பதி கோவிலில் ஒரே நாளில் 90 ஆயிரம் பக்தர்கள் சாமி தரிசனம்...', 'திருப்பதி-கோவிலில்-ஒரே-நாளில்-90-ஆயிரம்-பக்தர்கள்-சாமி-தரிசனம்', 'திருப்பதி மலைக்கோவிலில் பக்தர்கள் வருகை தொடர்ந்து அதிகரித்து வருகிறது. விடுமுறை மற்றும் சிறப்பு வழிபாட்டு நாட்களை முன்னிட்டு, ஒரே நாளில் சுமார் 90 ஆயிரம் பக்தர்…', 'திருப்பதி மலைக்கோவிலில் பக்தர்கள் வருகை தொடர்ந்து அதிகரித்து வருகிறது. விடுமுறை மற்றும் சிறப்பு வழிபாட்டு நாட்களை முன்னிட்டு, ஒரே நாளில் சுமார் 90 ஆயிரம் பக்தர்கள் சுவாமி தரிசனம் செய்ததாக கோவில் நிர்வாகம் தெரிவித்துள்ளது.\r\n\r\nபக்தர்களின் வசதிக்காக தரிசன ஏற்பாடுகள், குடிநீர், மருத்துவம் மற்றும் பாதுகாப்பு உள்ளிட்ட சேவைகள் கூடுதலாக செய்யப்பட்டுள்ளன. கூட்ட நெரிசலை கட்டுப்படுத்த கூடுதல் பணியாளர்களும் பாதுகாப்புப் படையினரும் பணியில் ஈடுபடுத்தப்பட்டுள்ளனர்.\r\n\r\nதரிசனத்திற்காக வரும் பக்தர்கள், அதிகாரிகள் வழங்கும் வழிகாட்டுதல்களை பின்பற்றி பொறுமையுடன் ஒத்துழைக்குமாறும், தேவையான முன்னெச்சரிக்கை நடவடிக்கைகளை கடைபிடிக்குமாறும் கோவில் நிர்வாகம் கேட்டுக் கொண்டுள்ளது.\r\nதிருமலையில் நேற்று மொத்தம் 90 ஆயிரத்து 546 பக்தர்கள் ஏழுமலையானை தரிசனம் செய்தனர். \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a49ee2bacde31.54375836.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-05 11:10:04', 0, 1, 0, 0, 0, 'திருப்பதி கோவிலில் ஒரே நாளில் 90 ஆயிரம் பக்தர்கள் சாமி தரிசனம்...    ', 'திருப்பதி மலைக்கோவிலில் பக்தர்கள் வருகை தொடர்ந்து அதிகரித்து வருகிறது. விடுமுறை மற்றும் சிறப்பு வழிபாட்டு நாட்களை முன்னிட்டு, ஒரே நாளில் சுமார் 90 ஆயிரம் பக்தர்', 18, 0, 0, 1, '2026-07-05 05:40:04', '2026-07-13 13:39:44', NULL, 0);
