(222, 5, NULL, 1, NULL, NULL, NULL, 70, 'தமிழ்நாட்டில் 2026-ஆம் ஆண்டு எல் நினோ', 'தமிழ்நாட்டில்-2026-ஆம்-ஆண்டு-எல்-நினோ', 'தமிழ்நாட்டில் 2026-ஆம் ஆண்டு ஏற்படவிருக்கும் எல் நினோ நிகழ்வானது, 12 மாவட்டங்களில் கடுமையான, குறிப்பிட்ட பகுதிகளில் வறட்சி என்ற இரட்டை அச்சுறுத்தலையும், வடகிழக்…', 'தமிழ்நாட்டில் 2026-ஆம் ஆண்டு ஏற்படவிருக்கும் எல் நினோ நிகழ்வானது, 12 மாவட்டங்களில் கடுமையான, குறிப்பிட்ட பகுதிகளில் வறட்சி என்ற இரட்டை அச்சுறுத்தலையும், வடகிழக்குப் பருவமழையின் போது அதீத, வெள்ளப்பெருக்கை ஏற்படுத்தக்கூடிய மழைக்கான அதிகரித்த அபாயத்தையும் தூண்டுகிறது. உருவாகிவரும் இந்த \"சூப்பர்\" நிகழ்வானது, நவம்பர் 2026 மற்றும் ஜனவரி 2027-க்கு இடையில் உச்சத்தை அடையும் என்று எதிர்பார்க்கப்படுகிறது.\r\n இது நீண்டகால வெப்பநிலை உயர்வுகளையும், சீரற்ற வானிலை முறைகளையும் உருவாக்கும்.முக்கிய தாக்கங்கள் மற்றும் முன்னறிவிப்புகள்வறட்சி <strong>எச்சரிக்கைகள்</strong>: கடுமையான வறட்சி அபாயங்களை எதிர்கொள்ளும் 12 பாதிக்கப்படக்கூடிய மாவட்டங்களை மத்திய அரசு அடையாளம் கண்டுள்ளது. \r\n அரியலூர், தர்மபுரி, திண்டுக்கல், கிருஷ்ணகிரி, நாமக்கல், நீலகிரி, பெரம்பலூர், இராமநாதபுரம், திருச்சி, திருப்பத்தூர், வேலூர் மற்றும் விருதுநகர். விவசாய இழப்புகளைக் குறைப்பதற்காக, மாநில அதிகாரிகள் பருப்பு வகைகள் போன்ற குறுகிய கால பயிர்களைப் பயிரிடுவதை தீவிரமாக ஊக்குவித்து வருகின்றனர்.\r\nஅதிதீவிர மழைப்பொழிவு: ஒட்டுமொத்த கோடைக்கால தென்மேற்குப் பருவமழை குறைந்திருந்தாலும், மாநிலத்தின் உயிர்நாடியான வடகிழக்குப் பருவமழையுடன் எல் நினோ மோதுவதால், வரலாற்று ரீதியாக இயல்பை விட அதிக மழைப்பொழிவுக்கான சாத்தியக்கூறுகள் அதிகரிக்கின்றன. மிகவும் அடர்த்தியான, கடுமையான கனமழை (உதாரணமாக, ஒரு மாதத்திற்கான மழை சில நிமிடங்களில் பெய்வது) பெய்யக்கூடும் என வானிலை வல்லுநர்கள் எச்சரிக்கின்றனர். இது சென்னை போன்ற கடலோரப் பகுதிகளில் நகர்ப்புறங்களில் நீர் தேக்கத்தையும், கடுமையான திடீர் வெள்ளப்பெருக்கையும் ஏற்படுத்தக்கூடும்.கடல்சார் மற்றும் சூழலியல் நெருக்கடி: இந்தியாவின் கிழக்குக் கடற்கரையோரம், அதிகரித்து வரும் கடல் மேற்பரப்பு வெப்பநிலை ஏற்கனவே பவளப்பாறைகள் வெளுப்பதை வேகப்படுத்துவதோடு, (மத்தி போன்ற) மீன்பிடிக்க உகந்த மீன்களின் பிடிப்பையும் குறைத்து வருகிறது.நீண்ட கால காலநிலை கண்ணோட்டம்உயரும் வெப்பநிலை: உலகளாவிய எல் நினோவின் கூட்டு விளைவுகளால், மாநிலங்கள் தழுவிய வெப்பநிலை வழக்கத்தை விட முன்னதாகவே 2°C முதல் 3°C வரை உயரும் என எதிர்பார்க்கப்படுகிறது. இது கோடைக்காலத்தின் தொடக்கத்தை 2027-ஆம் ஆண்டின் தொடக்கத்திற்குத் தள்ளிப்போடும்.சூழலியல் பாதிப்பு: மேற்கு மற்றும் கிழக்குத் தொடர்ச்சி மலைகளில் நிலவும் நீடித்த வறட்சியானது, பசுமை மாறா வனப்பரப்பில் படிப்படியான சரிவை ஏற்படுத்தி, அதனைப் புதர் காடுகளாக மாற்றி, மண் வளத்தையும் மாற்றிவிடுகிறது என்றுஅண்ணா பல்கலைக்கழகத்தின் காலநிலை நிபுணர்கள் எச்சரிக்கின்றனர்.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4e8938245317.83041106.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-08 23:00:41', 0, 1, 0, 0, 0, 'தமிழ்நாட்டில் 2026-ஆம் ஆண்டு எல் நினோ ', 'தமிழ்நாட்டில் 2026-ஆம் ஆண்டு ஏற்படவிருக்கும் எல் நினோ நிகழ்வானது, 12 மாவட்டங்களில் கடுமையான, குறிப்பிட்ட பகுதிகளில் வறட்சி என்ற இரட்டை அச்சுறுத்தலையும், வடகிழக்', 59, 0, 0, 1, '2026-07-08 17:30:41', '2026-07-13 18:35:06', NULL, 0),
(223, 4, NULL, 1, NULL, NULL, NULL, 71, 'கரூரில் 32 பேருக்கு அரசுப் பணி.. நாளை வழங்குகிறார் முதல்-அமைச்சர் விஜய் ...', 'கரூரில்-32-பேருக்கு-அரசுப்-பணி-நாளை-வழங்குகிறார்-முதல்-அமைச்சர்-விஜய்', 'கரூரில் நடைபெற்ற கூட்ட நெரிசல் சம்பவத்தில் பாதிக்கப்பட்ட குடும்பங்களுக்கு நிவாரண நடவடிக்கையாக, 32 பேருக்கு கருணை அடிப்படையில் அரசுப் பணிக்கான நியமன ஆணைகளை முதல்…', 'கரூரில் நடைபெற்ற கூட்ட நெரிசல் சம்பவத்தில் பாதிக்கப்பட்ட குடும்பங்களுக்கு நிவாரண நடவடிக்கையாக, 32 பேருக்கு கருணை அடிப்படையில் அரசுப் பணிக்கான நியமன ஆணைகளை முதல்-அமைச்சர் விஜய் நாளை வழங்க உள்ளார். \r\nகரூர் மாவட்டத்திற்கு வருகை தரும் அவர், அரசு விழாவில் கலந்து கொண்டு பணிநியமன ஆணைகளை வழங்குவதுடன், பல்வேறு நலத்திட்ட உதவிகளையும் பயனாளிகளிடம் வழங்கவுள்ளார்.\r\nமேலும், ரூ.1,700 கோடி முதலீட்டில் தோல் அல்லாத காலணி உற்பத்தி தொழிற்சாலைக்கான அடிக்கல் நாட்டும் நிகழ்ச்சியிலும் பங்கேற்கிறார். இந்தத் திட்டத்தின் மூலம் சுமார் 13,500 பேருக்கு வேலைவாய்ப்பு உருவாகும் என அதிகாரப்பூர்வ தகவல்கள் தெரிவிக்கின்றன. \r\nமுதல்-அமைச்சரின் வருகையை முன்னிட்டு கரூரில் பாதுகாப்பு ஏற்பாடுகள் தீவிரப்படுத்தப்பட்டுள்ளன. அரசு விழா மற்றும் மக்கள் சந்திப்பு நிகழ்ச்சிகளில் ஏராளமானோர் பங்கேற்பார்கள் என எதிர்பார்க்கப்படுகிறது.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f300300b502.58917048.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 10:52:24', 0, 1, 0, 0, 0, 'கரூரில் 32 பேருக்கு அரசுப் பணி.. நாளை வழங்குகிறார் முதல்-அமைச்சர் விஜய் ...  ', 'கரூரில் நடைபெற்ற கூட்ட நெரிசல் சம்பவத்தில் பாதிக்கப்பட்ட குடும்பங்களுக்கு நிவாரண நடவடிக்கையாக, 32 பேருக்கு கருணை அடிப்படையில் அரசுப் பணிக்கான நியமன ஆணைகளை முதல்', 5, 0, 0, 1, '2026-07-09 05:22:24', '2026-07-12 15:03:51', NULL, 0),
(224, 4, NULL, 1, NULL, NULL, NULL, 72, 'தூத்துக்குடியில் பயங்கர தீ விபத்து: 5 வீடுகள் எரிந்து சேதம்...', 'தூத்துக்குடியில்-பயங்கர-தீ-விபத்து-5-வீடுகள்-எரிந்து-சேதம்', 'தூத்துக்குடி மாநகராட்சிக்குட்பட்ட லூர்தம்மாள்புரம் அருகேயுள்ள திருவள்ளூர்புரம் பகுதியில் ஏற்பட்ட திடீர் தீ விபத்தில் 5 வீடுகள் முழுமையாக சேதமடைந்தன.\r\nதகவலின்படி…', 'தூத்துக்குடி மாநகராட்சிக்குட்பட்ட லூர்தம்மாள்புரம் அருகேயுள்ள திருவள்ளூர்புரம் பகுதியில் ஏற்பட்ட திடீர் தீ விபத்தில் 5 வீடுகள் முழுமையாக சேதமடைந்தன.\r\nதகவலின்படி, அருகிலிருந்த குப்பைகளுக்கு வைக்கப்பட்ட தீ, பலத்த காற்றின் காரணமாக குடியிருப்பு பகுதிக்குப் பரவி வீடுகளை சூழ்ந்தது. தீயில் வீடுகளில் இருந்த அத்தியாவசிய பொருட்கள், மரச்சாமான்கள் மற்றும் வீட்டு உபயோகப் பொருட்கள் அனைத்தும் எரிந்து நாசமாயின.\r\nஒரு வீட்டில் இருந்த சமையல் எரிவாயு சிலிண்டர் வெடித்ததால் அப்பகுதியில் பெரும் பரபரப்பு ஏற்பட்டது. தகவலறிந்த தீயணைப்பு வீரர்கள் பல வாகனங்களுடன் விரைந்து சென்று நீண்ட நேரப் போராட்டத்திற்குப் பிறகு தீயை கட்டுக்குள் கொண்டு வந்தனர்.\r\nஇந்த சம்பவத்தில் உயிரிழப்பு எதுவும் ஏற்படவில்லை. தீ விபத்திற்கான காரணம் குறித்து போலீசார் வழக்குப்பதிவு செய்து விசாரணை மேற்கொண்டு வருகின்றனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f314169a960.38052038.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 10:57:46', 0, 1, 0, 0, 0, 'தூத்துக்குடியில் பயங்கர தீ விபத்து: 5 வீடுகள் எரிந்து சேதம்...    ', 'தூத்துக்குடி மாநகராட்சிக்குட்பட்ட லூர்தம்மாள்புரம் அருகேயுள்ள திருவள்ளூர்புரம் பகுதியில் ஏற்பட்ட திடீர் தீ விபத்தில் 5 வீடுகள் முழுமையாக சேதமடைந்தன.\r\nதகவலின்படி', 22, 0, 0, 1, '2026-07-09 05:27:46', '2026-07-12 07:17:49', NULL, 0),
(225, 4, NULL, 1, NULL, NULL, NULL, 73, 'அரசு மருத்துவமனையில் நோயாளிக்கு காவலாளி இ.சி.ஜி. எடுத்தல்', 'அரசு-மருத்துவமனையில்-நோயாளிக்கு-காவலாளி-இசிஜி-எடுத்தல்', 'ஆலங்குடி,\r\nபுதுக்கோட்டை மாவட்டம் ஆலங்குடியில்  அரசு மருத்துவமனையில் சிகிச்சைக்காக அனுமதிக்கப்பட்டிருந்த நோயாளிக்கு, மருத்துவ பணியாளருக்குப் பதிலாக பாதுகாப்பு கா…', 'ஆலங்குடி,\r\nபுதுக்கோட்டை மாவட்டம் ஆலங்குடியில்  அரசு மருத்துவமனையில் சிகிச்சைக்காக அனுமதிக்கப்பட்டிருந்த நோயாளிக்கு, மருத்துவ பணியாளருக்குப் பதிலாக பாதுகாப்பு காவலாளி இ.சி.ஜி. (ECG) பரிசோதனை மேற்கொண்டதாக கூறப்படும் சம்பவம் சர்ச்சையை ஏற்படுத்தியுள்ளது.\r\nஇந்த சம்பவம் தொடர்பான புகைப்படங்கள் மற்றும் தகவல்கள் சமூக வலைதளங்களில் பரவியதைத் தொடர்ந்து, மருத்துவமனை நிர்வாகம் விசாரணையைத் தொடங்கியுள்ளது. மருத்துவ நடைமுறைகள் முறையாகப் பின்பற்றப்பட்டனவா, பாதுகாப்பு விதிமுறைகள் மீறப்பட்டனவா என்பது குறித்து அதிகாரிகள் ஆய்வு செய்து வருகின்றனர்.\r\nமுதற்கட்ட விசாரணையின் அடிப்படையில், சம்பவத்தில் தொடர்புடையவர்களிடம் விளக்கம் கேட்கப்பட்டுள்ளதாகவும், விதிமீறல் உறுதியானால் உரிய நடவடிக்கை எடுக்கப்படும் என்றும் அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nஇந்த விவகாரம் நோயாளிகளின் பாதுகாப்பு மற்றும் மருத்துவ சேவைகளின் தரம் குறித்த கேள்விகளை எழுப்பியுள்ள நிலையில், விசாரணை அறிக்கைக்காக பொதுமக்கள் காத்திருக்கின்றனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f361187a308.97684192.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 11:18:21', 0, 1, 0, 0, 0, 'அரசு மருத்துவமனையில் நோயாளிக்கு காவலாளி இ.சி.ஜி. எடுத்தல் ', 'ஆலங்குடி,\r\nபுதுக்கோட்டை மாவட்டம் ஆலங்குடியில்  அரசு மருத்துவமனையில் சிகிச்சைக்காக அனுமதிக்கப்பட்டிருந்த நோயாளிக்கு, மருத்துவ பணியாளருக்குப் பதிலாக பாதுகாப்பு கா', 8, 0, 0, 1, '2026-07-09 05:48:21', '2026-07-12 10:11:03', NULL, 0),
(226, 4, NULL, 2, NULL, NULL, NULL, 74, 'மராட்டியம்: வெள்ளத்தில் அடித்துச் செல்லப்பட்ட 3,000 கேஸ் சிலிண்டர்கள்... அதிர்ச்சி காட்சிகள்...', 'மராட்டியம்-வெள்ளத்தில்-அடித்துச்-செல்லப்பட்ட-3000-கேஸ்-சிலிண்டர்கள்-அதிர்ச்சி-காட்சிகள்', 'மராட்டிய மாநிலத்தின் ராய்காட் மாவட்டத்தில் பெய்த கனமழையால் ஏற்பட்ட வெள்ளப்பெருக்கில், எச்பிசிஎல் (HPCL) எரிவாயு நிரப்பும் நிலையத்தில் இருந்த சுமார் 3,000 எல்பிஜ…', 'மராட்டிய மாநிலத்தின் ராய்காட் மாவட்டத்தில் பெய்த கனமழையால் ஏற்பட்ட வெள்ளப்பெருக்கில், எச்பிசிஎல் (HPCL) எரிவாயு நிரப்பும் நிலையத்தில் இருந்த சுமார் 3,000 எல்பிஜி கேஸ் சிலிண்டர்கள் வெள்ளநீரில் அடித்துச் செல்லப்பட்டன. பாதுகாப்புச் சுவர் சேதமடைந்ததால், சிலிண்டர்கள் அருகிலுள்ள பாதாள்கங்கா ஆற்றில் கலந்ததாக அதிகாரிகள் தெரிவித்துள்ளனர். \r\nவெள்ளத்தில் மிதந்து செல்லும் சிலிண்டர்களின் காட்சிகள் சமூக வலைதளங்களில் பரவி பரபரப்பை ஏற்படுத்தியுள்ளன. ஆற்றங்கரையில் அல்லது வெள்ளநீரில் சிலிண்டர்கள் தென்பட்டால் அவற்றை தொடவோ, எடுத்துச் செல்லவோ கூடாது என மாவட்ட நிர்வாகம் பொதுமக்களுக்கு எச்சரிக்கை விடுத்துள்ளது. \r\nமீட்புப் பணிகள் தீவிரமாக நடைபெற்று வரும் நிலையில், வெள்ளத்தில் அடித்துச் செல்லப்பட்ட சிலிண்டர்களை பாதுகாப்பாக மீட்கும் நடவடிக்கைகளை சம்பந்தப்பட்ட துறைகள் மேற்கொண்டு வருகின்றன. \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f3855556815.64386508.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 11:27:47', 0, 1, 0, 0, 0, 'மராட்டியம்: வெள்ளத்தில் அடித்துச் செல்லப்பட்ட 3,000 கேஸ் சிலிண்டர்கள்... அதிர்ச்சி காட்சிகள்...  ', 'மராட்டிய மாநிலத்தின் ராய்காட் மாவட்டத்தில் பெய்த கனமழையால் ஏற்பட்ட வெள்ளப்பெருக்கில், எச்பிசிஎல் (HPCL) எரிவாயு நிரப்பும் நிலையத்தில் இருந்த சுமார் 3,000 எல்பிஜ', 10, 0, 0, 1, '2026-07-09 05:57:47', '2026-07-12 16:28:49', NULL, 0),
(227, 4, NULL, 3, NULL, NULL, NULL, 75, 'ஆஸ்திரேலியா சென்றடைந்தார் பிரதமர் மோடி: இந்தியாவில் முதலீடு செய்ய அந்நாட்டு நிறுவனங்களுக்கு அழைப்பு...', 'ஆஸ்திரேலியா-சென்றடைந்தார்-பிரதமர்-மோடி-இந்தியாவில்-முதலீடு-செய்ய-அந்நாட்டு-நிறுவனங்களுக்கு-அழைப்பு', 'இந்திய பிரதமர் நரேந்திர மோடி, அதிகாரப்பூர்வ பயணத்தின் ஒரு பகுதியாக ஆஸ்திரேலியா சென்றடைந்தார். அங்கு நடைபெற்ற இந்தியா–ஆஸ்திரேலியா தொழில் முனைவோர் சந்திப்பில் கலந…', 'இந்திய பிரதமர் நரேந்திர மோடி, அதிகாரப்பூர்வ பயணத்தின் ஒரு பகுதியாக ஆஸ்திரேலியா சென்றடைந்தார். அங்கு நடைபெற்ற இந்தியா–ஆஸ்திரேலியா தொழில் முனைவோர் சந்திப்பில் கலந்து கொண்ட அவர், இந்தியாவில் முதலீடு செய்ய ஆஸ்திரேலிய நிறுவனங்களை அழைத்தார். \r\nஉலகின் வேகமாக வளர்ந்து வரும் முக்கிய பொருளாதார நாடுகளில் இந்தியா ஒன்றாக இருப்பதாகக் குறிப்பிட்ட அவர், உள்கட்டமைப்பு, புதுப்பிக்கத்தக்க எரிசக்தி, தொழில்நுட்பம், முக்கிய தாதுக்கள், நிதிச் சேவைகள் உள்ளிட்ட பல்வேறு துறைகளில் முதலீட்டிற்கு ஏராளமான வாய்ப்புகள் இருப்பதாக தெரிவித்தார். \r\nமேலும், இந்தியா–ஆஸ்திரேலியா இடையிலான பொருளாதார ஒத்துழைப்பை மேலும் வலுப்படுத்தும் வகையில் விரிவான பொருளாதார ஒப்பந்தத்தை விரைவில் நிறைவு செய்ய வேண்டும் என்றும் அவர் வலியுறுத்தினார். \r\nஇந்த பயணத்தின் போது இருநாட்டு தலைவர்களும் வர்த்தகம், முதலீடு, தூய்மையான எரிசக்தி, முக்கிய தாதுக்கள் மற்றும் தொழில்நுட்ப ஒத்துழைப்பு உள்ளிட்ட பல்வேறு அம்சங்கள் குறித்து ஆலோசனை நடத்த உள்ளனர். \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f417b85a4d2.80896710.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 12:06:56', 0, 1, 0, 0, 0, 'ஆஸ்திரேலியா சென்றடைந்தார் பிரதமர் மோடி: இந்தியாவில் முதலீடு செய்ய அந்நாட்டு நிறுவனங்களுக்கு அழைப்பு...    ', 'இந்திய பிரதமர் நரேந்திர மோடி, அதிகாரப்பூர்வ பயணத்தின் ஒரு பகுதியாக ஆஸ்திரேலியா சென்றடைந்தார். அங்கு நடைபெற்ற இந்தியா–ஆஸ்திரேலியா தொழில் முனைவோர் சந்திப்பில் கலந', 13, 0, 0, 1, '2026-07-09 06:36:56', '2026-07-12 11:38:52', NULL, 0),
(228, 4, NULL, 3, NULL, NULL, NULL, 76, 'சீனாவில் கனமழையால் ஏற்பட்ட வெள்ளத்தில் சிக்கி 39 பேர் பலி...', 'சீனாவில்-கனமழையால்-ஏற்பட்ட-வெள்ளத்தில்-சிக்கி-39-பேர்-பலி', 'சீனாவின் தெற்கு பகுதியில் தொடர்ந்து பெய்த கனமழையால் ஏற்பட்ட கடும் வெள்ளப்பெருக்கில் சிக்கி 39 பேர் உயிரிழந்துள்ளனர். மேலும், பலர் மாயமாகியிருப்பதாக அந்நாட்டு அத…', 'சீனாவின் தெற்கு பகுதியில் தொடர்ந்து பெய்த கனமழையால் ஏற்பட்ட கடும் வெள்ளப்பெருக்கில் சிக்கி 39 பேர் உயிரிழந்துள்ளனர். மேலும், பலர் மாயமாகியிருப்பதாக அந்நாட்டு அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nகுவாங்சி மாகாணத்தின் பல பகுதிகளில் அணைகள் நிரம்பி வழிந்ததுடன், ஆறுகளில் ஏற்பட்ட வெள்ளம் குடியிருப்புகள், சாலைகள் மற்றும் விவசாய நிலங்களை கடுமையாக பாதித்துள்ளது. பாதுகாப்பு முன்னெச்சரிக்கையாக ஆயிரக்கணக்கான மக்கள் பாதுகாப்பான இடங்களுக்கு மாற்றப்பட்டுள்ளனர்.\r\nமீட்புப் பணிகளில் அவசர உதவிக்குழுக்கள், படகுகள் மற்றும் சிறப்பு மீட்பு உபகரணங்கள் பயன்படுத்தப்பட்டு வருகின்றன. சேதமடைந்த பகுதிகளில் மின்சாரம் மற்றும் போக்குவரத்து சேவைகளை விரைவாக சீரமைக்கும் பணிகளும் நடைபெற்று வருகின்றன.\r\nகனமழை தொடரும் என வானிலை அமைப்புகள் எச்சரித்துள்ளதால், பாதிக்கப்பட்ட பகுதிகளில் மக்கள் மிகுந்த எச்சரிக்கையுடன் இருக்குமாறு அதிகாரிகள் அறிவுறுத்தியுள்ளனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f4281391ef3.25597116.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 12:11:32', 0, 1, 0, 0, 0, 'சீனாவில் கனமழையால் ஏற்பட்ட வெள்ளத்தில் சிக்கி 39 பேர் பலி...   ', 'சீனாவின் தெற்கு பகுதியில் தொடர்ந்து பெய்த கனமழையால் ஏற்பட்ட கடும் வெள்ளப்பெருக்கில் சிக்கி 39 பேர் உயிரிழந்துள்ளனர். மேலும், பலர் மாயமாகியிருப்பதாக அந்நாட்டு அத', 9, 0, 0, 1, '2026-07-09 06:41:32', '2026-07-12 11:01:33', NULL, 0),
(229, 4, NULL, 3, NULL, NULL, NULL, 77, 'அரபிக்கடலில் மாயமான சரக்கு விமானம்: பலுசிஸ்தான் கடற்கரையில் சிதைந்த பாகங்கள் மீட்பு...', 'அரபிக்கடலில்-மாயமான-சரக்கு-விமானம்-பலுசிஸ்தான்-கடற்கரையில்-சிதைந்த-பாகங்கள்-மீட்பு', 'அரபிக்கடலில் மாயமான தனியார் சரக்கு விமானத்தின் சிதைந்த பாகங்கள் பலுசிஸ்தான் கடற்கரைக்கு அருகிலுள்ள கடற்பகுதியில் மீட்கப்பட்டுள்ளன. விமானம் காணாமல் போனதைத் தொடர்…', 'அரபிக்கடலில் மாயமான தனியார் சரக்கு விமானத்தின் சிதைந்த பாகங்கள் பலுசிஸ்தான் கடற்கரைக்கு அருகிலுள்ள கடற்பகுதியில் மீட்கப்பட்டுள்ளன. விமானம் காணாமல் போனதைத் தொடர்ந்து கடற்படை, கடலோர பாதுகாப்புப் படை மற்றும் மீட்புக் குழுக்கள் இணைந்து தீவிர தேடுதல் பணிகளை மேற்கொண்டன.\r\nமீட்பு நடவடிக்கையின்போது விமானத்தின் பல உடைந்த பாகங்கள் கண்டுபிடிக்கப்பட்டதாக அதிகாரிகள் தெரிவித்துள்ளனர். எனினும், விமானத்தில் இருந்த பணியாளர்களின் நிலை குறித்து இதுவரை அதிகாரப்பூர்வ தகவல் வெளியாகவில்லை.\r\nமுதற்கட்ட தகவலின்படி, விமானம் பறப்பின் இறுதிக்கட்டத்தில் தொழில்நுட்பக் கோளாறு ஏற்பட்டதாக தகவல் அனுப்பியிருந்ததாக கூறப்படுகிறது. இதையடுத்து தொடர்பு துண்டிக்கப்பட்ட நிலையில், விமானம் ரேடார் கண்காணிப்பிலிருந்தும் மறைந்தது.\r\nவிபத்திற்கான காரணத்தை உறுதிப்படுத்த, விமானத்தின் கருப்புப் பெட்டி (Black Box) மற்றும் கூடுதல் சிதைவுப் பகுதிகளை மீட்கும் பணிகள் தொடர்ந்து நடைபெற்று வருகின்றன. சம்பவம் தொடர்பாக விமானப் பாதுகாப்பு அதிகாரிகள் விரிவான விசாரணையைத் தொடங்கியுள்ளனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f4458af9891.91066955.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 12:19:49', 0, 1, 0, 0, 0, 'அரபிக்கடலில் மாயமான சரக்கு விமானம்: பலுசிஸ்தான் கடற்கரையில் சிதைந்த பாகங்கள் மீட்பு...', 'அரபிக்கடலில் மாயமான தனியார் சரக்கு விமானத்தின் சிதைந்த பாகங்கள் பலுசிஸ்தான் கடற்கரைக்கு அருகிலுள்ள கடற்பகுதியில் மீட்கப்பட்டுள்ளன. விமானம் காணாமல் போனதைத் தொடர்', 11, 0, 0, 1, '2026-07-09 06:49:49', '2026-07-12 22:28:17', NULL, 0),
(230, 4, NULL, 1, NULL, NULL, NULL, 78, 'தூத்துக்குடி அனல்மின் நிலையத்தில் தீ விபத்து:', 'தூத்துக்குடி-அனல்மின்-நிலையத்தில்-தீ-விபத்து', 'தூத்துக்குடி அனல்மின் நிலைய வளாகத்தில் ஏற்பட்ட திடீர் தீ விபத்தில், சுமார் ரூ.3 கோடி மதிப்பிலான நிலக்கரி எரிந்து சேதமடைந்ததாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nநிலக…', 'தூத்துக்குடி அனல்மின் நிலைய வளாகத்தில் ஏற்பட்ட திடீர் தீ விபத்தில், சுமார் ரூ.3 கோடி மதிப்பிலான நிலக்கரி எரிந்து சேதமடைந்ததாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nநிலக்கரி சேமிப்பு பகுதியில் புகை எழுந்ததை கவனித்த ஊழியர்கள் உடனடியாக தீயணைப்புத் துறைக்கு தகவல் அளித்தனர். சம்பவ இடத்திற்கு விரைந்த தீயணைப்பு வீரர்கள் பல மணி நேரம் போராடி தீயை கட்டுக்குள் கொண்டு வந்தனர்.\r\nஇந்த விபத்தில் உயிரிழப்பு அல்லது காயம் எதுவும் ஏற்படவில்லை என்று முதற்கட்ட தகவல்கள் தெரிவிக்கின்றன. இருப்பினும், அதிகளவு நிலக்கரி எரிந்ததால் பொருளாதார இழப்பு ஏற்பட்டுள்ளதாக கூறப்படுகிறது.\r\nதீ விபத்துக்கான காரணம் குறித்து அதிகாரிகள் விசாரணை மேற்கொண்டு வருகின்றனர். பாதுகாப்பு நடைமுறைகள் மற்றும் சேமிப்பு வசதிகள் தொடர்பாகவும் ஆய்வு நடைபெற்று வருகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f479ad8d113.99506463.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 12:33:12', 0, 1, 0, 0, 0, 'தூத்துக்குடி அனல்மின் நிலையத்தில் தீ விபத்து: ', 'தூத்துக்குடி அனல்மின் நிலைய வளாகத்தில் ஏற்பட்ட திடீர் தீ விபத்தில், சுமார் ரூ.3 கோடி மதிப்பிலான நிலக்கரி எரிந்து சேதமடைந்ததாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nநிலக', 8, 0, 0, 1, '2026-07-09 07:03:12', '2026-07-12 17:05:48', NULL, 0),
(231, 4, NULL, 2, NULL, NULL, NULL, 79, 'வயநாடு நிலச்சரிவு: மேலும் ஒரு சடலம் மீட்பு', 'வயநாடு-நிலச்சரிவு-மேலும்-ஒரு-சடலம்-மீட்பு', 'கேரளாவின் வயநாடு மாவட்டத்தில் கனமழையால் ஏற்பட்ட நிலச்சரிவு சம்பவத்தில் மீட்புப் பணிகள் தொடர்ந்து நடைபெற்று வருகின்றன. இந்நிலையில், இடிபாடுகளுக்குள் சிக்கியிருந்…', 'கேரளாவின் வயநாடு மாவட்டத்தில் கனமழையால் ஏற்பட்ட நிலச்சரிவு சம்பவத்தில் மீட்புப் பணிகள் தொடர்ந்து நடைபெற்று வருகின்றன. இந்நிலையில், இடிபாடுகளுக்குள் சிக்கியிருந்த மேலும் ஒருவரின் உடல் மீட்கப்பட்டுள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nஇதன் மூலம் இந்த நிலச்சரிவு சம்பவத்தில் உயிரிழந்தவர்களின் எண்ணிக்கை 5 ஆக உயர்ந்துள்ளது. மேலும் சிலர் காணாமல் போயிருப்பதாக கூறப்படுவதால், அவர்களைத் தேடும் பணியில் பேரிடர் மீட்புப் படையினர், தீயணைப்புத் துறையினர் மற்றும் காவல்துறையினர் தீவிரமாக ஈடுபட்டுள்ளனர்.\r\nதொடர்ந்து பெய்து வரும் கனமழை காரணமாக மீட்புப் பணிகளில் சிரமம் ஏற்பட்டுள்ள நிலையில், பாதிப்பு அதிகம் உள்ள பகுதிகளில் வசிக்கும் மக்களுக்கு பாதுகாப்பு முன்னெச்சரிக்கை அறிவுறுத்தப்பட்டுள்ளது.\r\nமழை நீடிக்கும் வாய்ப்பு இருப்பதாக வானிலை மையம் எச்சரித்துள்ளதால், மலைப்பகுதிகளுக்கு தேவையற்ற பயணங்களைத் தவிர்க்குமாறு அதிகாரிகள் பொதுமக்களிடம் கேட்டுக் கொண்டுள்ளனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f4ba2287416.68774044.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 12:50:30', 0, 1, 0, 0, 0, 'வயநாடு நிலச்சரிவு: மேலும் ஒரு சடலம் மீட்பு', 'கேரளாவின் வயநாடு மாவட்டத்தில் கனமழையால் ஏற்பட்ட நிலச்சரிவு சம்பவத்தில் மீட்புப் பணிகள் தொடர்ந்து நடைபெற்று வருகின்றன. இந்நிலையில், இடிபாடுகளுக்குள் சிக்கியிருந்', 19, 0, 0, 1, '2026-07-09 07:20:30', '2026-07-14 05:11:48', NULL, 0),
(232, 4, NULL, 1, NULL, NULL, NULL, 80, 'ஓய்வூதியர்களுக்கான புதிய காப்பீடு திட்ட குறைகளை நீக்கி திருத்தப்பட்ட அரசாணை வெளியிடவேண்டும் - வேல்முருகன்...', 'ஓய்வூதியர்களுக்கான-புதிய-காப்பீடு-திட்ட-குறைகளை-நீக்கி-திருத்தப்பட்ட-அரசாணை-வெளியிடவேண்டும்-வேல்முருகன்', 'சென்னை: ஓய்வூதியர்களுக்காக அமல்படுத்தப்பட்டுள்ள புதிய மருத்துவக் காப்பீட்டு திட்டத்தில் உள்ள குறைபாடுகளை நீக்கி, திருத்தப்பட்ட அரசாணையை தமிழக அரசு உடனடியாக வெளி…', 'சென்னை: ஓய்வூதியர்களுக்காக அமல்படுத்தப்பட்டுள்ள புதிய மருத்துவக் காப்பீட்டு திட்டத்தில் உள்ள குறைபாடுகளை நீக்கி, திருத்தப்பட்ட அரசாணையை தமிழக அரசு உடனடியாக வெளியிட வேண்டும் என்று தமிழக வாழ்வுரிமைக் கட்சி தலைவர் வேல்முருகன் வலியுறுத்தியுள்ளார்.\r\nஅவர் வெளியிட்டுள்ள அறிக்கையில், புதிய காப்பீட்டு திட்டத்தில் பல சிகிச்சைகளுக்கான \'பேக்கேஜ்\' தொகைகள் போதுமான அளவில் நிர்ணயிக்கப்படவில்லை என்றும், இதனால் ஓய்வூதியர்கள் தரமான சிகிச்சையை பெறுவதில் சிக்கல்கள் உருவாகும் அபாயம் இருப்பதாகவும் தெரிவித்துள்ளார். \r\nமேலும், கண்புரை, ஆஞ்சியோபிளாஸ்டி உள்ளிட்ட முக்கிய சிகிச்சைகளுக்கான நிதி ஒதுக்கீடு குறைவாக இருப்பதாகவும், மருத்துவமனைகளில் சிகிச்சை பெறும் ஓய்வூதியர்களுக்கு இது கூடுதல் சுமையை ஏற்படுத்தக்கூடும் என்றும் அவர் குறிப்பிட்டுள்ளார். \r\nஎனவே, ஓய்வூதியர் சங்கங்கள் முன்வைத்துள்ள கோரிக்கைகளை அரசு பரிசீலித்து, திட்டத்தின் குறைகளை நீக்கி, தெளிவான விதிமுறைகளுடன் திருத்தப்பட்ட அரசாணையை விரைவில் வெளியிட வேண்டும் என்று வேல்முருகன் அரசை கேட்டுக்கொண்டுள்ளார்.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f4e7bc592d6.90792878.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 13:02:50', 0, 1, 0, 0, 0, 'ஓய்வூதியர்களுக்கான புதிய காப்பீடு திட்ட குறைகளை நீக்கி திருத்தப்பட்ட அரசாணை வெளியிடவேண்டும் - வேல்முருகன்...    ', 'சென்னை: ஓய்வூதியர்களுக்காக அமல்படுத்தப்பட்டுள்ள புதிய மருத்துவக் காப்பீட்டு திட்டத்தில் உள்ள குறைபாடுகளை நீக்கி, திருத்தப்பட்ட அரசாணையை தமிழக அரசு உடனடியாக வெளி', 26, 0, 0, 1, '2026-07-09 07:32:50', '2026-07-14 00:24:10', NULL, 0),
(233, 4, NULL, 1, NULL, NULL, NULL, 81, 'குலசேகரன்பட்டினம் ராக்கெட் ஏவுதளம் அடுத்த ஆண்டு மார்ச் மாதத்துக்குள் தயாராகும்: இஸ்ரோ தகவல்', 'குலசேகரன்பட்டினம்-ராக்கெட்-ஏவுதளம்-அடுத்த-ஆண்டு-மார்ச்-மாதத்துக்குள்-தயாராகும்-இஸ்ரோ-தகவல்', 'தூத்துக்குடி மாவட்டம் குலசேகரன்பட்டினத்தில் அமைக்கப்பட்டு வரும் இந்தியாவின் இரண்டாவது ராக்கெட் ஏவுதளப் பணிகள் வேகமாக நடைபெற்று வருகின்றன. இந்த ஏவுதளம் அடுத்த ஆண…', 'தூத்துக்குடி மாவட்டம் குலசேகரன்பட்டினத்தில் அமைக்கப்பட்டு வரும் இந்தியாவின் இரண்டாவது ராக்கெட் ஏவுதளப் பணிகள் வேகமாக நடைபெற்று வருகின்றன. இந்த ஏவுதளம் அடுத்த ஆண்டு மார்ச் மாதத்திற்குள் முழுமையாகத் தயாராகும் என இந்திய விண்வெளி ஆய்வு நிறுவனம் (இஸ்ரோ) தெரிவித்துள்ளது.\r\nதற்போது ஒருங்கிணைப்பு கட்டிடம், ஏவுதள சேவை மையம், தரைவழிச் சோதனை வசதிகள் மற்றும் சிறிய செயற்கைக்கோள் ஏவுதலுக்கான தேவையான உள்கட்டமைப்பு பணிகள் நடைபெற்று வருகின்றன. இத்தளத்தில் இருந்து முதற்கட்டமாக சிறிய ரக ராக்கெட்டுகளை ஏவுவதற்கான திட்டங்கள் முன்னெடுக்கப்பட்டுள்ளன.\r\nஇந்த புதிய ஏவுதளம் செயல்பாட்டுக்கு வந்தால்,சிறிய செயற்கைக்கோள்களை விரைவாகவும் குறைந்த செலவிலும் விண்ணில் செலுத்த இந்தியாவுக்கு கூடுதல் திறன் கிடைக்கும். மேலும், உலகளாவிய வணிக ரீதியிலான விண்வெளி சேவைகளில் இந்தியாவின் போட்டித்திறனையும் இது அதிகரிக்கும் என்று இஸ்ரோ அதிகாரிகள் நம்பிக்கை தெரிவித்துள்ளனர்\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f7728abcdd5.08390010.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 15:56:06', 0, 1, 0, 0, 0, 'குலசேகரன்பட்டினம் ராக்கெட் ஏவுதளம் அடுத்த ஆண்டு மார்ச் மாதத்துக்குள் தயாராகும்: இஸ்ரோ தகவல் ', 'தூத்துக்குடி மாவட்டம் குலசேகரன்பட்டினத்தில் அமைக்கப்பட்டு வரும் இந்தியாவின் இரண்டாவது ராக்கெட் ஏவுதளப் பணிகள் வேகமாக நடைபெற்று வருகின்றன. இந்த ஏவுதளம் அடுத்த ஆண', 14, 0, 0, 1, '2026-07-09 10:26:06', '2026-07-12 15:35:59', NULL, 0),
(234, 4, NULL, 1, NULL, NULL, NULL, 82, 'விக்ரம் சோலார் நிறுவனத்துடன் புரிந்துணர்வு ஒப்பந்தம்...', 'விக்ரம்-சோலார்-நிறுவனத்துடன்-புரிந்துணர்வு-ஒப்பந்தம்', ' விக்ரம் சோலாருடன் தமிழக அரசு ஒப்பந்தம் முதல்-அமைச்சர் ஜோசப் விஜய் முன்னிலையில் விக்ரம் சோலார் நிறுவனத்தின் உற்பத்தி ஆலைக்கான புரிந்துணர்வு ஒப்பந்தம் மேற்கொள்ளப…', ' விக்ரம் சோலாருடன் தமிழக அரசு ஒப்பந்தம் முதல்-அமைச்சர் ஜோசப் விஜய் முன்னிலையில் விக்ரம் சோலார் நிறுவனத்தின் உற்பத்தி ஆலைக்கான புரிந்துணர்வு ஒப்பந்தம் மேற்கொள்ளப்பட்டது.... \r\nதமிழகத்தில் புதுப்பிக்கத்தக்க எரிசக்தித் துறையை மேலும் வலுப்படுத்தும் நோக்கில், விக்ரம் சோலார் நிறுவனத்துடன் மாநில அரசு புரிந்துணர்வு ஒப்பந்தத்தில் கையெழுத்திட்டுள்ளது.\r\nஇந்த ஒப்பந்தத்தின் மூலம் சுமார் **ரூ.15,000 கோடி** முதலீடு மேற்கொள்ளப்பட உள்ளது. இதன் மூலம் **2,670 பேருக்கு நேரடி வேலைவாய்ப்புகள்** உருவாகும் என எதிர்பார்க்கப்படுகிறது.\r\nஇந்த முதலீட்டின் மூலம் சோலார் உற்பத்தி மற்றும் அதனுடன் தொடர்புடைய தொழில்நுட்ப வசதிகள் விரிவுபடுத்தப்பட உள்ளன. மாநிலத்தில் பசுமை ஆற்றல் உற்பத்தியை அதிகரிப்பதோடு, தொழில் வளர்ச்சி மற்றும் வேலைவாய்ப்புகளையும் ஊக்குவிக்கும் முக்கிய திட்டமாக இது பார்க்கப்படுகிறது.\r\nவிக்ரம் சோலார் நிறுவனம் இந்தியாவின் முன்னணி சூரிய மின்சக்தி உபகரண உற்பத்தியாளர்களில் ஒன்றாகும். புதிய முதலீடு தமிழகத்தை சோலார் உற்பத்திக்கான முக்கிய மையமாக மாற்றும் முயற்சிக்கு மேலும் வலுசேர்க்கும் என தொழில்துறை வட்டாரங்கள் தெரிவித்துள்ளன. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f7a4f65ba36.70856393.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 16:09:56', 0, 1, 0, 0, 0, 'விக்ரம் சோலார் நிறுவனத்துடன் புரிந்துணர்வு ஒப்பந்தம்...    ', ' விக்ரம் சோலாருடன் தமிழக அரசு ஒப்பந்தம் முதல்-அமைச்சர் ஜோசப் விஜய் முன்னிலையில் விக்ரம் சோலார் நிறுவனத்தின் உற்பத்தி ஆலைக்கான புரிந்துணர்வு ஒப்பந்தம் மேற்கொள்ளப', 10, 0, 0, 1, '2026-07-09 10:39:56', '2026-07-13 02:03:20', NULL, 0),
(235, 4, NULL, 3, NULL, NULL, NULL, 83, 'அமெரிக்காவின் 2 நாள் தாக்குதல்களில் 14 பேர் பலி: ஈரான்...', 'அமெரிக்காவின்-2-நாள்-தாக்குதல்களில்-14-பேர்-பலி-ஈரான்', 'அமெரிக்கா மேற்கொண்டதாகக் கூறப்படும் இரு நாள் தாக்குதல்களில் **14 பேர் உயிரிழந்துள்ளதாக** ஈரான் அதிகாரப்பூர்வமாக தெரிவித்துள்ளது.\r\nஇந்த தாக்குதல்களில் பலர் காயமட…', 'அமெரிக்கா மேற்கொண்டதாகக் கூறப்படும் இரு நாள் தாக்குதல்களில் **14 பேர் உயிரிழந்துள்ளதாக** ஈரான் அதிகாரப்பூர்வமாக தெரிவித்துள்ளது.\r\nஇந்த தாக்குதல்களில் பலர் காயமடைந்துள்ளதாகவும், பாதிக்கப்பட்ட பகுதிகளில் மீட்பு மற்றும் நிவாரணப் பணிகள் தொடர்ந்து நடைபெற்று வருவதாகவும் அதிகாரிகள் கூறினர்.\r\nதாக்குதலால் சேதமடைந்த கட்டிடங்கள் மற்றும் முக்கிய கட்டமைப்புகள் குறித்து ஆய்வு மேற்கொள்ளப்பட்டு வருகிறது. உயிரிழந்தோரின் விவரங்களை உறுதிப்படுத்தும் பணிகளும் நடைபெற்று வருகின்றன.\r\nஇந்த சம்பவம் மத்திய கிழக்கு பிராந்தியத்தில் பதற்றத்தை மேலும் அதிகரித்துள்ள நிலையில், நிலைமையை உலக நாடுகள் உன்னிப்பாக கவனித்து வருகின்றன. பதற்றத்தை தணிக்கும் வகையில் அனைத்து தரப்பினரும் கட்டுப்பாட்டுடன் செயல்பட வேண்டும் என்று சர்வதேச அளவில் வலியுறுத்தப்பட்டு வருகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4f7cc526d637.01850256.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 16:20:25', 0, 1, 0, 0, 0, 'அமெரிக்காவின் 2 நாள் தாக்குதல்களில் 14 பேர் பலி: ஈரான்...    ', 'அமெரிக்கா மேற்கொண்டதாகக் கூறப்படும் இரு நாள் தாக்குதல்களில் **14 பேர் உயிரிழந்துள்ளதாக** ஈரான் அதிகாரப்பூர்வமாக தெரிவித்துள்ளது.\r\nஇந்த தாக்குதல்களில் பலர் காயமட', 13, 0, 0, 1, '2026-07-09 10:50:25', '2026-07-14 03:37:55', NULL, 0),
