(237, 5, NULL, 1, NULL, NULL, NULL, NULL, 'அமெரிக்கா ஈரான் மீதி குண்டு மழை', 'அமெரிக்கா-ஈரான்-மீதி-குண்டு-மழை', 'புரிந்துணர்வு ஒப்பந்தம் செய்து எந்த பலனமில்லை ஈரான் அமெரிக்கா கப்பல் மீது குண்டு மழை பொழிந்தது அதற்கு பதிலடியாக அமெரிக்கா ஈரான் பல நகரங்களை குறிவைத்து தொடர்ந்து…', 'புரிந்துணர்வு ஒப்பந்தம் செய்து எந்த பலனமில்லை ஈரான் அமெரிக்கா கப்பல் மீது குண்டு மழை பொழிந்தது அதற்கு பதிலடியாக அமெரிக்கா ஈரான் பல நகரங்களை குறிவைத்து தொடர்ந்து கொண்டு மழை பொழிகிறது இதனால் கச்சா எண்ணெய் கேஸ் எரிவாயு உயரும் நிலை உள்ளது இந்தியாவின் பங்குச்சந்தை வெகுவாக கீழ்நோக்கி குறைந்தது', 'news', NULL, 'ta', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 19:00:42', 0, 0, 0, 0, 0, 'அமெரிக்கா ஈரான் மீதி குண்டு மழை', 'புரிந்துணர்வு ஒப்பந்தம் செய்து எந்த பலனமில்லை ஈரான் அமெரிக்கா கப்பல் மீது குண்டு மழை பொழிந்தது அதற்கு பதிலடியாக அமெரிக்கா ஈரான் பல நகரங்களை குறிவைத்து தொடர்ந்து', 11, 0, 0, 1, '2026-07-09 13:30:42', '2026-07-12 12:05:45', NULL, 0),
(238, 5, NULL, 1, NULL, NULL, NULL, 85, 'பொள்ளாச்சியில் சிறுவன் அடித்துக் கொலை', 'பொள்ளாச்சியில்-சிறுவன்-அடித்துக்-கொலை', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் கொலை செய்யப்பட்ட வழக்கில், ஐந்து சிறார்க…', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் கொலை செய்யப்பட்ட வழக்கில், ஐந்து சிறார்களை பிடித்து காவல்துறையினர் தீவிர விசாரணை நடத்தி வருகின்றனர்.\r\nஉயிரிழந்த பூவரசன், பெண் ஒருவருடன் திருமணத்தை மீறிய உறவில் இருந்ததாகக் கூறப்படுகிறது. அந்தப் பெண்ணின் இரு மகன்களும், தங்களது Free Fire கேம் குழு நண்பர்களை அழைத்து வந்து பூவரசனை தாக்கியதாக தகவல் வெளியாகியுள்ளது.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4fa52b883795.69405719.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 19:32:34', 0, 0, 0, 0, 0, 'பொள்ளாச்சியில் சிறுவன் அடித்துக் கொலை ', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் கொலை செய்யப்பட்ட வழக்கில், ஐந்து சிறார்க', 20, 0, 0, 1, '2026-07-09 13:42:24', '2026-07-13 07:44:53', NULL, 0),
(239, 5, NULL, 1, NULL, NULL, NULL, NULL, 'பொள்ளாச்சியில் சிறுவன் அடித்துக் கொலை', 'பொள்ளாச்சியில்-சிறுவன்-அடித்துக்-கொலை-1', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் கொலை செய்யப்பட்ட வழக்கில், ஐந்து சிறார்க…', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் கொலை செய்யப்பட்ட வழக்கில், ஐந்து சிறார்களை பிடித்து காவல்துறையினர் தீவிர விசாரணை நடத்தி வருகின்றனர்.\r\nஉயிரிழந்த பூவரசன், பெண் ஒருவருடன் திருமணத்தை மீறிய உறவில் இருந்ததாகக் கூறப்படுகிறது. அந்தப் பெண்ணின் இரு மகன்களும், தங்களது Free Fire கேம் குழு நண்பர்களை அழைத்து வந்து பூவரசனை தாக்கியதாக தகவல் வெளியாகியுள்ளது.', 'news', NULL, 'ta', NULL, NULL, NULL, NULL, NULL, NULL, NULL, 'draft', 'reporter', NULL, NULL, NULL, NULL, NULL, 0, 0, 0, 0, 0, 'பொள்ளாச்சியில் சிறுவன் அடித்துக் கொலை ', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் கொலை செய்யப்பட்ட வழக்கில், ஐந்து சிறார்களை பிடித்து காவல்துறையினர் தீவிர விசாரணை நடத்தி வருகின்றனர்.\r\nஉயிரிழந்த பூவரசன், பெண் ஒருவருடன் திருமணத்தை மீறிய உறவில் இருந்ததாகக் கூறப்படுகிறது. அந்தப் பெண்ணின் இரு மகன்களும், தங்களது Free Fire கேம் குழு நண்பர்களை அழைத்து வந்து பூவரசனை தாக்கியதாக தகவல் வெளியாகியுள்ளது.', 0, 0, 0, 1, '2026-07-09 13:59:21', '2026-07-09 13:59:21', NULL, 0),
(240, 5, NULL, 1, NULL, NULL, NULL, 88, 'பாகப்பிரிவால் கோவில் திருவிளக்கு பூஜை', 'பாகப்பிரியாள் திருகோவில்-திருவிளக்கு-பூஜை', '🌺 திருவெற்றியூர் பாகம்பிரியாள் அம்மன் – பக்தர்களின் சொத்துகளைக் கூட காக்கும் தாயுள்ளம் கொண்ட தெய்வம்! 🌺\r\n\r\nதமிழகத்தின் தென் மாவட்டங்களில் எண்ணற்ற கிராமத் தெய்வங்கள் பக்தர்களின் வாழ்வோடு கலந்திருக்கின்றன.\r\n\r\nஅவற்றில் சில தெய்வங்கள் நோய்களை தீர்க்கும் அருளால் புகழ்பெறுகின்றன…\r\n\r\nசில தெய்வங்கள் திருமண பாக்கியம் அருளும் சக்தியால் போற்றப்படுகின்றன…\r\n\r\nசில தெய்வங்கள் குழந்தை பாக்கியம் வழங்கும் தாயாக வணங்கப்படுகின்றன…\r\n\r\nஆனால்…\r\n\r\nபக்தர்களின் உயிரையும், உடமைகளையும், நம்பிக்கையையும் காத்து நிற்கும் தெய்வமாக விளங்கும் அருள்மிகு பாகம்பிரியாள் அம்மன் தனித்துவமான இடத்தைப் பெற்றுள்ளார்.\r\n\r\nராமநாதபுரம் மாவட்டம், திருவாடானை அருகே அமைந்துள்ள திருவெற்றியூர் என்னும் புனிதத் தலத்தில் அருள்பாலிக்கும் பாகம்பிரியாள் அம்மன், தாயின் கருணையும் காவல் தெய்வத்தின் கடுமையும் ஒன்றாக கலந்த சக்தியாக பக்தர்களால் போற்றப்படுகிறார்.\r\n\r\nஇங்கு அம்மனை மனமார வேண்டினால் நோய்கள் நீங்கும்…\r\n\r\nதிருமணத் தடைகள் விலகும்…\r\n\r\nகுழந்தை பாக்கியம் கிட்டும்…\r\n\r\nமேலும் பக்தர்களின் உடமைகளைக் கூட அம்மன் காத்தருளுவாள் என்ற அசைக்க முடியாத நம்பிக்கை இன்றும் நிலவுகிறது.\r\n\r\n━━━━━━━━━━━━━━━\r\n\r\n🌺 தாயுள்ளம் கொண்ட பாகம்பிரியாள்\r\n\r\nஇத்தலத்தில் அருள்பாலிக்கும் அம்பாள் “பாகம்பிரியாள்” என்று அழைக்கப்படுகிறார்.\r\n\r\n“பாகம் பிரியாதவள்” என்பதே இந்தத் திருநாமத்தின் பொருள்.\r\n\r\nஅதாவது…\r\n\r\nகணவன்–மனைவி பிரியாமல் இருக்க…\r\n\r\nகுடும்ப உறவுகள் சிதையாமல் இருக்க…\r\n\r\nஅன்பும் ஒற்றுமையும் நிலைத்திருக்க…\r\n\r\nஅம்மன் அருள்புரிவாள் என்ற நம்பிக்கை மக்களிடையே பரவலாக உள்ளது.\r\n\r\nஇத்தலத்தின் மூலவராக அருள்பாலிப்பவர் பழம்புத்திரநாதர் (வால்மீகநாதர்) சிவபெருமான்.\r\n\r\nஅவருடன் பாகம்பிரியாள் அம்மன் எழுந்தருளியுள்ளார்.\r\n\r\nசிவனும் சக்தியும் ஒன்றாய் அருள்பாலிக்கும் இந்தத் திருத்தலம் பக்தர்களுக்கு மிகுந்த ஆன்மீக அமைதியை அளிக்கிறது.\r\n\r\n━━━━━━━━━━━━━━━\r\n\r\n🌺 மருத்துவத்திற்கே சவால் விடுக்கும் அருள்\r\n\r\nபக்தர்கள் மத்தியில் மிகவும் பிரபலமான நம்பிக்கை ஒன்று உள்ளது.\r\n\r\nமருத்துவ சிகிச்சையால் குணமாகாத சில நோய்களும்…\r\n\r\nநீண்ட கால தோல் நோய்களும்…\r\n\r\nவிஷக்கடிகளால் ஏற்பட்ட பாதிப்புகளும்…\r\n\r\nஅம்மனின் அருளாலும், தீர்த்தத்தாலும் நீங்கும் என்பது அந்த நம்பிக்கை.\r\n\r\nஇதன் காரணமாகவே இங்குள்ள அம்பாளை\r\n\r\n🌿 “மருத்துவச்சி அம்மன்” 🌿\r\n\r\nஎன்று அன்போடு அழைக்கின்றனர', '🌺 திருவெற்றியூர் பாகம்பிரியாள் அம்மன் – பக்தர்களின் சொத்துகளைக் கூட காக்கும் தாயுள்ளம் கொண்ட தெய்வம்! 🌺\r\n\r\nதமிழகத்தின் தென் மாவட்டங்களில் எண்ணற்ற கிராமத் தெய்வங்கள் பக்தர்களின் வாழ்வோடு கலந்திருக்கின்றன.\r\n\r\nஅவற்றில் சில தெய்வங்கள் நோய்களை தீர்க்கும் அருளால் புகழ்பெறுகின்றன…\r\n\r\nசில தெய்வங்கள் திருமண பாக்கியம் அருளும் சக்தியால் போற்றப்படுகின்றன…\r\n\r\nசில தெய்வங்கள் குழந்தை பாக்கியம் வழங்கும் தாயாக வணங்கப்படுகின்றன…\r\n\r\nஆனால்…\r\n\r\nபக்தர்களின் உயிரையும், உடமைகளையும், நம்பிக்கையையும் காத்து நிற்கும் தெய்வமாக விளங்கும் அருள்மிகு பாகம்பிரியாள் அம்மன் தனித்துவமான இடத்தைப் பெற்றுள்ளார்.\r\n\r\nராமநாதபுரம் மாவட்டம், திருவாடானை அருகே அமைந்துள்ள திருவெற்றியூர் என்னும் புனிதத் தலத்தில் அருள்பாலிக்கும் பாகம்பிரியாள் அம்மன், தாயின் கருணையும் காவல் தெய்வத்தின் கடுமையும் ஒன்றாக கலந்த சக்தியாக பக்தர்களால் போற்றப்படுகிறார்.\r\n\r\nஇங்கு அம்மனை மனமார வேண்டினால் நோய்கள் நீங்கும்…\r\n\r\nதிருமணத் தடைகள் விலகும்…\r\n\r\nகுழந்தை பாக்கியம் கிட்டும்…\r\n\r\nமேலும் பக்தர்களின் உடமைகளைக் கூட அம்மன் காத்தருளுவாள் என்ற அசைக்க முடியாத நம்பிக்கை இன்றும் நிலவுகிறது.\r\n\r\n━━━━━━━━━━━━━━━\r\n\r\n🌺 தாயுள்ளம் கொண்ட பாகம்பிரியாள்\r\n\r\nஇத்தலத்தில் அருள்பாலிக்கும் அம்பாள் “பாகம்பிரியாள்” என்று அழைக்கப்படுகிறார்.\r\n\r\n“பாகம் பிரியாதவள்” என்பதே இந்தத் திருநாமத்தின் பொருள்.\r\n\r\nஅதாவது…\r\n\r\nகணவன்–மனைவி பிரியாமல் இருக்க…\r\n\r\nகுடும்ப உறவுகள் சிதையாமல் இருக்க…\r\n\r\nஅன்பும் ஒற்றுமையும் நிலைத்திருக்க…\r\n\r\nஅம்மன் அருள்புரிவாள் என்ற நம்பிக்கை மக்களிடையே பரவலாக உள்ளது.\r\n\r\nஇத்தலத்தின் மூலவராக அருள்பாலிப்பவர் பழம்புத்திரநாதர் (வால்மீகநாதர்) சிவபெருமான்.\r\n\r\nஅவருடன் பாகம்பிரியாள் அம்மன் எழுந்தருளியுள்ளார்.\r\n\r\nசிவனும் சக்தியும் ஒன்றாய் அருள்பாலிக்கும் இந்தத் திருத்தலம் பக்தர்களுக்கு மிகுந்த ஆன்மீக அமைதியை அளிக்கிறது.\r\n\r\n━━━━━━━━━━━━━━━\r\n\r\n🌺 மருத்துவத்திற்கே சவால் விடுக்கும் அருள்\r\n\r\nபக்தர்கள் மத்தியில் மிகவும் பிரபலமான நம்பிக்கை ஒன்று உள்ளது.\r\n\r\nமருத்துவ சிகிச்சையால் குணமாகாத சில நோய்களும்…\r\n\r\nநீண்ட கால தோல் நோய்களும்…\r\n\r\nவிஷக்கடிகளால் ஏற்பட்ட பாதிப்புகளும்…\r\n\r\nஅம்மனின் அருளாலும், தீர்த்தத்தாலும் நீங்கும் என்பது அந்த நம்பிக்கை.\r\n\r\nஇதன் காரணமாகவே இங்குள்ள அம்பாளை\r\n\r\n🌿 “மருத்துவச்சி அம்மன்” 🌿\r\n\r\nஎன்று அன்போடு அழைக்கின்றனர', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a4faeac7c1af9.40695597.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-09 19:52:21', 0, 0, 0, 0, 0, 'பாகப்பிரிவால் கோவில் திருவிளக்கு பூஜை ', '🌺 திருவெற்றியூர் பாகம்பிரியாள் அம்மன் – பக்தர்களின் சொத்துகளைக் கூட காக்கும் தாயுள்ளம் கொண்ட தெய்வம்! 🌺\r\n\r\nதமிழகத்தின் தென் மாவட்டங்களில் எண்ணற்ற கிராமத் தெய்வங', 21, 0, 0, 1, '2026-07-09 14:22:21', '2026-07-13 12:28:50', NULL, 0),
(241, 4, NULL, 2, NULL, NULL, NULL, 89, 'செயற்கை கருத்தரிப்பு சிகிச்சை மையங்களுக்கு புதிய கட்டுப்பாடுகள்', 'செயற்கை-கருத்தரிப்பு-சிகிச்சை-மையங்களுக்கு-புதிய-கட்டுப்பாடுகள்', 'இந்தியாவில் தற்போது 2 ஆயிரத்துக்கும் மேற்பட்ட ஐ.வி.எப். (IVF) மையங்கள் செயல்பட்டு வருகின்றன.  இவற்றில் தேசிய ஆர்ட் மற்றும் வாடகைத்தாய் பதிவகத்தின் தரவுகளின்படி,…', 'இந்தியாவில் தற்போது 2 ஆயிரத்துக்கும் மேற்பட்ட ஐ.வி.எப். (IVF) மையங்கள் செயல்பட்டு வருகின்றன.  இவற்றில் தேசிய ஆர்ட் மற்றும் வாடகைத்தாய் பதிவகத்தின் தரவுகளின்படி, 7,803 மையங்கள் பதிவு செய்ய விண்ணப்பித்துள்ளன. அவற்றில 4,268 மையங்களுக்கு மட்டுமே இதுவரை அனுமதி வழங்கப்பட்டுள்ளது.\r\nசெயற்கை கருத்தரிப்பு (IVF) சிகிச்சை மையங்கள் மற்றும் விந்தணு வங்கிகளின் செயல்பாடுகளை ஒழுங்குபடுத்தும் வகையில் மத்திய அரசு புதிய கட்டுப்பாடுகளை அமல்படுத்தியுள்ளது.\r\nபுதிய விதிகளின்படி, **அங்கீகாரம் பெற்ற மற்றும் பதிவு செய்யப்பட்ட** கருத்தரிப்பு சிகிச்சை மையங்கள் மற்றும் விந்தணு வங்கிகளுக்கு மட்டுமே IVF சிகிச்சைக்கு தேவையான ஆய்வகப் பொருட்கள் மற்றும் மருத்துவப் பயன்பாட்டு உபகரணங்கள் வழங்கப்பட வேண்டும் என்று அறிவுறுத்தப்பட்டுள்ளது.\r\nஇதன் மூலம் பதிவு செய்யப்படாத மையங்கள் அத்தியாவசிய மருத்துவப் பொருட்களை பெற முடியாத நிலை உருவாகும். நோயாளிகளின் பாதுகாப்பை உறுதி செய்தல், சிகிச்சை தரத்தை மேம்படுத்தல் மற்றும் சட்டவிரோத அல்லது தரமற்ற செயல்பாடுகளைத் தடுக்கவே இந்த நடவடிக்கை எடுக்கப்பட்டுள்ளதாக தெரிவிக்கப்பட்டுள்ளது.\r\nமேலும், உதவி இனப்பெருக்கத் தொழில்நுட்ப (ART) சட்டம் மற்றும் வாடகைத் தாய்மை தொடர்பான விதிமுறைகளை அனைத்து மையங்களும் கட்டாயமாக பின்பற்ற வேண்டும் என்றும் மத்திய அரசு வலியுறுத்தியுள்ளது.\r\nஇந்த புதிய கட்டுப்பாடுகள் நாடு முழுவதும் செயற்கை கருத்தரிப்பு சேவைகளில் வெளிப்படைத்தன்மை, தரநிலை மற்றும் பொறுப்புணர்வை அதிகரிக்கும் நடவடிக்கையாக பார்க்கப்படுகின்றன.\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5080b7de0901.52621180.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 10:49:19', 0, 1, 0, 0, 0, 'செயற்கை கருத்தரிப்பு சிகிச்சை மையங்களுக்கு புதிய கட்டுப்பாடுகள் ', 'இந்தியாவில் தற்போது 2 ஆயிரத்துக்கும் மேற்பட்ட ஐ.வி.எப். (IVF) மையங்கள் செயல்பட்டு வருகின்றன.  இவற்றில் தேசிய ஆர்ட் மற்றும் வாடகைத்தாய் பதிவகத்தின் தரவுகளின்படி,', 6, 0, 0, 1, '2026-07-10 05:19:19', '2026-07-12 22:35:52', NULL, 0),
(242, 4, NULL, 1, NULL, NULL, NULL, 92, 'கடத்தப்பட்ட பழமையான 3 சிலைகள் ஆஸ்திரேலியாவில் இருந்து தமிழகம் வருகை ...', 'கடத்தப்பட்ட-பழமையான-3-சிலைகள்-ஆஸ்திரேலியாவில்-இருந்து-தமிழகம்-வருகை', 'தமிழகத்தில் இருந்து பல ஆண்டுகளுக்கு முன்பு கடத்தப்பட்ட பழமையான மூன்று அரிய சிலைகள், ஆஸ்திரேலிய அதிகாரிகளின் ஒத்துழைப்புடன் மீட்கப்பட்டு தமிழகம் கொண்டு வரப்பட்டு…', 'தமிழகத்தில் இருந்து பல ஆண்டுகளுக்கு முன்பு கடத்தப்பட்ட பழமையான மூன்று அரிய சிலைகள், ஆஸ்திரேலிய அதிகாரிகளின் ஒத்துழைப்புடன் மீட்கப்பட்டு தமிழகம் கொண்டு வரப்பட்டுள்ளன.\r\nஇந்தச் சிலைகள், தொல்லியல் மற்றும் கலாச்சார பாரம்பரியத்திற்கு முக்கியத்துவம் வாய்ந்தவை எனக் கூறப்படுகிறது. சிலைகள் வெளிநாட்டிற்கு சட்டவிரோதமாக கடத்தப்பட்டதாக கண்டறியப்பட்டதைத் தொடர்ந்து, இந்திய அரசு மற்றும் ஆஸ்திரேலிய அரசின் ஒருங்கிணைந்த முயற்சியால் அவை மீட்கப்பட்டன.\r\nமீட்கப்பட்ட சிலைகள் உரிய பாதுகாப்புடன் தமிழகத்திற்கு கொண்டு வரப்பட்டுள்ள நிலையில், அவற்றின் வரலாற்றுப் பின்னணி, சொந்த கோவில் மற்றும் காலக்கட்டம் குறித்து தொல்லியல் மற்றும் சிலைக் கடத்தல் தடுப்புப் பிரிவு அதிகாரிகள் ஆய்வு மேற்கொண்டு வருகின்றனர்.\r\nகலாச்சாரச் சொத்துகளை மீட்கும் நடவடிக்கைகளில் இது குறிப்பிடத்தக்க முன்னேற்றமாகக் கருதப்படுவதுடன், வெளிநாடுகளுக்கு கடத்தப்பட்ட தமிழகத்தின் பாரம்பரியச் சின்னங்களை மீட்கும் முயற்சிகள் தொடர்ந்து மேற்கொள்ளப்படும் என அதிகாரிகள் தெரிவித்துள்ளனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50931f930493.52237522.webp', NULL, NULL, NULL, NULL, 'published', 'published', NULL, 4, '2026-07-10 06:36:05', NULL, '2026-07-10 11:05:55', 0, 1, 0, 0, 0, 'கடத்தப்பட்ட பழமையான 3 சிலைகள் ஆஸ்திரேலியாவில் இருந்து தமிழகம் வருகை ...  ', 'தமிழகத்தில் இருந்து பல ஆண்டுகளுக்கு முன்பு கடத்தப்பட்ட பழமையான மூன்று அரிய சிலைகள், ஆஸ்திரேலிய அதிகாரிகளின் ஒத்துழைப்புடன் மீட்கப்பட்டு தமிழகம் கொண்டு வரப்பட்டு', 11, 0, 0, 1, '2026-07-10 05:35:55', '2026-07-14 04:06:44', NULL, 0),
(243, 4, NULL, 1, NULL, NULL, NULL, 93, 'கரூரில் முதல்-அமைச்சர் விஜய்: வழி நெடுகிலும் ஆயிரக்கணக்கானோர் உற்சாக வரவேற்பு...', 'கரூரில்-முதல்-அமைச்சர்-விஜய்-வழி-நெடுகிலும்-ஆயிரக்கணக்கானோர்-உற்சாக-வரவேற்பு', 'கரூரில் நடைபெற்ற மக்கள் சந்திப்பு மற்றும் அரசு நிகழ்ச்சிகளில் பங்கேற்க முதல்-அமைச்சர் விஜய் இன்று திருச்சி வழியாக கரூருக்கு வந்தார். அவரது வருகையையொட்டி, திருச்…', 'கரூரில் நடைபெற்ற மக்கள் சந்திப்பு மற்றும் அரசு நிகழ்ச்சிகளில் பங்கேற்க முதல்-அமைச்சர் விஜய் இன்று திருச்சி வழியாக கரூருக்கு வந்தார். அவரது வருகையையொட்டி, திருச்சி–கரூர் சாலையின் பல்வேறு பகுதிகளில் ஆயிரக்கணக்கான பொதுமக்கள் மற்றும் ஆதரவாளர்கள் திரண்டனர்.\r\n-அமைச்சரின் வாகனம் சென்ற வழியெங்கும் மக்கள் கைகளை அசைத்து வரவேற்பு தெரிவித்ததுடன், பல இடங்களில் மலர்கள் தூவி உற்சாகமாக வரவேற்றனர். இளைஞர்கள், பெண்கள் மற்றும் குடும்பத்தினருடன் வந்த பொதுமக்களும் சாலையோரங்களில் திரண்டு அவரை வரவேற்றனர்.\r\nகரூரில் நடைபெறும் அரசு நிகழ்ச்சிக்காக மாவட்டம் முழுவதும் பாதுகாப்பு ஏற்பாடுகள் தீவிரப்படுத்தப்பட்டன. முக்கிய சாலைகளில் போக்குவரத்து ஒழுங்குபடுத்தப்பட்டதுடன், பாதுகாப்பு பணியிலும் ஏராளமான காவல்துறையினர் ஈடுபடுத்தப்பட்டனர்.\r\nமுதல்-அமைச்சர் விஜய், அரசு நிகழ்ச்சியில் பல்வேறு நலத்திட்டங்களை தொடங்கி வைத்து, பயனாளிகளுக்கு அரசு பணி நியமன ஆணைகள் மற்றும் பிற நலத்திட்ட உதவிகளையும் வழங்க உள்ளதாக அதிகாரப்பூர்வ தகவல்கள் தெரிவிக்கின்றன. மேலும், மக்கள் சந்திப்பு நிகழ்ச்சியிலும் அவர் கலந்து கொண்டு உரையாற்றுகிறார். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a509f132b3323.59227444.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 12:58:38', 0, 1, 0, 0, 0, 'கரூரில் முதல்-அமைச்சர் விஜய்: வழி நெடுகிலும் ஆயிரக்கணக்கானோர் உற்சாக வரவேற்பு... ', 'கரூரில் நடைபெற்ற மக்கள் சந்திப்பு மற்றும் அரசு நிகழ்ச்சிகளில் பங்கேற்க முதல்-அமைச்சர் விஜய் இன்று திருச்சி வழியாக கரூருக்கு வந்தார். அவரது வருகையையொட்டி, திருச்', 8, 0, 0, 1, '2026-07-10 07:28:38', '2026-07-13 17:06:46', NULL, 0),
(244, 4, NULL, 1, NULL, NULL, NULL, 95, 'என் மனதின் ஆறாத காயம் கரூர் சம்பவம்: முதல்-அமைச்சர் விஜய்...', 'என்-மனதின்-ஆறாத-காயம்-கரூர்-சம்பவம்-முதல்-அமைச்சர்-விஜய்', 'கரூரில் நடைபெற்ற அரசு நியமன ஆணை வழங்கும் நிகழ்ச்சியில் பேசிய முதல்-அமைச்சர் விஜய், கடந்த ஆண்டு கரூரில் நிகழ்ந்த கூட்ட நெரிசல் சம்பவம் தனது வாழ்க்கையில் மறக்க மு…', 'கரூரில் நடைபெற்ற அரசு நியமன ஆணை வழங்கும் நிகழ்ச்சியில் பேசிய முதல்-அமைச்சர் விஜய், கடந்த ஆண்டு கரூரில் நிகழ்ந்த கூட்ட நெரிசல் சம்பவம் தனது வாழ்க்கையில் மறக்க முடியாத துயரமாக இருப்பதாகக் கூறினார்.\r\nபேச்சின் போது, உயர்ந்த பதவிக்கு சென்றாலும் சில நிகழ்வுகள் மனதில் ஆழமான காயத்தை ஏற்படுத்தும் என்றும், கரூர் சம்பவம் அத்தகைய மறக்க முடியாத வேதனையாகவே தன்னுள் நிலைத்திருப்பதாகவும் அவர் தெரிவித்தார். அந்த விபத்தில் உயிரிழந்தவர்களை நினைக்கும் போதெல்லாம் மிகுந்த மனவேதனை ஏற்படுவதாக கூறிய அவர், பாதிக்கப்பட்ட குடும்பங்களின் துயரத்தை பகிர்ந்து கொள்வதே அரசின் கடமை என்றும் வலியுறுத்தினார்.\r\nஇந்த நிகழ்ச்சியில், கரூர் கூட்ட நெரிசலில் உயிரிழந்தவர்களின் குடும்பங்களைச் சேர்ந்த 32 பேருக்கு அவர்களின் கல்வித் தகுதிக்கு ஏற்ப அரசு பணி நியமன ஆணைகள் வழங்கப்பட்டன. இந்த நடவடிக்கை, பாதிக்கப்பட்ட குடும்பங்களுக்கு நீண்டகால ஆதரவாக அமையும் என அரசு தரப்பில் தெரிவிக்கப்பட்டது. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50a20fcb3762.24243720.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 13:11:15', 0, 1, 0, 0, 0, 'என் மனதின் ஆறாத காயம் கரூர் சம்பவம்: முதல்-அமைச்சர் விஜய்...    ', 'கரூரில் நடைபெற்ற அரசு நியமன ஆணை வழங்கும் நிகழ்ச்சியில் பேசிய முதல்-அமைச்சர் விஜய், கடந்த ஆண்டு கரூரில் நிகழ்ந்த கூட்ட நெரிசல் சம்பவம் தனது வாழ்க்கையில் மறக்க மு', 19, 0, 0, 1, '2026-07-10 07:41:15', '2026-07-14 05:23:54', NULL, 0),
(245, 4, NULL, 1, NULL, NULL, NULL, 96, 'கோவை மண்ணின் வரலாற்றுச் சாதனை: 1937-ல் உருவான இந்தியாவின் முதல் உள்நாட்டு மின்சார மோட்டார்!...', 'கோவை-மண்ணின்-வரலாற்றுச்-சாதனை-1937-ல்-உருவான-இந்தியாவின்-முதல்-உள்நாட்டு-மின்சார-மோட்டார்', 'இந்திய தொழில்துறை வரலாற்றில் கோவை நகரம் தனித்துவமான இடத்தைப் பெற்றுள்ளது. அந்தப் பெருமைக்கு முக்கிய காரணமாக திகழ்பவர் தொழில்துறை முன்னோடியும் கண்டுபிடிப்பாளருமா…', 'இந்திய தொழில்துறை வரலாற்றில் கோவை நகரம் தனித்துவமான இடத்தைப் பெற்றுள்ளது. அந்தப் பெருமைக்கு முக்கிய காரணமாக திகழ்பவர் தொழில்துறை முன்னோடியும் கண்டுபிடிப்பாளருமான ஜி.டி. நாயுடு.\r\n1937-ஆம் ஆண்டில், கோவையின் பீளமேட்டில் செயல்பட்ட **நேஷனல் எலக்ட்ரிக் வொர்க்ஸ் (NEW)** நிறுவனத்தில், இந்தியாவிலேயே முழுமையாக உள்நாட்டுத் தொழில்நுட்பத்தில் உருவாக்கப்பட்ட முதல் மின்சார மோட்டார் தயாரிக்கப்பட்டது. இந்த முயற்சியில் டி. பாலசுந்தரம் நாயுடுவும் முக்கிய பங்காற்றினார்.\r\nஇந்த கண்டுபிடிப்பு, இந்திய பொறியியல் மற்றும் உற்பத்தித் துறைக்கு புதிய திசையை ஏற்படுத்தியது. பின்னர் கோவையில் வளர்ச்சி பெற்ற இயந்திர உற்பத்தி நிறுவனங்கள், ஜவுளி இயந்திரத் தொழில் மற்றும் கனரக பொறியியல் துறைகளுக்கான அடித்தளமாக இந்த சாதனை அமைந்ததாக வரலாற்றாசிரியர்கள் குறிப்பிடுகின்றனர்.\r\nஇன்று \"தென்னிந்தியாவின் மான்செஸ்டர்\" என்று அழைக்கப்படும் கோவை, மோட்டார், பம்ப், இயந்திரங்கள் மற்றும் ஆட்டோமொபைல் உதிரிபாக உற்பத்தியில் முன்னணி மையமாக திகழ்கிறது. அதன் தொழில்துறை வளர்ச்சியின் முக்கிய மைல்கல்லாக 1937-ல் உருவான இந்தியாவின் முதல் உள்நாட்டு மின்சார மோட்டார் கருதப்படுகிறது. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50a5078d2423.90555074.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 13:23:58', 0, 1, 0, 0, 0, 'கோவை மண்ணின் வரலாற்றுச் சாதனை: 1937-ல் உருவான இந்தியாவின் முதல் உள்நாட்டு மின்சார மோட்டார்!...', 'இந்திய தொழில்துறை வரலாற்றில் கோவை நகரம் தனித்துவமான இடத்தைப் பெற்றுள்ளது. அந்தப் பெருமைக்கு முக்கிய காரணமாக திகழ்பவர் தொழில்துறை முன்னோடியும் கண்டுபிடிப்பாளருமா', 10, 0, 0, 1, '2026-07-10 07:53:58', '2026-07-13 17:01:01', NULL, 0),
(246, 4, NULL, 2, NULL, NULL, NULL, 97, 'கேரளா கோழிக்கோடு ரெயில் நிலையத்தில் மணிக்கூண்டு இடிந்தது', 'கேரளா-கோழிக்கோடு-ரெயில்-நிலையத்தில்-மணிக்கூண்டு-இடிந்தது', 'கேரள மாநிலம் கோழிக்கோடு ரெயில் நிலையத்தில் நூற்றாண்டு பழமையான மணிக்கூண்டு கோபுரம் திடீரென இடிந்து விழுந்ததால் ரெயில் சேவையில் பாதிப்பு ஏற்பட்டது.\r\nநிலையத்தின் ப…', 'கேரள மாநிலம் கோழிக்கோடு ரெயில் நிலையத்தில் நூற்றாண்டு பழமையான மணிக்கூண்டு கோபுரம் திடீரென இடிந்து விழுந்ததால் ரெயில் சேவையில் பாதிப்பு ஏற்பட்டது.\r\nநிலையத்தின் பழைய கட்டிடத்தை சீரமைக்கும் பணிகள் நடைபெற்று வந்த நிலையில், கனமழைக்கு இடையே மணிக்கூண்டு அமைந்திருந்த பகுதி 2-வது நடைமேடையில் சரிந்து விழுந்தது. பாதுகாப்பு முன்னெச்சரிக்கையாக அந்த பகுதி ஏற்கனவே தடுப்புகள் அமைத்து மூடப்பட்டிருந்ததால் உயிரிழப்போ, காயமோ ஏற்படவில்லை. \r\nஇடிபாடுகள் தண்டவாளம் மற்றும் நடைமேடையில் விழுந்ததால் 1, 2, 3-வது தண்டவாளங்களில் ரெயில் இயக்கம் தற்காலிகமாக நிறுத்தப்பட்டது. பின்னர் 4-வது தண்டவாளம் வழியாக மட்டுமே ரெயில்கள் இயக்கப்பட்டதால் பல ரெயில்கள் தாமதமாக இயக்கப்பட்டன. சில ரெயில்களின் புறப்பாடு மற்றும் நிறுத்துமிடங்களிலும் தற்காலிக மாற்றங்கள் செய்யப்பட்டன. \r\nஇடிபாடுகளை அகற்றும் பணியை ரெயில்வே, தீயணைப்புத் துறை மற்றும் மீட்புப் படையினர் இணைந்து மேற்கொண்டனர். சம்பவம் தொடர்பாக அதிகாரிகள் விசாரணை நடத்தி வருகின்றனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50a7254cd5f2.72408562.webp', NULL, NULL, NULL, NULL, 'published', 'published', NULL, 4, '2026-07-10 08:03:38', NULL, '2026-07-10 13:33:14', 0, 1, 0, 0, 0, 'கேரளா கோழிக்கோடு ரெயில் நிலையத்தில் மணிக்கூண்டு இடிந்தது', 'கேரள மாநிலம் கோழிக்கோடு ரெயில் நிலையத்தில் நூற்றாண்டு பழமையான மணிக்கூண்டு கோபுரம் திடீரென இடிந்து விழுந்ததால் ரெயில் சேவையில் பாதிப்பு ஏற்பட்டது.\r\nநிலையத்தின் ப', 12, 0, 0, 1, '2026-07-10 08:03:14', '2026-07-14 06:33:33', NULL, 0),
(247, 4, NULL, 1, NULL, NULL, NULL, 98, 'நெல்லையப்பர் கோவிலில் ஆடிப்பூர திருவிழா தொடங்கியது ...', 'நெல்லையப்பர்-கோவிலில்-ஆடிப்பூர-திருவிழா-தொடங்கியது', 'திருநெல்வேலியில் உள்ள புகழ்பெற்ற நெல்லையப்பர்–காந்திமதி அம்மன் திருக்கோவிலில் ஆண்டுதோறும் நடைபெறும் ஆடிப்பூர திருவிழா கொடியேற்றத்துடன் சிறப்பாக தொடங்கியது. அதிக…', 'திருநெல்வேலியில் உள்ள புகழ்பெற்ற நெல்லையப்பர்–காந்திமதி அம்மன் திருக்கோவிலில் ஆண்டுதோறும் நடைபெறும் ஆடிப்பூர திருவிழா கொடியேற்றத்துடன் சிறப்பாக தொடங்கியது. அதிகாலை நடைபெற்ற சிறப்பு பூஜைகள், யாகசாலை வழிபாடுகள் மற்றும் தீபாராதனையைத் தொடர்ந்து கொடிமரத்தில் விழாக்கொடி ஏற்றப்பட்டது.\r\nதிருவிழாவை முன்னிட்டு காந்திமதி அம்மனுக்கு சிறப்பு அலங்காரம் செய்யப்பட்டு, பக்தர்கள் திரளாக கலந்து கொண்டு தரிசனம் செய்தனர். கோவில் வளாகத்தில் பக்தர்களின் வசதிக்காக தேவையான ஏற்பாடுகளும் செய்யப்பட்டிருந்தன. வரும் நாட்களில் அம்மனுக்கு வளைகாப்பு வைபவம், பல்வேறு வாகனங்களில் வீதி உலா, சிறப்பு அபிஷேகங்கள் மற்றும் ஆன்மிக நிகழ்ச்சிகள் நடைபெற உள்ளன. திருவிழாவின் முக்கிய நிகழ்வுகளில் ஆயிரக்கணக்கான பக்தர்கள் பங்கேற்பார்கள் என கோவில் நிர்வாகம் எதிர்பார்க்கிறது. ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50aa043643d1.97759463.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 13:45:18', 0, 1, 0, 0, 0, 'நெல்லையப்பர் கோவிலில் ஆடிப்பூர திருவிழா தொடங்கியது ...   ', 'திருநெல்வேலியில் உள்ள புகழ்பெற்ற நெல்லையப்பர்–காந்திமதி அம்மன் திருக்கோவிலில் ஆண்டுதோறும் நடைபெறும் ஆடிப்பூர திருவிழா கொடியேற்றத்துடன் சிறப்பாக தொடங்கியது. அதிக', 26, 0, 0, 1, '2026-07-10 08:15:18', '2026-07-12 23:05:50', NULL, 0);
