(248, 4, NULL, 3, NULL, NULL, NULL, 99, '1.750 கிலோ எடையில் பூண்டு அறுவடை செய்து கின்னஸ் உலக சாதனை படைத்த விவசாயி...', '1750-கிலோ-எடையில்-பூண்டு-அறுவடை-செய்து-கின்னஸ்-உலக-சாதனை-படைத்த-விவசாயி', 'விவசாயத்தில் புதிய மைல்கல்லை எட்டிய ஒரு விவசாயி, 1.750 கிலோ எடையுள்ள பிரம்மாண்ட பூண்டை அறுவடை செய்து உலகளவில் கவனம் ஈர்த்துள்ளார். வழக்கமாக சில நூறு கிராம் எடைய…', 'விவசாயத்தில் புதிய மைல்கல்லை எட்டிய ஒரு விவசாயி, 1.750 கிலோ எடையுள்ள பிரம்மாண்ட பூண்டை அறுவடை செய்து உலகளவில் கவனம் ஈர்த்துள்ளார். வழக்கமாக சில நூறு கிராம் எடையில் மட்டுமே வளரும் பூண்டு, இதைவிட பல மடங்கு அதிக எடையில் வளர்ந்தது அனைவரையும் ஆச்சரியப்பட வைத்துள்ளது.\r\nசிறப்பு பராமரிப்பு, வளமான மண், சீரான நீர்ப்பாசனம் மற்றும் துல்லியமான ஊட்டச்சத்து மேலாண்மை ஆகியவற்றின் மூலம் இந்த அபூர்வ விளைச்சல் கிடைத்ததாக தெரிவிக்கப்பட்டுள்ளது. இந்த சாதனை உலக சாதனைப் பட்டியலில் இடம்பெற்று, விவசாயியின் முயற்சிக்கு சர்வதேச அங்கீகாரத்தை பெற்றுத் தந்துள்ளது.\r\nஇந்த சாதனை, நவீன தொழில்நுட்பம் மற்றும் அறிவியல் சார்ந்த சாகுபடி முறைகளை பயன்படுத்தினால் விவசாயத்தில் புதிய உயரங்களை எட்ட முடியும் என்பதை எடுத்துக்காட்டுகிறது. மேலும், உலகம் முழுவதும் உள்ள விவசாயிகளுக்கு இது ஒரு புதிய ஊக்கமாகவும் அமைந்துள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50c54053c968.94423494.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 15:41:22', 0, 1, 0, 0, 0, '1.750 கிலோ எடையில் பூண்டு அறுவடை செய்து கின்னஸ் உலக சாதனை படைத்த விவசாயி...    ', 'விவசாயத்தில் புதிய மைல்கல்லை எட்டிய ஒரு விவசாயி, 1.750 கிலோ எடையுள்ள பிரம்மாண்ட பூண்டை அறுவடை செய்து உலகளவில் கவனம் ஈர்த்துள்ளார். வழக்கமாக சில நூறு கிராம் எடைய', 10, 0, 0, 1, '2026-07-10 10:11:22', '2026-07-13 21:12:00', NULL, 0),
(249, 4, NULL, 2, NULL, NULL, NULL, 100, 'மதுபோதையில் அரசு பஸ்சை கடத்தி சென்ற இளைஞர்...', 'மதுபோதையில்-அரசு-பஸ்சை-கடத்தி-சென்ற-இளைஞர்', 'தெலுங்கானா மாநிலத்தில் மதுபோதையில் இருந்த இளைஞர் ஒருவர் அரசு பேருந்தை அனுமதியின்றி எடுத்துச் சென்று பரபரப்பை ஏற்படுத்தினார்.\r\nஜேசிபி இயந்திர ஆபரேட்டராக பணியாற்ற…', 'தெலுங்கானா மாநிலத்தில் மதுபோதையில் இருந்த இளைஞர் ஒருவர் அரசு பேருந்தை அனுமதியின்றி எடுத்துச் சென்று பரபரப்பை ஏற்படுத்தினார்.\r\nஜேசிபி இயந்திர ஆபரேட்டராக பணியாற்றும் அந்த இளைஞர், பேருந்து நிலையத்தில் நிறுத்தப்பட்டிருந்த அரசு பேருந்தை ஓட்டிச் சென்றதாக கூறப்படுகிறது. சுமார் 21 கிலோமீட்டர் தூரம் சென்ற பிறகு, சுங்கச்சாவடி அருகே பேருந்து கட்டுப்பாட்டை இழந்து மோதியது.\r\nதகவல் அறிந்த போலீசார் உடனடியாக சம்பவ இடத்திற்கு சென்று இளைஞரை கைது செய்தனர். இந்தச் சம்பவத்தில் உயிரிழப்பு எதுவும் ஏற்படவில்லை என்றும், பேருந்துக்கு சேதம் ஏற்பட்டுள்ளதாகவும் தெரிவிக்கப்பட்டுள்ளது.\r\nஇந்த சம்பவம் குறித்து வழக்குப்பதிவு செய்துள்ள போலீசார், மதுபோதையில் அரசு சொத்தை அனுமதியின்றி இயக்கியதற்கான காரணங்கள் குறித்து தொடர்ந்து விசாரணை நடத்தி வருகின்றனர்.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50d583a2bd72.74460511.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 16:50:41', 0, 1, 0, 0, 0, 'மதுபோதையில் அரசு பஸ்சை கடத்தி சென்ற இளைஞர்...    ', 'தெலுங்கானா மாநிலத்தில் மதுபோதையில் இருந்த இளைஞர் ஒருவர் அரசு பேருந்தை அனுமதியின்றி எடுத்துச் சென்று பரபரப்பை ஏற்படுத்தினார்.\r\nஜேசிபி இயந்திர ஆபரேட்டராக பணியாற்ற', 13, 0, 0, 1, '2026-07-10 11:20:41', '2026-07-13 20:48:31', NULL, 0),
(250, 4, NULL, 3, NULL, NULL, NULL, 101, 'டிசம்பரில் நாடு திரும்ப திட்டம்; கோர்ட்டில் சரணடைய தயாராக இருப்பதாக ஹசீனா அறிவிப்பு...', 'டிசம்பரில்-நாடு-திரும்ப-திட்டம்-கோர்ட்டில்-சரணடைய-தயாராக-இருப்பதாக-ஹசீனா-அறிவிப்பு', 'வங்காளதேசத்தின் முன்னாள் பிரதமர் ஷேக் ஹசீனா, வரும் டிசம்பர் மாதத்தில் நாடு திரும்பத் திட்டமிட்டுள்ளதாகவும், நீதிமன்றத்தில் நேரில் ஆஜராகி சட்ட நடைமுறைகளை எதிர்கொ…', 'வங்காளதேசத்தின் முன்னாள் பிரதமர் ஷேக் ஹசீனா, வரும் டிசம்பர் மாதத்தில் நாடு திரும்பத் திட்டமிட்டுள்ளதாகவும், நீதிமன்றத்தில் நேரில் ஆஜராகி சட்ட நடைமுறைகளை எதிர்கொள்ளத் தயாராக இருப்பதாகவும் தகவல் வெளியாகியுள்ளது.\r\nதனக்கு எதிராக பதிவு செய்யப்பட்டுள்ள வழக்குகளில் சட்டப்படி விளக்கம் அளிக்க விருப்பம் இருப்பதாகவும், சட்டத்தின் முன் தன்னுடைய நிலைப்பாட்டை வெளிப்படுத்தத் தயாராக இருப்பதாகவும் அவர் தெரிவித்ததாக கூறப்படுகிறது.\r\nஅதேசமயம், ஹசீனா நாடு திரும்பும் சூழல், பாதுகாப்பு ஏற்பாடுகள் மற்றும் நீதிமன்ற நடவடிக்கைகள் குறித்து வங்காளதேச அரசியல் வட்டாரங்களில் பரபரப்பு நிலவி வருகிறது.\r\nஇந்த விவகாரம் தொடர்பாக அதிகாரப்பூர்வ அறிவிப்புகள் மற்றும் நீதிமன்றத்தின் அடுத்தகட்ட நடவடிக்கைகள் எதிர்பார்க்கப்படுகின்றன.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50d6e5453408.02397419.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 16:56:38', 0, 1, 0, 0, 0, 'டிசம்பரில் நாடு திரும்ப திட்டம்; கோர்ட்டில் சரணடைய தயாராக இருப்பதாக ஹசீனா அறிவிப்பு... ', 'வங்காளதேசத்தின் முன்னாள் பிரதமர் ஷேக் ஹசீனா, வரும் டிசம்பர் மாதத்தில் நாடு திரும்பத் திட்டமிட்டுள்ளதாகவும், நீதிமன்றத்தில் நேரில் ஆஜராகி சட்ட நடைமுறைகளை எதிர்கொ', 13, 0, 0, 1, '2026-07-10 11:26:38', '2026-07-14 05:12:09', NULL, 0),
(251, 4, NULL, 2, NULL, NULL, NULL, 102, 'இந்தியாவை வளர்ந்த நாடாக மாற்றுங்கள்’ - பட்டமளிப்பு விழாவில் மாணவர்களுக்கு இஸ்ரோ தலைவர் ...', 'இந்தியாவை-வளர்ந்த-நாடாக-மாற்றுங்கள்-பட்டமளிப்பு-விழாவில்-மாணவர்களுக்கு-இஸ்ரோ-தலைவர்', 'இந்திய அறிவியல் கழகத்தின் (IISc) பட்டமளிப்பு விழாவில் பங்கேற்ற இஸ்ரோ தலைவர் டாக்டர் வி. நாராயணன், பட்டம் பெறும் மாணவர்கள் சமூகத்திற்கு தங்களின் பங்களிப்பை வழங்க…', 'இந்திய அறிவியல் கழகத்தின் (IISc) பட்டமளிப்பு விழாவில் பங்கேற்ற இஸ்ரோ தலைவர் டாக்டர் வி. நாராயணன், பட்டம் பெறும் மாணவர்கள் சமூகத்திற்கு தங்களின் பங்களிப்பை வழங்க வேண்டும் என்றும், இந்தியாவை வளர்ந்த நாடாக மாற்றும் பயணத்தில் முக்கிய பங்கு வகிக்க வேண்டும் என்றும் வலியுறுத்தினார்.\r\nபட்டம் என்பது தனிப்பட்ட சாதனை மட்டுமல்ல; பெற்றோர், ஆசிரியர்கள், கல்வி நிறுவனம் மற்றும் வரி செலுத்தும் மக்களின் கூட்டு முயற்சியின் பலன் என்றும் அவர் குறிப்பிட்டார். அதனால் சமூகத்தின் முன்னேற்றத்திற்காக திறமைகளை பயன்படுத்துவது ஒவ்வொரு பட்டதாரியின் பொறுப்பு என்றார். \r\nமேலும், தொடர்ந்து புதிய அறிவை கற்றுக்கொள்ளும் மனப்பான்மை, புதுமைகளை உருவாக்கும் திறன் மற்றும் நாட்டின் வளர்ச்சிக்காக அர்ப்பணிப்புடன் செயல்படும் எண்ணம் ஆகியவை இன்றைய இளைஞர்களுக்கு அவசியம் என வலியுறுத்தினார்.\r\nஇந்தியா 2047-ஆம் ஆண்டுக்குள் வளர்ந்த நாடாக மாறும் இலக்கை நோக்கி பயணித்து வருவதாகக் கூறிய அவர், அந்த இலக்கை எட்டுவதில் இன்றைய மாணவர்களின் அறிவும் திறமையும் முக்கிய பங்காற்றும் என நம்பிக்கை தெரிவித்தார். \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50d85e8b5b48.09463238.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 17:03:13', 0, 1, 0, 0, 0, 'இந்தியாவை வளர்ந்த நாடாக மாற்றுங்கள்’ - பட்டமளிப்பு விழாவில் மாணவர்களுக்கு இஸ்ரோ தலைவர் ...', 'இந்திய அறிவியல் கழகத்தின் (IISc) பட்டமளிப்பு விழாவில் பங்கேற்ற இஸ்ரோ தலைவர் டாக்டர் வி. நாராயணன், பட்டம் பெறும் மாணவர்கள் சமூகத்திற்கு தங்களின் பங்களிப்பை வழங்க', 10, 0, 0, 1, '2026-07-10 11:33:13', '2026-07-13 23:41:01', NULL, 0),
(252, 4, NULL, 1, NULL, NULL, NULL, 103, 'குஜராத்தில் இருந்து வேளாங்கண்ணிக்கு சிறப்பு ரெயில்...', 'குஜராத்தில்-இருந்து-வேளாங்கண்ணிக்கு-சிறப்பு-ரெயில்', 'பயணிகளின் வசதியை கருத்தில் கொண்டு, குஜராத் மாநிலம் வல்சாத் (Valsad) நகரிலிருந்து வேளாங்கண்ணிக்கு சிறப்பு ரெயில் இயக்கப்பட உள்ளது.\r\nஇந்த சிறப்பு ரெயில் (எண்: 090…', 'பயணிகளின் வசதியை கருத்தில் கொண்டு, குஜராத் மாநிலம் வல்சாத் (Valsad) நகரிலிருந்து வேளாங்கண்ணிக்கு சிறப்பு ரெயில் இயக்கப்பட உள்ளது.\r\nஇந்த சிறப்பு ரெயில் (எண்: 09030) ஜூலை 14-ஆம் தேதி மாலை 6.25 மணிக்கு வல்சாத்தில் இருந்து புறப்பட்டு, மூன்றாவது நாள் காலை 10.00 மணிக்கு வேளாங்கண்ணி சென்றடையும்.\r\nமறுமார்க்கத்தில், வேளாங்கண்ணியில் இருந்து தஹானு ரோடு நோக்கி சிறப்பு ரெயில் (எண்: 09029) ஜூலை 17-ஆம் தேதி இரவு 12.30 மணிக்கு புறப்பட்டு, மறுநாள் மதியம் 2.50 மணிக்கு சென்றடையும்.\r\n22 பெட்டிகள் கொண்ட இந்த சிறப்பு ரெயில், தமிழ்நாட்டில் நாகப்பட்டினம், நாகூர், காரைக்கால், திருநள்ளாறு, மயிலாடுதுறை, சிதம்பரம், திருப்பாதிரிப்புலியூர், விழுப்புரம், திருவண்ணாமலை, வேலூர் கண்டோன்மெண்ட் மற்றும் காட்பாடி உள்ளிட்ட முக்கிய நிலையங்கள் வழியாக இயக்கப்படும்.\r\nஇந்த சிறப்பு ரெயிலுக்கான முன்பதிவு ஜூலை 11-ஆம் தேதி காலை 8.00 மணி முதல் தொடங்கும் என தெற்கு ரெயில்வே தெரிவித்துள்ளது. \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50d9c1bdf6a4.85323181.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 17:09:07', 0, 1, 0, 0, 0, 'குஜராத்தில் இருந்து வேளாங்கண்ணிக்கு சிறப்பு ரெயில்...    ', 'பயணிகளின் வசதியை கருத்தில் கொண்டு, குஜராத் மாநிலம் வல்சாத் (Valsad) நகரிலிருந்து வேளாங்கண்ணிக்கு சிறப்பு ரெயில் இயக்கப்பட உள்ளது.\r\nஇந்த சிறப்பு ரெயில் (எண்: 090', 16, 0, 0, 1, '2026-07-10 11:39:07', '2026-07-13 22:35:40', NULL, 0),
(253, 4, NULL, 3, NULL, NULL, NULL, 104, 'தென் ஆப்பிரிக்கா: சட்டவிரோத அகதிகளை வெளியேற்றக்கோரி தொடரும் போராட்டம்...', 'தென்-ஆப்பிரிக்கா-சட்டவிரோத-அகதிகளை-வெளியேற்றக்கோரி-தொடரும்-போராட்டம்', 'தென் ஆப்பிரிக்காவில் சட்டவிரோதமாக தங்கியிருக்கும் வெளிநாட்டு அகதிகளை வெளியேற்ற வேண்டும் என்ற கோரிக்கையுடன் பல நகரங்களில் போராட்டங்கள் தொடர்ந்து நடைபெற்று வருகின…', 'தென் ஆப்பிரிக்காவில் சட்டவிரோதமாக தங்கியிருக்கும் வெளிநாட்டு அகதிகளை வெளியேற்ற வேண்டும் என்ற கோரிக்கையுடன் பல நகரங்களில் போராட்டங்கள் தொடர்ந்து நடைபெற்று வருகின்றன.\r\nவேலைவாய்ப்பு, குற்றச்செயல்கள் மற்றும் பொதுச் சேவைகளின் மீதான அழுத்தம் அதிகரித்துள்ளதாகக் கூறும் போராட்டக்காரர்கள், சட்டவிரோத குடியேற்றத்தை கட்டுப்படுத்த அரசு கடுமையான நடவடிக்கை எடுக்க வேண்டும் என்று வலியுறுத்தியுள்ளனர்.\r\nசில பகுதிகளில் போராட்டங்கள் பதற்றமாக மாறிய நிலையில், போலீசார் பாதுகாப்பு பணியை தீவிரப்படுத்தியுள்ளனர். இதனால் அச்சமடைந்த சில வெளிநாட்டு குடியேறிகள் தங்கள் சொந்த நாடுகளுக்குத் திரும்பத் தொடங்கியுள்ளதாக தகவல்கள் தெரிவிக்கின்றன.\r\nஇதற்கிடையில், சட்டத்தை கையில் எடுத்து செயல்பட வேண்டாம் என்றும், குடியேற்றப் பிரச்சினைக்கு சட்டரீதியான தீர்வுகள் மட்டுமே ஏற்றவை என்றும் தென் ஆப்பிரிக்க அரசு வலியுறுத்தியுள்ளது. \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50db0f684b77.16680325.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 17:14:25', 0, 1, 0, 0, 0, 'தென் ஆப்பிரிக்கா: சட்டவிரோத அகதிகளை வெளியேற்றக்கோரி தொடரும் போராட்டம்...    ', 'தென் ஆப்பிரிக்காவில் சட்டவிரோதமாக தங்கியிருக்கும் வெளிநாட்டு அகதிகளை வெளியேற்ற வேண்டும் என்ற கோரிக்கையுடன் பல நகரங்களில் போராட்டங்கள் தொடர்ந்து நடைபெற்று வருகின', 9, 0, 0, 1, '2026-07-10 11:44:25', '2026-07-13 15:09:37', NULL, 0),
(254, 4, NULL, 3, NULL, NULL, NULL, 105, 'நியூசிலாந்து சென்றார் பிரதமர் மோடி.....', 'நியூசிலாந்து-சென்றார்-பிரதமர்-மோடி', 'பிரதமர் நரேந்திர மோடி அதிகாரப்பூர்வ பயணமாக நியூசிலாந்து சென்றடைந்தார். அந்நாட்டு அரசு அதிகாரிகள் மற்றும் இந்திய சமூகத்தினர் அவருக்கு உற்சாக வரவேற்பு அளித்தனர்.\r\n…', 'பிரதமர் நரேந்திர மோடி அதிகாரப்பூர்வ பயணமாக நியூசிலாந்து சென்றடைந்தார். அந்நாட்டு அரசு அதிகாரிகள் மற்றும் இந்திய சமூகத்தினர் அவருக்கு உற்சாக வரவேற்பு அளித்தனர்.\r\nஇந்தப் பயணத்தின் போது, நியூசிலாந்து பிரதமருடன் இருதரப்பு பேச்சுவார்த்தை நடத்த உள்ளார். வர்த்தகம், முதலீடு, பாதுகாப்பு ஒத்துழைப்பு, கல்வி, தொழில்நுட்பம் மற்றும் பசுமைஆற்றல் உள்ளிட்ட பல்வேறு துறைகளில் இரு நாடுகளுக்கும் இடையேயான உறவை மேலும் வலுப்படுத்துவது குறித்து ஆலோசிக்கப்பட உள்ளது.\r\nமேலும், இந்திய வம்சாவளியினருடன் பிரதமர் மோடி கலந்துரையாடுவதுடன், பல முக்கிய நிகழ்ச்சிகளிலும் பங்கேற்கிறார். இந்தப் பயணம் இந்தியா–நியூசிலாந்து உறவுகளை புதிய கட்டத்திற்கு கொண்டு செல்லும் என எதிர்பார்க்கப்படுகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a50dc22cfa694.49375234.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-10 17:19:03', 0, 1, 0, 0, 0, 'நியூசிலாந்து சென்றார் பிரதமர் மோடி.....   ', 'பிரதமர் நரேந்திர மோடி அதிகாரப்பூர்வ பயணமாக நியூசிலாந்து சென்றடைந்தார். அந்நாட்டு அரசு அதிகாரிகள் மற்றும் இந்திய சமூகத்தினர் அவருக்கு உற்சாக வரவேற்பு அளித்தனர்.\r\n', 73, 0, 0, 1, '2026-07-10 11:49:03', '2026-07-13 22:04:38', NULL, 0),
(256, 4, NULL, 1, NULL, NULL, NULL, 108, 'தமிழகத்தில் மக்கள் தொகை கணக்கெடுப்பின்போது கேட்கப்படும் 33 கேள்விகள் என்னென்ன..', 'தமிழகத்தில்-மக்கள்-தொகை-கணக்கெடுப்பின்போது-கேட்கப்படும்-33-கேள்விகள்-என்னென்ன', 'இந்தியாவில் நடைபெற்று வரும் டிஜிட்டல் மக்கள் தொகை கணக்கெடுப்பின் முதல் கட்டமான வீடுகள் மற்றும் குடியிருப்பு கணக்கெடுப்பில்* குடும்பங்கள் மற்றும் வீடுகள் தொடர்பா…', 'இந்தியாவில் நடைபெற்று வரும் டிஜிட்டல் மக்கள் தொகை கணக்கெடுப்பின் முதல் கட்டமான வீடுகள் மற்றும் குடியிருப்பு கணக்கெடுப்பில்* குடும்பங்கள் மற்றும் வீடுகள் தொடர்பான 33 முக்கிய விவரங்கள் சேகரிக்கப்படுகின்றன. இந்த தகவல்கள் நாட்டின் மக்கள் தொகை, குடியிருப்பு வசதிகள் மற்றும் அடிப்படை உள்கட்டமைப்பு திட்டங்களை வடிவமைக்க பயன்படுத்தப்படுகின்றன.\r\nகேட்கப்படும் 33 கேள்விகள்:\r\n1. கட்டிட எண்\r\n2. மக்கள் தொகை கணக்கெடுப்பு வீட்டு எண்\r\n3. தரையின் முக்கிய கட்டுமானப் பொருள்\r\n4. சுவரின் முக்கிய கட்டுமானப் பொருள்\r\n5. கூரையின் முக்கிய கட்டுமானப் பொருள்\r\n6. வீடு எதற்காக பயன்படுத்தப்படுகிறது?\r\n7. வீட்டின் நிலை (நல்லது/சராசரி/மோசம்)\r\n8. குடும்ப எண்\r\n9. அந்த வீட்டில் வழக்கமாக வசிக்கும் நபர்களின் எண்ணிக்கை\r\n10. குடும்பத் தலைவரின் பெயர்\r\n11. குடும்பத் தலைவரின் பாலினம்\r\n12. குடும்பத் தலைவர் எஸ்.சி./எஸ்.டி./பிற பிரிவைச் சேர்ந்தவரா?\r\n13. வீட்டு உரிமை நிலை (சொந்தம்/வாடகை உள்ளிட்டவை)\r\n14. குடும்பம் பயன்படுத்தும் அறைகளின் எண்ணிக்கை\r\n15. வீட்டில் வசிக்கும் திருமணமான தம்பதிகளின் எண்ணிக்கை\r\n16. முக்கிய குடிநீர் ஆதாரம்\r\n17. குடிநீர் வீட்டிலேயே கிடைக்கிறதா?\r\n18. முக்கிய மின்விளக்கு வசதி\r\n19. கழிப்பறை வசதி உள்ளதா?\r\n20. இருந்தால் அதன் வகை என்ன?\r\n21. கழிவுநீர் வெளியேற்றும் முறை\r\n22. குளியலறை வசதி உள்ளதா?\r\n23. சமையலறை மற்றும் எல்.பி.ஜி./பி.என்.ஜி. இணைப்பு உள்ளதா?\r\n24. சமையலுக்கு பயன்படுத்தப்படும் முக்கிய எரிபொருள்\r\n25. ரேடியோ/டிரான்சிஸ்டர் உள்ளதா?\r\n26. தொலைக்காட்சி உள்ளதா?\r\n27. இணைய வசதி உள்ளதா?\r\n28. கணினி அல்லது மடிக்கணினி உள்ளதா?\r\n29. தொலைபேசி/மொபைல்/ஸ்மார்ட்போன் உள்ளதா?\r\n30. மிதிவண்டி அல்லது இருசக்கர வாகனம் உள்ளதா?\r\n31. கார்/ஜீப்/வேன் உள்ளதா?\r\n32. குடும்பத்தில் அதிகம் பயன்படுத்தப்படும் முக்கிய தானியம் எது?\r\n33. தொடர்பு கொள்ள மொபைல் எண். \r\nஇந்த தகவல்கள் முழுமையாக அரசின் மக்கள் தொகை மற்றும் வீட்டு வசதி திட்டமிடலுக்காக மட்டுமே பயன்படுத்தப்படும் என்றும், தனிநபர் தகவல்களின் ரகசியம் சட்டப்படி பாதுகாக்கப்படும் என்றும் அதிகாரிகள் தெரிவித்துள்ளனர்.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a51e2647c09c2.34760915.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 11:56:09', 0, 1, 0, 0, 0, 'தமிழகத்தில் மக்கள் தொகை கணக்கெடுப்பின்போது கேட்கப்படும் 33 கேள்விகள் என்னென்ன..', 'இந்தியாவில் நடைபெற்று வரும் டிஜிட்டல் மக்கள் தொகை கணக்கெடுப்பின் முதல் கட்டமான வீடுகள் மற்றும் குடியிருப்பு கணக்கெடுப்பில்* குடும்பங்கள் மற்றும் வீடுகள் தொடர்பா', 10, 0, 0, 1, '2026-07-11 06:26:09', '2026-07-13 20:41:04', NULL, 0),
(257, 4, NULL, 7, NULL, NULL, NULL, 109, 'சீர்காழி-அருகே-அகஸ்தீஸ்வரர்-ஆலயத்தில்-மழை-வேண்டி-மஹா-சங்கல்ப-யாகம்', 'சீர்காழி-அருகே-அகஸ்தீஸ்வரர்-ஆலயத்தில்-மழை-வேண்டி-மஹா-சங்கல்ப-யாகம்', 'நாட்டின் பல பகுதிகளில் பருவமழை தாமதமாகி, விவசாய பணிகள் பாதிக்கப்பட்டுள்ள நிலையில், விவசாயம் செழித்து நல்ல மழை பெய்ய வேண்டும் என்ற நோக்கில் சிறப்பு **மஹா சங்கல்ப…', 'மயிலாடுதுறை மாவட்டம் சீர்காழி அருகிலுள்ள ஆலஞ்சேரி கிராமத்தில் அமைந்துள்ள பழமையான அகஸ்தீஸ்வரர் ஆலயத்தில், விவசாயம் செழித்து நல்ல மழை பெய்ய வேண்டி மஹா சங்கல்ப யாகம் நடைபெற்றது.\r\nஅகத்திய முனிவருடன் தொடர்புடைய வரலாற்றுச் சிறப்புமிக்க இந்த ஆலயத்தில், வேத விற்பன்னர்கள் வேத மந்திரங்கள் முழங்க யாக பூஜைகளை நடத்தினர். மழை வளம் பெருகுதல், நீர்நிலைகள் நிரம்புதல், பயிர்கள் செழித்து வளருதல் மற்றும் விவசாயிகளின் வாழ்வாதாரம் மேம்பட வேண்டும் என்ற நோக்கில் சிறப்பு பிரார்த்தனைகள் செய்யப்பட்டன.\r\nஇந்த யாகத்தில் சுற்றுவட்டார கிராமங்களைச் சேர்ந்த விவசாயிகள், பக்தர்கள் மற்றும் பொதுமக்கள் திரளாக பங்கேற்று வழிபட்டனர். யாக நிறைவில் பூர்ணாஹூதி, தீபாராதனை மற்றும் பிரசாதம் வழங்கப்பட்டன.\r\nபருவமழை சீராக பொழிந்து விவசாயம் வளம் பெற வேண்டும் என்ற நம்பிக்கையுடன் நடைபெற்ற இந்த ஆன்மிக நிகழ்வு, பக்தர்களிடையே பெரும் வரவேற்பைப் பெற்றது.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a51ea79bbf846.70718656.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 12:32:57', 0, 1, 0, 0, 0, 'விவசாயம் செழிக்க மழை வேண்டி மஹா சங்கல்ப மஹா யாகம்...   ', 'நாட்டின் பல பகுதிகளில் பருவமழை தாமதமாகி, விவசாய பணிகள் பாதிக்கப்பட்டுள்ள நிலையில், விவசாயம் செழித்து நல்ல மழை பெய்ய வேண்டும் என்ற நோக்கில் சிறப்பு **மஹா சங்கல்ப', 2, 0, 0, 1, '2026-07-11 07:02:57', '2026-07-11 14:00:16', NULL, 0),
(258, 4, NULL, 2, NULL, NULL, NULL, 112, 'வயநாட்டில் குடியிருப்புப் பகுதிக்குள் புகுந்த சிறுத்தை கூண்டில் சிக்கியது: பொதுமக்கள் நிம்மதி...', 'வயநாட்டில்-குடியிருப்புப்-பகுதிக்குள்-புகுந்த-சிறுத்தை-கூண்டில்-சிக்கியது-பொதுமக்கள்-நிம்மதி', 'கேரள மாநிலம் வயநாடு மாவட்டத்தில் குடியிருப்புப் பகுதிக்குள் அடிக்கடி சுற்றித்திரிந்து அச்சத்தை ஏற்படுத்தி வந்த சிறுத்தை, வனத்துறையினர் அமைத்திருந்த கூண்டில் சிக…', 'கேரள மாநிலம் வயநாடு மாவட்டத்தில் குடியிருப்புப் பகுதிக்குள் அடிக்கடி சுற்றித்திரிந்து அச்சத்தை ஏற்படுத்தி வந்த சிறுத்தை, வனத்துறையினர் அமைத்திருந்த கூண்டில் சிக்கியதால் அப்பகுதி மக்கள் நிம்மதி அடைந்தனர். சமீப நாட்களாக இரவு நேரங்களில் வீடுகள் அருகே சிறுத்தை நடமாடுவதாக பொதுமக்கள் தொடர்ந்து புகார் அளித்திருந்தனர். சில இடங்களில் கால்நடைகள் தாக்கப்பட்டதாகவும் தகவல்கள் வெளியானதைத் தொடர்ந்து, வனத்துறையினர் சம்பவ இடத்தில் கண்காணிப்பை தீவிரப்படுத்தினர். \r\nஇதையடுத்து, சிறுத்தையைப் பிடிக்க பல்வேறு இடங்களில் கூண்டுகள் அமைக்கப்பட்டன. அதிகாலை நேரத்தில் அவற்றில் ஒன்றில் சிறுத்தை சிக்கியிருப்பதை உள்ளூர் மக்கள் கவனித்து வனத்துறைக்கு தகவல் தெரிவித்தனர். உடனடியாக அங்கு சென்ற அதிகாரிகள் பாதுகாப்பு நடவடிக்கைகளுடன் சிறுத்தையை மீட்டு, மருத்துவ பரிசோதனைக்குப் பிறகு பாதுகாப்பான வனப்பகுதிக்கு மாற்ற ஏற்பாடு செய்தனர்.\r\nசிறுத்தை பிடிபட்டதைத் தொடர்ந்து அப்பகுதியில் நிலவி வந்த பதற்றம் குறைந்து, பொதுமக்கள் நிம்மதி அடைந்தனர். இருப்பினும், வனப்பகுதிகளை ஒட்டிய கிராமங்களில் மக்கள் எச்சரிக்கையுடன் இருக்க வேண்டும் என்றும், வனவிலங்குகள் தென்பட்டால் உடனடியாக வனத்துறைக்கு தகவல் தெரிவிக்க வேண்டும் என்றும் அதிகாரிகள் அறிவுறுத்தியுள்ளனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a51f5fc2e2402.23361163.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 13:20:07', 0, 1, 0, 0, 0, 'வயநாட்டில் குடியிருப்புப் பகுதிக்குள் புகுந்த சிறுத்தை கூண்டில் சிக்கியது: பொதுமக்கள் நிம்மதி...  ', 'கேரள மாநிலம் வயநாடு மாவட்டத்தில் குடியிருப்புப் பகுதிக்குள் அடிக்கடி சுற்றித்திரிந்து அச்சத்தை ஏற்படுத்தி வந்த சிறுத்தை, வனத்துறையினர் அமைத்திருந்த கூண்டில் சிக', 13, 0, 0, 1, '2026-07-11 07:50:07', '2026-07-14 05:49:13', NULL, 0),
(259, 4, NULL, 1, NULL, NULL, NULL, 113, 'விழுப்புரத்தில் இருந்து புறப்படும் ரெயில் சேவைகளில் மாற்றம்', 'விழுப்புரத்தில்-இருந்து-புறப்படும்-ரெயில்-சேவைகளில்-மாற்றம்', 'விழுப்புரம் வழித்தடத்தில் நடைபெற்று வரும் பராமரிப்பு மற்றும் பொறியியல் மேம்பாட்டு பணிகளால், விழுப்புரம் ரெயில் நிலையத்தில் இருந்து புறப்படும் மற்றும் அந்த வழியா…', 'விழுப்புரம் வழித்தடத்தில் நடைபெற்று வரும் பராமரிப்பு மற்றும் பொறியியல் மேம்பாட்டு பணிகளால், விழுப்புரம் ரெயில் நிலையத்தில் இருந்து புறப்படும் மற்றும் அந்த வழியாக இயக்கப்படும் பல்வேறு ரெயில்களின் சேவைகளில் தற்காலிக மாற்றங்கள் அறிவிக்கப்பட்டுள்ளன. \r\nமாற்றங்களின் படி, சில ரெயில்கள் பகுதியளவில் ரத்து செய்யப்பட்டுள்ளன. மேலும், சில ரெயில்கள் வழக்கமான நிலையங்களுக்கு பதிலாக மாற்று நிலையங்களில் இருந்து இயக்கப்படுகின்றன. குறிப்பிட்ட சில சேவைகள் வழித்தட மாற்றத்துடனும், சில ரெயில்கள் தாமதமாகவும் இயக்கப்படும் என தெரிவிக்கப்பட்டுள்ளது.\r\nவிழுப்புரம்–சென்னை கடற்கரை பயணிகள் ரெயில் உள்ளிட்ட சில சேவைகள் முண்டியம்பாக்கம் போன்ற மாற்று நிலையங்களில் இருந்து புறப்பட உள்ளன. புதுச்சேரி, திண்டுக்கல், திருப்பதி உள்ளிட்ட வழித்தடங்களில் இயக்கப்படும் சில ரெயில்களின் தொடக்க நிலையங்களிலும் தற்காலிக மாற்றங்கள் செய்யப்பட்டுள்ளன. \r\nபயணிகள் தாங்கள் பயணம் செய்ய உள்ள ரெயிலின் இயக்கநிலை, புறப்படும் நிலையம் மற்றும் நேரத்தை முன்கூட்டியே உறுதிப்படுத்திக் கொண்டு பயணம் மேற்கொள்ளுமாறு ரெயில்வே நிர்வாகம் அறிவுறுத்தியுள்ளது. \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a51f7bb737ce3.47475495.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 13:29:13', 0, 1, 0, 0, 0, 'விழுப்புரத்தில் இருந்து புறப்படும் ரெயில் சேவைகளில் மாற்றம் ', 'விழுப்புரம் வழித்தடத்தில் நடைபெற்று வரும் பராமரிப்பு மற்றும் பொறியியல் மேம்பாட்டு பணிகளால், விழுப்புரம் ரெயில் நிலையத்தில் இருந்து புறப்படும் மற்றும் அந்த வழியா', 6, 0, 0, 1, '2026-07-11 07:59:13', '2026-07-12 15:43:01', NULL, 0),
(260, 4, NULL, 3, NULL, NULL, NULL, 114, 'உகாண்டாவில் பள்ளி சுற்றுலா பஸ் மீது ரெயில் மோதி விபத்து: ஆசிரியர் உயிரிழப்பு, மாணவர்கள் உயிர் தப்பினர்', 'உகாண்டாவில் பள்ளி சுற்றுலா பஸ் மீது ரெயில் மோதி விபத்து', 'உகாண்டாவின் முகோனோ பகுதியில் பள்ளி மாணவர்களை ஏற்றிச் சென்ற சுற்றுலா பஸ் மீது ரெயில் மோதியதில் ஆசிரியர் ஒருவர் உயிரிழந்தார். இந்த சம்பவம் அப்பகுதியில் பெரும் அதி…', 'உகாண்டாவின் முகோனோ பகுதியில் பள்ளி மாணவர்களை ஏற்றிச் சென்ற சுற்றுலா பஸ் மீது ரெயில் மோதியதில் ஆசிரியர் ஒருவர் உயிரிழந்தார். இந்த சம்பவம் அப்பகுதியில் பெரும் அதிர்ச்சியை ஏற்படுத்தியுள்ளது.\r\nதகவலின்படி, சுமார் 70 மாணவர்கள் மற்றும் ஆசிரியர்கள் பயணம் செய்த பஸ் ரெயில்வே கடவையை கடக்க முயன்றபோது, எதிர்பாராத விதமாக வந்த ரெயில் மோதியது. விபத்தில் ஒரு ஆசிரியர் சம்பவ இடத்திலேயே உயிரிழந்தார்.\r\nபஸ்சில் பயணம் செய்த மாணவர்கள் மற்றும் பிற ஆசிரியர்கள் பலர் சிறிய காயங்களுடன் உயிர் தப்பியதாக அதிகாரிகள் தெரிவித்தனர். காயமடைந்தவர்கள் அருகிலுள்ள மருத்துவமனைகளில் சிகிச்சைக்காக அனுமதிக்கப்பட்டுள்ளனர்.\r\nஇந்த விபத்துக்கான காரணம் குறித்து காவல்துறையும் ரெயில்வே அதிகாரிகளும் இணைந்து விசாரணை நடத்தி வருகின்றனர். ரெயில்வே கடவைகளில் பாதுகாப்பு விதிகளை கடைபிடிப்பதன் அவசியத்தை இந்த சம்பவம் மீண்டும் நினைவூட்டியுள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a51fbbf602280.49598363.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 13:48:12', 0, 1, 0, 0, 0, 'உகாண்டாவில் பள்ளி சுற்றுலா பஸ் மீது ரெயில் மோதி விபத்து: ஆசிரியர் உயிரிழப்பு, மாணவர்கள் உயிர் தப்பினர்', 'உகாண்டாவின் முகோனோ பகுதியில் பள்ளி மாணவர்களை ஏற்றிச் சென்ற சுற்றுலா பஸ் மீது ரெயில் மோதியதில் ஆசிரியர் ஒருவர் உயிரிழந்தார். இந்த சம்பவம் அப்பகுதியில் பெரும் அதி', 9, 0, 0, 1, '2026-07-11 08:18:12', '2026-07-13 17:56:17', NULL, 0),
(261, 4, NULL, 3, NULL, NULL, NULL, 116, 'நாசா விண்கலத்தில் விண்வெளிக்கு செல்லும் இந்திய வம்சாவளி வீரர்', 'நாசா-விண்கலத்தில்-விண்வெளிக்கு-செல்லும்-இந்திய-வம்சாவளி-வீரர்', 'இந்திய வம்சாவளியைச் சேர்ந்த நாசா விண்வெளி வீரர் **அனில் மேனன்**, தனது முதல் நீண்டகால விண்வெளிப் பயணத்திற்காக சர்வதேச விண்வெளி நிலையம் (ISS) நோக்கி புறப்படத் தயா…', 'இந்திய வம்சாவளியைச் சேர்ந்த நாசா விண்வெளி வீரர் **அனில் மேனன்**, தனது முதல் நீண்டகால விண்வெளிப் பயணத்திற்காக சர்வதேச விண்வெளி நிலையம் (ISS) நோக்கி புறப்படத் தயாராகியுள்ளார். ரஷ்யாவின் சோயுஸ் MS-29 விண்கலத்தின் மூலம் நடைபெறும் இந்தப் பயணத்தில் அவர் சுமார் எட்டு மாதங்கள் விண்வெளியில் தங்கி அறிவியல் ஆய்வுகள் மற்றும் தொழில்நுட்பச் சோதனைகளில் பங்கேற்க உள்ளார். அனில் மேனன் அவசர மருத்துவ நிபுணர், விண்வெளி மருத்துவ வல்லுநர் மற்றும் அமெரிக்க விண்வெளிப் படையில் கர்னலாகவும் பணியாற்றியவர். பின்னர் நாசா விண்வெளி வீரராகத் தேர்வு செய்யப்பட்ட அவர், மனிதர்கள் நீண்டகாலம் விண்வெளியில் வாழ்வது தொடர்பான பல்வேறு ஆய்வுகளில் முக்கிய பங்காற்றவுள்ளார். இந்திய வேர்களைக் கொண்ட ஒருவர் நாசாவின் நீண்டகால விண்வெளி ஆய்வு திட்டத்தில் பங்கேற்பது இந்தியர்களுக்கு பெருமை சேர்க்கும் நிகழ்வாகக் கருதப்படுகிறது. விண்வெளி ஆராய்ச்சியில் இந்திய வம்சாவளியினரின் பங்களிப்பை மேலும் வலுப்படுத்தும் ஒரு முக்கிய மைல்கல்லாக இந்தப் பயணம் பார்க்கப்படுகிறது. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a51fee74fd779.82789970.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 13:59:39', 0, 1, 0, 0, 0, 'நாசா விண்கலத்தில் விண்வெளிக்கு செல்லும் இந்திய வம்சாவளி வீரர் ', 'இந்திய வம்சாவளியைச் சேர்ந்த நாசா விண்வெளி வீரர் **அனில் மேனன்**, தனது முதல் நீண்டகால விண்வெளிப் பயணத்திற்காக சர்வதேச விண்வெளி நிலையம் (ISS) நோக்கி புறப்படத் தயா', 0, 0, 0, 1, '2026-07-11 08:29:39', '2026-07-11 14:00:24', NULL, 0),
(262, 4, NULL, 1, NULL, NULL, NULL, 117, 'தாமிரபரணி நதியை மாசுபட அனுமதிக்க முடியாது: ஐகோர்ட்டு மதுரை கிளை...', 'தாமிரபரணி-நதியை-மாசுபட-அனுமதிக்க-முடியாது-ஐகோர்ட்டு-மதுரை-கிளை', 'மதுரை:தாமிரபரணி ஆற்றின் மாசுபாடு தொடர்பான வழக்கை விசாரித்த மதுரை உயர்நீதிமன்ற கிளை, எந்தக் காரணத்திற்காகவும் நீர்நிலைகளை மாசுபடுத்த அனுமதிக்க முடியாது என்று வலி…', 'மதுரை:தாமிரபரணி ஆற்றின் மாசுபாடு தொடர்பான வழக்கை விசாரித்த மதுரை உயர்நீதிமன்ற கிளை, எந்தக் காரணத்திற்காகவும் நீர்நிலைகளை மாசுபடுத்த அனுமதிக்க முடியாது என்று வலியுறுத்தியுள்ளது.\r\nவிசாரணையின்போது, மத நம்பிக்கைகள் மதிக்கப்பட வேண்டியவை என்றாலும், அவற்றின் பெயரில் ஆறுகள் மற்றும் பிற நீர்நிலைகளில் சுற்றுச்சூழலுக்கு தீங்கு விளைவிக்கும் பொருட்களை கொட்டுவது ஏற்க முடியாதது என்று நீதிபதிகள் கருத்து தெரிவித்தனர்.\r\nநீரில் கரையாத துணிகள், பாலியஸ்டர் உள்ளிட்ட பொருட்கள் நீர்வாழ் உயிரினங்களுக்கும், ஆற்றின் இயற்கைச் சூழலுக்கும் பாதிப்பை ஏற்படுத்தும் என்பதால், இதுபோன்ற செயல்களைத் தடுக்க அரசு உறுதியான நடவடிக்கை எடுக்க வேண்டும் என்றும் நீதிமன்றம் குறிப்பிட்டது.\r\nமேலும், தாமிரபரணி ஆற்றில் இனி மாசுபாடு ஏற்படாமல் தடுக்க எடுக்கப்படும் நடவடிக்கைகள் குறித்து பொதுமக்களுக்கு விழிப்புணர்வு ஏற்படுத்தவும், நிரந்தர தீர்வுக்கான விரிவான அறிக்கையை தாக்கல் செய்யவும் திருநெல்வேலி மாவட்ட ஆட்சியருக்கு உத்தரவிடப்பட்டது.\r\nஇந்த வழக்கின் அடுத்தகட்ட விசாரணை ஜூலை 16-ஆம் தேதிக்கு ஒத்திவைக்கப்பட்டது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a52017d30ea59.01511059.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 14:11:39', 0, 1, 0, 0, 0, 'தாமிரபரணி நதியை மாசுபட அனுமதிக்க முடியாது: ஐகோர்ட்டு மதுரை கிளை...  ', 'மதுரை:தாமிரபரணி ஆற்றின் மாசுபாடு தொடர்பான வழக்கை விசாரித்த மதுரை உயர்நீதிமன்ற கிளை, எந்தக் காரணத்திற்காகவும் நீர்நிலைகளை மாசுபடுத்த அனுமதிக்க முடியாது என்று வலி', 15, 0, 0, 1, '2026-07-11 08:41:39', '2026-07-14 03:09:18', 5.00, 1),
(263, 4, NULL, 2, NULL, NULL, NULL, 118, 'டில்லி செங்கோட்டைக்கு வெடிகுண்டு மிரட்டல்', 'டில்லி-செங்கோட்டைக்கு-வெடிகுண்டு-மிரட்டல்', 'புதுடெல்லியில் ;தலைநகர் டெல்லியில் உள்ள வரலாற்றுச் சிறப்புமிக்க செங்கோட்டைக்கு வெடிகுண்டு மிரட்டல் விடுக்கப்பட்டதாக தகவல் வெளியாகியுள்ளது.\r\nஇதையடுத்து போலீசார்,…', 'புதுடெல்லியில் ;தலைநகர் டெல்லியில் உள்ள வரலாற்றுச் சிறப்புமிக்க செங்கோட்டைக்கு வெடிகுண்டு மிரட்டல் விடுக்கப்பட்டதாக தகவல் வெளியாகியுள்ளது.\r\nஇதையடுத்து போலீசார், வெடிகுண்டு செயலிழப்பு நிபுணர்கள் மற்றும் பாதுகாப்புப் படையினர் உடனடியாக சம்பவ இடத்திற்கு சென்று தீவிர சோதனையில் ஈடுபட்டனர். செங்கோட்டை வளாகம் முழுவதும் மற்றும் அதன் சுற்றுப்புறப் பகுதிகளிலும் பலத்த பாதுகாப்பு ஏற்பாடுகள் செய்யப்பட்டன.\r\nபார்வையாளர்களின் பாதுகாப்பை கருத்தில் கொண்டு, நுழைவு மற்றும் கண்காணிப்பு நடவடிக்கைகள் மேலும் வலுப்படுத்தப்பட்டன. சந்தேகத்திற்கிடமான பொருட்கள் ஏதேனும் உள்ளதா என்பது குறித்து அதிகாரிகள் விரிவாக ஆய்வு மேற்கொண்டனர்.\r\nமிரட்டல் தொடர்பாக விசாரணை நடைபெற்று வருகிறது. தகவல் எங்கிருந்து வந்தது, அதன் நம்பகத்தன்மை என்ன என்பது உள்ளிட்ட விவரங்களை போலீசார் ஆராய்ந்து வருகின்றனர்.\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5205888679e5.84076517.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 14:28:10', 0, 1, 0, 0, 0, 'டில்லி செங்கோட்டைக்கு வெடிகுண்டு மிரட்டல்', 'புதுடெல்லியில் ;தலைநகர் டெல்லியில் உள்ள வரலாற்றுச் சிறப்புமிக்க செங்கோட்டைக்கு வெடிகுண்டு மிரட்டல் விடுக்கப்பட்டதாக தகவல் வெளியாகியுள்ளது.\r\nஇதையடுத்து போலீசார்,', 15, 0, 0, 1, '2026-07-11 08:58:10', '2026-07-14 06:23:49', NULL, 0),
(264, 4, NULL, 1, NULL, NULL, NULL, 119, 'கோவை: வேளாண் பல்கலைக்கழக விடுதியில் மாணவி மர்ம மரணம்', 'கோவை-வேளாண்-பல்கலைக்கழக-விடுதியில்-மாணவி-மர்ம-மரணம்', 'கோவையில் உள்ள தமிழ்நாடு வேளாண் பல்கலைக்கழக விடுதியில் தங்கி படித்து வந்த இரண்டாம் ஆண்டு பி.எஸ்.சி. மாணவி ஒருவர் உயிரிழந்த நிலையில் மீட்கப்பட்ட சம்பவம் பெரும் பர…', 'கோவையில் உள்ள தமிழ்நாடு வேளாண் பல்கலைக்கழக விடுதியில் தங்கி படித்து வந்த இரண்டாம் ஆண்டு பி.எஸ்.சி. மாணவி ஒருவர் உயிரிழந்த நிலையில் மீட்கப்பட்ட சம்பவம் பெரும் பரபரப்பை ஏற்படுத்தியுள்ளது.\r\nவிழுப்புரம் மாவட்டத்தைச் சேர்ந்த 18 வயது மாணவி, பல்கலைக்கழக விடுதியில் உள்ள குளியலறையில் மயங்கிய நிலையில் கிடந்ததாகக் கூறப்படுகிறது. உடனடியாக அவர் கோவை அரசு மருத்துவமனைக்கு கொண்டு செல்லப்பட்ட நிலையில், மருத்துவர்கள் அவர் ஏற்கனவே உயிரிழந்துவிட்டதாக தெரிவித்தனர். இந்த சம்பவம் குறித்து தகவல் அறிந்த மாணவியின் பெற்றோர் மற்றும் உறவினர்கள், மரணத்தில் சந்தேகம் இருப்பதாக கூறி பல்கலைக்கழக வளாகத்தில் விளக்கம் கோரினர். மாணவிக்கு என்ன நடந்தது என்பது குறித்து நிர்வாகம் தெளிவான தகவல் வழங்கவில்லை என்றும், சில கண்காணிப்பு கேமரா (CCTV) காட்சிகள் காண்பிக்கப்படவில்லை என்றும் அவர்கள் குற்றம்சாட்டியுள்ளனர். \r\nமேலும், மாணவி வகுப்பிற்கு வராத நிலையில் பல மணி நேரம் யாரும் கவனிக்கவில்லை என்றும், சம்பவம் தொடர்பான தகவல்கள் தாமதமாக தெரிவிக்கப்பட்டதாகவும் பெற்றோர் வேதனை தெரிவித்துள்ளனர். இருப்பினும், இந்த குற்றச்சாட்டுகள் குறித்து அதிகாரப்பூர்வ உறுதிப்படுத்தல் வெளியாகவில்லை. \r\nசம்பவம் தொடர்பாக ஆர்.எஸ்.புரம் காவல்துறையினர் வழக்குப்பதிவு செய்து விசாரணை நடத்தி வருகின்றனர். மாணவியின் உயிரிழப்புக்கான உண்மையான காரணம் பிரேதப் பரிசோதனை அறிக்கை மற்றும் காவல்துறை விசாரணைக்குப் பிறகே தெரியவரும் என அதிகாரிகள் தெரிவித்துள்ளனர். ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5212680fa4e2.97812748.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 15:22:53', 0, 1, 0, 0, 0, 'கோவை: வேளாண் பல்கலைக்கழக விடுதியில் மாணவி மர்ம மரணம்', 'கோவையில் உள்ள தமிழ்நாடு வேளாண் பல்கலைக்கழக விடுதியில் தங்கி படித்து வந்த இரண்டாம் ஆண்டு பி.எஸ்.சி. மாணவி ஒருவர் உயிரிழந்த நிலையில் மீட்கப்பட்ட சம்பவம் பெரும் பர', 11, 0, 0, 1, '2026-07-11 09:52:53', '2026-07-13 22:06:37', NULL, 0),
(265, 4, NULL, 1, NULL, NULL, NULL, 120, '757 கோவில்களுக்கு அறங்காவலர்கள் நியமனத்திற்கான விண்ணப்பங்கள் வரவேற்பு...', '757-கோவில்களுக்கு-அறங்காவலர்கள்-நியமனத்திற்கான-விண்ணப்பங்கள்-வரவேற்பு', 'தமிழக இந்து சமய அறநிலையத் துறையின் கட்டுப்பாட்டில் உள்ள 757 திருக்கோவில்களுக்கு பரம்பரை முறை வழிசாரா அறங்காவலர்களை நியமிக்கும் பணிக்காக தகுதியானவர்களிடமிருந்து …', 'தமிழக இந்து சமய அறநிலையத் துறையின் கட்டுப்பாட்டில் உள்ள 757 திருக்கோவில்களுக்கு பரம்பரை முறை வழிசாரா அறங்காவலர்களை நியமிக்கும் பணிக்காக தகுதியானவர்களிடமிருந்து விண்ணப்பங்கள் வரவேற்கப்பட்டுள்ளன.\r\nஅறங்காவலர் பொறுப்பில் ஆர்வமுள்ளவர்கள், சம்பந்தப்பட்ட கோவில்களின் விவரங்கள், தகுதிகள் மற்றும் விண்ணப்பப் படிவங்களை இந்து சமய அறநிலையத் துறையின் அதிகாரப்பூர்வ இணையதளத்தில் பெற்றுக்கொள்ளலாம். விண்ணப்பங்களை இணையவழி அல்லது அறிவிப்பில் குறிப்பிடப்பட்டுள்ள முகவரிக்கு தேவையான ஆவணங்களுடன் நேரில் அல்லது விரைவு அஞ்சல் மூலம் சமர்ப்பிக்கலாம். \r\nஇந்த நடவடிக்கை மூலம் கோவில் நிர்வாகத்தை மேலும் சிறப்பாக மேற்கொள்ளவும், பக்தர்களின் பங்களிப்பை ஊக்குவிக்கவும் அறநிலையத் துறை திட்டமிட்டுள்ளது. விண்ணப்பிக்க விரும்புவோர் அறிவிப்பில் குறிப்பிடப்பட்டுள்ள கடைசி தேதிக்குள் விண்ணப்பங்களை சமர்ப்பிக்குமாறு அறிவுறுத்தப்பட்டுள்ளது. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5214bd519f87.40395271.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 15:33:06', 0, 1, 0, 0, 0, '757 கோவில்களுக்கு அறங்காவலர்கள் நியமனத்திற்கான விண்ணப்பங்கள் வரவேற்பு...  ', 'தமிழக இந்து சமய அறநிலையத் துறையின் கட்டுப்பாட்டில் உள்ள 757 திருக்கோவில்களுக்கு பரம்பரை முறை வழிசாரா அறங்காவலர்களை நியமிக்கும் பணிக்காக தகுதியானவர்களிடமிருந்து ', 8, 0, 0, 1, '2026-07-11 10:03:06', '2026-07-11 15:28:52', NULL, 0),
(266, 4, NULL, 2, NULL, NULL, NULL, 122, 'அதிநவீன ஐஎன்எஸ் மகேந்திரகிரி போர் கப்பல் நாட்டுக்கு அர்ப்பணிப்பு...', 'அதிநவீன-ஐஎன்எஸ்-மகேந்திரகிரி-போர்-கப்பல்-நாட்டுக்கு-அர்ப்பணிப்பு', 'இந்திய கடற்படையின் வலிமையை மேலும் உயர்த்தும் வகையில், உள்நாட்டிலேயே வடிவமைத்து கட்டப்பட்ட அதிநவீன ஸ்டெல்த் போர் கப்பலான **ஐஎன்எஸ் மகேந்திரகிரி** நாட்டுக்கு அர்ப…', 'இந்திய கடற்படையின் வலிமையை மேலும் உயர்த்தும் வகையில், உள்நாட்டிலேயே வடிவமைத்து கட்டப்பட்ட அதிநவீன ஸ்டெல்த் போர் கப்பலான **ஐஎன்எஸ் மகேந்திரகிரி** நாட்டுக்கு அர்ப்பணிக்கப்பட்டது.\r\nவிசாகப்பட்டினத்தில் நடைபெற்ற விழாவில் இந்த போர்க்கப்பல் இந்திய கடற்படையில் அதிகாரப்பூர்வமாக இணைக்கப்பட்டது. \'ப்ராஜெக்ட் 17A\' திட்டத்தின் கீழ் உருவாக்கப்பட்டுள்ள இந்த போர்க்கப்பல், நவீன ஏவுகணை அமைப்புகள், மேம்பட்ட ரேடார், மின்னணு போர் தொழில்நுட்பங்கள் மற்றும் நீர்மூழ்கிக் கப்பல்களை எதிர்கொள்ளும் திறனுடன் வடிவமைக்கப்பட்டுள்ளது. எதிரி ரேடார்களின் கண்காணிப்பில் எளிதில் சிக்காத வகையிலான ஸ்டெல்த் தொழில்நுட்பம் இதில் பயன்படுத்தப்பட்டுள்ளது. கடல்சார் பாதுகாப்பு, கண்காணிப்பு, போர் நடவடிக்கைகள் மற்றும் மனிதாபிமான மீட்பு பணிகள் உள்ளிட்ட பல்வேறு பணிகளை திறம்பட மேற்கொள்ளும் வகையில் இந்த கப்பல் உருவாக்கப்பட்டுள்ளது. இந்தியாவில் உள்நாட்டு பாதுகாப்பு உற்பத்தியை ஊக்குவிக்கும் முயற்சியின் முக்கிய மைல்கல்லாக ஐஎன்எஸ் மகேந்திரகிரி கருதப்படுகிறது. இதன் இணைப்பு, இந்திய கடற்படையின் நவீனமயமாக்கலுக்கும், இந்தியப் பெருங்கடல் பிராந்தியத்தில் நாட்டின் கடல்சார் பாதுகாப்பை வலுப்படுத்துவதற்கும் முக்கிய பங்களிப்பாக அமையும்.\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a521871e818d9.23228929.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 15:48:41', 0, 1, 0, 0, 0, 'அதிநவீன ஐஎன்எஸ் மகேந்திரகிரி போர் கப்பல் நாட்டுக்கு அர்ப்பணிப்பு... ', 'இந்திய கடற்படையின் வலிமையை மேலும் உயர்த்தும் வகையில், உள்நாட்டிலேயே வடிவமைத்து கட்டப்பட்ட அதிநவீன ஸ்டெல்த் போர் கப்பலான **ஐஎன்எஸ் மகேந்திரகிரி** நாட்டுக்கு அர்ப', 10, 0, 0, 1, '2026-07-11 10:18:41', '2026-07-13 13:16:09', NULL, 0),
(267, 4, NULL, 3, NULL, NULL, NULL, 123, 'வியட்நாம்: இந்திய சுற்றுலா பயணிகளுடன் சென்ற படகு கடலில் கவிழ்ந்து விபத்து - 10க்கும் மேற்பட்டோர் பலி?...', 'வியட்நாம்-இந்திய-சுற்றுலா-பயணிகளுடன்-சென்ற-படகு-கடலில்-கவிழ்ந்து-விபத்து-10க்கும்-மேற்பட்டோர்-பலி', 'வியட்நாமில் சுற்றுலா பயணிகளை ஏற்றிச் சென்ற படகு கடலில் கவிழ்ந்ததில் 10க்கும் மேற்பட்டோர் உயிரிழந்ததாக தகவல்கள் வெளியாகியுள்ளன. இந்த படகில் இந்திய சுற்றுலா பயணிக…', 'வியட்நாமில் சுற்றுலா பயணிகளை ஏற்றிச் சென்ற படகு கடலில் கவிழ்ந்ததில் 10க்கும் மேற்பட்டோர் உயிரிழந்ததாக தகவல்கள் வெளியாகியுள்ளன. இந்த படகில் இந்திய சுற்றுலா பயணிகளும் இருந்ததாக அதிகாரிகள் தெரிவித்துள்ளனர்.சுற்றுலா தலத்திற்கு சென்றுகொண்டிருந்தபோது, கடலில் திடீரென ஏற்பட்ட மோசமான வானிலை மற்றும் பலத்த காற்றின் காரணமாக படகு கட்டுப்பாட்டை இழந்து கவிழ்ந்ததாக முதற்கட்ட தகவல்கள் தெரிவிக்கின்றன.விபத்து நடந்தவுடன் கடலோர பாதுகாப்புப் படையினர் மற்றும் மீட்புக் குழுவினர் சம்பவ இடத்துக்கு விரைந்து சென்று மீட்புப் பணிகளை தீவிரமாக மேற்கொண்டனர். பலர் உயிருடன் மீட்கப்பட்ட நிலையில், காணாமல் போனவர்களை தேடும் பணி தொடர்ந்து நடைபெற்று வருகிறது.உயிரிழந்தவர்களின் அடையாளம் மற்றும் இந்தியர்களின் நிலை குறித்து அதிகாரப்பூர்வ தகவல்கள் சேகரிக்கப்பட்டு வருகின்றன. விபத்துக்கான துல்லியமான காரணம் குறித்து வியட்நாம் அதிகாரிகள் விசாரணை மேற்கொண்டு வருகின்றனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a522437b80386.30807525.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 16:39:01', 0, 1, 0, 0, 0, 'வியட்நாம்: இந்திய சுற்றுலா பயணிகளுடன் சென்ற படகு கடலில் கவிழ்ந்து விபத்து - 10க்கும் மேற்பட்டோர் பலி?... ', 'வியட்நாமில் சுற்றுலா பயணிகளை ஏற்றிச் சென்ற படகு கடலில் கவிழ்ந்ததில் 10க்கும் மேற்பட்டோர் உயிரிழந்ததாக தகவல்கள் வெளியாகியுள்ளன. இந்த படகில் இந்திய சுற்றுலா பயணிக', 7, 0, 0, 1, '2026-07-11 11:09:01', '2026-07-11 20:28:21', NULL, 0),
(268, 4, NULL, 1, NULL, NULL, NULL, 124, 'கொடைக்கானல்: சிட்டி வியூ பாயிண்ட்டில் பாதுகாப்பு வேலி அமைக்க சுற்றுலா பயணிகள் கோரிக்கை...', 'கொடைக்கானல்-சிட்டி-வியூ-பாயிண்ட்டில்-பாதுகாப்பு-வேலி-அமைக்க-சுற்றுலா-பயணிகள்-கோரிக்கை', 'திண்டுக்கல் மாவட்டம் கொடைக்கானலில் உள்ள சிட்டி வியூ பாயிண்ட், சுற்றுலா பயணிகளை அதிகம் கவரும் முக்கிய இடங்களில் ஒன்றாக உள்ளது. தினமும் ஏராளமான உள்நாட்டு மற்றும் …', 'திண்டுக்கல் மாவட்டம் கொடைக்கானலில் உள்ள சிட்டி வியூ பாயிண்ட், சுற்றுலா பயணிகளை அதிகம் கவரும் முக்கிய இடங்களில் ஒன்றாக உள்ளது. தினமும் ஏராளமான உள்நாட்டு மற்றும் வெளிநாட்டு சுற்றுலா பயணிகள் இங்கு வந்து இயற்கை அழகை ரசித்து செல்கின்றனர்.\r\nஇந்தப் பகுதியில் சில இடங்களில் பாதுகாப்பு வசதிகள் போதுமான அளவில் இல்லாததால், பார்வையாளர்கள் பள்ளத்தாக்கு விளிம்புப் பகுதிகளுக்கு அருகில் சென்று புகைப்படம் எடுப்பது ஆபத்தை ஏற்படுத்தும் சூழலை உருவாக்குவதாக கூறப்படுகிறது.\r\nஎனவே, பொதுமக்களின் பாதுகாப்பை உறுதி செய்யும் வகையில் சிட்டி வியூ பாயிண்ட்டின் ஆபத்தான பகுதிகளில் வலுவான பாதுகாப்பு வேலி அமைக்கவும், எச்சரிக்கை பலகைகள் மற்றும் கண்காணிப்பு வசதிகளை அதிகரிக்கவும் சுற்றுலா பயணிகள் கோரிக்கை விடுத்துள்ளனர்.மேலும், சுற்றுலா தலங்களில் பாதுகாப்பு நடவடிக்கைகள் வலுப்படுத்தப்பட்டால் விபத்துகளைத் தவிர்க்க முடியும் என்றும், இதற்கான நடவடிக்கையை சம்பந்தப்பட்ட துறையினர் விரைந்து மேற்கொள்ள வேண்டும் என்றும் அவர்கள் வலியுறுத்தியுள்ளனர்.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a522c4b7a9c55.93854672.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 17:13:41', 0, 1, 0, 0, 0, 'கொடைக்கானல்: சிட்டி வியூ பாயிண்ட்டில் பாதுகாப்பு வேலி அமைக்க சுற்றுலா பயணிகள் கோரிக்கை...    ', 'திண்டுக்கல் மாவட்டம் கொடைக்கானலில் உள்ள சிட்டி வியூ பாயிண்ட், சுற்றுலா பயணிகளை அதிகம் கவரும் முக்கிய இடங்களில் ஒன்றாக உள்ளது. தினமும் ஏராளமான உள்நாட்டு மற்றும் ', 10, 0, 0, 1, '2026-07-11 11:43:41', '2026-07-11 17:59:52', NULL, 0),
(269, 4, NULL, 1, NULL, NULL, NULL, 125, 'மாமல்லபுரத்தில் சோகம்: மின்சாரம் தாக்கி 4 பேர் பலி...', 'மாமல்லபுரத்தில்-சோகம்-மின்சாரம்-தாக்கி-4-பேர்-பலி', 'செங்கல்பட்டு மாவட்டம் மாமல்லபுரம் அருகே உள்ள தனியார் தங்கும் விடுதியில் ஆழ்துளைக் கிணறு (போர்வெல்) அமைக்கும் பணியின்போது ஏற்பட்ட விபத்தில் 4 தொழிலாளர்கள் உயிரிழ…', 'செங்கல்பட்டு மாவட்டம் மாமல்லபுரம் அருகே உள்ள தனியார் தங்கும் விடுதியில் ஆழ்துளைக் கிணறு (போர்வெல்) அமைக்கும் பணியின்போது ஏற்பட்ட விபத்தில் 4 தொழிலாளர்கள் உயிரிழந்தனர்.போர்வெல் குழாயை பொருத்தும் பணியின் போது, நீளமான உபகரணம் மேலே சென்ற மின்கம்பியில் உரசியதாக கூறப்படுகிறது. இதனால் உயர் மின்னழுத்தம் பாய்ந்து, பணியில் ஈடுபட்டிருந்த நான்கு பேரும் சம்பவ இடத்திலேயே உயிரிழந்தனர்.விபத்து குறித்து தகவல் அறிந்த போலீசார் மற்றும் மீட்புப் பணியாளர்கள் உடனடியாக சம்பவ இடத்திற்கு சென்று, உயிரிழந்தவர்களின் உடல்களை மீட்டு பிரேதப் பரிசோதனைக்காக அரசு மருத்துவமனைக்கு அனுப்பி வைத்தனர். மேலும், விபத்துக்கான காரணம் மற்றும் பாதுகாப்பு நடைமுறைகளில் ஏதேனும் அலட்சியம் ஏற்பட்டதா என்பது குறித்து விசாரணை நடத்தப்பட்டு வருகிறது.இந்த சம்பவம் அப்பகுதியில் பெரும் சோகத்தையும் அதிர்ச்சியையும் ஏற்படுத்தியுள்ளது. தொழிலாளர்கள் பணியாற்றும் இடங்களில் மின் பாதுகாப்பு விதிகளை கடுமையாக பின்பற்ற வேண்டும் என்ற கோரிக்கையும் வலுத்து வருகிறது.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a522f1f5eef67.90220428.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 17:25:23', 0, 1, 0, 0, 0, 'மாமல்லபுரத்தில் சோகம்: மின்சாரம் தாக்கி 4 பேர் பலி... ', 'செங்கல்பட்டு மாவட்டம் மாமல்லபுரம் அருகே உள்ள தனியார் தங்கும் விடுதியில் ஆழ்துளைக் கிணறு (போர்வெல்) அமைக்கும் பணியின்போது ஏற்பட்ட விபத்தில் 4 தொழிலாளர்கள் உயிரிழ', 9, 0, 0, 1, '2026-07-11 11:55:23', '2026-07-11 23:42:16', NULL, 0),
(270, 4, NULL, 1, NULL, NULL, NULL, 126, 'நாமக்கல், திருப்பூர் அரசு மருத்துவ கல்லூரிகளில் கூடுதல் 50 மாணவர் சேர்க்கை இடங்கள் ஒதுக்கீடு...', 'நாமக்கல்-திருப்பூர்-அரசு-மருத்துவ-கல்லூரிகளில்-கூடுதல்-150-மாணவர்-சேர்க்கை-இடங்கள்-ஒதுக்கீடு', 'தமிழகத்தில் மருத்துவக் கல்வியை விரிவுபடுத்தும் முயற்சியாக, நாமக்கல் மற்றும் திருப்பூர் அரசு மருத்துவக் கல்லூரிகளுக்கு தலா 50 கூடுதல் எம்பிபிஎஸ் (MBBS) மாணவர் சே…', 'தமிழகத்தில் மருத்துவக் கல்வியை விரிவுபடுத்தும் முயற்சியாக, நாமக்கல் மற்றும் திருப்பூர் அரசு மருத்துவக் கல்லூரிகளுக்கு தலா 50 கூடுதல் எம்பிபிஎஸ் (MBBS) மாணவர் சேர்க்கை இடங்களுக்கு அனுமதி வழங்கப்பட்டுள்ளது. இதன் மூலம், இரு கல்லூரிகளிலும் மாணவர் சேர்க்கை திறன் 100-இலிருந்து 150 ஆக உயர்கிறது.இந்த புதிய இடங்கள் 2026–27 கல்வியாண்டு முதல் நடைமுறைக்கு வரும் என தெரிவிக்கப்பட்டுள்ளது. மருத்துவக் கல்வியில் சேர விரும்பும் மாணவர்களுக்கு இது கூடுதல் வாய்ப்புகளை உருவாக்கும். மேலும், எதிர்காலத்தில் மாநிலத்தின் மருத்துவ சேவைக்கு தேவையான மருத்துவர்களின் எண்ணிக்கையையும் அதிகரிக்க இந்த நடவடிக்கை உதவும் என எதிர்பார்க்கப்படுகிறது.மருத்துவக் கல்வி வசதிகளை வலுப்படுத்தும் நோக்கில் தேசிய மருத்துவ ஆணையத்தின் (NMC) ஒப்புதலுடன் இந்த இடங்கள் அதிகரிக்கப்பட்டுள்ளன. இதன் மூலம் அரசு மருத்துவக் கல்லூரிகளில் தரமான மருத்துவக் கல்வியை அதிகமான மாணவர்கள் பெறும் வாய்ப்பு உருவாகியுள்ளது. \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5231f64ecd05.96942952.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 17:37:47', 0, 1, 0, 0, 0, 'நாமக்கல், திருப்பூர் அரசு மருத்துவ கல்லூரிகளில் கூடுதல் 50 மாணவர் சேர்க்கை இடங்கள் ஒதுக்கீடு...  ', 'தமிழகத்தில் மருத்துவக் கல்வியை விரிவுபடுத்தும் முயற்சியாக, நாமக்கல் மற்றும் திருப்பூர் அரசு மருத்துவக் கல்லூரிகளுக்கு தலா 50 கூடுதல் எம்பிபிஎஸ் (MBBS) மாணவர் சே', 17, 0, 0, 1, '2026-07-11 12:07:47', '2026-07-13 20:06:35', NULL, 0),
(271, 4, NULL, 1, NULL, NULL, NULL, 127, 'சித்தா, ஆயுர்வேதா, யுனானி மற்றும் ஓமியோபதி - மருத்துவ பட்டப்படிப்புக்கான மாணவர் சேர்க்கை அறிவிப்பு வெளியீடு...', 'சித்தா-ஆயுர்வேதா-யுனானி-மற்றும்-ஓமியோபதி-மருத்துவ-பட்டப்படிப்புக்கான-மாணவர்-சேர்க்கை-அறிவிப்பு-வெளியீடு', 'தமிழகத்தில் சித்தா, ஆயுர்வேதா, யுனானி மற்றும் ஹோமியோபதி உள்ளிட்ட இந்திய மருத்துவ முறைகளின் இளநிலை பட்டப்படிப்புகளுக்கான மாணவர் சேர்க்கை அறிவிப்பு வெளியிடப்பட்டு…', 'தமிழகத்தில் சித்தா, ஆயுர்வேதா, யுனானி மற்றும் ஹோமியோபதி உள்ளிட்ட இந்திய மருத்துவ முறைகளின் இளநிலை பட்டப்படிப்புகளுக்கான மாணவர் சேர்க்கை அறிவிப்பு வெளியிடப்பட்டுள்ளது.அரசு மற்றும் தனியார் மருத்துவக் கல்லூரிகளில் உள்ள இடங்களுக்கு தகுதியான மாணவர்கள் விண்ணப்பிக்கலாம் என்று தெரிவிக்கப்பட்டுள்ளது. தகுதி, இட ஒதுக்கீடு, கலந்தாய்வு நடைமுறை, முக்கிய தேதிகள் உள்ளிட்ட விவரங்கள் அதிகாரப்பூர்வ சேர்க்கை அறிவிப்பில் இடம்பெற்றுள்ளன.மாணவர்கள் தேவையான கல்வித் தகுதிகளை பூர்த்தி செய்து, குறிப்பிட்ட காலக்கெடுவிற்குள் விண்ணப்பங்களை சமர்ப்பிக்க வேண்டும் என அறிவுறுத்தப்பட்டுள்ளது. விண்ணப்பங்கள் பரிசீலிக்கப்பட்ட பிறகு, தரவரிசைப் பட்டியல் மற்றும் கலந்தாய்வு அட்டவணை வெளியிடப்படும்.மருத்துவத் துறையில் மாற்று மருத்துவ முறைகளை தேர்வு செய்ய விரும்பும் மாணவர்களுக்கு இந்த சேர்க்கை நடைமுறை முக்கிய வாய்ப்பாக அமையும். அதிகாரப்பூர்வ அறிவிப்பில் வழங்கப்பட்ட வழிகாட்டுதல்களை கவனமாக படித்து, அனைத்து ஆவணங்களையும் தயார் நிலையில் வைத்திருக்குமாறும் மாணவர்களுக்கு அறிவுறுத்தப்பட்டுள்ளது.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a52340ebf6741.01672124.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 17:46:45', 0, 1, 0, 0, 0, 'சித்தா, ஆயுர்வேதா, யுனானி மற்றும் ஓமியோபதி - மருத்துவ பட்டப்படிப்புக்கான மாணவர் சேர்க்கை அறிவிப்பு வெளியீடு... ', 'தமிழகத்தில் சித்தா, ஆயுர்வேதா, யுனானி மற்றும் ஹோமியோபதி உள்ளிட்ட இந்திய மருத்துவ முறைகளின் இளநிலை பட்டப்படிப்புகளுக்கான மாணவர் சேர்க்கை அறிவிப்பு வெளியிடப்பட்டு', 13, 0, 0, 1, '2026-07-11 12:16:45', '2026-07-14 03:37:10', NULL, 0),
(272, 4, NULL, 2, NULL, NULL, NULL, 128, 'காட்டு யானை தாக்கி 2 பேர் பலி...', 'காட்டு-யானை-தாக்கி-2-பேர்-பலி', 'சத்தீஷ்கார் மாநிலத்தில் காட்டு யானை தாக்கிய சம்பவத்தில் இரண்டு பேர் உயிரிழந்தனர். இந்தச் சம்பவம் அப்பகுதி மக்களிடையே அச்சத்தை ஏற்படுத்தியுள்ளது.வனப்பகுதியை ஒட்ட…', 'சத்தீஷ்கார் மாநிலத்தில் காட்டு யானை தாக்கிய சம்பவத்தில் இரண்டு பேர் உயிரிழந்தனர். இந்தச் சம்பவம் அப்பகுதி மக்களிடையே அச்சத்தை ஏற்படுத்தியுள்ளது.வனப்பகுதியை ஒட்டிய கிராமத்தில் இருந்தபோது காட்டு யானை திடீரென புகுந்து தாக்கியதாக கூறப்படுகிறது. இதில் இருவரும் பலத்த காயமடைந்த நிலையில் மீட்கப்பட்டாலும், சிகிச்சை பலனின்றி உயிரிழந்தனர்.சம்பவம் குறித்து தகவல் கிடைத்ததும் வனத்துறை மற்றும் உள்ளூர் நிர்வாக அதிகாரிகள் சம்பவ இடத்துக்கு சென்று ஆய்வு மேற்கொண்டனர். யானையின் நடமாட்டத்தை கண்காணித்து, பொதுமக்கள் எச்சரிக்கையுடன் இருக்குமாறும் அதிகாரிகள் அறிவுறுத்தியுள்ளனர்.\r\nமனிதர்கள் மற்றும் வனவிலங்குகள் இடையேயான மோதல்களை குறைக்கும் வகையில் கூடுதல் பாதுகாப்பு நடவடிக்கைகள் மேற்கொள்ளப்பட வேண்டும் என உள்ளூர் மக்கள் கோரிக்கை விடுத்துள்ளனர். சம்பவம் தொடர்பாக வனத்துறை தொடர்ந்து விசாரணை நடத்தி வருகிறது.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5235f5635aa7.21530521.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 17:54:31', 0, 1, 0, 0, 0, 'காட்டு யானை தாக்கி 2 பேர் பலி...  ', 'சத்தீஷ்கார் மாநிலத்தில் காட்டு யானை தாக்கிய சம்பவத்தில் இரண்டு பேர் உயிரிழந்தனர். இந்தச் சம்பவம் அப்பகுதி மக்களிடையே அச்சத்தை ஏற்படுத்தியுள்ளது.வனப்பகுதியை ஒட்ட', 41, 0, 0, 1, '2026-07-11 12:24:31', '2026-07-13 03:07:27', NULL, 0),
(273, 5, NULL, 2, NULL, NULL, NULL, 129, 'புகழ்பெற்ற பின்னணிப் பாடகி எஸ். ஜானகி காலமானார் – இசை உலகம் பேரிழப்பு', 'புகழ்பெற்ற-பின்னணிப்-பாடகி-எஸ்-ஜானகி-காலமானார்-இசை-உலகம்-பேரிழப்பு', 'இந்திய திரையிசை உலகின் தலைசிறந்த பின்னணிப் பாடகிகளில் ஒருவரான எஸ். ஜானகி, மைசூரில் இன்று காலமானார். அவருக்கு வயது 88.\r\n\r\nதமிழ், தெலுங்கு, கன்னடம், மலையாளம், இந்…', 'இந்திய திரையிசை உலகின் தலைசிறந்த பின்னணிப் பாடகிகளில் ஒருவரான எஸ். ஜானகி, மைசூரில் இன்று காலமானார். அவருக்கு வயது 88.\r\n\r\nதமிழ், தெலுங்கு, கன்னடம், மலையாளம், இந்தி உள்ளிட்ட பல இந்திய மொழிகளில் சுமார் 48,000 பாடல்களைப் பாடி, பல தலைமுறைகளின் மனதில் அழியாத இடத்தைப் பெற்றவர் எஸ். ஜானகி. தனித்துவமான குரல், உணர்வுபூர்வமான பாடும் பாணி மற்றும் இசைக்கான அர்ப்பணிப்பு ஆகியவற்றால் அவர் இந்திய இசை வரலாற்றில் தனி முத்திரை பதித்துள்ளார்.\r\n\r\nபல தசாப்தங்களாக திரையிசை உலகில் தனது குரலால் கோடிக்கணக்கான ரசிகர்களை கவர்ந்த அவர், ஏராளமான தேசிய மற்றும் மாநில விருதுகளைப் பெற்றுள்ளார். பல முன்னணி இசையமைப்பாளர்கள் மற்றும் பாடகர்களுடன் இணைந்து எண்ணற்ற காலத்தால் அழியாத பாடல்களை வழங்கியுள்ளார்.\r\n\r\nஎஸ். ஜானகியின் மறைவு இந்திய இசை உலகிற்கே ஈடு செய்ய முடியாத இழப்பாகக் கருதப்படுகிறது. அவரது மறைவுக்கு இசைக் கலைஞர்கள், திரையுலக பிரபலங்கள், அரசியல் தலைவர்கள் மற்றும் ரசிகர்கள் ஆழ்ந்த இரங்கல் தெரிவித்து வருகின்றனர்.\r\n\r\nஇசை ரசிகர்களின் நினைவில் அவரது இனிமையான குரலும், மறக்க முடியாத பாடல்களும் என்றும் நிலைத்திருக்கும்.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5284aedc18b0.15640866.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 23:30:19', 0, 1, 0, 0, 0, 'புகழ்பெற்ற பின்னணிப் பாடகி எஸ். ஜானகி காலமானார் – இசை உலகம் பேரிழப்பு', 'இந்திய திரையிசை உலகின் தலைசிறந்த பின்னணிப் பாடகிகளில் ஒருவரான எஸ். ஜானகி, மைசூரில் இன்று காலமானார். அவருக்கு வயது 88.\r\n\r\nதமிழ், தெலுங்கு, கன்னடம், மலையாளம், இந்', 17, 0, 0, 1, '2026-07-11 18:00:19', '2026-07-12 08:30:07', NULL, 0),
(274, 5, NULL, 1, NULL, NULL, NULL, 130, 'மாவீரன் அழகுமுத்துக்கோன் நினைவு நாள்', 'மாவீரன்-அழகுமுத்துக்கோன்-நினைவு-நாள்', 'இந்திய சுதந்திரப் போராட்ட வீரர் மாவீரன் அழகுமுத்துக்கோன் நினைவு நாளை முன்னிட்டு மலர் தூவி மரியாதை\r\n\r\nஇந்திய விடுதலைப் போராட்ட வரலாற்றில் தனித்துவமான இடத்தைப் பெ…', 'இந்திய சுதந்திரப் போராட்ட வீரர் மாவீரன் அழகுமுத்துக்கோன் நினைவு நாளை முன்னிட்டு மலர் தூவி மரியாதை\r\n\r\nஇந்திய விடுதலைப் போராட்ட வரலாற்றில் தனித்துவமான இடத்தைப் பெற்ற மாவீரன் அழகுமுத்துக்கோனின் நினைவு நாளையொட்டி, பல்வேறு இடங்களில் அவரது திருவுருவப் படத்திற்கு மலர் தூவி மரியாதை செலுத்தப்பட்டது.\r\n\r\n<strong>வெள்ளாளர் முன்னேற்றக் கழகத்தின் மாநில மகளிர் அணித் தலைவி அன்னலட்சுமி சகிலா கணேசன்</strong> தலைமையில் நடைபெற்ற நிகழ்ச்சியில், அழகுமுத்துக்கோனின் உருவப்படத்திற்கு மலர்மாலை அணிவித்து அஞ்சலி செலுத்தப்பட்டது. பின்னர் அவரது வீர வரலாறு மற்றும் சுதந்திரப் போராட்டத்திற்காக ஆற்றிய தியாகங்கள் குறித்து பொதுமக்களிடம் எடுத்துரைக்கப்பட்டது.\r\n\r\nநிகழ்ச்சியில் பேசியவர்கள், ஆங்கிலேய ஆட்சிக்கு எதிராக முதன்முதலில் ஆயுதம் ஏந்தி வீரமரணம் அடைந்த முன்னோடி போராட்ட வீரர்களில் அழகுமுத்துக்கோன் முக்கியமானவர் என்றும், அவரது தியாகத்தை இன்றைய தலைமுறையினர் அறிந்து கொள்ள வேண்டும் என்றும் வலியுறுத்தினர்.\r\n\r\nமேலும், நாட்டின் விடுதலைக்காக உயிர்நீத்த வீரர்களின் வரலாற்றை பள்ளி, கல்லூரி மாணவர்கள் அறிந்து கொள்ளும் வகையில் அரசு மற்றும் சமூக அமைப்புகள் தொடர்ந்து விழிப்புணர்வு நிகழ்ச்சிகளை நடத்த வேண்டும் எனவும் அவர்கள் கேட்டுக் கொண்டனர்.\r\n\r\nஇந்த நினைவு நாள் நிகழ்வில் அமைப்பின் நிர்வாகிகள், உறுப்பினர்கள், சமூக ஆர்வலர்கள் மற்றும் பொதுமக்கள் பலர் கலந்து கொண்டு மாவீரன் அழகுமுத்துக்கோனுக்கு மலர் தூவி மரியாதை செலுத்தினர்.', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5288932b1099.97523140.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-11 23:47:53', 0, 1, 0, 0, 0, 'மாவீரன் அழகுமுத்துக்கோன் நினைவு நாள் ', 'இந்திய சுதந்திரப் போராட்ட வீரர் மாவீரன் அழகுமுத்துக்கோன் நினைவு நாளை முன்னிட்டு மலர் தூவி மரியாதை\r\n\r\nஇந்திய விடுதலைப் போராட்ட வரலாற்றில் தனித்துவமான இடத்தைப் பெ', 15, 0, 0, 1, '2026-07-11 18:17:53', '2026-07-12 08:06:03', NULL, 0),
(275, 4, NULL, 2, NULL, NULL, NULL, 133, 'பாடகி எஸ். ஜானகி உடலுக்கு அரசு மரியாதையுடன் இறுதிச்சடங்கு: கர்நாடக அரசு அறிவிப்பு...', 'பாடகி-எஸ்-ஜானகி-உடலுக்கு-அரசு-மரியாதையுடன்-இறுதிச்சடங்கு-கர்நாடக-அரசு-அறிவிப்பு', 'புகழ்பெற்ற பின்னணிப் பாடகி எஸ். ஜானகி மறைவையொட்டி, அவருக்கு முழு அரசு மரியாதையுடன் இறுதிச்சடங்கு நடத்த கர்நாடக அரசு அறிவித்துள்ளது. மைசூருவில் நடைபெறும் இறுதி அ…', 'புகழ்பெற்ற பின்னணிப் பாடகி எஸ். ஜானகி மறைவையொட்டி, அவருக்கு முழு அரசு மரியாதையுடன் இறுதிச்சடங்கு நடத்த கர்நாடக அரசு அறிவித்துள்ளது. மைசூருவில் நடைபெறும் இறுதி அஞ்சலி நிகழ்வில் பொதுமக்கள், திரையுலகினர் மற்றும் இசை ரசிகர்கள் அஞ்சலி செலுத்தும் வகையில் ஏற்பாடுகள் செய்யப்பட்டுள்ளன.கர்நாடக அரசின் அறிவிப்பின்படி, அரசு சார்பில் அனைத்து மரியாதைகளும் வழங்கப்பட்டு இறுதிச்சடங்கு நடைபெறும். இதற்கான ஏற்பாடுகளை மாநில அரசு மேற்கொண்டுள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர். பல தசாப்தங்களாக ஆயிரக்கணக்கான பாடல்கள் மூலம் இந்திய இசை உலகில் தனித்துவமான இடத்தைப் பெற்ற எஸ். ஜானகியின் மறைவு, இசைத்துறைக்கு ஈடு செய்ய முடியாத இழப்பாகக் கருதப்படுகிறது. அவரது மறைவுக்கு அரசியல் தலைவர்கள், கலைஞர்கள் மற்றும் ரசிகர்கள் பலரும் ஆழ்ந்த இரங்கலைத் தெரிவித்துள்ளனர். \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a53250cb41ab4.37064462.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-12 10:52:17', 0, 1, 0, 0, 0, 'பாடகி எஸ். ஜானகி உடலுக்கு அரசு மரியாதையுடன் இறுதிச்சடங்கு: கர்நாடக அரசு அறிவிப்பு... ', 'புகழ்பெற்ற பின்னணிப் பாடகி எஸ். ஜானகி மறைவையொட்டி, அவருக்கு முழு அரசு மரியாதையுடன் இறுதிச்சடங்கு நடத்த கர்நாடக அரசு அறிவித்துள்ளது. மைசூருவில் நடைபெறும் இறுதி அ', 18, 0, 0, 1, '2026-07-12 05:22:17', '2026-07-13 08:16:43', NULL, 0);
INSERT INTO `tn_articles` (`id`, `user_id`, `contributor_id`, `category_id`, `district_id`, `city_id`, `city_text`, `media_id`, `title`, `slug`, `excerpt`, `content`, `content_type`, `sponsored_subscription_id`, `language`, `youtube_url`, `youtube_video_id`, `image_url`, `news_card_image`, `thumb_url`, `image_caption`, `image_credit`, `status`, `approval_stage`, `rejection_reason`, `approved_by`, `approved_at`, `scheduled_at`, `published_at`, `is_breaking`, `is_featured`, `is_editors_pick`, `is_premium`, `is_sponsored`, `meta_title`, `meta_desc`, `view_count`, `share_count`, `comment_count`, `read_time`, `created_at`, `updated_at`, `rating_avg`, `rating_count`) VALUES
(276, 4, NULL, 1, NULL, NULL, NULL, 134, 'அமோனியா வாயு கசிவு ஏற்பட்ட தொழிற்சாலையில் மரங்களை அகற்றும் பணி தீவிரம்...', 'அமோனியா-வாயு-கசிவு-ஏற்பட்ட-தொழிற்சாலையில்-மரங்களை-அகற்றும்-பணி-தீவிரம்', 'திருவள்ளூர் மாவட்டத்தில் அமோனியா வாயு கசிவு ஏற்பட்ட இறால் பதப்படுத்தும் தொழிற்சாலையில், மீட்பு மற்றும் பாதுகாப்பு நடவடிக்கைகள் தொடர்ந்து தீவிரமாக நடைபெற்று வருக…', 'திருவள்ளூர் மாவட்டத்தில் அமோனியா வாயு கசிவு ஏற்பட்ட இறால் பதப்படுத்தும் தொழிற்சாலையில், மீட்பு மற்றும் பாதுகாப்பு நடவடிக்கைகள் தொடர்ந்து தீவிரமாக நடைபெற்று வருகின்றன. தொழிற்சாலை வளாகத்தில் உள்ள பெரிய மரக்கிளைகள் மற்றும் அடர்ந்த தாவரங்கள் அகற்றப்பட்டு, மீட்பு மற்றும் ஆய்வுப் பணிகள் தடையின்றி நடைபெறுவதற்கான ஏற்பாடுகள் செய்யப்பட்டுள்ளன.அமோனியா வாயுவை முழுமையாக பாதுகாப்பான முறையில் வெளியேற்றும் பணியில் தொழில்நுட்ப நிபுணர்கள், தீயணைப்பு மற்றும் மீட்புப் படையினர், மாசுக்கட்டுப்பாட்டு வாரியம் உள்ளிட்ட பல்வேறு துறையினர் இணைந்து செயல்பட்டு வருகின்றனர். பணிகள் நடைபெறும் பகுதியில் பாதுகாப்பு வளையம் அமைக்கப்பட்டுள்ளதுடன், பொதுமக்கள் நுழைவுக்கும் தற்காலிக கட்டுப்பாடுகள் விதிக்கப்பட்டுள்ளன. சுற்றுப்புற சூழலை தொடர்ந்து கண்காணித்து, எந்தவித ஆபத்தும் ஏற்படாத வகையில் அதிகாரிகள் முன்னெச்சரிக்கை நடவடிக்கைகளை மேற்கொண்டு வருகின்றனர். அமோனியா வாயு அகற்றும் பணிகள் முழுமையாக நிறைவடைந்த பிறகு, தொழிற்சாலையில் விரிவான பாதுகாப்பு ஆய்வு மேற்கொள்ளப்பட்டு, அடுத்தகட்ட நடவடிக்கைகள் குறித்து மாவட்ட நிர்வாகம் முடிவு எடுக்க உள்ளது. \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a53267cb6fdd1.70481969.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-12 11:00:48', 0, 1, 0, 0, 0, 'அமோனியா வாயு கசிவு ஏற்பட்ட தொழிற்சாலையில் மரங்களை அகற்றும் பணி தீவிரம்... ', 'திருவள்ளூர் மாவட்டத்தில் அமோனியா வாயு கசிவு ஏற்பட்ட இறால் பதப்படுத்தும் தொழிற்சாலையில், மீட்பு மற்றும் பாதுகாப்பு நடவடிக்கைகள் தொடர்ந்து தீவிரமாக நடைபெற்று வருக', 9, 0, 0, 1, '2026-07-12 05:30:48', '2026-07-13 00:25:18', NULL, 0),
(277, 4, NULL, 1, NULL, NULL, NULL, 135, 'சென்னை: கடலில் குளித்தபோது ராட்சத அலையில் சிக்கி பிளஸ்-1 மாணவர் பலி...', 'சென்னை-கடலில்-குளித்தபோது-ராட்சத-அலையில்-சிக்கி-பிளஸ்-1-மாணவர்-பலி', 'சென்னை எண்ணூர் அருகே கடலில் குளிக்கச் சென்ற பள்ளி மாணவர்களில் ஒருவர் ராட்சத அலையில் சிக்கி உயிரிழந்த சம்பவம் சோகத்தை ஏற்படுத்தியுள்ளது. உயிரிழந்த மாணவர் பிளஸ்-1…', 'சென்னை எண்ணூர் அருகே கடலில் குளிக்கச் சென்ற பள்ளி மாணவர்களில் ஒருவர் ராட்சத அலையில் சிக்கி உயிரிழந்த சம்பவம் சோகத்தை ஏற்படுத்தியுள்ளது. உயிரிழந்த மாணவர் பிளஸ்-1 படித்து வந்த 15 வயது சிறுவர் என போலீசார் தெரிவித்துள்ளனர். நேற்று மாலை நண்பருடன் எண்ணூர் பெரியக்குப்பம் கடற்கரையில் குளித்துக் கொண்டிருந்தபோது திடீரென எழுந்த பலத்த அலை இருவரையும் கடலுக்குள் இழுத்துச் சென்றது. அங்கிருந்த மீனவர்கள் உடனடியாக மீட்புப் பணியில் ஈடுபட்டு இருவரையும் கரைக்கு கொண்டு வந்தனர். 108 ஆம்புலன்ஸ் மூலம் மருத்துவமனைக்கு கொண்டு செல்லப்பட்ட மாணவர்களில் ஒருவரை பரிசோதித்த மருத்துவர்கள், அவர் ஏற்கனவே உயிரிழந்துவிட்டதாக தெரிவித்தனர். மற்றொரு மாணவருக்கு தொடர்ந்து சிகிச்சை அளிக்கப்பட்டு வருகிறது.\r\nஇந்த சம்பவம் குறித்து போலீசார் வழக்குப்பதிவு செய்து விசாரணை நடத்தி வருகின்றனர். இதையடுத்து, கடலோரப் பகுதிகளில் பொதுமக்கள், குறிப்பாக மாணவர்கள் மற்றும் இளைஞர்கள், எச்சரிக்கையுடன் இருக்க வேண்டும் என்றும், அபாய எச்சரிக்கை விடுக்கப்படும் நேரங்களில் கடலில் இறங்க வேண்டாம் என்றும் அதிகாரிகள் அறிவுறுத்தியுள்ளனர். ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5327cf1b11a6.90718780.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-12 11:06:21', 0, 1, 0, 0, 0, 'சென்னை: கடலில் குளித்தபோது ராட்சத அலையில் சிக்கி பிளஸ்-1 மாணவர் பலி... ', 'சென்னை எண்ணூர் அருகே கடலில் குளிக்கச் சென்ற பள்ளி மாணவர்களில் ஒருவர் ராட்சத அலையில் சிக்கி உயிரிழந்த சம்பவம் சோகத்தை ஏற்படுத்தியுள்ளது. உயிரிழந்த மாணவர் பிளஸ்-1', 12, 0, 0, 1, '2026-07-12 05:36:21', '2026-07-12 18:06:19', NULL, 0),
(278, 4, NULL, 3, NULL, NULL, NULL, 136, 'ராக்கெட்டை வெற்றிகரமாக சோதித்தது ஜப்பான்', 'ராக்கெட்டை-வெற்றிகரமாக-சோதித்தது-ஜப்பான்', 'விண்வெளித் தொழில்நுட்பத்தில் புதிய முன்னேற்றமாக, மீண்டும் பயன்படுத்தக்கூடிய ராக்கெட்டின் சோதனையை ஜப்பான் வெற்றிகரமாக நிறைவு செய்துள்ளது. இந்தச் சோதனையின் மூலம்,…', 'விண்வெளித் தொழில்நுட்பத்தில் புதிய முன்னேற்றமாக, மீண்டும் பயன்படுத்தக்கூடிய ராக்கெட்டின் சோதனையை ஜப்பான் வெற்றிகரமாக நிறைவு செய்துள்ளது. இந்தச் சோதனையின் மூலம், ஏவுதலுக்குப் பிறகு ராக்கெட்டை பாதுகாப்பாக தரையிறக்கும் தொழில்நுட்பத்தை சோதித்து அதன் செயல்திறன் உறுதி செய்யப்பட்டது.இந்த சோதனையில், ராக்கெட் திட்டமிட்ட உயரம் வரை பறந்த பின்னர் கட்டுப்பாட்டுடன் செங்குத்தாக தரையிறங்கியது. சோதனையின் போது சேகரிக்கப்பட்ட தொழில்நுட்பத் தகவல்கள் அடுத்த கட்ட மேம்பாடுகளுக்கு பயன்படுத்தப்படும் என்று திட்டத்தை முன்னெடுக்கும் குழு தெரிவித்துள்ளது.மீண்டும் பயன்படுத்தக்கூடிய ராக்கெட் தொழில்நுட்பம், விண்வெளிப் பயணங்களின் செலவைக் குறைப்பதோடு, குறுகிய கால இடைவெளியில் அதிக ஏவுதல்களை மேற்கொள்ளவும் உதவும் என நிபுணர்கள் கூறுகின்றனர்.இந்த வெற்றிகரமான சோதனை, விண்வெளித் துறையில் ஜப்பானின் தொழில்நுட்ப திறனை மேலும் வலுப்படுத்தும் முயற்சியாகவும், எதிர்கால செயற்கைக்கோள் மற்றும் ஆய்வுப் பயணங்களுக்கு முக்கிய மைல்கல்லாகவும் பார்க்கப்படுகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a53295601d3d7.57595207.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-12 11:13:01', 0, 1, 0, 0, 0, ' ராக்கெட்டை வெற்றிகரமாக சோதித்தது ஜப்பான் ', 'விண்வெளித் தொழில்நுட்பத்தில் புதிய முன்னேற்றமாக, மீண்டும் பயன்படுத்தக்கூடிய ராக்கெட்டின் சோதனையை ஜப்பான் வெற்றிகரமாக நிறைவு செய்துள்ளது. இந்தச் சோதனையின் மூலம்,', 0, 0, 0, 1, '2026-07-12 05:43:01', '2026-07-12 11:14:05', NULL, 0),
(279, 4, NULL, 2, NULL, NULL, NULL, 137, 'வீட்டு கூரைகளில் சூரிய மின்சாரம்: இந்தியாவுக்கு உலக வங்கி ரூ.8,455 கோடி நிதி', 'வீட்டு-கூரைகளில்-சூரிய-மின்சாரம்-இந்தியாவுக்கு-உலக-வங்கி-ரூ8455-கோடி-நிதி', 'வீட்டு மாடிக் கூரைகளில் சூரிய மின்சார அமைப்புகளை அதிகரிக்கும் முயற்சிக்கு ஊக்கமளிக்கும் வகையில், இந்தியாவுக்கு உலக வங்கி ரூ.8,455 கோடி மதிப்பிலான நிதியுதவியை வழ…', 'வீட்டு மாடிக் கூரைகளில் சூரிய மின்சார அமைப்புகளை அதிகரிக்கும் முயற்சிக்கு ஊக்கமளிக்கும் வகையில், இந்தியாவுக்கு உலக வங்கி ரூ.8,455 கோடி மதிப்பிலான நிதியுதவியை வழங்கியுள்ளது. இந்த நிதி, புதுப்பிக்கத்தக்க எரிசக்தி பயன்பாட்டை விரிவுபடுத்தவும், தூய்மையான மின்சார உற்பத்தியை ஊக்குவிக்கவும் பயன்படுத்தப்பட உள்ளது.இந்தத் திட்டத்தின் மூலம் வீடுகளில் சூரிய மின்சார அமைப்புகளை நிறுவுவதற்கு தேவையான உள்கட்டமைப்பு மேம்படுத்தப்படுவதுடன், மின் விநியோக அமைப்புகளும் வலுப்படுத்தப்பட உள்ளன. மேலும், மின்சாரச் செலவைக் குறைப்பதோடு சுற்றுச்சூழலுக்கு உகந்த ஆற்றல் பயன்பாட்டையும் அதிகரிப்பதே திட்டத்தின் முக்கிய நோக்கமாகும்.\r\nமத்திய அரசின் வீட்டு மாடி சூரிய மின்சாரத் திட்டத்திற்கு இந்த நிதி கூடுதல் ஊக்கமாக அமையும் என அதிகாரிகள் தெரிவித்துள்ளனர். இதன் மூலம் நகர்ப்புறங்களும் கிராமப்புறங்களும் சேர்ந்த அதிகமான குடும்பங்கள் சூரிய மின்சார வசதியைப் பெறும் வாய்ப்பு உருவாகும்.\r\nபுதுப்பிக்கத்தக்க எரிசக்தி துறையில் இந்தியாவின் வளர்ச்சியை வேகப்படுத்தவும், கார்பன் உமிழ்வைக் குறைக்கும் இலக்கை அடையவும் இந்த நிதியுதவி முக்கிய பங்காற்றும் என எதிர்பார்க்கப்படுகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a532ade2dd501.73087283.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-12 11:19:23', 0, 1, 0, 0, 0, 'வீட்டு கூரைகளில் சூரிய மின்சாரம்: இந்தியாவுக்கு உலக வங்கி ரூ.8,455 கோடி நிதி ', 'வீட்டு மாடிக் கூரைகளில் சூரிய மின்சார அமைப்புகளை அதிகரிக்கும் முயற்சிக்கு ஊக்கமளிக்கும் வகையில், இந்தியாவுக்கு உலக வங்கி ரூ.8,455 கோடி மதிப்பிலான நிதியுதவியை வழ', 8, 0, 0, 1, '2026-07-12 05:49:23', '2026-07-13 08:19:08', NULL, 0),
(280, 4, NULL, 2, NULL, NULL, NULL, 138, 'மராட்டியத்தில் மீண்டும் நிலநடுக்கம்', 'மராட்டியத்தில்-மீண்டும்-நிலநடுக்கம்', 'மராட்டிய மாநிலத்தின் மராத்வாடா பகுதியில் மீண்டும் நிலநடுக்க அதிர்வுகள் உணரப்பட்டதால் பொதுமக்களிடையே அச்சம் நிலவியது.நான்டேட், ஹிங்கோலி மற்றும் பர்பானி மாவட்டங்க…', 'மராட்டிய மாநிலத்தின் மராத்வாடா பகுதியில் மீண்டும் நிலநடுக்க அதிர்வுகள் உணரப்பட்டதால் பொதுமக்களிடையே அச்சம் நிலவியது.நான்டேட், ஹிங்கோலி மற்றும் பர்பானி மாவட்டங்களில் அதிகாலை நேரத்தில் அடுத்தடுத்து பல மிதமான நிலநடுக்க அதிர்வுகள் பதிவாகின. ரிக்டர் அளவுகோலில் 3.6 முதல் 4.6 வரை தீவிரம் பதிவானதாக அதிகாரிகள் தெரிவித்துள்ளனர். அதிர்வுகளை உணர்ந்த மக்கள் பலர் பாதுகாப்பு கருதி வீடுகளை விட்டு வெளியேறி திறந்தவெளி பகுதிகளில் தஞ்சமடைந்தனர். இதனால் சில மணி நேரம் பதற்றமான சூழல் காணப்பட்டது.இதுவரை உயிரிழப்பு அல்லது பெரிய அளவிலான சேதம் ஏற்பட்டதாக எந்த அதிகாரப்பூர்வ தகவலும் வெளியாகவில்லை. நிலைமையை மாவட்ட நிர்வாகம் மற்றும் பேரிடர் மேலாண்மை அதிகாரிகள் தொடர்ந்து கண்காணித்து வருகின்றனர். மேலும், வதந்திகளை நம்பாமல் அதிகாரப்பூர்வ அறிவிப்புகளை மட்டுமே பொதுமக்கள் பின்பற்ற வேண்டும் என்று அதிகாரிகள் அறிவுறுத்தியுள்ளனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a532e12ea6568.65551309.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-12 11:34:10', 0, 1, 0, 0, 0, 'மராட்டியத்தில் மீண்டும் நிலநடுக்கம்', 'மராட்டிய மாநிலத்தின் மராத்வாடா பகுதியில் மீண்டும் நிலநடுக்க அதிர்வுகள் உணரப்பட்டதால் பொதுமக்களிடையே அச்சம் நிலவியது.நான்டேட், ஹிங்கோலி மற்றும் பர்பானி மாவட்டங்க', 11, 0, 0, 1, '2026-07-12 06:04:10', '2026-07-13 17:05:42', NULL, 0),
(281, 4, NULL, 1, NULL, NULL, NULL, 139, 'தமிழக செய்திகள் விடுமுறை தினம்: குற்றாலத்தில் சுற்றுலா பயணிகள் உற்சாக குளியல்...', 'தமிழக-செய்திகள்-விடுமுறை-தினம்-குற்றாலத்தில்-சுற்றுலா-பயணிகள்-உற்சாக-குளியல்', 'விடுமுறை தினத்தை முன்னிட்டு தென்காசி மாவட்டம் குற்றாலத்திற்கு ஏராளமான சுற்றுலா பயணிகள் வருகை தந்தனர். இதனால் முக்கிய அருவிகள் மற்றும் சுற்றுலா மையங்களில் காலை ம…', 'விடுமுறை தினத்தை முன்னிட்டு தென்காசி மாவட்டம் குற்றாலத்திற்கு ஏராளமான சுற்றுலா பயணிகள் வருகை தந்தனர். இதனால் முக்கிய அருவிகள் மற்றும் சுற்றுலா மையங்களில் காலை முதலே கூட்டம் அதிகரித்தது.மெயின் அருவி, ஐந்தருவி, பழைய குற்றாலம் உள்ளிட்ட பகுதிகளில் குடும்பத்தினருடன் வந்திருந்த பயணிகள் அருவி நீரில் மகிழ்ச்சியுடன் குளித்து இயற்கை சூழலை ரசித்தனர். சிறுவர்கள் முதல் பெரியவர்கள் வரை அனைவரும் உற்சாகமாக பொழுதைக் கழித்தனர்.\r\nசுற்றுலா பயணிகளின் வருகையால் வாகன நிறுத்துமிடங்கள், உணவகங்கள் மற்றும் உள்ளூர் வணிக நிலையங்களிலும் பரபரப்பு காணப்பட்டது. பாதுகாப்பு நடவடிக்கையாக காவல்துறையினரும் தீயணைப்பு மற்றும் மீட்புப் பணியாளர்களும் முக்கிய இடங்களில் கண்காணிப்பில் ஈடுபட்டனர்.அருவிப் பகுதிகளில் பொதுமக்கள் பாதுகாப்பு விதிமுறைகளை கடைப்பிடிக்கவும், ஆபத்தான பகுதிகளுக்குச் செல்லாமல் எச்சரிக்கையுடன் இருக்கவும் அதிகாரிகள் அறிவுறுத்தியுள்ளனர்.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a53310921c526.26828763.webp', NULL, NULL, NULL, NULL, 'published', 'published', NULL, 4, '2026-07-12 06:17:02', NULL, '2026-07-12 11:46:27', 0, 1, 0, 0, 0, 'தமிழக செய்திகள் விடுமுறை தினம்: குற்றாலத்தில் சுற்றுலா பயணிகள் உற்சாக குளியல்...  ', 'விடுமுறை தினத்தை முன்னிட்டு தென்காசி மாவட்டம் குற்றாலத்திற்கு ஏராளமான சுற்றுலா பயணிகள் வருகை தந்தனர். இதனால் முக்கிய அருவிகள் மற்றும் சுற்றுலா மையங்களில் காலை ம', 32, 0, 0, 1, '2026-07-12 06:16:27', '2026-07-13 18:32:11', NULL, 0),
(282, 4, NULL, 3, NULL, NULL, NULL, 140, 'வங்காளதேசத்தில் வெள்ளம், நிலச்சரிவு; 51 பேர் பலி...', 'வங்காளதேசத்தில்-வெள்ளம்-நிலச்சரிவு-51-பேர்-பலி', 'வங்காளதேசத்தின் தென்கிழக்குப் பகுதிகளில் கடந்த சில நாட்களாக பெய்து வரும் கனமழையால் ஏற்பட்ட வெள்ளம் மற்றும் நிலச்சரிவுகளில் உயிரிழந்தோரின் எண்ணிக்கை 51 ஆக உயர்ந்…', 'வங்காளதேசத்தின் தென்கிழக்குப் பகுதிகளில் கடந்த சில நாட்களாக பெய்து வரும் கனமழையால் ஏற்பட்ட வெள்ளம் மற்றும் நிலச்சரிவுகளில் உயிரிழந்தோரின் எண்ணிக்கை 51 ஆக உயர்ந்துள்ளது.சிட்டகாங், காக்ஸ் பசார், பந்தர்பன், ரங்கமட்டி உள்ளிட்ட பல மாவட்டங்கள் கடுமையாக பாதிக்கப்பட்டுள்ளன. வெள்ளநீரால் ஆயிரக்கணக்கான வீடுகள் சேதமடைந்ததுடன், சாலைகள் மற்றும் பாலங்கள் பாதிக்கப்பட்டதால் பல கிராமங்கள் வெளி உலகத் தொடர்பை இழந்துள்ளன. ஒரு மில்லியனுக்கும் அதிகமான மக்கள் வெள்ளத்தால் பாதிக்கப்பட்டுள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர். தாழ்வான பகுதிகளில் வசிக்கும் மக்களை பாதுகாப்பான முகாம்களுக்கு மாற்றும் பணிகள் தீவிரமாக நடைபெற்று வருகின்றன. ராணுவம் மற்றும் மீட்புக் குழுக்கள் படகுகள் மூலம் உணவு, குடிநீர் மற்றும் அத்தியாவசிய பொருட்களை வழங்கி வருகின்றன. தொடர்ந்து கனமழை நீடிக்கும் என வானிலை மையம் எச்சரித்துள்ளதால், மேலும் வெள்ளப்பெருக்கு மற்றும் நிலச்சரிவு ஏற்படும் அபாயம் இருப்பதாக அதிகாரிகள் எச்சரிக்கை விடுத்துள்ளனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a546f95051b18.08636951.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:24:54', 0, 1, 0, 0, 0, 'வங்காளதேசத்தில் வெள்ளம், நிலச்சரிவு; 51 பேர் பலி...   ', 'வங்காளதேசத்தின் தென்கிழக்குப் பகுதிகளில் கடந்த சில நாட்களாக பெய்து வரும் கனமழையால் ஏற்பட்ட வெள்ளம் மற்றும் நிலச்சரிவுகளில் உயிரிழந்தோரின் எண்ணிக்கை 51 ஆக உயர்ந்', 0, 0, 0, 1, '2026-07-13 04:54:54', '2026-07-13 10:25:04', NULL, 0),
(283, 4, NULL, 1, NULL, NULL, NULL, 142, 'பாம்பன் பழைய தூக்குப்பாலத்தின் ஒரு பகுதி அகற்றம்...', 'பாம்பன்-பழைய-தூக்குப்பாலத்தின்-ஒரு-பகுதி-அகற்றம்', 'ராமேஸ்வரம்–மண்டபம் இடையே அமைந்துள்ள வரலாற்றுச் சிறப்புமிக்க பாம்பன் பழைய தூக்குப்பாலத்தின் ஒரு பகுதியை அகற்றும் பணிகள் தொடங்கப்பட்டுள்ளன. பல ஆண்டுகளாக பயன்பாட்ட…', 'ராமேஸ்வரம்–மண்டபம் இடையே அமைந்துள்ள வரலாற்றுச் சிறப்புமிக்க பாம்பன் பழைய தூக்குப்பாலத்தின் ஒரு பகுதியை அகற்றும் பணிகள் தொடங்கப்பட்டுள்ளன. பல ஆண்டுகளாக பயன்பாட்டில் இருந்த இந்தப் பாலத்தின் பழுதடைந்த பகுதிகளை பாதுகாப்பு காரணங்களுக்காக அகற்றும் நடவடிக்கை மேற்கொள்ளப்பட்டு வருகிறது.\r\nரயில்வே துறை மற்றும் தொழில்நுட்ப நிபுணர்களின் மேற்பார்வையில் நடைபெறும் இந்தப் பணிகளில், சிறப்பு இயந்திரங்கள் மற்றும் கனரக உபகரணங்கள் பயன்படுத்தப்பட்டு பாலத்தின் சேதமடைந்த கட்டமைப்புகள் கவனமாக பிரிக்கப்பட்டு அகற்றப்படுகின்றன.\r\nபணிகள் நடைபெறும் காலத்தில் பாதுகாப்பு முன்னெச்சரிக்கை நடவடிக்கைகள் பலப்படுத்தப்பட்டுள்ளன. கடல்சார் போக்குவரத்து மற்றும் சுற்றுப்புற பகுதிகளில் எந்தவித பாதிப்பும் ஏற்படாத வகையில் அதிகாரிகள் தொடர்ந்து கண்காணித்து வருகின்றனர்.\r\nபழைய பாலத்தின் வரலாற்று முக்கியத்துவத்தை கருத்தில் கொண்டு, அதன் நினைவுச் சின்ன மதிப்பை பாதுகாக்கும் நடவடிக்கைகளும் பரிசீலனையில் உள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர். பணிகள் நிறைவடைந்த பின்னர் அடுத்தகட்ட பராமரிப்பு மற்றும் கட்டமைப்பு தொடர்பான நடவடிக்கைகள் மேற்கொள்ளப்படும் என எதிர்பார்க்கப்படுகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54707279aef6.33950233.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:28:33', 0, 1, 0, 0, 0, 'பாம்பன் பழைய தூக்குப்பாலத்தின் ஒரு பகுதி அகற்றம்...  ', 'ராமேஸ்வரம்–மண்டபம் இடையே அமைந்துள்ள வரலாற்றுச் சிறப்புமிக்க பாம்பன் பழைய தூக்குப்பாலத்தின் ஒரு பகுதியை அகற்றும் பணிகள் தொடங்கப்பட்டுள்ளன. பல ஆண்டுகளாக பயன்பாட்ட', 5, 0, 0, 1, '2026-07-13 04:58:33', '2026-07-14 05:26:13', NULL, 0),
(284, 4, NULL, 1, NULL, NULL, NULL, 143, 'ராமேஸ்வரத்தில் திடீரென உள்வாங்கிய கடல்.!...', 'ராமேஸ்வரத்தில்-திடீரென-உள்வாங்கிய-கடல்', 'ராமேஸ்வரம் கடற்கரை பகுதியில் திடீரென கடல் நீர் உள்வாங்கியதால், வழக்கமாக நீரில் மூழ்கியிருக்கும் பாறைகள், பாசி படர்ந்த பகுதிகள் மற்றும் கடலடிப் பரப்பின் சில பகுத…', 'ராமேஸ்வரம் கடற்கரை பகுதியில் திடீரென கடல் நீர் உள்வாங்கியதால், வழக்கமாக நீரில் மூழ்கியிருக்கும் பாறைகள், பாசி படர்ந்த பகுதிகள் மற்றும் கடலடிப் பரப்பின் சில பகுதிகள் வெளிப்படையாகக் காட்சியளித்தன. இந்த அரிய இயற்கைக் காட்சியை காண ஏராளமான பக்தர்களும் சுற்றுலா பயணிகளும் கடற்கரையில் திரண்டனர்.கடல் நீர் பல மீட்டர் தூரம் உள்வாங்கியதால், சில இடங்களில் நாட்டுப்படகுகள் தரையைத் தொட்டு நின்றன. மேலும், பாதுகாப்பு காரணங்களுக்காக சில கடல்சார் நடவடிக்கைகள் தற்காலிகமாக கட்டுப்படுத்தப்பட்டதாகத் தகவல்கள் தெரிவிக்கின்றன.கடலோர பகுதியை பார்வையிட வந்தவர்கள் இந்த நிகழ்வை புகைப்படம் மற்றும் வீடியோவாக பதிவு செய்து சமூக வலைதளங்களில் பகிர்ந்தனர். பின்னர் சில மணி நேரங்களில் கடல் நீர் மீண்டும் இயல்பான நிலைக்குத் திரும்பியது.கடலியல் நிபுணர்களின் விளக்கப்படி, பருவக்காற்று, அலைச்சுழற்சி மற்றும் கடல் நீர்மட்ட மாற்றங்கள் போன்ற இயற்கை காரணங்களால் இத்தகைய நிகழ்வுகள் அவ்வப்போது ஏற்படக்கூடும் என்றும், இது அசாதாரண பேரிடரைக் குறிக்கும் அறிகுறி அல்ல என்றும் தெரிவிக்கப்பட்டுள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a547135407585.79776137.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:31:44', 0, 1, 0, 0, 0, 'ராமேஸ்வரத்தில் திடீரென உள்வாங்கிய கடல்.!...  ', 'ராமேஸ்வரம் கடற்கரை பகுதியில் திடீரென கடல் நீர் உள்வாங்கியதால், வழக்கமாக நீரில் மூழ்கியிருக்கும் பாறைகள், பாசி படர்ந்த பகுதிகள் மற்றும் கடலடிப் பரப்பின் சில பகுத', 0, 0, 0, 1, '2026-07-13 05:01:44', '2026-07-13 10:32:09', NULL, 0),
(285, 4, NULL, 1, NULL, NULL, NULL, 144, 'மின் தடையால் தண்ணீர் பாய்ச்ச வழியின்றி காய்ந்து வரும் நெற்பயிர்கள்...', 'மின்-தடையால்-தண்ணீர்-பாய்ச்ச-வழியின்றி-காய்ந்து-வரும்-நெற்பயிர்கள்', 'தொடர்ச்சியான மின் தடையால் பாசனத்திற்குத் தேவையான தண்ணீரை வயல்களுக்கு பாய்ச்ச முடியாமல், பல பகுதிகளில் நெற்பயிர்கள் காய்ந்து வருவதாக விவசாயிகள் வேதனை தெரிவித்துள…', 'தொடர்ச்சியான மின் தடையால் பாசனத்திற்குத் தேவையான தண்ணீரை வயல்களுக்கு பாய்ச்ச முடியாமல், பல பகுதிகளில் நெற்பயிர்கள் காய்ந்து வருவதாக விவசாயிகள் வேதனை தெரிவித்துள்ளனர். குறிப்பாக மின்மோட்டார்களை நம்பி சாகுபடி செய்து வரும் விவசாயிகள் கடுமையாக பாதிக்கப்பட்டுள்ளனர்.பயிர்கள் வளர்ச்சியின் முக்கிய கட்டத்தில் இருக்கும் நிலையில், நீர் கிடைக்காததால் நெற்பயிர்களின் இலைகள் வாடத் தொடங்கியுள்ளன. இதனால் விளைச்சல் குறையும் அபாயம் ஏற்பட்டுள்ளதாகவும், சாகுபடிக்காக எடுத்த கடன்களை திருப்பிச் செலுத்த முடியுமோ என்ற அச்சமும் விவசாயிகள் மத்தியில் நிலவுகிறது.மின் விநியோகம் சீராக இல்லாததால் இரவு நேரங்களிலும் விவசாயிகள் வயல்களில் காத்திருந்து மின்சாரம் வந்தவுடன் தண்ணீர் பாய்ச்சும் நிலை ஏற்பட்டுள்ளது. இருப்பினும் போதுமான நேரம் மின்சாரம் கிடைக்காததால் பயிர்களை காப்பாற்ற முடியாமல் தவித்து வருகின்றனர்.எனவே, விவசாய பாசனத்திற்கான மின் விநியோகத்தை இடையூறு இல்லாமல் வழங்கவும், பாதிக்கப்பட்ட பகுதிகளில் உடனடி ஆய்வு மேற்கொண்டு தேவையான நிவாரண நடவடிக்கைகளை அரசு எடுக்க வேண்டும் என்று விவசாயிகள் வலியுறுத்தியுள்ளனர்.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5472a13d63a1.65091804.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:37:58', 0, 1, 0, 0, 0, 'மின் தடையால் தண்ணீர் பாய்ச்ச வழியின்றி காய்ந்து வரும் நெற்பயிர்கள்...  ', 'தொடர்ச்சியான மின் தடையால் பாசனத்திற்குத் தேவையான தண்ணீரை வயல்களுக்கு பாய்ச்ச முடியாமல், பல பகுதிகளில் நெற்பயிர்கள் காய்ந்து வருவதாக விவசாயிகள் வேதனை தெரிவித்துள', 0, 0, 0, 1, '2026-07-13 05:07:58', '2026-07-13 10:38:14', NULL, 0),
(286, 4, NULL, 1, NULL, NULL, NULL, 145, '6 மாதங்களில் மு.க.ஸ்டாலின் முதல்-அமைச்சர் ஆவார்: அனிதா ராதாகிருஷ்ணன்', '6-மாதங்களில்-முகஸ்டாலின்-முதல்-அமைச்சர்-ஆவார்-அனிதா-ராதாகிருஷ்ணன்', 'தமிழக அரசியல் சூழல் குறித்து பேசிய அமைச்சர் அனிதா ராதாகிருஷ்ணன், அடுத்த ஆறு மாதங்களுக்குள் மு.க. ஸ்டாலின் மீண்டும் முதல்-அமைச்சராக பொறுப்பேற்பார் என்ற நம்பிக்கை…', 'தமிழக அரசியல் சூழல் குறித்து பேசிய அமைச்சர் அனிதா ராதாகிருஷ்ணன், அடுத்த ஆறு மாதங்களுக்குள் மு.க. ஸ்டாலின் மீண்டும் முதல்-அமைச்சராக பொறுப்பேற்பார் என்ற நம்பிக்கையை வெளிப்படுத்தினார்.ஒரு பொதுக்கூட்டத்தில் உரையாற்றிய அவர், அரசின் மக்கள் நலத் திட்டங்கள் பொதுமக்களிடையே நல்ல வரவேற்பைப் பெற்றுள்ளதாகவும், அதனால் ஆளும் கட்சிக்கு மக்கள் ஆதரவு தொடர்ந்து அதிகரித்து வருவதாகவும் கூறினார்.வரவிருக்கும் தேர்தலில் கட்சி தொண்டர்கள் ஒற்றுமையுடன் செயல்பட்டு வெற்றிக்காக உழைக்க வேண்டும் என்றும், அரசின் சாதனைகளை மக்களிடம் எடுத்துரைக்க வேண்டியது அவசியம் என்றும் அவர் வலியுறுத்தினார்.மேலும், தமிழகத்தின் வளர்ச்சிக்காக பல்வேறு துறைகளில் மேற்கொள்ளப்பட்டுள்ள திட்டங்கள் எதிர்காலத்திலும் தொடரும் என்றும், மக்கள் மீண்டும் தற்போதைய ஆட்சிக்கு ஆதரவு அளிப்பார்கள் என்ற நம்பிக்கையையும் அவர் தெரிவித்தார்.இந்தப் பேச்சு அரசியல் வட்டாரங்களில் கவனத்தை ஈர்த்துள்ள நிலையில், பல்வேறு கட்சித் தலைவர்களும் இதற்கு தங்களது கருத்துகளை தெரிவித்து வருகின்றனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5474657f7df3.38783118.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:45:23', 0, 1, 0, 0, 0, '6 மாதங்களில் மு.க.ஸ்டாலின் முதல்-அமைச்சர் ஆவார்: அனிதா ராதாகிருஷ்ணன் ', 'தமிழக அரசியல் சூழல் குறித்து பேசிய அமைச்சர் அனிதா ராதாகிருஷ்ணன், அடுத்த ஆறு மாதங்களுக்குள் மு.க. ஸ்டாலின் மீண்டும் முதல்-அமைச்சராக பொறுப்பேற்பார் என்ற நம்பிக்கை', 0, 0, 0, 1, '2026-07-13 05:15:23', '2026-07-13 10:45:59', NULL, 0),
(287, 4, NULL, 2, NULL, NULL, NULL, 146, 'ஜம்மு-காஷ்மீரில் லேசான நில அதிர்வு', 'ஜம்மு-காஷ்மீரில்-லேசான-நில-அதிர்வு', 'ஜம்மு-காஷ்மீரின் சில பகுதிகளில் இன்று லேசான நில அதிர்வு உணரப்பட்டதால் பொதுமக்கள் சிறிது நேரம் பதற்றமடைந்தனர். நிலநடுக்கம் ஏற்பட்டதைத் தொடர்ந்து பலர் பாதுகாப்பு …', 'ஜம்மு-காஷ்மீரின் சில பகுதிகளில் இன்று லேசான நில அதிர்வு உணரப்பட்டதால் பொதுமக்கள் சிறிது நேரம் பதற்றமடைந்தனர். நிலநடுக்கம் ஏற்பட்டதைத் தொடர்ந்து பலர் பாதுகாப்பு கருதி வீடுகள் மற்றும் அலுவலகங்களில் இருந்து திறந்த வெளிப் பகுதிகளுக்கு வெளியேறினர்.\r\nஇந்த நில அதிர்வு குறுகிய நேரமே நீடித்ததாகவும், இதனால் உயிரிழப்பு அல்லது பெரிய அளவிலான சேதங்கள் எதுவும் பதிவாகவில்லை என்றும் ஆரம்பகட்ட தகவல்கள் தெரிவிக்கின்றன.நிலநடுக்கத்தின் மையப்பகுதி மற்றும் அதன் ரிக்டர் அளவு குறித்து சம்பந்தப்பட்ட நில அதிர்வு கண்காணிப்பு அமைப்புகள் ஆய்வு மேற்கொண்டு வருகின்றன. அதிகாரிகள் தொடர்ந்து நிலைமையை கண்காணித்து வருவதாகவும், பொதுமக்கள் தேவையற்ற வதந்திகளை நம்ப வேண்டாம் என்றும் அறிவுறுத்தியுள்ளனர்.நில அதிர்வைத் தொடர்ந்து பேரிடர் மேலாண்மை மற்றும் உள்ளூர் நிர்வாக அதிகாரிகள் முன்னெச்சரிக்கை நடவடிக்கைகளை மேற்கொண்டு, பாதிப்பு ஏற்பட்டுள்ளதா என்பதை ஆய்வு செய்து வருகின்றனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a547540e1f9a7.96239604.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:49:27', 0, 1, 0, 0, 0, 'ஜம்மு-காஷ்மீரில் லேசான நில அதிர்வு ', 'ஜம்மு-காஷ்மீரின் சில பகுதிகளில் இன்று லேசான நில அதிர்வு உணரப்பட்டதால் பொதுமக்கள் சிறிது நேரம் பதற்றமடைந்தனர். நிலநடுக்கம் ஏற்பட்டதைத் தொடர்ந்து பலர் பாதுகாப்பு ', 0, 0, 0, 1, '2026-07-13 05:19:27', '2026-07-13 10:49:45', NULL, 0),
(288, 4, NULL, 2, NULL, NULL, NULL, 147, 'ககன்யான் விண்கலத்தில் 3 புதிய சோதனைகள் வெற்றி...', 'ககன்யான்-விண்கலத்தில்-3-புதிய-சோதனைகள்-வெற்றி', 'இந்தியாவின் மனித விண்வெளி பயணத் திட்டமான **ககன்யான்** திட்டத்தில் மேற்கொள்ளப்பட்ட மூன்று முக்கிய தொழில்நுட்ப சோதனைகள் வெற்றிகரமாக நிறைவடைந்துள்ளதாக இந்திய விண்வ…', 'இந்தியாவின் மனித விண்வெளி பயணத் திட்டமான **ககன்யான்** திட்டத்தில் மேற்கொள்ளப்பட்ட மூன்று முக்கிய தொழில்நுட்ப சோதனைகள் வெற்றிகரமாக நிறைவடைந்துள்ளதாக இந்திய விண்வெளி ஆராய்ச்சி நிறுவனம் (இஸ்ரோ) தெரிவித்துள்ளது.\r\nவிண்கலத்தின் பாதுகாப்பு, தகவல் தொடர்பு மற்றும் கட்டுப்பாட்டு அமைப்புகளின் செயல்திறனை மதிப்பீடு செய்யும் நோக்கில் இந்த சோதனைகள் மேற்கொள்ளப்பட்டன. அனைத்து அமைப்புகளும் எதிர்பார்த்தபடி செயல்பட்டதாகவும், சோதனை முடிவுகள் திருப்திகரமாக இருந்ததாகவும் அதிகாரிகள் கூறியுள்ளனர்.இந்த வெற்றிகரமான சோதனைகள், ககன்யான் திட்டத்தின் அடுத்த கட்ட பணிகளுக்கு முக்கிய முன்னேற்றமாகக் கருதப்படுகின்றன. மனிதர்களை விண்வெளிக்கு பாதுகாப்பாக அனுப்புவதற்கான பல்வேறு தொழில்நுட்ப அம்சங்கள் தொடர்ந்து பரிசோதிக்கப்பட்டு வருகின்றன.எதிர்வரும் கட்டங்களிலும் மேலும் பல சோதனைகள் திட்டமிடப்பட்டுள்ள நிலையில், அவை வெற்றிகரமாக நிறைவடைந்தால் இந்தியாவின் முதல் மனித விண்வெளி பயணத்தை மேற்கொள்ளும் இலக்கை நோக்கி ககன்யான் திட்டம் மேலும் ஒரு படி முன்னேறும் என விண்வெளி ஆராய்ச்சி வட்டாரங்கள் தெரிவித்துள்ளன.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5476546ecdb7.39714949.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:53:43', 0, 1, 0, 0, 0, 'ககன்யான் விண்கலத்தில் 3 புதிய சோதனைகள் வெற்றி...  ', 'இந்தியாவின் மனித விண்வெளி பயணத் திட்டமான **ககன்யான்** திட்டத்தில் மேற்கொள்ளப்பட்ட மூன்று முக்கிய தொழில்நுட்ப சோதனைகள் வெற்றிகரமாக நிறைவடைந்துள்ளதாக இந்திய விண்வ', 0, 0, 0, 1, '2026-07-13 05:23:43', '2026-07-13 05:23:43', NULL, 0),
(290, 4, NULL, 2, NULL, NULL, NULL, 150, 'உத்தரபிரதேசத்தில் 14 வயது சிறுமி கூட்டு பாலியல் வன்கொடுமை', 'உத்தரபிரதேசத்தில்-14-வயது-சிறுமி-கூட்டு-பாலியல்-வன்கொடுமை', 'உத்தரபிரதேசத்தில் 14 வயது சிறுமி மீது கூட்டு பாலியல் வன்கொடுமை நடத்தப்பட்டதாகக் கூறப்படும் சம்பவம் பெரும் அதிர்ச்சியை ஏற்படுத்தியுள்ளது. பாதிக்கப்பட்ட சிறுமியின…', 'உத்தரபிரதேசத்தில் 14 வயது சிறுமி மீது கூட்டு பாலியல் வன்கொடுமை நடத்தப்பட்டதாகக் கூறப்படும் சம்பவம் பெரும் அதிர்ச்சியை ஏற்படுத்தியுள்ளது. பாதிக்கப்பட்ட சிறுமியின் புகாரின் அடிப்படையில் போலீசார் வழக்குப்பதிவு செய்து விசாரணையைத் தொடங்கியுள்ளனர்.\r\nசிறுமி மருத்துவ பரிசோதனைக்காக மருத்துவமனைக்கு அனுப்பப்பட்டுள்ள நிலையில், சம்பவத்தில் தொடர்புடையதாகக் கூறப்படும் நபர்களை அடையாளம் கண்டு பிடிக்கும் பணியில் போலீசார் தீவிரமாக ஈடுபட்டுள்ளனர்.இந்த வழக்கில் கிடைத்துள்ள ஆதாரங்கள் மற்றும் சாட்சிகளின் அடிப்படையில் நடவடிக்கை மேற்கொள்ளப்பட்டு வருவதாக அதிகாரிகள் தெரிவித்துள்ளனர். குற்றவாளிகள் மீது சட்டப்படி கடுமையான நடவடிக்கை எடுக்கப்படும் என்றும் போலீசார் உறுதியளித்துள்ளனர்.\r\nஇந்தச் சம்பவம் தொடர்பாக குழந்தைகள் பாதுகாப்பு மற்றும் மகளிர் பாதுகாப்பு அமைப்புகளும் கவனம் செலுத்தியுள்ளன. இதுபோன்ற குற்றங்களைத் தடுக்க கடுமையான அமலாக்க நடவடிக்கைகள் அவசியம் என சமூக ஆர்வலர்கள் வலியுறுத்தியுள்ளனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5478096cb4a7.02997457.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 10:59:08', 0, 1, 0, 0, 0, 'உத்தரபிரதேசத்தில் 14 வயது சிறுமி கூட்டு பாலியல் வன்கொடுமை ', 'உத்தரபிரதேசத்தில் 14 வயது சிறுமி மீது கூட்டு பாலியல் வன்கொடுமை நடத்தப்பட்டதாகக் கூறப்படும் சம்பவம் பெரும் அதிர்ச்சியை ஏற்படுத்தியுள்ளது. பாதிக்கப்பட்ட சிறுமியின', 5, 0, 0, 1, '2026-07-13 05:29:08', '2026-07-13 13:18:09', NULL, 0),
(291, 4, NULL, 3, NULL, NULL, NULL, 151, 'வெனிசுலா நிலநடுக்கம்: பலி எண்ணிக்கை 4,490 ஆக உயர்வு;', 'வெனிசுலா-நிலநடுக்கம்-பலி-எண்ணிக்கை-4490-ஆக-உயர்வு', 'வெனிசுலாவில் கடந்த ஜூன் 24-ஆம் தேதி ஏற்பட்ட சக்திவாய்ந்த இரட்டை நிலநடுக்கத்தின் உயிரிழப்பு எண்ணிக்கை 4,490 ஆக உயர்ந்துள்ளதாக அதிகாரப்பூர்வ தகவல்கள் தெரிவிக்கின்…', 'வெனிசுலாவில் கடந்த ஜூன் 24-ஆம் தேதி ஏற்பட்ட சக்திவாய்ந்த இரட்டை நிலநடுக்கத்தின் உயிரிழப்பு எண்ணிக்கை 4,490 ஆக உயர்ந்துள்ளதாக அதிகாரப்பூர்வ தகவல்கள் தெரிவிக்கின்றன. காயமடைந்தோரின் எண்ணிக்கை 16,740 ஆக உள்ளதாகவும், இதுவரை 6,462 பேர் உயிருடன் மீட்கப்பட்டுள்ளதாகவும் அதிகாரிகள் தெரிவித்துள்ளனர். நிலநடுக்கத்தால் ஆயிரக்கணக்கான வீடுகள் சேதமடைந்துள்ளதால் பல குடும்பங்கள் தற்காலிக முகாம்களில் தங்க வைக்கப்பட்டுள்ளனர். மீட்பு மற்றும் நிவாரணப் பணிகளில் உள்ளூர் மீட்புக் குழுக்களுடன் சர்வதேச உதவிக் குழுக்களும் தொடர்ந்து ஈடுபட்டு வருகின்றன. பாதிக்கப்பட்ட பகுதிகளில் உணவு, குடிநீர், மருத்துவ உதவி உள்ளிட்ட அத்தியாவசிய சேவைகள் வழங்கப்பட்டு வருகின்றன. சேதமடைந்த கட்டிடங்கள் மற்றும் உள்கட்டமைப்புகளை ஆய்வு செய்யும் பணிகளும் தொடர்ந்து நடைபெற்று வருவதாக அதிகாரிகள் தெரிவித்துள்ளனர். \r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54794329ed71.58999002.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 11:06:10', 0, 1, 0, 0, 0, 'வெனிசுலா நிலநடுக்கம்: பலி எண்ணிக்கை 4,490 ஆக உயர்வு; ', 'வெனிசுலாவில் கடந்த ஜூன் 24-ஆம் தேதி ஏற்பட்ட சக்திவாய்ந்த இரட்டை நிலநடுக்கத்தின் உயிரிழப்பு எண்ணிக்கை 4,490 ஆக உயர்ந்துள்ளதாக அதிகாரப்பூர்வ தகவல்கள் தெரிவிக்கின்', 0, 0, 0, 1, '2026-07-13 05:36:10', '2026-07-13 05:36:10', NULL, 0),
(293, 4, NULL, 1, NULL, NULL, NULL, 153, 'அணை பகுதியில் மயங்கிய நிலையில் கண்டெடுக்கப்பட்ட குட்டி யானை உயிரிழப்பு', 'அணை-பகுதியில்-மயங்கிய-நிலையில்-கண்டெடுக்கப்பட்ட-குட்டி-யானை-உயிரிழப்பு', 'ஈரோடு மாவட்டம் டி.என்.பாளையம் வனச்சரகத்துக்கு உட்பட்ட குண்டேரிப்பள்ளம் அணை பகுதியில் மயங்கிய நிலையில் கிடந்த குட்டி யானை, சிகிச்சை அளிக்கப்பட்டும் உயிரிழந்த சம்…', 'ஈரோடு மாவட்டம் டி.என்.பாளையம் வனச்சரகத்துக்கு உட்பட்ட குண்டேரிப்பள்ளம் அணை பகுதியில் மயங்கிய நிலையில் கிடந்த குட்டி யானை, சிகிச்சை அளிக்கப்பட்டும் உயிரிழந்த சம்பவம் சோகத்தை ஏற்படுத்தியுள்ளது.வனத்துறையினர் ரோந்து பணியின்போது குட்டி யானை உடல்நலக்குறைவுடன் கிடப்பதை கண்டறிந்து, உடனடியாக கால்நடை மருத்துவக் குழுவை வரவழைத்தனர். முதலுதவி அளிக்கப்பட்ட பின்னர், மேல்சிகிச்சைக்காக பாதுகாப்பான இடத்துக்கு கொண்டு செல்லப்பட்டது.மருத்துவர்கள் தீவிர சிகிச்சை அளித்த போதிலும், குட்டி யானையை காப்பாற்ற முடியவில்லை. இதையடுத்து, உயிரிழப்புக்கான காரணத்தை உறுதிப்படுத்த உடற்கூறு பரிசோதனை மேற்கொள்ளப்பட்டுள்ளது.உடற்கூறு ஆய்வு அறிக்கை கிடைத்த பிறகே யானை உயிரிழந்ததற்கான துல்லியமான காரணம் தெரியவரும் என வனத்துறையினர் தெரிவித்துள்ளனர். மேலும், அப்பகுதியில் யானைக் கூட்டத்தின் நடமாட்டம் கண்காணிக்கப்பட்டு, தேவையான பாதுகாப்பு நடவடிக்கைகள் மேற்கொள்ளப்பட்டு வருகின்றன.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a547b3d420aa5.99709734.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 11:13:41', 0, 1, 0, 0, 0, 'அணை பகுதியில் மயங்கிய நிலையில் கண்டெடுக்கப்பட்ட குட்டி யானை உயிரிழப்பு ', 'ஈரோடு மாவட்டம் டி.என்.பாளையம் வனச்சரகத்துக்கு உட்பட்ட குண்டேரிப்பள்ளம் அணை பகுதியில் மயங்கிய நிலையில் கிடந்த குட்டி யானை, சிகிச்சை அளிக்கப்பட்டும் உயிரிழந்த சம்', 9, 0, 0, 1, '2026-07-13 05:43:41', '2026-07-13 19:47:32', NULL, 0),
(294, 4, NULL, 1, NULL, NULL, NULL, 154, 'மதுரை அருகே அரசு பஸ் மீது ஆம்னி பஸ் மோதி பயங்கர விபத்து:', 'மதுரை-அருகே-அரசு-பஸ்-மீது-ஆம்னி-பஸ்-மோதி-பயங்கர-விபத்து', 'சென்னையில் இருந்து மார்த்தாண்டம் நோக்கி சென்ற தனியார் ஆம்னி பேருந்தும், எதிரே வந்த அரசு பேருந்தும் மதுரை அருகே நேருக்கு நேர் மோதியதில் 5 பேர் உயிரிழந்தனர். இந்த…', 'சென்னையில் இருந்து மார்த்தாண்டம் நோக்கி சென்ற தனியார் ஆம்னி பேருந்தும், எதிரே வந்த அரசு பேருந்தும் மதுரை அருகே நேருக்கு நேர் மோதியதில் 5 பேர் உயிரிழந்தனர். இந்த விபத்தில் பலர் காயமடைந்ததாக தகவல் வெளியாகியுள்ளது.விபத்து நடந்தவுடன் அப்பகுதி மக்கள், காவல்துறையினர் மற்றும் தீயணைப்பு வீரர்கள் இணைந்து மீட்புப் பணியில் ஈடுபட்டனர். பேருந்துகளில் சிக்கியிருந்த பயணிகள் மீட்கப்பட்டு, அருகிலுள்ள அரசு மற்றும் தனியார் மருத்துவமனைகளுக்கு சிகிச்சைக்காக அனுப்பி வைக்கப்பட்டனர்.உயிரிழந்தவர்களின் உடல்கள் மீட்கப்பட்டு உடற்கூறு பரிசோதனைக்காக அரசு மருத்துவமனைக்கு அனுப்பப்பட்டுள்ளன. காயமடைந்தவர்களில் சிலரின் நிலைமை கவலைக்கிடமாக இருப்பதாக மருத்துவமனை வட்டாரங்கள் தெரிவித்துள்ளன.\r\nஇந்த விபத்தால் அந்தப் பகுதியில் சில மணி நேரம் போக்குவரத்து பாதிக்கப்பட்டது. பின்னர் சேதமடைந்த வாகனங்கள் அகற்றப்பட்டதைத் தொடர்ந்து போக்குவரத்து இயல்பு நிலைக்குத் திரும்பியது.விபத்திற்கான காரணம் குறித்து போலீசார் வழக்குப்பதிவு செய்து விசாரணை நடத்தி வருகின்றனர். முதற்கட்ட விசாரணையில் அதிக வேகம் அல்லது பிற காரணிகள் விபத்துக்கு காரணமாக இருந்ததா என்பது குறித்து ஆய்வு செய்யப்பட்டு வருகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a5488c9e37073.89132586.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 12:12:40', 0, 1, 0, 0, 0, 'மதுரை அருகே அரசு பஸ் மீது ஆம்னி பஸ் மோதி பயங்கர விபத்து: ', 'சென்னையில் இருந்து மார்த்தாண்டம் நோக்கி சென்ற தனியார் ஆம்னி பேருந்தும், எதிரே வந்த அரசு பேருந்தும் மதுரை அருகே நேருக்கு நேர் மோதியதில் 5 பேர் உயிரிழந்தனர். இந்த', 0, 0, 0, 1, '2026-07-13 06:42:40', '2026-07-13 12:13:34', NULL, 0),
(295, 4, NULL, 1, NULL, NULL, NULL, 155, 'பொறியியல் படிப்பு மாணவர் சேர்க்கைக்கான கலந்தாய்வு தொடங்கியது...', 'பொறியியல்-படிப்பு-மாணவர்-சேர்க்கைக்கான-கலந்தாய்வு-தொடங்கியது', 'தமிழகத்தில் பொறியியல் படிப்புகளுக்கான மாணவர் சேர்க்கை கலந்தாய்வு இன்று தொடங்கியது. அரசுப் பொறியியல் கல்லூரிகள், அரசு உதவி பெறும் கல்லூரிகள் மற்றும் சுயநிதி பொறி…', 'தமிழகத்தில் பொறியியல் படிப்புகளுக்கான மாணவர் சேர்க்கை கலந்தாய்வு இன்று தொடங்கியது. அரசுப் பொறியியல் கல்லூரிகள், அரசு உதவி பெறும் கல்லூரிகள் மற்றும் சுயநிதி பொறியியல் கல்லூரிகளில் உள்ள இடங்களை நிரப்பும் வகையில் இந்த கலந்தாய்வு நடத்தப்படுகிறது.தரவரிசைப் பட்டியல் மற்றும் இடஒதுக்கீட்டு விதிமுறைகளின் அடிப்படையில், மாணவர்கள் தங்களுக்கான கல்லூரி மற்றும் பாடப்பிரிவுகளை இணையவழி முறையில் தேர்வு செய்து வருகின்றனர். ஒவ்வொரு கட்டமாக கலந்தாய்வு நடைபெறுவதால், தகுதியான மாணவர்கள் அறிவிக்கப்பட்ட கால அட்டவணையின்படி பங்கேற்க அறிவுறுத்தப்பட்டுள்ளனர்.\r\nஇடம் ஒதுக்கப்பட்ட மாணவர்கள், குறிப்பிட்ட காலக்கெடுவுக்குள் தங்களது விருப்பத்தை உறுதி செய்து, தேவையான ஆவணங்களைச் சமர்ப்பித்து சேர்க்கை நடைமுறைகளை நிறைவு செய்ய வேண்டும் என அதிகாரிகள் தெரிவித்துள்ளனர்.மாணவர்கள் கலந்தாய்வு அட்டவணை, இட ஒதுக்கீட்டு விவரங்கள் மற்றும் சேர்க்கை தொடர்பான அறிவிப்புகளை தொடர்ந்து கவனித்து, உரிய காலத்தில் அனைத்து நடைமுறைகளையும் பூர்த்தி செய்யுமாறு அறிவுறுத்தப்பட்டுள்ளது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a548af81150f5.87581894.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 12:22:14', 0, 1, 0, 0, 0, 'பொறியியல் படிப்பு மாணவர் சேர்க்கைக்கான கலந்தாய்வு தொடங்கியது...  ', 'தமிழகத்தில் பொறியியல் படிப்புகளுக்கான மாணவர் சேர்க்கை கலந்தாய்வு இன்று தொடங்கியது. அரசுப் பொறியியல் கல்லூரிகள், அரசு உதவி பெறும் கல்லூரிகள் மற்றும் சுயநிதி பொறி', 0, 0, 0, 1, '2026-07-13 06:52:14', '2026-07-13 12:22:59', NULL, 0),
(296, 4, NULL, 1, NULL, NULL, NULL, 156, 'சென்னையில் விமானம் தரையிறங்கியபோது பறவை மோதி விபத்து', 'சென்னையில்-விமானம்-தரையிறங்கியபோது-பறவை-மோதி-விபத்து', 'பிரிட்டிஷ் ஏர்வேஸ் விமானம் லண்டனில் இருந்து 224 பயணிகள், 12 விமான ஊழியர்களுடன் சென்னை வந்தது.சென்னை சர்வதேச விமான நிலையத்தில் தரையிறங்கிய பயணிகள் விமானம் ஒன்று,…', 'பிரிட்டிஷ் ஏர்வேஸ் விமானம் லண்டனில் இருந்து 224 பயணிகள், 12 விமான ஊழியர்களுடன் சென்னை வந்தது.சென்னை சர்வதேச விமான நிலையத்தில் தரையிறங்கிய பயணிகள் விமானம் ஒன்று, ஓடுபாதையில் இறங்கும் தருணத்தில் பறவை மோதியதால் சிறிய தொழில்நுட்ப பாதிப்பு ஏற்பட்டது.விமானம் பாதுகாப்பாக தரையிறங்கிய நிலையில், விமானத்தில் இருந்த பயணிகள் மற்றும் பணியாளர்கள் அனைவரும் எந்த பாதிப்பும் இன்றி பாதுகாப்பாக வெளியேற்றப்பட்டனர். சம்பவத்தைத் தொடர்ந்து விமானம் உடனடியாக தொழில்நுட்ப ஆய்வுக்காக நிறுத்தி வைக்கப்பட்டது.விமானப் பொறியாளர்கள் மேற்கொண்ட முதற்கட்ட ஆய்வில், பறவை மோதியதால் விமானத்தின் முன்பகுதியில் லேசான சேதம் ஏற்பட்டிருப்பது கண்டறியப்பட்டது. இதையடுத்து, தேவையான பராமரிப்பு பணிகள் மேற்கொள்ளப்பட்டு வருகின்றன.இந்தச் சம்பவம் குறித்து விமான நிலைய அதிகாரிகள் மற்றும் சம்பந்தப்பட்ட விமான நிறுவனம் விசாரணை நடத்தி வருகின்றன. மேலும், பறவைகள் விமானப் போக்குவரத்துக்கு இடையூறு ஏற்படுத்தாத வகையில் விமான நிலைய வளாகத்தில் முன்னெச்சரிக்கை நடவடிக்கைகள் தொடர்ந்து மேற்கொள்ளப்பட்டு வருகின்றன.\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a548ed27604b4.44788828.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 12:38:40', 0, 1, 0, 0, 0, 'சென்னையில் விமானம் தரையிறங்கியபோது பறவை மோதி விபத்து ', 'பிரிட்டிஷ் ஏர்வேஸ் விமானம் லண்டனில் இருந்து 224 பயணிகள், 12 விமான ஊழியர்களுடன் சென்னை வந்தது.சென்னை சர்வதேச விமான நிலையத்தில் தரையிறங்கிய பயணிகள் விமானம் ஒன்று,', 2, 0, 0, 1, '2026-07-13 07:08:40', '2026-07-13 11:18:08', NULL, 0),
(297, 4, NULL, 3, NULL, NULL, NULL, 157, 'கனடா: இசை திருவிழாவில் துப்பாக்கி சூடு; 2 வாலிபர்கள் பலி - பிரதமர் இரங்கல்', 'கனடா-இசை-திருவிழாவில்-துப்பாக்கி-சூடு-2-வாலிபர்கள்-பலி-பிரதமர்-இரங்கல்', 'கனடாவில் நடைபெற்ற இசை திருவிழாவின் போது ஏற்பட்ட துப்பாக்கிச்சூட்டில் இரண்டு இளைஞர்கள் உயிரிழந்தனர். இந்தச் சம்பவத்தில் மேலும் சிலர் காயமடைந்ததாக அதிகாரிகள் தெரி…', 'கனடாவில் நடைபெற்ற இசை திருவிழாவின் போது ஏற்பட்ட துப்பாக்கிச்சூட்டில் இரண்டு இளைஞர்கள் உயிரிழந்தனர். இந்தச் சம்பவத்தில் மேலும் சிலர் காயமடைந்ததாக அதிகாரிகள் தெரிவித்துள்ளனர்.நடந்ததைத் தொடர்ந்து போலீசார் சம்பவ இடத்தைச் சுற்றிவளைத்து பாதுகாப்பு ஏற்பாடுகளை பலப்படுத்தினர். காயமடைந்தவர்கள் உடனடியாக அருகிலுள்ள மருத்துவமனைகளுக்கு கொண்டு செல்லப்பட்டு சிகிச்சை அளிக்கப்பட்டு வருகிறது.\r\nதொடர்பாக போலீசார் தீவிர விசாரணை மேற்கொண்டு, துப்பாக்கிச்சூட்டில் தொடர்புடைய நபர்களை கண்டறியும் பணியில் ஈடுபட்டுள்ளனர். சம்பவத்திற்கான காரணம் குறித்து தொடர்ந்து விசாரணை நடைபெற்று வருகிறது.இந்த துயரச் சம்பவத்திற்கு கனடா பிரதமர் ஆழ்ந்த இரங்கல் தெரிவித்துள்ளார். உயிரிழந்தோரின் குடும்பங்களுக்கு ஆறுதல் தெரிவித்து, காயமடைந்தவர்கள் விரைவில் குணமடைய வாழ்த்திய அவர், குற்றவாளிகளை சட்டத்தின் முன் நிறுத்த தேவையான அனைத்து நடவடிக்கைகளும் எடுக்கப்படும் என்று உறுதியளித்துள்ளார்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54927eb87592.37218359.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 12:54:17', 0, 1, 0, 0, 0, 'கனடா: இசை திருவிழாவில் துப்பாக்கி சூடு; 2 வாலிபர்கள் பலி - பிரதமர் இரங்கல் ', 'கனடாவில் நடைபெற்ற இசை திருவிழாவின் போது ஏற்பட்ட துப்பாக்கிச்சூட்டில் இரண்டு இளைஞர்கள் உயிரிழந்தனர். இந்தச் சம்பவத்தில் மேலும் சிலர் காயமடைந்ததாக அதிகாரிகள் தெரி', 4, 0, 0, 1, '2026-07-13 07:24:17', '2026-07-14 06:09:30', NULL, 0),
(298, 4, NULL, 1, NULL, NULL, NULL, 159, 'ரூ.36 லட்சம் மதிப்பீட்டில் கட்டப்பட்டுள்ள பல்நோக்கு மையக் கட்டடம் - மேயர் பிரியா திறந்து வைத்தார்', 'ரூ36-லட்சம்-மதிப்பீட்டில்-கட்டப்பட்டுள்ள-பல்நோக்கு-மையக்-கட்டடம்-மேயர்-பிரியா-திறந்து-வைத்தார்', 'சென்னை மாநகராட்சி, அடையாறு மண்டலம், வார்டு-178, தரமணி, அண்ணா தெருவில் 178-வது வார்டு மாமன்ற உறுப்பினரின் .சென்னை மாநகராட்சியின் சார்பில் ரூ.36 லட்சம் மதிப்பீட்ட…', 'சென்னை மாநகராட்சி, அடையாறு மண்டலம், வார்டு-178, தரமணி, அண்ணா தெருவில் 178-வது வார்டு மாமன்ற உறுப்பினரின் .சென்னை மாநகராட்சியின் சார்பில் ரூ.36 லட்சம் மதிப்பீட்டில் புதிதாக கட்டப்பட்ட பல்நோக்கு மையக் கட்டடம் பொதுமக்கள் பயன்பாட்டிற்காக திறந்து வைக்கப்பட்டது. இந்த நிகழ்ச்சியில் சென்னை மேயர் ஆர். பிரியா கலந்து கொண்டு கட்டடத்தை திறந்து வைத்தார். புதிய பல்நோக்கு மையம், அப்பகுதி மக்களின் சமூக மற்றும் பொது பயன்பாட்டு தேவைகளை கருத்தில் கொண்டு அமைக்கப்பட்டுள்ளது. இதில் பொதுக்கூட்டங்கள், சமூக நிகழ்ச்சிகள், மக்களுக்கான சேவை முகாம்கள் உள்ளிட்ட பல்வேறு நிகழ்வுகளை நடத்துவதற்கான வசதிகள் ஏற்படுத்தப்பட்டுள்ளன.திறப்பு விழாவில் உள்ளாட்சி பிரதிநிதிகள், மாநகராட்சி அதிகாரிகள் மற்றும் பொதுமக்கள் கலந்து கொண்டனர். இந்தக் கட்டடம் அப்பகுதி மக்களுக்கு பல்வேறு சமூக சேவைகள் மற்றும் நலத்திட்ட நடவடிக்கைகளுக்கான மையமாக செயல்படும் என தெரிவிக்கப்பட்டது. \r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a549a8ad89500.32973779.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 13:28:09', 0, 1, 0, 0, 0, 'ரூ.36 லட்சம் மதிப்பீட்டில் கட்டப்பட்டுள்ள பல்நோக்கு மையக் கட்டடம் - மேயர் பிரியா திறந்து வைத்தார் ', 'சென்னை மாநகராட்சி, அடையாறு மண்டலம், வார்டு-178, தரமணி, அண்ணா தெருவில் 178-வது வார்டு மாமன்ற உறுப்பினரின் .சென்னை மாநகராட்சியின் சார்பில் ரூ.36 லட்சம் மதிப்பீட்ட', 6, 0, 0, 1, '2026-07-13 07:58:09', '2026-07-13 18:02:57', NULL, 0),
(299, 4, NULL, 1, NULL, NULL, NULL, 160, 'நில அபகரிப்பு புகார்: தா.மோ.அன்பரசன் மீது வழக்குப்பதிவு', 'நில-அபகரிப்பு-புகார்-தாமோஅன்பரசன்-மீது-வழக்குப்பதிவு', 'நில அபகரிப்பு தொடர்பாக பெறப்பட்ட புகாரின் அடிப்படையில், முன்னாள் அமைச்சர் தா.மோ. அன்பரசன், அவரது உதவியாளர் ஜெய்சங்கர் மற்றும் தொடர்புடைய அதிகாரி ஒருவருக்கு எதிர…', 'நில அபகரிப்பு தொடர்பாக பெறப்பட்ட புகாரின் அடிப்படையில், முன்னாள் அமைச்சர் தா.மோ. அன்பரசன், அவரது உதவியாளர் ஜெய்சங்கர் மற்றும் தொடர்புடைய அதிகாரி ஒருவருக்கு எதிராக பரங்கிமலை போலீசார் வழக்குப்பதிவு செய்து விசாரணையை தொடங்கியுள்ளனர்.\r\nசென்னையைச் சேர்ந்த தொழிலதிபர் ஒருவர் அளித்த புகாரில், 2024 மக்களவைத் தேர்தல் காலத்தில் தேர்தல் பணிமனை அமைப்பதற்காக குத்தகைக்கு வழங்கப்பட்ட சுமார் 5,500 சதுர அடி நிலம், ஒப்பந்த காலம் முடிந்த பின்னரும் திருப்பி ஒப்படைக்கப்படவில்லை என்றும், கடந்த இரண்டு ஆண்டுகளாக வாடகையும் வழங்கப்படவில்லை என்றும் தெரிவித்துள்ளார்.\r\nமேலும், நிலத்தை மீட்டுத் தர வேண்டும் என முதலமைச்சரின் தனிப்பிரிவில் அளிக்கப்பட்ட மனுவைத் தொடர்ந்து, போலீசார் முதற்கட்ட விசாரணை மேற்கொண்டனர்.\r\nஇதையடுத்து, புகாரின் அடிப்படையில் சம்பந்தப்பட்டோர் மீது வழக்குப்பதிவு செய்யப்பட்டுள்ளதாகவும், நிலத்தின் உரிமை, குத்தகை ஒப்பந்த விவரங்கள் மற்றும் புகாரில் கூறப்பட்டுள்ள குற்றச்சாட்டுகள் குறித்து போலீசார் தொடர்ந்து விசாரணை நடத்தி வருவதாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\n\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54a1c6684290.65685840.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 13:59:06', 0, 1, 0, 0, 0, 'நில அபகரிப்பு புகார்: தா.மோ.அன்பரசன் மீது வழக்குப்பதிவு', 'நில அபகரிப்பு தொடர்பாக பெறப்பட்ட புகாரின் அடிப்படையில், முன்னாள் அமைச்சர் தா.மோ. அன்பரசன், அவரது உதவியாளர் ஜெய்சங்கர் மற்றும் தொடர்புடைய அதிகாரி ஒருவருக்கு எதிர', 6, 0, 0, 1, '2026-07-13 08:29:06', '2026-07-14 01:50:10', NULL, 0),
(300, 4, NULL, 2, NULL, NULL, NULL, 161, 'ஆந்திரா: 6 தலைமுறையாக சேர்ந்து வாழும் பிரமாண்ட கூட்டுக்குடும்பம்...', 'ஆந்திரா-6-தலைமுறையாக-சேர்ந்து-வாழும்-பிரமாண்ட-கூட்டுக்குடும்பம்', 'ஆந்திரப் பிரதேசத்தின் அனந்தபூர் மாவட்டம், குர்லப்பள்ளி கிராமத்தில் வசிக்கும் ஒரு குடும்பம், பாரம்பரிய கூட்டுக்குடும்ப வாழ்க்கைக்கு முன்னுதாரணமாக திகழ்கிறது. இந்…', 'ஆந்திரப் பிரதேசத்தின் அனந்தபூர் மாவட்டம், குர்லப்பள்ளி கிராமத்தில் வசிக்கும் ஒரு குடும்பம், பாரம்பரிய கூட்டுக்குடும்ப வாழ்க்கைக்கு முன்னுதாரணமாக திகழ்கிறது. இந்தக் குடும்பத்தில் ஆறு தலைமுறைகளைச் சேர்ந்த மொத்தம் 83 பேர் ஒன்றுபட்டு வாழ்ந்து வருகின்றனர். நான்கு அடுத்தடுத்த வீடுகளில் வசித்தாலும், அனைவரும் ஒரே குடும்பமாகவே அன்றாட வாழ்க்கையை நடத்துகின்றனர். வருமானம், செலவுகள், வீட்டு பொறுப்புகள் உள்ளிட்ட அனைத்தும் பகிர்ந்து நிர்வகிக்கப்படுகின்றன. குடும்ப உறுப்பினர்கள் இணைந்து விவசாயம் மற்றும் போக்குவரத்து தொழிலில் ஈடுபட்டு வருகின்றனர். ஒவ்வொரு நாளும் குடும்ப மூத்தவர்கள் ஆலோசனை நடத்தி, அன்றைய பணிகள், சமையல் மற்றும் விவசாயப் பொறுப்புகளைப் பகிர்ந்து வழங்குகின்றனர். அனைவருக்கும் ஒரே சமையலறையில் உணவு தயாரிக்கப்படுவது இந்தக் குடும்பத்தின் தனிச்சிறப்பாக உள்ளது.தனிக்குடும்பங்கள் அதிகரித்து வரும் இன்றைய காலகட்டத்தில், ஒற்றுமை, பொறுப்புணர்வு மற்றும் பரஸ்பர ஒத்துழைப்புடன் வாழும் இந்தப் பிரமாண்ட கூட்டுக்குடும்பம் பலரது கவனத்தை ஈர்த்துள்ளது. ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54a4585d5049.03808066.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 14:10:27', 0, 1, 0, 0, 0, 'ஆந்திரா: 6 தலைமுறையாக சேர்ந்து வாழும் பிரமாண்ட கூட்டுக்குடும்பம்... ', 'ஆந்திரப் பிரதேசத்தின் அனந்தபூர் மாவட்டம், குர்லப்பள்ளி கிராமத்தில் வசிக்கும் ஒரு குடும்பம், பாரம்பரிய கூட்டுக்குடும்ப வாழ்க்கைக்கு முன்னுதாரணமாக திகழ்கிறது. இந்', 6, 0, 0, 1, '2026-07-13 08:40:27', '2026-07-13 17:23:07', NULL, 0),
(301, 4, NULL, 1, NULL, NULL, NULL, 162, 'திருவள்ளூரில் அமோனியா வாயு கசிவு ஏற்பட்ட கடல் உணவுத் தொழிற்சாலைக்கு அதிகாரிகள் ‘சீல்’', 'திருவள்ளூரில்-அமோனியா-வாயு-கசிவு-ஏற்பட்ட-கடல்-உணவுத்-தொழிற்சாலைக்கு-அதிகாரிகள்-சீல்', 'திருவள்ளூர் மாவட்டம் கன்னிகைப்பேரில் இயங்கி வந்த கடல் உணவுப் பொருட்கள் ஏற்றுமதி தொழிற்சாலையில் கடந்த மாதம் ஏற்பட்ட அமோனியா வாயு கசிவு சம்பவத்தைத் தொடர்ந்து, மாவ…', 'திருவள்ளூர் மாவட்டம் கன்னிகைப்பேரில் இயங்கி வந்த கடல் உணவுப் பொருட்கள் ஏற்றுமதி தொழிற்சாலையில் கடந்த மாதம் ஏற்பட்ட அமோனியா வாயு கசிவு சம்பவத்தைத் தொடர்ந்து, மாவட்ட நிர்வாகம் மற்றும் சம்பந்தப்பட்ட துறைகள் இணைந்து நடவடிக்கை மேற்கொண்டுள்ளன.\r\nஇந்தச் சம்பவம் தொடர்பாக நடத்தப்பட்ட ஆய்வில், பாதுகாப்பு நடைமுறைகள் மற்றும் தொழிற்சாலை செயல்பாடுகள் குறித்து பல்வேறு அம்சங்கள் பரிசீலிக்கப்பட்டன. அதன் அடிப்படையில், தொழிற்சாலையின் செயல்பாட்டை தற்காலிகமாக நிறுத்தி, வளாகத்திற்கு அதிகாரிகள் ‘சீல்’ வைத்துள்ளனர்.மேலும், பாதுகாப்பு விதிமுறைகள் முழுமையாக பின்பற்றப்படுகிறதா என்பதை உறுதி செய்ய சம்பந்தப்பட்ட துறைகள் தொடர்ந்து ஆய்வு மேற்கொண்டு வருகின்றன. ஆய்வு அறிக்கை மற்றும் விதிமுறை பின்பற்றல் தொடர்பான மதிப்பீட்டின் பின்னர், அடுத்தகட்ட நடவடிக்கை குறித்து முடிவு செய்யப்படும் என்று அதிகாரிகள் தெரிவித்துள்ளனர்.இந்தச் சம்பவத்தால் பாதிக்கப்பட்ட பகுதிகளில் பொதுமக்களின் பாதுகாப்பை உறுதி செய்ய தேவையான கண்காணிப்பு மற்றும் முன்னெச்சரிக்கை நடவடிக்கைகளும் தொடரப்பட்டு வருகின்றன.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54a815284d08.08573133.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 14:26:28', 0, 1, 0, 0, 0, 'திருவள்ளூரில் அமோனியா வாயு கசிவு ஏற்பட்ட கடல் உணவுத் தொழிற்சாலைக்கு அதிகாரிகள் ‘சீல்’', 'திருவள்ளூர் மாவட்டம் கன்னிகைப்பேரில் இயங்கி வந்த கடல் உணவுப் பொருட்கள் ஏற்றுமதி தொழிற்சாலையில் கடந்த மாதம் ஏற்பட்ட அமோனியா வாயு கசிவு சம்பவத்தைத் தொடர்ந்து, மாவ', 10, 0, 0, 1, '2026-07-13 08:56:28', '2026-07-13 18:53:08', NULL, 0),
(302, 4, NULL, 2, NULL, NULL, NULL, 164, 'கொலம்பியாவில் நடைபெற்ற சர்வதேச இயற்பியல் ஒலிம்பியாட் போட்டியில் இந்திய அணி தங்கம் வென்றுள்ளது.', 'கொலம்பியாவில்-நடைபெற்ற-சர்வதேச-இயற்பியல்-ஒலிம்பியாட்-போட்டியில்-இந்திய-அணி-தங்கம்-வென்றுள்ளது', 'சர்வதேச இயற்பியல் ஒலிம்பியாட்: இந்திய அணிக்கு தங்கப் பதக்கம்\r\nகொலம்பியாவில் நடைபெற்ற சர்வதேச இயற்பியல் ஒலிம்பியாட் (International Physics Olympiad) போட்டியில் இ…', 'சர்வதேச இயற்பியல் ஒலிம்பியாட்: இந்திய அணிக்கு தங்கப் பதக்கம்\r\nகொலம்பியாவில் நடைபெற்ற சர்வதேச இயற்பியல் ஒலிம்பியாட் (International Physics Olympiad) போட்டியில் இந்திய மாணவர்கள் சிறப்பான திறமையை வெளிப்படுத்தி தங்கப் பதக்கத்தை வென்றுள்ளனர்.உலகின் பல்வேறு நாடுகளைச் சேர்ந்த திறமையான மாணவர்கள் பங்கேற்ற இந்தப் போட்டியில், கோட்பாட்டு மற்றும் செய்முறை இயற்பியல் தொடர்பான பல்வேறு கடினமான சவால்களை இந்திய அணி வெற்றிகரமாக எதிர்கொண்டது.இந்த வெற்றியின் மூலம் சர்வதேச அளவில் இந்திய மாணவர்களின் அறிவியல் திறன் மீண்டும் ஒருமுறை நிரூபிக்கப்பட்டுள்ளது. வெற்றி பெற்ற மாணவர்கள் மற்றும் அவர்களுக்கு பயிற்சி அளித்த ஆசிரியர்களுக்கு கல்வியாளர்கள், அறிவியல் ஆர்வலர்கள் மற்றும் பல்வேறு தரப்பினரும் பாராட்டு தெரிவித்து வருகின்றனர்.இந்த சாதனை, அறிவியல் கல்வியில் இந்திய மாணவர்கள் தொடர்ந்து முன்னேறி வருவதற்கான மற்றொரு முக்கிய மைல்கல்லாகக் கருதப்படுகிறது.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54aaf2b65978.95222204.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 14:36:43', 0, 1, 0, 0, 0, 'கொலம்பியாவில் நடைபெற்ற சர்வதேச இயற்பியல் ஒலிம்பியாட் போட்டியில் இந்திய அணி தங்கம் வென்றுள்ளது. ', 'சர்வதேச இயற்பியல் ஒலிம்பியாட்: இந்திய அணிக்கு தங்கப் பதக்கம்\r\nகொலம்பியாவில் நடைபெற்ற சர்வதேச இயற்பியல் ஒலிம்பியாட் (International Physics Olympiad) போட்டியில் இ', 10, 0, 0, 1, '2026-07-13 09:06:43', '2026-07-13 18:53:07', NULL, 0),
(303, 4, NULL, 2, NULL, NULL, NULL, 165, 'தாய்லாந்தில் தீ விபத்து; 27 பேர் பலி ...', 'தாய்லாந்தில்-தீ-விபத்து-27-பேர்-பலி', 'தாய்லாந்து தலைநகர் பாங்காக்கில் உள்ள ஒரு பிரபல பொழுதுபோக்கு வளாகத்தில் ஏற்பட்ட பயங்கர தீ விபத்தில் குறைந்தது 27 பேர் உயிரிழந்துள்ளனர். மேலும் பலர் காயமடைந்த நில…', 'தாய்லாந்து தலைநகர் பாங்காக்கில் உள்ள ஒரு பிரபல பொழுதுபோக்கு வளாகத்தில் ஏற்பட்ட பயங்கர தீ விபத்தில் குறைந்தது 27 பேர் உயிரிழந்துள்ளனர். மேலும் பலர் காயமடைந்த நிலையில் மருத்துவமனைகளில் சிகிச்சை பெற்று வருகின்றனர். அவர்களில் சிலரின் நிலை கவலைக்கிடமாக இருப்பதாக அதிகாரிகள் தெரிவித்துள்ளனர். நள்ளிரவு நேரத்தில் ஏற்பட்ட இந்த தீ விபத்தின்போது வளாகத்தில் ஏராளமானோர் இருந்ததாக கூறப்படுகிறது. தீ வேகமாக பரவியதால் பலர் வெளியேற முடியாமல் சிக்கிக் கொண்டனர். தீயணைப்பு வீரர்கள் விரைந்து வந்து தீயை கட்டுப்பாட்டுக்குள் கொண்டு வந்தனர். தீ விபத்துக்கான காரணம் குறித்து அதிகாரிகள் தீவிர விசாரணை நடத்தி வருகின்றனர். மின்கசிவு, அவசர வெளியேறும் வழிகளில் ஏற்பட்ட சிக்கல்கள் உள்ளிட்ட பல்வேறு கோணங்களில் விசாரணை மேற்கொள்ளப்பட்டு வருகிறது. உயிரிழந்தோரின் குடும்பங்களுக்கு தாய்லாந்து அரசு இரங்கல் தெரிவித்துள்ளதுடன், காயமடைந்தவர்களுக்கு தேவையான அனைத்து மருத்துவ உதவிகளும் வழங்கப்பட்டு வருகின்றன. ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54aece2c13f1.38222469.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 14:54:43', 0, 1, 0, 0, 0, 'தாய்லாந்தில் தீ விபத்து; 27 பேர் பலி ...  ', 'தாய்லாந்து தலைநகர் பாங்காக்கில் உள்ள ஒரு பிரபல பொழுதுபோக்கு வளாகத்தில் ஏற்பட்ட பயங்கர தீ விபத்தில் குறைந்தது 27 பேர் உயிரிழந்துள்ளனர். மேலும் பலர் காயமடைந்த நில', 10, 0, 0, 1, '2026-07-13 09:24:43', '2026-07-14 06:09:50', NULL, 0),
(304, 4, NULL, 1, NULL, NULL, NULL, 166, 'தமிழ்நாடு பாடநூல் கழக தலைவராக லயோலா மணி நியமனம் ...', 'தமிழ்நாடு-பாடநூல்-கழக-தலைவராக-லயோலா-மணி-நியமனம்', 'தமிழ்நாடு அரசின் பாடநூல் மற்றும் கல்வியியல் பணிகள் கழகத்தின் (தமிழ்நாடு பாடநூல் கழகம்) புதிய தலைவராக கல்வியாளர் லயோலா மணி நியமிக்கப்பட்டுள்ளார். இதற்கான அதிகாரப…', 'தமிழ்நாடு அரசின் பாடநூல் மற்றும் கல்வியியல் பணிகள் கழகத்தின் (தமிழ்நாடு பாடநூல் கழகம்) புதிய தலைவராக கல்வியாளர் லயோலா மணி நியமிக்கப்பட்டுள்ளார். இதற்கான அதிகாரப்பூர்வ அறிவிப்பை தமிழக அரசு வெளியிட்டுள்ளது. கல்வித் துறையில் நீண்டகால அனுபவம் கொண்ட லயோலா மணி, பள்ளிக் கல்வி தொடர்பான பல்வேறு கல்வி மேம்பாட்டு முயற்சிகளில் ஈடுபட்டு வந்தவர் எனக் கூறப்படுகிறது. அவரது நியமனம் மூலம் பாடநூல் தயாரிப்பு, கல்வி உள்ளடக்க மேம்பாடு மற்றும் மாணவர்களுக்கு தரமான கற்றல் வளங்களை வழங்கும் பணிகள் மேலும் வலுப்பெறும் என எதிர்பார்க்கப்படுகிறது. பாடநூல் கழகம் மாநில பள்ளி மாணவர்களுக்கான பாடநூல்கள், கற்றல் வளங்கள் மற்றும் கல்வி சார்ந்த வெளியீடுகளை தயாரித்து வழங்கும் முக்கிய அரசுத் துறையாக செயல்பட்டு வருகிறது. புதிய தலைவரின் பொறுப்பேற்பைத் தொடர்ந்து பல்வேறு கல்வி மேம்பாட்டு நடவடிக்கைகள் தீவிரப்படுத்தப்படும் என தகவல்கள் தெரிவிக்கின்றன.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54bf5681b722.13074502.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 16:08:07', 0, 1, 0, 0, 0, 'தமிழ்நாடு பாடநூல் கழக தலைவராக லயோலா மணி நியமனம் ...    ', 'தமிழ்நாடு அரசின் பாடநூல் மற்றும் கல்வியியல் பணிகள் கழகத்தின் (தமிழ்நாடு பாடநூல் கழகம்) புதிய தலைவராக கல்வியாளர் லயோலா மணி நியமிக்கப்பட்டுள்ளார். இதற்கான அதிகாரப', 8, 0, 0, 1, '2026-07-13 10:38:07', '2026-07-14 01:50:31', NULL, 0),
(305, 4, NULL, 3, NULL, NULL, NULL, 167, 'நேபாளம்: போதைப்பொருள் கடத்திய இந்தியர்கள் 5 பேர் கைது', 'நேபாளம்-போதைப்பொருள்-கடத்திய-இந்தியர்கள்-5-பேர்-கைது', 'நேபாளத்தில் போதைப்பொருள் கடத்தலைத் தடுக்க போலீசார் நடத்திய தொடர் சோதனை நடவடிக்கைகளில், இந்தியர்களைச் சேர்ந்த ஐந்து பேர் கைது செய்யப்பட்டுள்ளனர்.\r\nஎல்லைப் பகுதிக…', 'நேபாளத்தில் போதைப்பொருள் கடத்தலைத் தடுக்க போலீசார் நடத்திய தொடர் சோதனை நடவடிக்கைகளில், இந்தியர்களைச் சேர்ந்த ஐந்து பேர் கைது செய்யப்பட்டுள்ளனர்.\r\nஎல்லைப் பகுதிகளை மையமாகக் கொண்டு மேற்கொள்ளப்பட்ட விசாரணையின் போது, சந்தேகத்திற்கிடமான வகையில் செயல்பட்டவர்களை போலீசார் தடுத்து நிறுத்தி சோதனையிட்டனர். அப்போது அவர்களிடமிருந்து தடைசெய்யப்பட்ட போதைப்பொருட்கள் கைப்பற்றப்பட்டதாக அதிகாரிகள் தெரிவித்தனர். கைது செய்யப்பட்டவர்களிடம் தீவிர விசாரணை நடைபெற்று வருகிறது. இந்தக் கடத்தல் வலையமைப்பில் மேலும் தொடர்புடையவர்கள் உள்ளனரா, போதைப்பொருட்கள் எந்த வழித்தடத்தின் மூலம் கொண்டு செல்லப்பட்டன என்பதையும் அதிகாரிகள் ஆராய்ந்து வருகின்றனர். சமீப காலமாக இந்தியா–நேபாள எல்லைப் பகுதிகளில் போதைப்பொருள் கடத்தலைத் தடுக்கும் நடவடிக்கைகள் தீவிரப்படுத்தப்பட்டுள்ள நிலையில், இந்த கைது அதில் ஒரு முக்கிய முன்னேற்றமாகக் கருதப்படுகிறது. ', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a54c4e205e176.48969797.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-13 16:30:15', 0, 1, 0, 0, 0, 'நேபாளம்: போதைப்பொருள் கடத்திய இந்தியர்கள் 5 பேர் கைது ', 'நேபாளத்தில் போதைப்பொருள் கடத்தலைத் தடுக்க போலீசார் நடத்திய தொடர் சோதனை நடவடிக்கைகளில், இந்தியர்களைச் சேர்ந்த ஐந்து பேர் கைது செய்யப்பட்டுள்ளனர்.\r\nஎல்லைப் பகுதிக', 11, 0, 0, 1, '2026-07-13 11:00:15', '2026-07-14 05:24:07', NULL, 0);
INSERT INTO `tn_articles` (`id`, `user_id`, `contributor_id`, `category_id`, `district_id`, `city_id`, `city_text`, `media_id`, `title`, `slug`, `excerpt`, `content`, `content_type`, `sponsored_subscription_id`, `language`, `youtube_url`, `youtube_video_id`, `image_url`, `news_card_image`, `thumb_url`, `image_caption`, `image_credit`, `status`, `approval_stage`, `rejection_reason`, `approved_by`, `approved_at`, `scheduled_at`, `published_at`, `is_breaking`, `is_featured`, `is_editors_pick`, `is_premium`, `is_sponsored`, `meta_title`, `meta_desc`, `view_count`, `share_count`, `comment_count`, `read_time`, `created_at`, `updated_at`, `rating_avg`, `rating_count`) VALUES
(306, 4, NULL, 1, NULL, NULL, NULL, 168, 'தாய்மாமன் தங்க மோதிரம் திட்டத்திற்கான ஒப்பந்த அறிவிப்பு வெளியீடு', 'தாய்மாமன்-தங்க-மோதிரம்-திட்டத்திற்கான-ஒப்பந்த-அறிவிப்பு-வெளியீடு', 'அறிஞர் அண்ணா பிறந்தநாளான செப்.15ஆம் தேதி தாய்மாமன் தங்கம் மோதிரம் திட்டத்தை முதல்-அமைச்சர் விஜய் தொடங்கி வைக்க உள்ளார்.\r\nஇந்நிலையில் ஒரு கிராம் தங்கம் ரூ.5,725-…', 'அறிஞர் அண்ணா பிறந்தநாளான செப்.15ஆம் தேதி தாய்மாமன் தங்கம் மோதிரம் திட்டத்தை முதல்-அமைச்சர் விஜய் தொடங்கி வைக்க உள்ளார்.\r\nஇந்நிலையில் ஒரு கிராம் தங்கம் ரூ.5,725-க்கு கொள்முதல் செய்ய டெண்டர் அறிவிக்கப்பட்டுள்ளது. இன்று (ஜூலை 14ம் தேதி) முதல் ஆகஸ்ட் 17-ஆம் தேதி வரை டெண்டருக்கு விண்ணப்பிக்கலாம் என்றும் தெரிவிக்கப்பட்டுள்ளது. இதன்படி ஒரு கிராம் எடையுள்ள 4,41,667 தங்க மோதிரங்களை வாங்க ஒப்பந்தம் அறிவிக்கப்பட்டுள்ளது.\r\nதமிழ்நாடு அரசின் சமூக நலத் திட்டங்களில் ஒன்றான தாய்மாமன் தங்க மோதிரம்\' திட்டத்தை செயல்படுத்துவதற்காக தங்க மோதிரங்களை கொள்முதல் செய்யும் பணிக்கான ஒப்பந்த அறிவிப்பை அரசு வெளியிட்டுள்ளது.இந்த அறிவிப்பின் மூலம் தகுதியான நிறுவனங்கள் மற்றும் உற்பத்தியாளர்களிடமிருந்து விண்ணப்பங்கள் வரவேற்கப்பட்டுள்ளன. ஒப்பந்த நிபந்தனைகள், தகுதிகள், தரநிலைகள் மற்றும் விண்ணப்பிக்கும் காலக்கெடு உள்ளிட்ட விவரங்கள் அரசின் டெண்டர் ஆவணத்தில் இடம்பெற்றுள்ளன.திட்டத்தின் பயனாளிகளுக்கு தரமான தங்க மோதிரங்கள் உரிய காலத்தில் வழங்கப்படுவதை உறுதி செய்வதற்காக இந்த ஒப்பந்த நடைமுறை மேற்கொள்ளப்படுவதாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a55c5ac50c3c5.90558226.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-14 10:44:30', 0, 1, 0, 0, 0, 'தாய்மாமன் தங்க மோதிரம் திட்டத்திற்கான ஒப்பந்த அறிவிப்பு வெளியீடு', 'அறிஞர் அண்ணா பிறந்தநாளான செப்.15ஆம் தேதி தாய்மாமன் தங்கம் மோதிரம் திட்டத்தை முதல்-அமைச்சர் விஜய் தொடங்கி வைக்க உள்ளார்.\r\nஇந்நிலையில் ஒரு கிராம் தங்கம் ரூ.5,725-', 0, 0, 0, 1, '2026-07-14 05:14:30', '2026-07-14 10:45:03', NULL, 0),
(307, 4, NULL, 1, NULL, NULL, NULL, 169, 'நலம் TN புதிய இணையதளம்: முதல்-அமைச்சர் விஜய் தொடங்கி வைத்தார்...', 'நலம்-tn-புதிய-இணையதளம்-முதல்-அமைச்சர்-விஜய்-தொடங்கி-வைத்தார்', 'தமிழக மக்களுக்கு சுகாதார சேவைகளை எளிதாகவும் விரைவாகவும் வழங்கும் நோக்கில் உருவாக்கப்பட்ட **‘நலம் TN’** புதிய இணையதளத்தை முதல்-அமைச்சர் விஜய் இன்று தொடங்கி வைத்த…', 'தமிழக மக்களுக்கு சுகாதார சேவைகளை எளிதாகவும் விரைவாகவும் வழங்கும் நோக்கில் உருவாக்கப்பட்ட **‘நலம் TN’** புதிய இணையதளத்தை முதல்-அமைச்சர் விஜய் இன்று தொடங்கி வைத்தார்.இந்த இணையதளம் மூலம் அரசு மருத்துவமனைகள், ஆரம்ப சுகாதார நிலையங்கள், மருத்துவத் திட்டங்கள், சுகாதார விழிப்புணர்வு தகவல்கள் உள்ளிட்ட பல்வேறு சேவைகள் ஒரே தளத்தில் பொதுமக்களுக்கு கிடைக்க ஏற்பாடு செய்யப்பட்டுள்ளதாக தெரிவிக்கப்பட்டுள்ளது.\r\nமக்கள் தங்களுக்குத் தேவையான சுகாதாரத் தகவல்களை எளிதில் அறிந்து, அரசு வழங்கும் மருத்துவ சேவைகளை விரைவாகப் பயன்படுத்தும் வகையில் இந்த இணையதளம் வடிவமைக்கப்பட்டுள்ளது.டிஜிட்டல் தொழில்நுட்பத்தை பயன்படுத்தி பொதுச் சுகாதார சேவைகளை மேலும் மேம்படுத்தும் முயற்சியின் ஒரு பகுதியாக இந்த புதிய இணையதளம் அறிமுகப்படுத்தப்பட்டுள்ளதாக அரசு அதிகாரிகள் தெரிவித்தனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a55c7d56cf324.71442512.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-14 10:53:38', 0, 1, 0, 0, 0, 'நலம் TN’ புதிய இணையதளம்: முதல்-அமைச்சர் விஜய் தொடங்கி வைத்தார்...', 'தமிழக மக்களுக்கு சுகாதார சேவைகளை எளிதாகவும் விரைவாகவும் வழங்கும் நோக்கில் உருவாக்கப்பட்ட **‘நலம் TN’** புதிய இணையதளத்தை முதல்-அமைச்சர் விஜய் இன்று தொடங்கி வைத்த', 0, 0, 0, 1, '2026-07-14 05:23:38', '2026-07-14 10:54:01', NULL, 0),
(308, 4, NULL, 1, NULL, NULL, NULL, 170, 'சேலத்தில் 3,600 ஆண்டுகள் பழமையான மனித புதைகுழிகள் கண்டுபிடிப்பு', 'சேலத்தில்-3600-ஆண்டுகள்-பழமையான-மனித-புதைகுழிகள்-கண்டுபிடிப்பு', 'சேலம் மாவட்டத்தில் நடைபெற்ற தொல்லியல் ஆய்வின்போது, சுமார் 3,600 ஆண்டுகள் பழமையான மனித புதைகுழிகள் கண்டறியப்பட்டுள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nஆய்வின்போது…', 'சேலம் மாவட்டத்தில் நடைபெற்ற தொல்லியல் ஆய்வின்போது, சுமார் 3,600 ஆண்டுகள் பழமையான மனித புதைகுழிகள் கண்டறியப்பட்டுள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nஆய்வின்போது முதுமக்கள் தாழிகள், மண் பானைகள், கற்களால் அமைக்கப்பட்ட புதைகுழி கட்டமைப்புகள் உள்ளிட்ட பல தொல்லியல் சான்றுகள் வெளிச்சத்துக்கு வந்துள்ளன. இவை அப்பகுதியில் பண்டைய கால மனிதர்களின் வாழ்வியல், அடக்க முறைகள் மற்றும் பண்பாட்டு மரபுகளை வெளிப்படுத்தும் முக்கிய ஆதாரங்களாகக் கருதப்படுகின்றன.கண்டுபிடிக்கப்பட்ட பொருட்கள் அனைத்தும் ஆய்வுக்காக பாதுகாப்பாக சேகரிக்கப்பட்டுள்ளன. அவற்றின் வயது மற்றும் வரலாற்றுப் பின்னணியை உறுதிப்படுத்தும் பணிகள் தொடர்ந்து நடைபெற்று வருகின்றன.இந்தக் கண்டுபிடிப்பு, தமிழகத்தின் தொன்மையான நாகரிக வரலாற்றை மேலும் வெளிக்கொணரும் முக்கியமான தொல்லியல் ஆதாரமாக ஆய்வாளர்கள் கருதுகின்றனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a55c908520839.53627547.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-14 10:58:49', 0, 1, 0, 0, 0, 'சேலத்தில் 3,600 ஆண்டுகள் பழமையான மனித புதைகுழிகள் கண்டுபிடிப்பு ', 'சேலம் மாவட்டத்தில் நடைபெற்ற தொல்லியல் ஆய்வின்போது, சுமார் 3,600 ஆண்டுகள் பழமையான மனித புதைகுழிகள் கண்டறியப்பட்டுள்ளதாக அதிகாரிகள் தெரிவித்துள்ளனர்.\r\nஆய்வின்போது', 0, 0, 0, 1, '2026-07-14 05:28:49', '2026-07-14 10:59:05', NULL, 0),
(309, 4, NULL, 1, NULL, NULL, NULL, 171, 'வியட்நாம் படகு விபத்தில் பலியான 10 பேரின் உடல்கள் தமிழகம் வந்தன', 'வியட்நாம்-படகு-விபத்தில்-பலியான-10-பேரின்-உடல்கள்-தமிழகம்-வந்தன', 'வியட்நாமின் பு குவோக் (Phu Quoc) தீவு அருகே கடந்த வாரம் ஏற்பட்ட சுற்றுலா படகு விபத்தில் உயிரிழந்த இந்தியர்களின் உடல்கள் இந்தியா கொண்டு வரப்பட்டன. அவர்களில் தமிழ…', 'வியட்நாமின் பு குவோக் (Phu Quoc) தீவு அருகே கடந்த வாரம் ஏற்பட்ட சுற்றுலா படகு விபத்தில் உயிரிழந்த இந்தியர்களின் உடல்கள் இந்தியா கொண்டு வரப்பட்டன. அவர்களில் தமிழ்நாட்டைச் சேர்ந்த 10 பேரின் உடல்கள் இன்று அவர்களின் சொந்த மாவட்டங்களுக்கு அனுப்பி வைக்கப்பட்டன. முதலில் ஹோ சி மின் நகரிலிருந்து மும்பைக்கு விமானம் மூலம் கொண்டு வரப்பட்ட உடல்கள், பின்னர் உள்நாட்டு விமானங்கள் மூலம் சென்னை உள்ளிட்ட மாநிலங்களுக்கு அனுப்பப்பட்டன. அதிகாரிகள் மற்றும் உறவினர்கள் அஞ்சலி செலுத்திய பின்னர் இறுதிச்சடங்கிற்காக குடும்பத்தினரிடம் ஒப்படைக்கப்பட்டன. இந்த விபத்தில் மொத்தம் 15 இந்தியர்கள் உயிரிழந்தனர். இவர்களில் 10 பேர் தமிழ்நாட்டைச் சேர்ந்தவர்கள், 3 பேர் ஆந்திரப் பிரதேசத்தையும், 2 பேர் கேரளாவையும் சேர்ந்தவர்கள் என இந்திய தூதரகம் தெரிவித்துள்ளது. விபத்துக்கான காரணம் குறித்து வியட்நாம் அதிகாரிகள் தொடர்ந்து விசாரணை நடத்தி வருகின்றனர். \r\n\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a55cad56df680.20477896.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-14 11:06:26', 0, 1, 0, 0, 0, 'வியட்நாம் படகு விபத்தில் பலியான 10 பேரின் உடல்கள் தமிழகம் வந்தன ', 'வியட்நாமின் பு குவோக் (Phu Quoc) தீவு அருகே கடந்த வாரம் ஏற்பட்ட சுற்றுலா படகு விபத்தில் உயிரிழந்த இந்தியர்களின் உடல்கள் இந்தியா கொண்டு வரப்பட்டன. அவர்களில் தமிழ', 0, 0, 0, 1, '2026-07-14 05:36:26', '2026-07-14 11:06:41', NULL, 0),
(310, 4, NULL, 1, NULL, NULL, NULL, 172, 'கச்சா எண்ணெய் விலை 10 சதவீதம் உயர்வு', 'கச்சா-எண்ணெய்-விலை-10-சதவீதம்-உயர்வு', 'சர்வதேச சந்தையில் கச்சா எண்ணெய் விலை சுமார் 10 சதவீதம் உயர்ந்துள்ளது. மத்திய கிழக்கு பிராந்தியத்தில் நிலவும் பதற்றம், உற்பத்தி மற்றும் விநியோகத்தில் ஏற்படக்கூடி…', 'ஈரான்-அமெரிக்க போரால் பெட்ரோல், டீசல் விலை நேற்று கணிசமாக உயர்ந்தது. சென்னையில் ஒரு லிட்டர் பெட்ரோல் விலை 1.69 ர ரூபாய் உயர்ந்து, லிட்டர் ரூ.109.46-க்கும், டீசல் விலை லிட்டருக்கு 1.71 ரூபாய் உயர்ந்து ரூ.101.26-க்கும் விற்பனையானது.சர்வதேச சந்தையில் கச்சா எண்ணெய் விலை சுமார் 10 சதவீதம் உயர்ந்துள்ளது. மத்திய கிழக்கு பிராந்தியத்தில் நிலவும் பதற்றம், உற்பத்தி மற்றும் விநியோகத்தில் ஏற்படக்கூடிய பாதிப்பு குறித்த அச்சம் ஆகியவை இந்த விலை உயர்வுக்கு முக்கிய காரணங்களாகக் கூறப்படுகின்றன.\r\nஎண்ணெய் விலை உயர்வால் பெட்ரோல், டீசல் உள்ளிட்ட எரிபொருட்களின் விலை நிலவரம் குறித்து நாடுகள் தீவிரமாக கண்காணித்து வருகின்றன. மேலும், போக்குவரத்து செலவு அதிகரிக்கும் வாய்ப்புள்ளதால் பல்வேறு பொருட்களின் விலையிலும் தாக்கம் ஏற்படலாம் என பொருளாதார நிபுணர்கள் தெரிவிக்கின்றனர்.உலக சந்தையின் நிலைமையைப் பொறுத்து கச்சா எண்ணெய் விலையில் மேலும் மாற்றங்கள் ஏற்படலாம் என்பதால், வர்த்தக நிறுவனங்களும் முதலீட்டாளர்களும் சந்தை நிலவரத்தை தொடர்ந்து கவனித்து வருகின்றனர்.\r\n', 'news', NULL, 'ta', NULL, NULL, '/uploads/2026/07/media_6a55cc53117071.45616985.webp', NULL, NULL, NULL, NULL, 'published', 'reporter', NULL, NULL, NULL, NULL, '2026-07-14 11:12:58', 0, 1, 0, 0, 0, 'கச்சா எண்ணெய் விலை 10 சதவீதம் உயர்வு ', 'சர்வதேச சந்தையில் கச்சா எண்ணெய் விலை சுமார் 10 சதவீதம் உயர்ந்துள்ளது. மத்திய கிழக்கு பிராந்தியத்தில் நிலவும் பதற்றம், உற்பத்தி மற்றும் விநியோகத்தில் ஏற்படக்கூடி', 0, 0, 0, 1, '2026-07-14 05:42:58', '2026-07-14 11:19:21', NULL, 0);
