INSERT INTO `tn_push_logs` (`id`, `type`, `ref_id`, `title`, `body`, `image_url`, `click_url`, `districts`, `sent_count`, `fail_count`, `status`, `sent_by`, `created_at`) VALUES
(1, 'article', 169, 'fasdfasdf', 'asfasdf aasdf df as fasdf asd', '/tamilnews/public/uploads/2026/06/media_6a3e3aa3573e46.86416118.webp', 'http://localhost/thinathulir/public/article/fasdfasdf', NULL, 0, 0, 'failed', NULL, '2026-06-29 14:56:57'),
(2, 'article', 195, 'திருப்பதி கோவிலில் ஒரே நாளில் 90 ஆயிரம் பக்தர்கள் சாமி தரிசனம்...', 'திருப்பதி மலைக்கோவிலில் பக்தர்கள் வருகை தொடர்ந்து அதிகரித்து வருகிறது. விடுமுறை மற்றும் சிறப்பு வழிபாட்டு நாட்களை முன்னி', '/uploads/2026/07/media_6a49ee2bacde31.54375836.webp', 'https://thinathulir.com/public/article/திருப்பதி-கோவிலில்-ஒரே-நாளில்-90-ஆயிரம்-பக்தர்கள்-சாமி-தரிசனம்', NULL, 0, 0, 'failed', NULL, '2026-07-05 16:49:24'),
(3, 'article', 194, 'குற்றாலத்தில் அனைத்து அருவிகளிலும் சுற்றுலா பயணிகள் குளிக்க அனுமதி...', 'தென்காசி மாவட்டம் குற்றாலத்தில் கடந்த சில நாட்களாக பெய்த மழையால் அருவிகளில் நீர்வரத்து அதிகரித்திருந்தது. பாதுகாப்பு நில', '/uploads/2026/07/media_6a49eb6708cf20.79220301.webp', 'https://thinathulir.com/public/article/குற்றாலத்தில்-அனைத்து-அருவிகளிலும்-சுற்றுலா-பயணிகள்-குளிக்க-அனுமதி', NULL, 0, 0, 'failed', NULL, '2026-07-05 16:49:39'),
(4, 'article', 238, 'பொள்ளாச்சியில் சிறுவன் அடித்துக் கொலை', 'சிறார்கள் இணைந்து செய்த சம்பவத்தில் அதிர்ச்சி\r\nபொள்ளாச்சி பகுதியில் பேக்கரி கேக் மாஸ்டர் பூவரசன் (30) என்பவர் அடித்துக் ', '/uploads/2026/07/media_6a4fa52b883795.69405719.webp', 'https://thinathulir.com/public/article/பொள்ளாச்சியில்-சிறுவன்-அடித்துக்-கொலை', NULL, 0, 0, 'failed', NULL, '2026-07-09 14:02:34'),
(5, 'article', 240, 'பாகப்பிரிவால் கோவில் திருவிளக்கு பூஜை', '🌺 திருவெற்றியூர் பாகம்பிரியாள் அம்மன் – பக்தர்களின் சொத்துகளைக் கூட காக்கும் தாயுள்ளம் கொண்ட தெய்வம்! 🌺\r\n\r\nதமிழகத்தின் த', '/uploads/2026/07/media_6a4faeac7c1af9.40695597.webp', 'https://thinathulir.com/public/article/பாகப்பிரியாள் திருகோவில்-திருவிளக்கு-பூஜை', NULL, 0, 0, 'failed', NULL, '2026-07-09 14:22:44');
